window.BANDS_FULL = [
  // ───────── Thu Apr 23 (d1) ─────────
  { id: 'b001', name: "Gov't Majik"                                               , day: 'd1', stage: 'festival',   start: '11:20', end: '12:10', yt: 'ibdL960ISJA', verified: true , blurb: 'Gov\'t Majik channels the raw, funky soul of New Orleans brass tradition through a contemporary lens, blending swagger-laden grooves with the kind of instrumental virtuosity that makes the Festival Stage come alive. This is the sound of the city\'s streets meeting its studios—infectious, unapologetic, and absolutely impossible to stand still for.'},
  { id: 'b002', name: "Johnny Sketch & The Dirty Notes"                           , day: 'd1', stage: 'festival',   start: '12:35', end: '13:35', yt: 'tTV0RBk_yEc', verified: true , blurb: 'Since its inception in 2001, Johnny Sketch & The Dirty Notes (JSDN) has gained a loyal following in a competitive New Orleans music scene. Their unique FUNK/ROCK style blends a hard driving rhythm section reminiscent of the Radiators\' swamp funk added to the punchy horns of Tower Of Power.'},
  { id: 'b003', name: "Brass-A-Holics"                                            , day: 'd1', stage: 'festival',   start: '14:00', end: '15:00', yt: '9jJqOvFIvJI', verified: true , blurb: 'Brass-A-Holics brings pure New Orleans brass band energy to the Festival Stage—a high-octane blend of traditional second line swagger and modern funk that\'ll have you moving before the first note lands. Their infectious grooves and undeniable horn power capture everything that makes this city\'s street music culture legendary, delivered with the polish and precision that keeps Jazz Fest crowds coming back year after year.'},
  { id: 'b004', name: "Cowboy Mouth"                                              , day: 'd1', stage: 'festival',   start: '15:25', end: '16:25', yt: 'NEfpoUuKFOY', verified: true , blurb: 'For Cowboy Mouth, the road goes on forever. Now approaching their third decade together, the New Orleans-based rockers continue to cement their reputation as celebratory, electrifying road warriors. They\'ve played more than 3,000 shows to over 10 million fans, mixing the party-friendly punch of their hometown — a city known for good times and even better music — with a raw, rock & roll foundation. From the opening guitar riff of the band\'s signature hit, "Jenny Says," to the furious percussion supplied by the group\'s drummer and larger-than-life frontman, Fred LeBlanc, Cowboy Mouth shows remain legendary. "A Cowboy Mouth concert is like a Southern gospel revival without the religion," says LeBlanc, who helped form the band in 1990. Nearly 30 years later, Cowboy Mouth continue to do their best work onstage, supplying their nightly congregation of rock & roll sinners and holy rollers— from the 100,000 people who watched the band open for Aerosmith at Jazz Fest 2018, to the densely-packed audiences that have filled the band\'s club and theater shows for decades — with a reminder that rock & roll music doesn\'t just swagger, sweat, and stomp. It saves. Back in the 1990s, when rock was king and record labels were loaded, Cowboy Mouth released hit songs for MCA Records and Atlantic Records. MTV loved the guys. The radio loved them, too, with "Jenny Says" charging up the Top 40 hit on multiple Billboard charts. Even so, it was the band\'s touring schedule and live show that truly set them apart. When the recording industry took a nosedive during the 2000s, Cowboy Mouth continued flying high, creating an even tighter bond with their audience by releasing music on their own. They didn\'t need help from any record execs. After all, it was the band\'s fan base that had always supported Cowboy Mouth…and today, it\'s still the high-energy live show that keeps the crowds coming back. That live show will receive new fuel in 2019, when Cowboy Mouth releases an EP of original songs loaded with the same in-your-face, amplified attack that launched the band\'s career years ago. Joining Fred LeBlanc on the new record is the band\'s longtime guitarist John Thomas Griffith, who fronted the nationally-acclaimed group Red Rockers (and sang on their early-1980s MTV staple, "China") before joining Cowboy Mouth\'s original lineup. Also featuring bassist Brian Broussard and guitarist Matt Jones, Cowboy Mouth\'s roster is stronger than ever: a lineup of four rock & roll veterans, all working together to stir the band\'s unique gumbo of pop, Big Easy blues, soul, punk, and redemptive rock & roll. "What we provide isn\'t just musical entertainment," LeBlanc explains. "It\'s an experience. We\'re constantly looking to top ourselves, because that\'s just who we are. We\'re galvanizers. We\'re a bit hyperbolic. We\'re Cowboy Mouth." Cake Magazine said it best: "On a bad night, they will blow the roof of the place. On a good night, Cowboy Mouth will save your soul.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41533/festivalartist-12439-artist_image-2cf9c005-70a8-4bda-9b93-5a70f3125aed.jpg'},
  { id: 'b005', name: "Kings of Leon"                                             , day: 'd1', stage: 'festival',   start: '17:00', end: '19:00', yt: 'RF0HhrwIwp0', verified: true , blurb: 'Kings of Leon is an American rock band formed in Nashville, Tennessee, in 1999. The band is composed of brothers Caleb, Nathan and Jared Followill, and their cousin Matthew Followill.'},
  { id: 'b006', name: "Sally Baby's Silver Dollars"                               , day: 'd1', stage: 'shell',      start: '11:20', end: '12:20', yt: 'tB2m3Jni21s', verified: true , blurb: 'Sally Baby\'s Silver Dollars brings gritty, soulful blues and R&B to the Gentilly Stage with the kind of swagger that only comes from deep New Orleans roots—expect vintage horns, talk-box grooves, and vocals that\'ll make you forget everything else. Jazz Fest devotees crave this exact blend of raw funk energy and classic soul that keeps the city\'s musical legacy alive.'},
  { id: 'b007', name: "Quiana Lynell"                                             , day: 'd1', stage: 'shell',      start: '12:45', end: '13:45', yt: 'wZzSUM1nWGQ', verified: true , blurb: 'Quiana Lynell brings sultry soul and contemporary R&B sophistication to the Shell Gentilly Stage, weaving New Orleans sensibility through modern grooves that feel both intimate and expansive. Her velvety vocals and genre-fluid approach make her a must-catch for fest-goers seeking the next generation of the city\'s vocal tradition.'},
  { id: 'b008', name: "Maggie Koerner"                                            , day: 'd1', stage: 'shell',      start: '14:10', end: '15:10', yt: '_C3BgoRN_94', verified: true , blurb: 'It’s not uncommon to find Maggie Koerner singing on stage with a list of iconic acts that has included Charles Bradley, Trombone Shorty, Widespread Panic and Gov’t Mule, to name a few. The Shreveport born singer-songwriter jump started her career, spending the majority of 2013 and 2014 as the lead singer and front-woman for the legendary New Orleans funk-band Galactic. After spending 2015 back on the road as a solo artist, Maggie released her “Dig Down Deep (EP)”, produced by esteemed UK producer Fink (Amy Winehouse, John Legend, Banks) on Ninja Tune in December 2016. While touring behind the EP in 2017, Maggie’s undeniable voice and live show got her noticed by several record labels. She eventually inked a deal with Concord Records and is releasing singles this year and a full length project in the Spring of 2020.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41440/festivalartist-12216-artist_image-09104da8-9ae2-4789-948e-08549f49f28d.jpg'},
  { id: 'b009', name: "Preservation Hall Jazz Band"                               , day: 'd1', stage: 'shell',      start: '15:35', end: '16:45', yt: 'rj_E63fwtnM', verified: true , blurb: 'At a moment when musical streams are crossing with unprecedented frequency, it’s crucial to remember that throughout its history, New Orleans has been the point at which sounds and cultures from around the world converge, mingle, and resurface, transformed by the Crescent City’s inimitable spirit and joie de vivre. Nowhere is that idea more vividly embodied than in the Preservation Hall Jazz Band, which has held the torch of New Orleans music aloft for more than 50 years, all the while carrying it enthusiastically forward as a reminder that the history they were founded to preserve is a vibrantly living history. PHJB marches that tradition forward once again on So It Is, the septet’s second release featuring all-new original music. The album redefines what New Orleans music means today by tapping into a sonic continuum that stretches back to the city’s Afro-Cuban roots, through its common ancestry with the Afrobeat of Fela Kuti and the Fire Music of Pharoah Sanders and John Coltrane, and forward to cutting-edge artists with whom the PHJB have shared festival stages from Coachella to Newport, including legends like Stevie Wonder, Elvis Costello and the Grateful Dead and modern giants like My Morning Jacket, Arcade Fire and the Black Keys.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41376/festivalartist-12049-artist_image-e5b6560a-ed07-435b-98d3-03834860498d.jpg'},
  { id: 'b010', name: "Raye"                                                      , day: 'd1', stage: 'shell',      start: '17:20', end: '19:00', yt: 'HtVcltkn3HI', verified: true , blurb: 'RAYE (Rachel Agatha Keen, born 24 October 1997) is a British singer-songwriter and record producer from Tooting who grew up in Croydon, South London.'},
  { id: 'b011', name: "Rik Jam and The Island Federation"                         , day: 'd1', stage: 'congo',      start: '11:20', end: '12:20', yt: 'JIs_RGSou48', verified: true , blurb: 'Rik Jam and The Island Federation bring reggae-rooted rhythms and pan-Caribbean grooves to Congo Square, blending island vibes with New Orleans\' deep musical soul for a set that\'ll have you moving from the first beat. This is the sound of cultural fusion done right—infectious, soulful, and authentically connected to the spirit that makes Jazz Fest legendary.'},
  { id: 'b012', name: "Omari Neville & The Fuel"                                  , day: 'd1', stage: 'congo',      start: '12:45', end: '13:45', yt: '1T68AObPab0', verified: true , blurb: 'Omari Neville & The Fuel bring a fierce, contemporary blend of soul, funk, and New Orleans R&B to Congo Square, channeling the spiritual energy of the stage through bold horns, hypnotic grooves, and Neville\'s commanding presence—a must-see for anyone craving modern heat rooted in the city\'s deepest traditions.'},
  { id: 'b013', name: "Big Chief Donald Harrison Deezle featuring and BlaqNmilD"  , day: 'd1', stage: 'congo',      start: '14:10', end: '15:10', yt: '-9kfyruxqDk', verified: true , blurb: 'Big Chief Donald Harrison Deezle brings the raw, unfiltered spirit of New Orleans Mardi Gras Indian culture to the Congo Square Stage, where traditional chants, hypnotic rhythms, and modern production collide in a celebration of Black Atlantic heritage and street tradition. This is funk meets folklore, a high-energy experience that channels decades of parade culture and improvisation into something thrilling and utterly authentic.'},
  { id: 'b014', name: "Cimafunk"                                                  , day: 'd1', stage: 'congo',      start: '15:40', end: '16:55', yt: 'o1YBngPfU-o', verified: true , blurb: 'Cimafunk is by far the most exciting new face in Cuba’s music scene. Cimafunk is a Cimarron*, a free being defying classification, a pilgrim in search of new musical miscegenation and the reunion of black music. He believes in nothing but the power of the Groove and the cathartic communion of dancing bodies. A renaissance man, conscious of his roots and musical ancestry, Cimafunk’s music looks firmly into the future. Singer, composer, and producer, Cimafunk offers a subtle and bold mix of funk with Cuban music and African rhythms, a life-affirming sound, a UFO in the island’s music scene. His debut album “Terapia” (Independent Production, 2017) and especially his electric live shows are inexorably conquering a multitude of audiences from Havana to Paris. He broke attendance records in iconic venues such as Fabrica de Arte Cubano, El Sauce and La Tropical. *Fugitive slaves who settled in the wild to lead a free life in Cuba.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41462/festivalartist-12277-artist_image-d1e129e2-e978-4e9a-87f0-9176649e71fa.jpg'},
  { id: 'b015', name: "Stephen Marley"                                            , day: 'd1', stage: 'congo',      start: '17:25', end: '18:55', yt: '0rUxoVDo1Uo', verified: true , blurb: 'Stephen Robert Nesta Marley, (⋆20  Apr 1972 in Wilmington, Delaware; raised in Kingston, Jam) is a reggae artist and producer, son to Bob Marley and Rita Marley and a 6-time Grammy award winner. 8-20 years old, he was a part of Ziggy Marley & The Melody Makers.'},
  { id: 'b016', name: "Loyola University Jazz Ensemble"                           , day: 'd1', stage: 'jazz',       start: '11:15', end: '12:00', yt: 'B-cOM3YQFiQ', verified: true , blurb: 'Loyola University Jazz Ensemble brings the living tradition of New Orleans jazz education to life with spirited arrangements that honor the past while swinging boldly into the present—a collective of young lions channeling the deep heritage that flows through the Crescent City\'s oldest musical institution. Their WWOZ Jazz Tent set is pure infectious energy: tightly locked rhythms, soaring horns, and the kind of ensemble cohesion that reminds you why New Orleans remains the birthplace of jazz.'},
  { id: 'b017', name: "Blodie's Jazz Jam"                                         , day: 'd1', stage: 'jazz',       start: '12:20', end: '13:10', yt: 'jFgAd83Bo4g', verified: true , blurb: 'Blodie\'s Jazz Jam brings the raw, unfiltered soul of New Orleans jazz to life with their high-energy blend of traditional and contemporary styles that keeps audiences moving and grooving all night long. This is pure, infectious jazz that celebrates the city\'s musical roots while pushing the sound forward—exactly what Jazz Fest devotees crave.'},
  { id: 'b018', name: "Kyle Roussel"                                              , day: 'd1', stage: 'jazz',       start: '13:30', end: '14:25', yt: '1W1lde35_H4', verified: true , blurb: 'Kyle Roussel channels the soulful, improvisational spirit of traditional New Orleans jazz with a modern sensibility, blending trombone-driven melodies and second-line swagger that honors the city\'s deepest musical roots. His WWOZ set delivers the kind of intimate, groove-heavy authenticity that keeps Jazz Fest devotees coming back to the tent all weekend long.'},
  { id: 'b019', name: "Peter Harris presents Double Bird"                         , day: 'd1', stage: 'jazz',       start: '14:45', end: '15:40', yt: 'RVD9aanv2EI', verified: true , blurb: 'Double Bird brings sharp, conversational interplay and modern jazz sophistication to the WWOZ Jazz Tent, where their telepathic musicianship and genre-blending sensibility—rooted in New Orleans tradition but reaching toward contemporary expression—will captivate fans seeking adventurous, intimate jazz at its finest.'},
  { id: 'b020', name: "Nicholas Payton featuring Butcher Brown presents A Supreme Blue", day: 'd1', stage: 'jazz',       start: '16:05', end: '17:20', yt: 'qrh1GTKgoIQ', verified: true , blurb: 'Nicholas Payton featuring Butcher Brown presents A Supreme Blue is a masterclass in modern jazz sophistication, blending virtuosic horn arrangements with funk-inflected grooves and deep spiritual resonance that honors New Orleans\' legacy while pushing boldly forward. This is essential listening for Jazz Fest devotees who crave innovation rooted in tradition—a sound that\'s equal parts intellectual exploration and pure, undeniable groove.'},
  { id: 'b021', name: "Monty Alexander \"Jamericana\""                            , day: 'd1', stage: 'jazz',       start: '17:45', end: '19:00', yt: 'By4TfZlpny0', verified: true , blurb: 'Monty Alexander\'s "Jamericana" swings hard at the intersection of Caribbean groove and American jazz soul, blending reggae rhythms with improvised piano mastery for a feel-good sound that hits like island sun and New Orleans heat. Jazz Fest devotees will dig the infectious energy and masterful musicianship that makes every performance a celebration.'},
  { id: 'b022', name: "Brother Tyrone & The Mindbenders"                          , day: 'd1', stage: 'blues',      start: '11:20', end: '12:25', yt: 'kzX8KAlzJKU', verified: true , blurb: 'Brother Tyrone & The Mindbenders bring raw, soulful blues with a psychedelic edge that cuts straight to the heart—expect hypnotic grooves, gritty guitar work, and vocals that echo the spiritual depth of New Orleans\' deepest traditions. Jazz Fest devotees will find themselves transported by their mind-bending arrangements that honor classic blues while pushing fearlessly into uncharted sonic territory.'},
  { id: 'b023', name: "Vieux Farka Touré"                                         , day: 'd1', stage: 'blues',      start: '12:50', end: '14:00', yt: '41nL2v4SG9w', verified: true , blurb: 'Vieux Farka Touré is a Malian singer and guitarist, and son of one of the African continent\'s most internationally renowned musicians Ali Farka Touré. Since his childhood, Vieux Farka Touré has been deeply inspired by the music of his father, Ali Farka Touré.'},
  { id: 'b024', name: "Kenny Neal"                                                , day: 'd1', stage: 'blues',      start: '14:25', end: '15:25', yt: 'jJidxU1ssjI', verified: true , blurb: 'One of the strongest modern proponents of Baton Rouge swamp blues, Kenny Neal is a second-generation southern Louisiana bluesman who is cognizant of the region’s venerable blues tradition and imaginative enough to steer it in fresh directions. Neal was born on October 14, 1957 in New Orleans. His dad, harpist Raful Neal, was a Baton Rouge blues mainstay whose pals included Buddy Guy and Slim Harpo (the latter gave three-year-old Kenny his first harmonica). At age 13, Neal was playing in his father’s band, and at 17, landed a job playing bass for Buddy Guy. The guitarist recruited some of his talented siblings to form the Neal Brothers Blues Band up in Toronto (brother Noel later played bass behind James Cotton; five other Neal brothers also play in various bands) before returning stateside. In 1987, Kenny Neal cut his debut LP for Florida producer Bob Greenlee, an updated swamp feast initially released by Kingsnake Records as Bio on the Bayou. The following year, Alligator Records signed Neal and reissued the debut under the title Big News from Baton Rouge!! Young Neal was on his way. Neal’s sizzling guitar work, sturdy harp, and gravelly, aged-beyond-his-years vocals served him well, and he cut four albums for Alligator Records between 1989 and 1994. An acclaimed 1991 stint on Broadway in a production of Mule Bone found him performing acoustic versions of Langston Hughes’ poetry set to music by Taj Mahal. In 1998, Neal moved from Alligator to the blues division of the jazz-based Telarc Records, releasing three albums for the label: Blues Fallin’ Down Like Rain (1998), What You Got (2000), and One Step Closer (2001). In the new millennium, Neal recorded sets for a variety of independent labels, including Easy Meeting (a 2003 collaboration with Billy Branch), Double Take (2004, a one-shot return to Alligator), and A Tribute to Slim Harpo and Raful Neal (released in 2005 for True Life Entertainment). Three years later, Neal hooked up with Blind Pig Records and released Let Life Flow in 2008, once again incorporating his gritty Louisiana roots with a sophisticated Chicago/Memphis soul approach. A second Blind Pig release, Hooked on Your Love, appeared two years later in 2010. In 2015, Neal released his first holiday-themed album, I’ll Be Home for Christmas. It was his first album for Cleopatra Records, which also issued his latest critically acclaimed release, Bloodline in 2016. Kenny’s 2016 release, Bloodline, was nomimated for a 2017 Grammy for Best Contemporary Blues Album and also won two 2017 BMAs (Blues Music Awards); one for Best Contemporary Blues Album and the other for Best Contemporary Male Blues Artist. Kenny Neal, a true living blues Legend is THE REAL DEAL and more poised than ever to deliver the blues like no one else can!', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41539/festivalartist-12450-artist_image-c92889f5-1540-4366-8ef5-58c9e5a8ce6c.jpg'},
  { id: 'b025', name: "Sierra Green and The Giants"                               , day: 'd1', stage: 'blues',      start: '15:50', end: '17:00', yt: 'r3ebhM1ugy4', verified: true , blurb: 'Sierra Green and The Giants bring gutsy, soulful blues with a modern edge to the Blues Tent, blending classic Delta traditions with contemporary groove that hits hard and stays with you long after the set ends. This is blues made for moving bodies and open hearts—exactly the kind of authentic, high-energy performance that keeps Jazz Fest audiences coming back to the Blues Tent year after year.'},
  { id: 'b026', name: "Charlie Musselwhite & GA-20: Together Onstage"             , day: 'd1', stage: 'blues',      start: '17:30', end: '18:45', yt: 'QSNyn2TIFaU', verified: true , blurb: 'Charlie Musselwhite and GA-20 bring raw, amplified blues firepower to the Blues Tent—a masterclass in harmonica virtuosity and tight, grooving instrumentation that channels the soul of the Deep South. This is blues that bites, burnished by decades of tradition yet crackling with contemporary energy that\'ll have you moving from first note to last.'},
  { id: 'b027', name: "Kid Simmon's Local International Allstars"                 , day: 'd1', stage: 'economy',    start: '11:20', end: '12:10', yt: 'fIZs9AZ92Kc', verified: true , blurb: 'Kid Simmons\' Local International Allstars blend deep New Orleans soul with global rhythms, delivering the kind of infectious, conversation-starting groove that keeps Economy Hall packed all festival long. Their infectious energy and genre-defying approach—rooted in second-line tradition but reaching across continents—captures everything Jazz Fest audiences crave: authenticity, joy, and pure musical adventurousness.'},
  { id: 'b028', name: "Norbert Susemihl's New Orleans Allstars"                   , day: 'd1', stage: 'economy',    start: '12:30', end: '13:25', yt: '0TKd9Ucybnc', verified: true , blurb: 'Norbert Susemihl\'s New Orleans Allstars bring the true spirit of the Crescent City to Economy Hall with their deep-rooted traditional jazz and second-line swagger, blending New Orleans\' musical DNA with infectious energy that\'ll have you moving from the first note.'},
  { id: 'b029', name: "Gregg Stafford's Jazz Hounds"                              , day: 'd1', stage: 'economy',    start: '13:45', end: '14:40', yt: '5hppsJnvyCw', verified: true , blurb: 'Gregg Stafford\'s Jazz Hounds bring traditional New Orleans jazz to life with spirited horn arrangements and that raw, authentic sound that makes the Economy Hall Tent swing—pure trad jazz energy that reminds you exactly why this music was born in the Crescent City.'},
  { id: 'b030', name: "The Lena Prima Band"                                       , day: 'd1', stage: 'economy',    start: '15:05', end: '16:10', yt: 'p4TGxYsDYDs', verified: true , blurb: 'The Lena Prima Band brings classic New Orleans jazz tradition alive with swinging horns, infectious rhythms, and the spirited energy that made this city a musical legend—a must-see for anyone craving authentic jazz authenticity and multigenerational groove.'},
  { id: 'b031', name: "Aurora Nealand's Royal Roses"                              , day: 'd1', stage: 'economy',    start: '16:30', end: '17:25', yt: 'O9c3qgtn4Mw', verified: true , blurb: 'Aurora Nealand\'s Royal Roses brings classic New Orleans brass tradition into the modern era with infectious second-line grooves and joyful, soulful horns that\'ll have you dancing through Economy Hall. This is the sound of the city\'s living legacy—funky, celebratory, and impossible to sit still for.'},
  { id: 'b032', name: "Jamil Sharif"                                              , day: 'd1', stage: 'economy',    start: '17:45', end: '18:40', yt: 'qTEfiAWM4ys', verified: true , blurb: 'Native New Orleans trumpeter,composer,educator,actor.  Jamil Sharif began playing music at the age of 14. Much of his influence came from his Father, the Late World Renowned Trumpeter Emery Humphrey Thompson (Umar Sharif).'},
  { id: 'b033', name: "Mason Trail and Zydeco Rhythm"                             , day: 'd1', stage: 'fais',       start: '11:15', end: '12:05', yt: 'ysg89Ryd-VQ', verified: true , blurb: 'Mason Trail and Zydeco Rhythm bring the swamp-fired soul of authentic Louisiana zydeco to the Fais Do-Do Stage, blending accordion-driven grooves with infectious rhythms that get the whole crowd moving. Their high-energy celebration of Cajun culture and traditional zydeco traditions is exactly what Jazz Fest devotees crave—raw, joyful, and undeniably rooted in New Orleans\' living musical heritage.'},
  { id: 'b034', name: "Cameron Dupuy & The Cajun Troubadours"                     , day: 'd1', stage: 'fais',       start: '12:25', end: '13:20', yt: 'T-ecAFfb4xA', verified: true , blurb: 'Cameron Dupuy & The Cajun Troubadours bring authentic bayou swagger and accordion-driven grooves that\'ll have you dancing on the grass—these are the keepers of that raw, unpolished Cajun sound that makes the Fais Do-Do stage legendary. Expect fiddles, washboards, and stories older than jazz itself, delivered with the kind of infectious joy that reminds you why New Orleans music matters.'},
  { id: 'b035', name: "Jeffery Broussard & The Creole Cowboys"                    , day: 'd1', stage: 'fais',       start: '13:40', end: '14:35', yt: 'fa8vyTfugcI', verified: true , blurb: 'Jeffery Broussard has long been respected as one of the greatest accordion players to ever grace the beautiful Creole culture and for that matter the world. He is one of the most influential accordionists and vocalists in modern Zydeco music, Jeffery Broussard continues to be one of the genre’s most dynamic performers. He has continually been an innovator, beginning his career with traditional Creole Zydeco music playing drums in his father’s band, Delton Broussard & The Lawtell Playboys, then moving on to develop the nouveau Zydeco sound in Zydeco Force, now returning to the more traditional Zydeco sound with his own band, Jeffery Broussard and The Creole Cowboys. Jeffery’s music career started very early in life, like many other famous Zydeco musicians. At the age of 8 he started playing drums in his father’s band, the renowned Delton Broussard & The Lawtell Playboys. Whenever he could, Jeffery would sneak in to the house and get his daddy’s accordion down from the closet where it was stored and would teach himself how to play. Jeffery Broussard is well, the real deal. Dedicated to preserving and promoting the Creole culture and traditional Zydeco music. Jeffery plays with passion and commitment to carry on his daddy’s legacy.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41346/festivalartist-11959-artist_image-cf00ecd3-6130-4700-9471-a3b351d27b41.jpg'},
  { id: 'b036', name: "T'Monde"                                                   , day: 'd1', stage: 'fais',       start: '14:55', end: '15:55', yt: 'a00vHkyDkWw', verified: true , blurb: 'Three remarkably accomplished young musicians come together in T’Monde, the Louisiana phenomenon that Offbeat Magazine has called “a creative fusion of classic country and out-of-the-way Cajun.” With a combined 10 Grammy nominations between members Drew Simon, Megan Constantin, and Kelli Jones, T’Monde brings influences ranging from early Country music to ancient French and Creole ballads to present day Cajun music. Coming together in 2011, T’Monde has traveled all over the United States and the world showing that this small band can produce a big sound. This is made very clear in their latest album, “Lights in the Harbor”. Whether it be with their instruments or their voices, these three continue to showcase their unique sound that is unmatched in Cajun music today.'},
  { id: 'b037', name: "Chubby Carrier & the Bayou Swamp Band"                     , day: 'd1', stage: 'fais',       start: '16:20', end: '17:20', yt: 'JeyIKzgzFIQ', verified: true , blurb: 'Roy "Chubby" Carrier is an American zydeco musician. Chubby Carrier And The Bayou Swamp Band is a Zydeco band from Louisiana founded by Chubby Carrier in 1989. Carrier\'s father and grandfather both played zydeco music, and his cousins recorded under the name The Carrier Brothers.'},
  { id: 'b038', name: "Shinyribs"                                                 , day: 'd1', stage: 'fais',       start: '17:45', end: '19:00', yt: '36wHP8WB0fY', verified: true , blurb: 'Kevin "Shinyribs" Russell is known as the front man of the Austin TX musical combo, The Gourds. Born in Beaumont TX, raised in The Church Of Christ he found his calling in biker bars of Louisiana at the tender age of seventeen playing a hybrid of loud country blues rock and psychedelic swamp jangle…'},
  { id: 'b039', name: "Moyuba: A Tribute to the Spirit of Michael Skinkus"        , day: 'd1', stage: 'heritage',   start: '11:20', end: '12:05', yt: 'hjtUK2eM3A8', verified: true , blurb: 'Moyuba channels the spiritual soul of New Orleans tradition through modern arrangements, blending funk grooves with deep jazz roots and the city\'s unshakeable reverence for honoring those who came before. This is essential Jazz Fest—music that moves both body and spirit, drawing you into the circle where heritage becomes living, breathing sound.'},
  { id: 'b040', name: "Black Foot Hunters Mardi Gras Indians"                     , day: 'd1', stage: 'heritage',   start: '12:25', end: '13:05', yt: 'AWzk5bNCe0Q', verified: true , blurb: 'The Black Foot Hunters bring the swagger and ceremonial grandeur of Mardi Gras Indian culture to the Jazz & Heritage Stage, blending traditional chants, funky brass arrangements, and deep New Orleans roots into a performance that\'s equal parts spiritual tradition and pure danceable energy. If you crave the raw soul and community spirit that makes Jazz Fest legendary, this is your stage.'},
  { id: 'b041', name: "High Steppers Brass Band"                                  , day: 'd1', stage: 'heritage',   start: '13:25', end: '14:25', yt: 'B0VEps5BKUM', verified: true , blurb: 'High Steppers Brass Band channels the swagger and celebration of traditional New Orleans brass band tradition with infectious horn arrangements that get crowds moving—their high-energy parade sound meets contemporary funk grooves, delivering exactly the kind of joyful, street-level authenticity that defines Jazz Fest\'s soul.'},
  { id: 'b042', name: "The Caesar Brothers FunkBox"                               , day: 'd1', stage: 'heritage',   start: '14:50', end: '15:50', yt: 'Slf1OFyUNhI', verified: true , blurb: 'Drummer Rickey and keyboardist Norman Caesar were born and raised in New Orleans’ notorious Uptown funk neighborhood. Related to the Nevilles by marriage—Cyril’s wife, Gaynielle Neville, is their aunt—they grew up in the 13th Ward on Valence and Chestnut Streets. That’s deep in the heart of Neville territory. “Caesar territory also,” Rickey quickly pipes in. Those musical roots—the funk and Mardi Gras Indian rhythms—run deep in their sound whether they’re leading their band, the Caesar Brothers’ Funk Box, or backing one of many New Orleans Black Indian chiefs. “The rhythms just stuck with us,” Norman offers. Since the two siblings were so close in age—Rickey is 44 and Norman, 43—their experiences both in life and music traveled a similar course. They attended the same high school, Walter L. Cohen, and both participated in the marching band, with Rickey blowing baritone horn and tuba and Norman on baritone horn and trombone. “I used to play the keys on a clothes hamper when I was about four years old,” Norman remembers with a laugh. “That was my imaginary keyboard when Rickey used to play drums.” Vocalists are also a strong tradition in the 13th Ward and the Caesar brothers are no exception. “We always sang in the church choir and also my grandmother, Thelma Housey, was a very excellent gospel singer,” says Rickey. “She was our biggest influence. Singing was always in our blood in our family.” On the brothers’ paternal side, their father, Julius Caesar III, was a cousin of Barbara and Rosa Lee Hawkins of the renowned Dixie Cups. “I grew up in the church as well,” Norman says. “We were around the Nevilles coming up and also [the band] the Louisiana Purchase with Terry and Phillip Manuel, who were singers in our neighborhood.” When the brothers were in their pre-teens, they began playing with their older cousin, valve trombonist Emanuel Steib. “We really embraced his music and started firing up horns behind him,” Rickey says, adding that both he and Steib also became involved with the dawning of the Soul Rebels Brass Band. The year 1988 marked the beginning of the group Deff Generation, which teamed the brothers and Steib with a bunch of Neville cousins—Aaron Neville Jr., Cyril Neville Jr., Damion Neville, Jason Neville and Omari Neville. It was with that band that they gained further recognition, particularly with the release of 1991s “Running with the Second Line,” considered by many as the first recording merging brass band music and hip-hop. In the group, the brothers double on instruments with Rickey on drums, percussion and tuba and Norman playing keyboards and trombone. “We switched off because we were like a brass band inside of a band,” Norman explains. The duo of Rickey and Norman Caesar dubbed as the Caesar Brothers kicked in at the now legendary Benny’s Bar, the Uptown place to go late nights following hot gigs at Tipitina’s. They were also often called on to put their funky touch behind numerous groups, including with Uncle Cyril Neville and in the world of bounce. One of their specialties remains backing various Mardi Gras Indian chiefs. “We’ve followed the Indians all our lives,” Rickey says. “Our first group of Indians was the Wild Tchoupitoulas when we were like three and four years old.” “I can remember when I was small going by Cyril’s house and Jolly [George Landry, Big Chief Jolly of the Wild Tchoupitoulas] used to be in there working on his suits and playing the piano,” Norman recalls. “That’s really how I got into playing the piano, watching Jolly—he was a really good piano player.” “We’re one of the main bands on the scene with the Indians,” Rickey says, naming early gigs with Black Indian gangs like the Wild Magnolias and June Victory and the Bayou Renegades. Nowadays, they lay down their funky rhythms and harmonies with chiefs like Juan Pardo of the Golden Comanche and Kevin Goodman of the Flaming Arrows. Through much of their career, the Caesars have backed, toured and/or recorded with a variety of artists including Cyril, the Neville Brothers and funkmaster George Clinton, among others. Throughout it all, they have regularly gigged as leaders. The Caesar Brothers’ Funk Box’s latest release, In a Place Called New Orleans, which is filled with primarily New Orleans–centric material, also includes a host of guests including family members plus Troy “Trombone Shorty” Andrews and saxophonist Tim Green, who played with them regularly until his passing in 2014. “We want everybody to know that we strive to keep New Orleans music alive,” says Rickey, adding that along with originals they perform classics such as the Meters’ “Love Slip Up on Ya” and Huey “Piano” Smith & His Clowns’ hit “Rockin’ Pneumonia and the Boogie Woogie Flu.” “You can’t forget Huey,” Norman enthusiastically reminds us. “We play New Orleans music the way it should be played. The Funk Box is like putting a quarter in the jukebox at one of these funky joints in New Orleans that you never heard of and the Caesars will be playin’ it.”', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41583/festivalartist-12547-artist_image-06ee9261-04b6-44c9-9ef1-23bd131c7b6b.jpg'},
  { id: 'b043', name: "Nidia Góngora of Colombia"                                 , day: 'd1', stage: 'heritage',   start: '16:15', end: '17:15', yt: 'biDlCLXrWJU', verified: true , blurb: 'Nidia Góngora channels the rich folkloric traditions of Colombia through a contemporary jazz lens, blending cumbia rhythms with sophisticated harmonies and virtuosic instrumentation that feels both deeply rooted and refreshingly modern. Her soulful vocal delivery and innovative arrangements make her a must-see for anyone seeking the kind of cross-cultural musical dialogue that defines the Jazz Fest experience.'},
  { id: 'b044', name: "Sporty's Brass Band"                                       , day: 'd1', stage: 'heritage',   start: '17:40', end: '18:35', yt: 'HXL4F7z_Q7M', verified: true , blurb: 'Sporty\'s Brass Band brings the raw, unfiltered energy of New Orleans street brass to the Jazz & Heritage Stage—tight horn arrangements, infectious grooves, and that perfect blend of tradition and swagger that gets the whole festival moving. These guys are the real deal: funky, soulful, and built for dancing, making them essential for anyone craving authentic New Orleans brass band culture.'},
  { id: 'b045', name: "Leo Jackson & the Melody Clouds"                           , day: 'd1', stage: 'gospel',     start: '11:15', end: '12:00', yt: '33243XvFOqM', verified: true , blurb: 'Leo Jackson & the Melody Clouds deliver soul-stirring gospel that reaches straight to the heart, blending traditional New Orleans spirituality with smooth, contemporary harmonies that lift the entire tent. Their warm, communal sound is pure joy—exactly what Jazz Fest\'s Gospel Tent was made for, drawing crowds year after year who crave authentic, feel-good music with roots deep in the city\'s faith and musical heritage.'},
  { id: 'b046', name: "Joel Jones and 3MC"                                        , day: 'd1', stage: 'gospel',     start: '12:15', end: '13:00', yt: 'GQJ9RtdCC1Q', verified: true , blurb: 'Joel Jones and 3MC bring transcendent spiritual fire to the Gospel Tent with their soulful blend of contemporary gospel, New Orleans soul, and hip-hop rhythms that uplifts the faithful and moves the skeptics alike. Their dynamic energy and message-driven performances create those unforgettable Jazz Fest moments where music becomes something deeper—a communal spiritual experience that echoes through the grounds.'},
  { id: 'b047', name: "Joanna Hale-McGill"                                        , day: 'd1', stage: 'gospel',     start: '13:15', end: '14:05', yt: 'CiBIVuCSztA', verified: true , blurb: 'Joanna is the loving wife of Jarmell McGill, proud mother of Jayla and Ja’Miya, Actress, Business Owner and Praise & Worship Leader of His Will Worship Center in Slidell, LA. Joanna currently resides between Louisiana and Mississippi with her husband and two daughters. Joanna has always served in the music ministry throughout her life. She is quickly becoming a sought after artist and award winning gospel singer. Joanna recorded and performed her new single, “Open Door” written and produced by Detrick Haddon in Orlando at the Tom Joyner Memorial weekend event. She also recorded a new Top of The Hour Jingle for the Tom Joyner Morning Show. Currently, Joanna is hitting the ground running as a new actress! She also completed her freshman album with McGill Music Group that released in the early Spring 2019.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41363/festivalartist-12018-artist_image-05103845-413d-4ea2-9c86-fb78756cbf60.jpg'},
  { id: 'b048', name: "Pastor Tyrone Jefferson"                                   , day: 'd1', stage: 'gospel',     start: '14:20', end: '15:10', yt: 'Yg9uJzYueQs', verified: true , blurb: 'Pastor Tyrone Jefferson brings soul-deep spiritual energy and contemporary gospel fire to the Gospel Tent, blending traditional New Orleans church roots with modern vocal arrangements that\'ll move your spirit and your feet in equal measure. His ministry through music channels the joy and conviction that makes Jazz Fest\'s Gospel Tent a pilgrimage destination for believers and music lovers alike.'},
  { id: 'b049', name: "Blind Boys of Alabama"                                     , day: 'd1', stage: 'gospel',     start: '15:30', end: '16:35', yt: 'B0EN_Hmq534', verified: true , blurb: 'The Blind Boys of Alabama are a gospel music group from Alabama that first formed at the Talledega School for the Deaf and Blind in 1939.'},
  { id: 'b050', name: "Betty Winn & One A-Chord"                                  , day: 'd1', stage: 'gospel',     start: '16:50', end: '17:40', yt: 'chrycRjhTUw', verified: true , blurb: 'Betty Winn & One A-Chord deliver pure, unvarnished gospel soul that cuts straight to the heart—their tight harmonies and spiritual fervor transform the Gospel Tent into a sanctuary of joy and redemption. These New Orleans veterans blend traditional hymn sensibilities with contemporary groove, creating an irresistible sound that\'ll have you clapping, swaying, and feeling the divine spirit that makes Jazz Fest\'s Gospel Tent the festival\'s spiritual epicenter.'},
  { id: 'b051', name: "St. Joseph the Worker"                                     , day: 'd1', stage: 'gospel',     start: '17:55', end: '18:40', yt: 'kBV7RJ6NFwg', verified: true , blurb: 'St. Joseph the Worker brings deep, soul-stirring gospel harmonies and spirited traditional New Orleans church music to the Jazz Fest stage, their powerful vocals and righteous energy channeling generations of Crescent City faith traditions. Jazz Fest devotees will be transported by their authentic, uncompromising sound—the kind of transcendent spiritual joy that reminds you why this festival celebrates music as salvation.'},
  { id: 'b052', name: "The Silver Lining Serenaders"                              , day: 'd1', stage: 'lagniappe',  start: '11:30', end: '12:30', yt: 'BAHR9b31uFI', verified: true , blurb: 'The Silver Lining Serenaders bring intimate, soulful jazz elegance to the Lagniappe Stage, blending classic New Orleans sensibility with contemporary sophistication—their lush harmonies and unhurried grooves are pure comfort for your soul. Jazz Fest devotees will find exactly what they crave: that sweet spot where tradition meets refinement, perfect for swaying through the afternoon with a Sazerac in hand.'},
  { id: 'b053', name: "Yusa"                                                      , day: 'd1', stage: 'lagniappe',  start: '12:50', end: '13:50', yt: 'gmHwlnJbt0k', verified: true , blurb: 'Born and raised in the Buena Vista area, now known as Playa, Yusa split her time between her love of music and her love of the sea. Influenced by her father, who was a sailor, Yusa started playing guitar at a young age, moving on to piano and bass lessons.'},
  { id: 'b054', name: "Karma and The Killjoys"                                    , day: 'd1', stage: 'lagniappe',  start: '14:15', end: '15:15', yt: '5Mwbow3NsTY', verified: true , blurb: 'Karma and the Killjoys is a piano-rock band based in Baton Rouge, Louisiana.'},
  { id: 'b055', name: "Lynn Drury"                                                , day: 'd1', stage: 'lagniappe',  start: '15:40', end: '16:40', yt: 'qt_uJ4fqGLA', verified: true , blurb: 'Lynn Drury brings a soulful, deeply rooted New Orleans sound to the Lagniappe Stage—where tradition meets intimate artistry. Her voice carries the warmth of the city\'s classic R&B and soul heritage, making her a must-catch for fans who crave authentic, feel-good grooves with genuine New Orleans soul.'},
  { id: 'b056', name: "Michael Hurtt & the Haunted Hearts"                        , day: 'd1', stage: 'lagniappe',  start: '17:00', end: '18:00', yt: '2EZ0z1Zx9gs', verified: true , blurb: 'Michael Hurtt & the Haunted Hearts conjure a soulful blend of blues, R&B, and funk that channels the spiritual depths of New Orleans music—raw vocals over hypnotic grooves that\'ll have you moving from the first note to the last.'},
  { id: 'b057', name: "007"                                                       , day: 'd1', stage: 'jamaica',    start: '11:30', end: '12:30', yt: '1_gNnq1lPHU', verified: true , blurb: '1) 1980s punk/ska/mod band from Boston, Massachusetts.  Second place in WBCN RocknRoll Rumble, 1984.  Opened for The Specials in 1981. Opened for The Clash, 1982.  Also see Joshua Hayes, Dub7, The Kessells. http://007-boston-dub7.'},
  { id: 'b058', name: "Nidia Góngora of Colombia"                                 , day: 'd1', stage: 'jamaica',    start: '12:55', end: '13:55', yt: 'biDlCLXrWJU', verified: true , blurb: 'Nidia Góngora channels the rich folkloric traditions of Colombia through a contemporary jazz lens, blending cumbia rhythms with sophisticated harmonies and virtuosic instrumentation that feels both deeply rooted and refreshingly modern. Her soulful vocal delivery and innovative arrangements make her a must-see for anyone seeking the kind of cross-cultural musical dialogue that defines the Jazz Fest experience.'},
  { id: 'b059', name: "Rik Jam and The Island Federation"                         , day: 'd1', stage: 'jamaica',    start: '14:20', end: '15:20', yt: 'JIs_RGSou48', verified: true , blurb: 'Rik Jam and The Island Federation bring reggae-rooted rhythms and pan-Caribbean grooves to Congo Square, blending island vibes with New Orleans\' deep musical soul for a set that\'ll have you moving from the first beat. This is the sound of cultural fusion done right—infectious, soulful, and authentically connected to the spirit that makes Jazz Fest legendary.'},
  { id: 'b060', name: "Silver Birds Steel Orchestra"                              , day: 'd1', stage: 'jamaica',    start: '15:45', end: '16:40', yt: 'mdMc7-T4RkU', verified: true , blurb: 'Silver Birds Steel Orchestra brings the hypnotic, shimmering percussion magic of Caribbean steelband tradition to Jazz Fest, transforming Sandals Jamaica Cultural Pavilion into a vibrant island celebration where intricate melodic layers and infectious rhythms create pure sonic joy that\'ll have you moving from first note to last.'},
  { id: 'b061', name: "Vieux Farka Touré of Mali"                                 , day: 'd1', stage: 'jamaica',    start: '17:00', end: '18:00', yt: '41nL2v4SG9w', verified: true , blurb: 'Vieux Farka Touré channels the hypnotic desert blues of Mali through fingerstyle guitar and layered rhythms that feel both ancient and urgently alive—a masterclass in West African string tradition that\'ll have you moving before you even realize the groove has shifted beneath your feet. Jazz Fest devotees who crave global sounds and infectious rhythmic complexity will find pure magic in his ability to make a single guitar contain multitudes.'},
  { id: 'b062', name: "Eric Schmitt"                                              , day: 'd1', stage: 'rhythm',     start: '12:00', end: '12:45', yt: 'cRp9r2AR1Gc', verified: true , blurb: 'Eric Schmitt brings a hypnotic blend of world percussion and electronic soundscapes to the Rhythmpourium Tent, where polyrhythmic grooves meet modern production for an immersive, dance-forward experience that transcends genre. His infectious rhythmic energy and innovative approach to global beats make him essential listening for Jazz Fest explorers seeking boundary-pushing sounds beyond the traditional.'},
  { id: 'b063', name: "Britti"                                                    , day: 'd1', stage: 'rhythm',     start: '13:10', end: '13:55', yt: 'JYvQlxC6jnM', verified: true , blurb: 'Born in 1968 in Rome, Alex Britti began playing the guitar at the age of 8. From the outset he showed a passion for blues and at 17 formed his first trio, which enjoyed success in renowned Rome night-life venues such as Big Mama.'},
  { id: 'b064', name: "007"                                                       , day: 'd1', stage: 'rhythm',     start: '14:20', end: '15:05', yt: '1_gNnq1lPHU', verified: true , blurb: '1) 1980s punk/ska/mod band from Boston, Massachusetts.  Second place in WBCN RocknRoll Rumble, 1984.  Opened for The Specials in 1981. Opened for The Clash, 1982.  Also see Joshua Hayes, Dub7, The Kessells. http://007-boston-dub7.'},
  { id: 'b065', name: "Clay Parker and Jodi James"                                , day: 'd1', stage: 'rhythm',     start: '15:30', end: '16:20', yt: 'K1u2HXfJgS4', verified: true , blurb: 'Clay Parker and Jodi James is an American folk singer-songwriter duo from Baton Rouge, Louisiana. Both Clay Parker and Jodi James are known for their solo work. As a duo, they released "The Lonesomest Sound That Can Sound" in 2018.'},
  { id: 'b066', name: "Cortes Ward - Honoring the Legacy of Michael Ward"         , day: 'd1', stage: 'rhythm',     start: '16:45', end: '17:30', yt: 'qc5w12IR2VE', verified: true , blurb: 'Cortes Ward channels the soul of New Orleans tradition through a contemporary lens, blending deep-rooted funk grooves with jazz sophistication and raw emotional power that honors the city\'s musical heritage. This is essential listening for anyone who wants to feel the heartbeat of the Crescent City—a masterclass in authenticity delivered with infectious energy and profound respect for what came before.'},
  { id: 'b067', name: "KID smART Showcase"                                        , day: 'd1', stage: 'children',   start: '11:30', end: '12:15', yt: 'KWSqMkRMS2Y', verified: true , blurb: 'KID smART Showcase brings infectious energy and playful innovation to the Ochsner Children\'s Tent, blending New Orleans funk traditions with contemporary beats and interactive performance art that gets families moving and grooving together. Their boundary-pushing sound—part hip-hop, part carnival percussion, part educational magic—captures the spirit of the city\'s most creative young artists and reminds Jazz Fest crowds why New Orleans music is built on joy, community, and pure creative fearlessness.'},
  { id: 'b068', name: "Donald Lewis"                                              , day: 'd1', stage: 'children',   start: '12:35', end: '13:15', yt: 'SqdWTeXWvOg', verified: true , blurb: 'Donald Lewis brings infectious joy and playful musicianship to the Ochsner Children\'s Tent, spinning New Orleans traditions into moments of pure delight that capture young imaginations and get families moving together. His warm, accessible sound celebrates the brass-band spirit and second-line soul that makes this city\'s music irresistible—perfect for introducing the next generation to the real soundtrack of the Quarter.'},
  { id: 'b069', name: "LPO Academy"                                               , day: 'd1', stage: 'children',   start: '13:35', end: '14:15', yt: 'sXKxcaNJb0I', verified: true , blurb: 'LPO Academy brings the next generation of New Orleans jazz tradition to life with infectious energy and educational joy, turning the Ochsner Children\'s Tent into a masterclass in brass-fueled fun that proves jazz is alive and thriving in the city that created it.'},
  { id: 'b070', name: "JunkGuy"                                                   , day: 'd1', stage: 'children',   start: '14:15', end: '15:15', yt: 't5r9RiwviZM', verified: true , blurb: 'JunkGuy brings playful, percussive funk grooves to the children\'s stage with homemade instruments and infectious energy that turns everyday objects into pure New Orleans joy. This is inventive, family-friendly music that celebrates creativity and rhythm—exactly what Jazz Fest is all about.'},
  { id: 'b071', name: "Chosen Vessels Dance & Performing Arts"                    , day: 'd1', stage: 'children',   start: '15:15', end: '15:55', yt: 'jhVoasT1dU8', verified: true , blurb: 'Chosen Vessels Dance & Performing Arts brings joyful, high-energy movement and infectious rhythms to the Ochsner Children\'s Tent, blending New Orleans tradition with contemporary performance that gets families on their feet. Their dynamic fusion of dance, music, and cultural celebration captures the second line spirit that makes Jazz Fest magic for all ages.'},
  { id: 'b072', name: "ISL Circus Arts Kids"                                      , day: 'd1', stage: 'children',   start: '16:15', end: '17:00', yt: 'iC_3GlcwJyA', verified: true , blurb: 'ISL Circus Arts Kids bring high-flying acrobatic energy and playful live music to the Ochsner Children\'s Tent, blending New Orleans funk grooves with theatrical spectacle that\'ll have kids and families on their feet. Their infectious blend of world percussion, infectious rhythms, and jaw-dropping aerial stunts creates pure joy—exactly what Jazz Fest\'s youngest fans crave.'},
  { id: 'b073', name: "A cappella Louisiana French Ballads T’Monde with Kristi Guillory Interviewer: Barry Ancelet", day: 'd1', stage: 'miner',      start: '12:45', end: '13:30', yt: 'fWUy2mhMkj4', verified: true , blurb: 'Kristi Guillory strips Louisiana French traditions down to their pure, unaccompanied essence—pure voices carrying centuries of Cajun soul across intimate, haunting ballads that transport you straight to the bayou\'s heart. This is folk music at its most authentic and moving, where language, melody, and oral history intertwine in a performance that reminds you why Jazz Fest exists to celebrate our region\'s irreplaceable cultural legacy.'},
  { id: 'b074', name: "Jon Batiste Interviewer: David Fricke"                     , day: 'd1', stage: 'miner',      start: '13:45', end: '14:30', yt: '3YHVC1DcHmo', verified: true , blurb: 'Jon Batiste\'s virtuosic piano and genre-defying artistry—rooted in New Orleans tradition yet boundless in ambition—make him essential listening for anyone seeking the spiritual heart of the festival. Expect transcendent joy, deep musicianship, and a masterclass in why this city remains the soul of American music.'},
  { id: 'b075', name: "Monty Alexander Interviewer: Tom McDermott"                , day: 'd1', stage: 'miner',      start: '14:45', end: '15:30', yt: 'D-D23NP0obE', verified: true , blurb: 'Monty Alexander brings his virtuosic piano mastery and infectious Caribbean-inflected groove to an intimate conversation with Tom McDermott, blending bebop sophistication with the warm, conversational spirit that makes Jazz Fest legendary. This is essential listening for anyone hungry for straight-ahead jazz storytelling and the kind of musical dialogue that only happens in New Orleans.'},
  { id: 'b076', name: "Sally Baby’s Silver Dollars Interviewer: Ben Sandmel"      , day: 'd1', stage: 'miner',      start: '15:45', end: '16:30', yt: 'a45OfuQcyXs', verified: true , blurb: 'Sally Baby\'s Silver Dollars channels the gritty soul and swagger of classic New Orleans R&B and funk, with Ben Sandmel\'s storytelling bringing out the raw authenticity that makes this ensemble a living link to the city\'s rich musical legacy. If you crave the real deal—that perfect blend of vintage groove and timeless soul that only the Crescent City can produce—this is essential Fest listening.'},

  // ───────── Fri Apr 24 (d2) ─────────
  { id: 'b077', name: "Naughty Professor"                                         , day: 'd2', stage: 'festival',   start: '11:20', end: '12:15', yt: 'RByfhpxnU0s', verified: true , blurb: 'Naughty Professor brings cerebral funk and New Orleans swagger to the Festival Stage, blending tight grooves with playful irreverence and enough musical muscle to get the whole crowd moving. These local cats know how to balance intellect with pure pleasure—expect sophisticated arrangements, infectious rhythms, and that unmistakable NOLA attitude that makes Jazz Fest fans lose their minds.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41572/festivalartist-12532-artist_image-982c9dc9-4695-499d-b9a0-806e228c9490.jpg'},
  { id: 'b078', name: "The Rumble ft. Chief Joseph Boudreaux Jr."                 , day: 'd2', stage: 'festival',   start: '12:40', end: '13:35', yt: 'KUcZHr-Ikuo', verified: true , blurb: 'The Rumble ft. Chief Joseph Boudreaux Jr. brings the raw, unfiltered energy of New Orleans brass tradition colliding with modern funk and second line swagger—a high-octane celebration of the city\'s deepest cultural roots that\'ll have the Festival Stage crowd moving from the opening note.'},
  { id: 'b079', name: "Cyril Neville The Uptown Ruler"                            , day: 'd2', stage: 'festival',   start: '14:00', end: '15:00', yt: 'jnHa4tK-FgU', verified: true , blurb: 'Cyril Neville brings the soulful, funk-driven essence of uptown New Orleans to the Festival Stage, blending R&B, soul, and the city\'s signature groove with a voice that channels decades of Crescent City tradition. Whether you\'re a devoted fan of authentic New Orleans sound or discovering the Neville family legacy for the first time, his set is pure, unfiltered soul wrapped in that irresistible uptown swagger.'},
  { id: 'b080', name: "The Dirty Dozen Brass Band"                                , day: 'd2', stage: 'festival',   start: '15:25', end: '16:40', yt: 'HXr3nrd33U0', verified: true , blurb: 'The Dirty Dozen Brass Band are a New Orleans style brass band which plays R&B and Traditional New Orleans music. Band Members include Charles Joseph, Keith Anderson, Roger Lewis, Kevin Harris, Lionel Batiste, Efrem Towns, Kirk Joseph, Jenell Marshall, Revert Andrews, Gregory Davis, and Raymond Weber.'},
  { id: 'b081', name: "Jon Batiste"                                               , day: 'd2', stage: 'festival',   start: '17:10', end: '19:00', yt: '3YHVC1DcHmo', verified: true , blurb: 'Jon Batiste (born November 11, 1986) is an American musician, bandleader and TV personality. He has recorded and performed with artists in various genres of music (Stevie Wonder, Prince, Willie Nelson, Lenny Kravitz, Ed Sheeran, and Mavis Staples), released recordings consistently since 2005 and per…'},
  { id: 'b082', name: "Bon Bon Vivant"                                            , day: 'd2', stage: 'shell',      start: '11:20', end: '12:20', yt: 'vOBYAY27_BI', verified: true , blurb: 'Bon Bon Vivant is an indie/gypsy band from New Orleans that electrifies audiences across the country with their signature sound. BBVs original music pays homage to the bawdy New Orleans music traditions while infusing an indie edge that leaves a lasting mark on listeners. This genre bending band\'s original songs are joyous, fierce, honest and heartbreaking as they celebrate life in minor keys. Helmed by songwriter /frontwoman AbigaiI Cosio and her husband, saxophonist Jeremy Kelley, sister-harmony by Glori Cosio, accordion by Ryan Brown, sousaphone Jason Jurzak, drums by Ry D\'Antonio. Abigail Cosio\'s rich lyrics are complemented perfectly by the blood harmonies of the two Cosio sisters creating a hauntingly beautiful soundscape to this already big sound. Bon Bon Vivant\'s uniquely contagious music and energetic live performances have earned them a considerable reputation at both live shows, press and radio across the nation.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41387/festivalartist-12076-artist_image-abb3a397-1d63-4d38-ba73-c1d3503e5923.jpg'},
  { id: 'b083', name: "Sevana"                                                    , day: 'd2', stage: 'shell',      start: '12:45', end: '13:45', yt: 'GAd3JQ1V-10', verified: true , blurb: 'Anna-Sharé Blake, professionally known as Sevana, is a Jamaican R & B, soul and reggae singer. She describes her music as "every genre with a Jamaican filter on it.'},
  { id: 'b084', name: "GIVERS In Light"                                           , day: 'd2', stage: 'shell',      start: '14:10', end: '15:15', yt: 'Mx1H5IP8_g8', verified: true , blurb: 'GIVERS In Light brings luminous, soul-stirred indie rock to the Shell Gentilly Stage, blending introspective lyrics with infectious grooves that feel both deeply personal and utterly communal—the kind of set that\'ll have you moving while feeling something true.'},
  { id: 'b085', name: "Seratones"                                                 , day: 'd2', stage: 'shell',      start: '15:40', end: '16:45', yt: 'uSgJbqaYS74', verified: true , blurb: '“We went through a pretty dramatic shift with this record,” says Seratones frontwoman AJ Haynes. “The band lineup, the creative process, the sound: all of it changed in ways that really reflected our growth and evolution.” One listen to ‘Power,’ Seratones’ spectacular sophomore album, and it’s clear just how much of an evolution has taken place. Produced by Cage The Elephant guitarist Brad Shultz, the record finds the Shreveport five-piece trading in the brash proto-punk of their critically acclaimed debut for a timeless brand of gritty soul, one that takes its cues from vintage Motown and Stax even as it flirts with modern synthesizers and experimental arrangements. Haynes’ captivating voice remains front and center here, but her delivery this time around is more measured and self-assured than ever before, a beacon of confidence and clarity amidst a sea of social and political turmoil. Perhaps even more marked than the any sonic development on the record, though, is Haynes’ lyrical turn, which points her gaze inwards for the first time as she grapples with race, gender, and justice, writing with an unfiltered honesty that at once exudes strength and vulnerability, hope and despair, beauty and pain. “I learned to tap more into my own stories with these songs,” says Haynes. “I came to recognize that I have this lineage and these inherited experiences that are beautiful and worthy of exploration. The more personal my writing got, the more deeply I was able to connect with people.” Seratones have been chasing those kinds of deep connections since 2016, when they first rocketed into the national spotlight with their breakout debut, ‘Get Gone.’ Rolling Stone called the album a “fitful collision of punk, soul and jazz echoing out of a shed strewn with whiskey bottles,” while Pitchfork praised the collection’s “soulful grease and punky grit,” and NPR hailed it as “lean and compact, with an impressive assortment of anthemic stompers.” The music earned the band dates on the road with artists as varied as St. Paul & The Broken Bones, Thao & The Get Down Stay Down, The Dandy Warhols, and Drive-By Truckers, along with festival slots from Hangout to Newport Folk and invitations to perform on national television and at NPR’s Tiny Desk. While it might have been easy for the band to stay the course with their follow-up, Haynes felt herself pulled in new artistic directions after the release of ‘Get Gone,’ and creative differences ultimately led to a parting of ways with original guitarist Connor Davis. In the wake of Davis’s departure, two new members— guitarist Travis Stewart and keyboardist Tyran Coker—officially joined the group, embarking with Haynes, drummer Jesse Gabriel, and bassist Adam Davis on their journey to “Power.’ “With this album, I knew that I really wanted to draw from the pantheon of soul music,” says Haynes. “Soul was what I danced to in the kitchen with my mother. It’s what I’d come home at night and listen to on my record player. Things are really heightened and scary and overwhelming in this country right now, and returning to soul music was a way of reaching for comfort and security in all of that.” Change came to the band’s live show first, where the manic on-stage energy of their early performances gave way to a more focused, provocative delivery designed to inspire movement on an almost primal level. Haynes says the shift came, in part, as a result of touring with Charles Bradley. “He radiated love,” she explains. “Every night, I’d look out at the audience and see people in love, and not just in the romantic sense. His performances created this space for healing and understanding, and I realized that I needed that in my life.” When it came time to record, Haynes and the band headed to Nashville institution Battle Tapes, where they set one simple rule for themselves before laying down a single note: don’t mess with the groove. “The groove is integral to each of these songs,” says Haynes. “As a band, I think we’ve learned to trust ourselves more, to be less reactionary, to know when to hold back. What I love about this album is that we know when to shut up in service of the song.” That collision of explosive abandon and nuanced restraint defines ‘Power’ from the outset, with gripping album opener “Fear” blurring the lines between sugary Doo-Wop and distorted gospel, between Ronnie Spector pop and Audre Lorde poetics. “Fear is the weight of the world coming down / With no love in return,” Haynes sings, artfully setting the table for an album all about the day-to-day beauty and horror of modern life. The impossibly funky “Gotta Get To Know Ya” transforms existential dread into dance floor ecstasy, while the playful “Sad Boi” cuts down toxic masculinity, and the astonishing title track exudes a fierce femininity in the face of corporal oppression. “I’m terrified by what women endure,” says Haynes, who spent years fighting for reproductive rights and serving as a counselor at one of Louisiana’s last remaining abortion providers. “I’m in awe of what women survive. I’m humbled by what women build. I wanted to write a song that could bring strength and encouragement to the women that have changed my life, and to anyone who works to change their world.” For Haynes, autonomy—be it political, social, or sexual—is non-negotiable. She locates the blissful freedom that follows a breakup on the infectious “Over You” and channels Prince’s unequivocal sensualism on the seductive “Permission,” painting pleasure and power as two sides of the same coin. “Sex can be more than just bodies in motion,” says Haynes. “It can be an expression of erotic intelligence, a language shaped by poetry and desire.” For all its bold confidence, though, ‘Power’ ultimately recognizes that we still exist at the mercy of forces far greater than ourselves, historic and systemic structures and institutions designed to strip away agency from the most vulnerable among us. “If they pull me over, will I see you again?” Haynes asks on closing track “Crossfire,” whispering the lines as if she’s almost afraid to say them out loud. “Sometimes, when you’re in the thick of the struggle, it’s hard to see the possibility of change,” she reflects, “but you keep striving nonetheless. Some call it faith. I have yet to find the right words, but I’m still trying.” In the end, there may be no act more subversive, more radical, more powerful than that.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41474/festivalartist-12307-artist_image-28df24f2-10f0-4a07-b897-28d148c601b8.jpg'},
  { id: 'b086', name: "Lorde"                                                     , day: 'd2', stage: 'shell',      start: '17:30', end: '19:00', yt: 'nlcIKh6sBtc', verified: true , blurb: 'Ella Marija Lani Yelich-O\'Connor, known professionally as Lorde (born 7 November 1996 in Takapuna, Auckland, New Zealand), is a New Zealand singer-songwriter. Taking inspiration from aristocracy for her stage name, she is known for her unconventional musical styles and introspective songwriting.'},
  { id: 'b087', name: "Nell Simmons- Bradley"                                     , day: 'd2', stage: 'congo',      start: '11:20', end: '12:20', yt: '314yc_fhP8g', verified: true , blurb: 'Nell Simmons-Bradley channels the spiritual depth and rhythmic innovation of New Orleans\' Black musical traditions, blending contemporary soul with roots-deep grooves that resonate from Congo Square\'s legendary legacy. Her commanding presence and genre-defying artistry create an unforgettable set where tradition and modernity move as one.'},
  { id: 'b088', name: "Jason Neville Funky Soul Allstar Band"                     , day: 'd2', stage: 'congo',      start: '12:45', end: '13:45', yt: 'wzUhU2BeOjg', verified: true , blurb: 'Jason Neville\'s Funky Soul Allstar Band brings the heat with infectious grooves, soulful vocals, and that deep New Orleans funk that gets the whole crowd moving as one. Congo Square Stage has never sounded so good—this is essential viewing for anyone craving authentic, present-moment celebration and serious musicianship.'},
  { id: 'b089', name: "TBC Brass Band"                                            , day: 'd2', stage: 'congo',      start: '14:10', end: '15:10', yt: '8Q9fa-HJNKg', verified: true , blurb: 'TBC Brass Band brings the raw, unfiltered spirit of New Orleans street brass to life with a sound that\'s equal parts Second Line swagger and contemporary innovation, blending traditional parade rhythms with modern grooves that\'ll have you moving whether you\'re in the crowd or dancing in the streets. These Congo Square veterans know how to turn up the energy and honor the deep roots of New Orleans music culture all at once.'},
  { id: 'b090', name: "DJ Arie Spins"                                             , day: 'd2', stage: 'congo',      start: '15:10', end: '15:50', yt: 'O0MggUaNEGM', verified: true , blurb: 'DJ Arie Spins brings infectious electronic energy and deep roots grooves to Congo Square Stage, blending soul samples with Afrobeat rhythms and New Orleans funk for a dance-floor experience that honors the past while propelling you into the future.'},
  { id: 'b091', name: "Protoje"                                                   , day: 'd2', stage: 'congo',      start: '15:50', end: '17:05', yt: 'hzqFmXZ8tOE', verified: true , blurb: 'Oje Ken Ollivierre popularly known as Protoje, is a contemporary reggae singer and songwriter from Saint Elizabeth, Jamaica. His mother is Jamaican singer, Lorna Bennett and his father is a former Calypso king. In 2010, Protoje began working with his cousin and popular Jamaican producer Don Corleon.'},
  { id: 'b092', name: "DJ Arie Spins"                                             , day: 'd2', stage: 'congo',      start: '17:05', end: '17:45', yt: 'O0MggUaNEGM', verified: true , blurb: 'DJ Arie Spins brings infectious electronic energy and deep roots grooves to Congo Square Stage, blending soul samples with Afrobeat rhythms and New Orleans funk for a dance-floor experience that honors the past while propelling you into the future.'},
  { id: 'b093', name: "Sean Paul"                                                 , day: 'd2', stage: 'congo',      start: '17:45', end: '19:00', yt: 'AQ4TW5Z8eu0', verified: true , blurb: 'Sean Paul Ryan Francis Henriques OD (born 9 January 1973) is a Jamaican dancehall singer and rapper. He released his first album, "Stage One", in 2000 and achieved international recognition with his second album, "Dutty Rock", in 2002.'},
  { id: 'b094', name: "Tulane BAM Ensemble"                                       , day: 'd2', stage: 'jazz',       start: '11:15', end: '12:00', yt: 'MpBLNUHsuac', verified: true , blurb: 'Tulane BAM Ensemble brings contemporary classical and avant-garde energy to the jazz tradition, blending precise compositional arrangements with the improvisational fire that defines New Orleans sound. Their intellectually adventurous approach to rhythm and harmony proves that jazz evolution thrives when academic rigor meets street-level soul.'},
  { id: 'b095', name: "Sean Schulich"                                             , day: 'd2', stage: 'jazz',       start: '12:20', end: '13:10', yt: 'EIHtcTOuI2Q', verified: true , blurb: 'Sean Schulich channels the soulful, improvisational spirit of New Orleans traditional jazz with a modern sensibility that keeps one foot in the classics and one on the dance floor. His WWOZ set delivers the kind of authentic, groove-heavy jazz that reminds you why this festival exists—intimate, conversational, and absolutely alive.'},
  { id: 'b096', name: "Jesse McBride Big Band"                                    , day: 'd2', stage: 'jazz',       start: '13:35', end: '14:30', yt: 'y3eiSP1dLMM', verified: true , blurb: 'Jesse McBride Big Band swings hard with the full-throttle energy of classic New Orleans jazz, delivering brass-driven arrangements that honor tradition while pushing forward with contemporary fire. Fans of big band sophistication and authentic New Orleans groove won\'t want to miss this powerhouse ensemble at the Jazz Tent.'},
  { id: 'b097', name: "Astral Project"                                            , day: 'd2', stage: 'jazz',       start: '14:50', end: '15:50', yt: 'Jm2XdotYf7E', verified: true , blurb: 'For more than forty years, Astral Project has delighted audiences around the world with its unique brand of cutting edge improvisation and near telepathic interplay over deep New Orleans’ grooves. In 1978, Tony Dagradi gathered together the brightest, most energetic young players in the Crescent City and started out on a path that would help shape the modern jazz scene for years to come. A devoted student of Eastern philosophy, Dagradi coined the band name as a reflection of the group’s quest for a higher plane of experience. As everyone who has seen the band in concert knows, each performance finds these men reaching for the stars. Over the years the personnel has remained remarkably constant. Master drummer John Vidacovich continues to direct the rhythmic ebb and flow of the music as only he can. A brilliant soloist and highly sensitive accompanist, he plays with a command of dynamics, distinctive melodic accents and effervescent swing. On bass, James Singleton is a conduit of pure energy. His solid rhythmic concept and harmonic sense are the foundation of this innovative group’s improvisational strength. Steve Masakowski has long been regarded as one of the most awe-inspiring guitarists and composers in contemporary music. His technique on the unique seven string instrument which he designed has influenced a generation of guitarists. Performing on tenor and soprano saxophones, Tony Dagradi brings an emotional urgency to each solo. His huge tone and soaring lines speak of the entire tradition of jazz and constantly push the energy of the band forward.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41467/festivalartist-12288-artist_image-8a893a42-2ac8-4cdf-a994-2bf7698ba6a5.jpg'},
  { id: 'b098', name: "Adonis Rose Jazz Orchestra featuring special guest Andromeda Turre", day: 'd2', stage: 'jazz',       start: '16:15', end: '17:15', yt: 'd2tMGcN1euM', verified: true , blurb: 'Adonis Rose brings his powerhouse orchestra to deliver straight-ahead New Orleans jazz with commanding presence and deep roots in the city\'s living tradition, while special guest Andromeda Turre adds a luminous trombone voice that bridges classic elegance with contemporary expressiveness. This is essential Jazz Fest—the sound of New Orleans jazz as it\'s meant to be heard, swinging hard and played by musicians who understand the weight of the music\'s legacy.'},
  { id: 'b099', name: "Hiromi's Sonicwonder"                                      , day: 'd2', stage: 'jazz',       start: '17:45', end: '19:00', yt: 'pnISpahN2dM', verified: true , blurb: 'Hiromi’s Sonicwonder is a project of pianist Hiromi Uehara which features Hadrien Féraud on bass, Gene Coye on drums and Adam O’Farrill on trumpet.'},
  { id: 'b100', name: "Parlor Greens"                                             , day: 'd2', stage: 'blues',      start: '11:20', end: '12:25', yt: 'c3crWNn2n6I', verified: true , blurb: 'Parlor Greens is an instrumental trio from Ohio that plays soul jazz and deep funk.   (Tim Carman: drums, Jimmy James: guitar, Adam Scone: organ).  Parlor Greens\' sound is vintage, drawing inspiration from the legacies of 1960s organ-guitar-drums masters.'},
  { id: 'b101', name: "Jonathon \"Boogie\" Long"                                  , day: 'd2', stage: 'blues',      start: '12:50', end: '14:05', yt: 'Y_gI6y4e8KE', verified: true , blurb: 'Jonathon "Boogie" Long brings raw, authentic New Orleans blues to the Blues Tent with a sound that grooves in your bones and speaks straight from the soul—a master of traditional and contemporary blues who channels the city\'s deep musical roots into electric, unforgettable sets that get the whole tent moving.'},
  { id: 'b102', name: "Al \"Lil Fats\" Jackson"                                   , day: 'd2', stage: 'blues',      start: '14:30', end: '15:30', yt: '4ooiz-EVobQ', verified: true , blurb: 'Al "Lil Fats" Jackson brings the raw, soulful grit of classic New Orleans blues to the Blues Tent, with a voice that cuts through like aged whiskey and harmonica work that\'ll have you swaying before the first verse ends. His no-frills, stripped-down style channels the spirit of the city\'s legendary bluesmen while keeping one foot planted firmly in the present—exactly what Jazz Fest devotees crave.'},
  { id: 'b103', name: "New Orleans R&B Classics Revue featuring The Dixie Cups, Wanda Rouzan, and Tony Owens", day: 'd2', stage: 'blues',      start: '15:55', end: '17:05', yt: 'DLMf5Ax84ts', verified: true , blurb: 'Step into the Blues Tent for a night of pure New Orleans soul as these legendary R&B voices deliver the smooth, gutsy classics that built the city\'s sound—expect velvet vocals, horn-powered grooves, and the kind of authentic heritage that only happens when you\'re standing in the birthplace of the blues.'},
  { id: 'b104', name: "Lil' Ed & The Blues Imperials"                             , day: 'd2', stage: 'blues',      start: '17:35', end: '18:50', yt: '_Va2uYwAKhc', verified: true , blurb: 'In Chicago, a city overflowing with unrivaled blues talent, world-renowned Lil’ Ed & The Blues Imperials have been standing tall for almost 30 years. The band’s big sound, fueled by Lil’ Ed’s gloriously rollicking slide work and deep blues string bending, along with his rough-edged, soulful vocals, is as real and hard-hitting as Chicago blues gets. The Chicago Sun-Times says, “Lil’ Ed & The Blues Imperials are the hottest purveyors of bottleneck boogie to come out of Chicago since Hound Dog Taylor.” Lil’ Ed Williams comes to the blues naturally. His uncle, Chicago slide guitar king and master songwriter J.B. Hutto, taught him how to feel, not just play the blues. Nine albums and thousands of performances later, Lil’ Ed is now universally hailed as a giant of the genre. Lil’ Ed and The Blues Imperials—bassist (and Ed’s half-brother) James “Pookie” Young, guitarist Mike Garrett and drummer Kelly Littleton—have remained together for nearly 30 years (an extraordinary feat for any group), the band fueling Ed’s songs with their rock-solid, road-tested, telepathic musicianship. The Big Sound Of Lil’ Ed & The Blues Imperials is the musically electrifying, emotionally intense and downright fun new album from the band Guitar Player calls “a snarling boogie-blues machine…they blow down the walls.” The CD features Lil’ Ed’s incendiary playing and playful, passionate singing, with the ragged-but-right Blues Imperials cooking like mad alongside him. Produced by Williams and Alligator president Bruce Iglauer, it is a tour-de-force of authentic, deeply rooted Chicago blues. Williams wrote or co-wrote all but two of album’s 14 songs, the other gems written by Uncle J.B. The Chicago Reader says the band’s music “is a soundtrack for dancing and celebration infused with a sense of hard-won survival. Williams attacks his lyrics like he attacks his guitar: with bare-bones intensity that makes each word sound like a matter of life or death.” Born in Chicago on April 8, 1955, in the heart of Chicago’s tough West Side, Ed grew up surrounded by music. He was playing guitar, then drums and bass, by the time he was 12. Ed and Pookie received lessons and support from their famous uncle. “J.B. taught me everything I know,” says Ed. “I wouldn’t be where I am today without him.” Ed and Pookie spent their teen years making music together, and in 1975 formed the first incarnation of The Blues Imperials. They played their first gig at a West Side club called Big Duke’s Blue Flame, splitting the $6 take four ways. Over the next few years, the group played every club in the neighborhood. Even so, they still needed day jobs to pay the bills. Ed worked ten hours a day as a buffer at the Red Carpet Car Wash. Pookie drove a school bus. Night after night they played their roaring brand of blues in tiny clubs, and eventually the word reached Alligator president Bruce Iglauer. At the time, Iglauer was looking for local talent for The New Bluebloods, an anthology of some of Chicago’s younger blues musicians. “Ed and his band had a good reputation,” recalls Iglauer. “I had only seen them live once or twice. I knew Ed was a hot slide player, but I had no idea what he and the band were really capable of. I just knew that their music reminded me of Hound Dog Taylor and J.B. Hutto, two of my favorite musicians. It seemed like having a band this rough and ready would be a nice change of pace for the anthology, so I asked them to come down to the studio and cut a couple of songs. I never expected what happened.” The band—never having been in a recording studio before—treated the studio like a club, playing live to Iglauer, the engineer, and all the people on the other side of the control room glass. After Ed recorded his two rehearsed songs quickly, there was still plenty of studio time left, so they just kept playing. After 10 songs were in the can, Iglauer offered the band a full album contract. The end result of the session was 30 songs cut in three hours with no overdubs and only one second take. Twelve of those songs became the band’s debut album, Roughhousin’, released in September of 1986. The national press reacted with amazement to the blues world’s new discovery. Feature stories ran in Spin, Musician, The New York Times, The Los Angeles Times, The Washington Post, The Boston Globe, The Chicago Tribune and dozens of other publications. The Village Voice declared, “Roughhousin’ just may be the blues album of the year.” The New York Times raved, “Raw-boned, old-fashioned Chicago blues has a new young master—Lil’ Ed Williams.” But it wasn’t until 1987, when guitarist Mike Garrett joined the band, and a year later, when Garrett recruited his Detroit hometown friend Kelly Littleton to play drums, that things really began to take off. Garrett’s risk-taking rhythm guitar work and Littleton’s unpredictable, old school drumming were the perfect complement to Lil’ Ed’s and Pookie’s rambunctious playing. With their 1989 album Chicken, Gravy & Biscuits, doors opened and audiences poured in. Through relentless touring, the group crystallized, becoming tighter with each performance, more adept in their abilities to read each other’s musical moves. Their spontaneous and unpredictable live show became legendary among blues fans worldwide. They have played the Chicago Blues Festival multiple times, and have appeared at The New Orleans Jazz & Heritage Festival, Portland’s Waterfront Blues Festival, The Tampa Bay Blues Festival, The San Diego Blues Festival, The Pennsylvania Blues Festival and dozens of other festivals around the country. Satisfying worldwide demand, they have performed at festivals in Canada, Great Britain, France, Spain, Sweden, Denmark, Poland, Japan, Australia, India, Turkey and Panama. Lil’ Ed & The Blues Imperials released eight Alligator albums between 1986 and 2012. With each one, the band’s national and international stature grew as their fan base—known internationally as “Ed Heads”—continued to expand. With 2006’s Rattleshake, Ed and company reached a whole new audience. Die-hard “Ed Head” Conan O’Brien brought the band before millions of television viewers on two separate occasions. Success and accolades never stop pouring in. Living Blues called 2012’s Jump Start “scorching and soulful” with “crafty, clever lyrics…joyous and stomping.” The group took home the Living Blues Award for Best Live Performer in 2011, 2012 and 2013. They won the prestigious Blues Music Award for Band Of The Year in both 2007 and 2009. The Associated Press says, “Williams fills Chicago’s biggest shoes with more life and heat than anyone on stage today.” With The Big Sound Of Lil’ Ed & The Blues Imperials, the band continues to bring their blistering Chicago blues to “Ed Heads” new and old. Their infectious energy, joyful showmanship and masterful playing have been honed to a razor’s edge by their many years together. Lil’ Ed, Pookie, Mike and Kelly have seen sports stars and presidents, musical fads and fashion trends come and go. Meanwhile, their fiery music has more than stood the test of time. “We’re not band members,” says Williams, “we’re family, and families stay together.” Night after night, gig after riotous gig, the musical family called Lil’ Ed & The Blues Imperials bring their big, dynamic Chicago blues sound to fans across the country and around the world.'},
  { id: 'b105', name: "Mark Brooks & Friends"                                     , day: 'd2', stage: 'economy',    start: '11:15', end: '12:05', yt: 'Ly-zQeSyDZs', verified: true , blurb: 'Mark Brooks & Friends bring deep, authentic New Orleans funk and soul to Economy Hall with the kind of groovy, communal spirit that defines the festival—these are the players who keep the tradition alive while making you move.'},
  { id: 'b106', name: "Tim Laughlin"                                              , day: 'd2', stage: 'economy',    start: '12:25', end: '13:20', yt: 'Douq1tcHhc8', verified: true , blurb: 'A native of New Orleans, Tim Laughlin began playing the clarinet at the age of nine. Shortly after, he heard jazz on the radio, focusing his musical journey for the rest of his life. During these formative years, Tim spent as many hours listening to jazz as he did practicing. His first job was on a Carnival float at the age of 15 with schoolmates. After graduating high school, he joined the musicians union where he met some of his mentors that would help shape his playing at “The Conservatory of Bourbon St.” In 1992, Laughlin was a member of The Dukes of Dixieland and performed at Carnegie Hall with the New York Pops. Featured in many festivals throughout the world, he has toured over twenty countries including a goodwill US State Department Tour one month after Hurricane Katrina. Tim has a dozen CD’s under his name. In 2003, he recorded “The Isle of Orleans”(Gentilly Records), an award winning CD of his own New Orleans jazz originals. Historically, Laughlin is still the only New Orleans jazz clarinetist to ever release an album of all originals in this genre. Two of his originals can be heard in a recent 2016 major motion picture called “Mr. Church,” starring Eddie Murphy. Many others have been used in television, commercials and movies. In 2014, Tim was asked to perform at The Vatican and was with a distinguished delegation that had a private audience with Pope Francis. At home, Laughlin is very much in demand and has been a local favorite at The French Quarter Festival and N.O Jazz & Heritage Festival and has enjoyed making his living in New Orleans for the past 35 years. He stays busy playing top clubs like Snug Harbor, The Palm Court and Preservation Hall. His latest CD, “Gert Town Blues”(2020) is his 2nd of all-originals album bringing more new melodies of New Orleans jazz to the 21st century.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41577/festivalartist-12539-artist_image-bb0b7c62-e3a3-43de-b43f-7538e4c276f6.jpg'},
  { id: 'b107', name: "Wendell Brunious & The New Orleans Jazz Legends"           , day: 'd2', stage: 'economy',    start: '13:40', end: '14:40', yt: 'ZrG46YTWCxY', verified: true , blurb: 'Wendell Brunious leads a powerhouse ensemble through the deep traditions of New Orleans jazz, blending classic brass-band swagger with the soulful sophistication that made the city a legend—this is the sound of the French Quarter distilled into pure, unfiltered joy that\'ll have you dancing from first note to last.'},
  { id: 'b108', name: "Tribute to Ragtime Piano Legends featuring Terry Waldo, Tom McDermott, and David Boeddinghaus", day: 'd2', stage: 'economy',    start: '15:05', end: '16:05', yt: 'ospXtJ9KeVs', verified: true , blurb: 'Three keyboard virtuosos honor the stride piano masters and ragtime innovators that shaped New Orleans\' soul, delivering percussive, syncopated brilliance that swings hard and swings deep in Economy Hall\'s intimate embrace. If you live for the pianos that made this city swing, this is your tent.'},
  { id: 'b109', name: "Treme Brass Band"                                          , day: 'd2', stage: 'economy',    start: '16:25', end: '17:25', yt: 'w7tN3jDrw_w', verified: true , blurb: 'The Treme Brass Band is a marching brass band from New Orleans, Louisiana led by snare drummer Benny Jones Sr.'},
  { id: 'b110', name: "Smoking Time Jazz Club"                                    , day: 'd2', stage: 'economy',    start: '17:45', end: '18:45', yt: 'dfuHwPtVQOc', verified: true , blurb: 'Smoking Time Jazz Club brings the smoldering, intimate soul of classic New Orleans jazz to Economy Hall, where traditional standards and soulful interpretations ignite an old-school listening experience that\'ll transport you straight to a smoke-filled room on Frenchmen Street. Jazz Fest devotees seeking authentic, unbuttoned ensemble playing and the kind of chemistry that only comes from years in the trenches will find their people here.'},
  { id: 'b111', name: "Poisson Rouge"                                             , day: 'd2', stage: 'fais',       start: '11:15', end: '12:05', yt: 'bO2rJPqqfQM', verified: true , blurb: 'Poisson Rouge brings electrifying New Orleans funk and soul to the Fais Do-Do Stage, blending traditional second line energy with modern grooves that\'ll have you dancing from your first listen. This is the sound of the city itself—raw, infectious, and impossible to stand still for.'},
  { id: 'b112', name: "Loose Cattle"                                              , day: 'd2', stage: 'fais',       start: '12:25', end: '13:20', yt: 'h4J7eOwppLc', verified: true , blurb: 'Loose Cattle brings the swaggering spirit of New Orleans funk and soul to the Fais Do-Do stage, blending grimy grooves with that unmistakable Big Easy rawness that keeps crowds moving all night long. Jazz Fest devotees will dig their infectious energy, loose-limbed swagger, and the kind of down-home authenticity that reminds you why this festival exists.'},
  { id: 'b113', name: "Rosie Ledet"                                               , day: 'd2', stage: 'fais',       start: '13:40', end: '14:35', yt: 'YhhHJgciKrk', verified: true , blurb: 'One of a small handful of women in Zydeco, this Louisiana native’s infectous accordion playing and bluesy voice make it impossible not to dance. She also is one of the few young Zydeco players who still writes and sings in Creole French.'},
  { id: 'b114', name: "Bonsoir, Catin"                                            , day: 'd2', stage: 'fais',       start: '14:55', end: '15:55', yt: 'zQjMIKt8CPg', verified: true , blurb: 'Bonsoir, Catin brings the irresistible bounce and raw energy of modern Louisiana swamp pop to the Fais Do-Do stage, blending accordion-driven rhythms with contemporary flair for a sound that feels both timeless and urgently alive. This is the genuine article of Gulf Coast culture—hypnotic, joyful, and made for dancing.'},
  { id: 'b115', name: "Ani DiFranco"                                              , day: 'd2', stage: 'fais',       start: '16:20', end: '17:35', yt: 'vVg7mtgEqGY', verified: true , blurb: 'Ani DiFranco (born Angela Maria DiFranco; September 23, 1970) is an American singer, multi-instrumentalist, poet, songwriter, feminist icon  and businesswoman from New York state.  Although much of DiFranco\'s material is autobiographical, it is often also strongly political.'},
  { id: 'b116', name: "Lost Bayou Ramblers"                                       , day: 'd2', stage: 'fais',       start: '18:00', end: '19:00', yt: '7XsxdQW1s8E', verified: true , blurb: 'Over the past 300 years, a cultural amalgam has been percolating in south Louisiana. The resulting cultural distillate gave rise to both Bayou Country\'s world famous cuisine and a musical concentrate that conveys the passions, tribulations, and elations of the Cajun people.'},
  { id: 'b117', name: "Bamboula 2000"                                             , day: 'd2', stage: 'heritage',   start: '11:20', end: '12:10', yt: 'F8D5k-6bE8g', verified: true , blurb: 'Bamboula 2000 brings the deep, percussive roots of New Orleans to life with their hypnotic blend of traditional rhythms, Creole grooves, and modern energy—a transcendent celebration of the city\'s most ancient musical traditions that will have you moving from the first beat.'},
  { id: 'b118', name: "Free Agents Brass Band"                                    , day: 'd2', stage: 'heritage',   start: '12:30', end: '13:30', yt: 'mPAL9GJPXrY', verified: true , blurb: 'Free Agents Brass Band is an Atlanta, Georgia, United States group, formed by a rotating line-up of New Orleans ex-pats in the wake of Hurricane Katrina.'},
  { id: 'b119', name: "Los Skarnales"                                             , day: 'd2', stage: 'heritage',   start: '13:55', end: '14:55', yt: 'XdOEUGvx4qc', verified: true , blurb: 'Sounds Like	A good fusion of danzon, cumbia, reggae, ska and cantina music with a punk rock attitude! (Una buena fusion de danzon, cumbia, reggae, ska y musica de cantina con actitud punk!)'},
  { id: 'b120', name: "Da Truth Brass Band"                                       , day: 'd2', stage: 'heritage',   start: '15:15', end: '16:15', yt: 'eshXQEwdPS4', verified: true , blurb: 'Da Truth Brass Band brings the authentic New Orleans second line energy straight from the streets—their horns cut through with raw power and infectious grooves that get the whole crowd moving in that signature NOLA way. This is the real deal: traditional brass band swagger meets contemporary funk, the kind of performance that reminds you exactly why the Jazz & Heritage Stage exists.'},
  { id: 'b121', name: "Spyboy J & Thee Storm Mardi Gras Indians"                  , day: 'd2', stage: 'heritage',   start: '16:40', end: '17:30', yt: 'X0RJdJciMnY', verified: true , blurb: 'Spyboy J & Thee Storm Mardi Gras Indians bring the raw spiritual power and infectious second-line swagger of New Orleans\' most iconic tradition to the Jazz & Heritage Stage, blending traditional Indian chants with modern funk grooves that\'ll have you dancing in the aisles. This is where Mardi Gras Indian culture meets contemporary New Orleans soul—unmissable for anyone hungry for the real heartbeat of the city.'},
  { id: 'b122', name: "Conjunto Tierra Linda"                                     , day: 'd2', stage: 'heritage',   start: '17:55', end: '18:45', yt: 'pcaDITQ3nmo', verified: true , blurb: 'Conjunto Tierra Linda brings the authentic soul of traditional Mexican folk and conjunto music to the Heritage Stage, their tight accordion-driven arrangements and bilingual vocals creating an irresistible blend of roots storytelling and infectious rhythm that connects perfectly with Jazz Fest\'s celebration of cultural crossroads and living traditions.'},
  { id: 'b123', name: "Edna Karr High School Gospel Choir"                        , day: 'd2', stage: 'gospel',     start: '11:15', end: '12:00', yt: 'gGHiAIMqgdM', verified: true , blurb: 'The Edna Karr High School Gospel Choir brings raw spiritual power and New Orleans soul to the Gospel Tent, their voices soaring with the joy and conviction that define the city\'s deepest musical traditions. Rising young singers deliver transcendent harmonies rooted in faith, funk, and the unshakeable resilience of the Tremé community—a performance that reconnects Jazz Fest audiences to gospel\'s sacred heart.'},
  { id: 'b124', name: "Eleanor McMain Singing Mustangs"                           , day: 'd2', stage: 'gospel',     start: '12:10', end: '12:55', yt: '55vJI-AAbho', verified: true , blurb: 'The Eleanor McMain Singing Mustangs bring pure joy and unshakeable faith to the Gospel Tent with their soaring harmonies and infectious energy—a New Orleans institution that channels generations of spiritual tradition through voices that\'ll lift your soul skyward. Their dynamic blend of traditional gospel, contemporary spirituals, and crowd-participation anthems makes them a Jazz Fest essential for anyone seeking music that moves body and spirit alike.'},
  { id: 'b125', name: "St. Mary's Academy Gospel Choir"                           , day: 'd2', stage: 'gospel',     start: '13:05', end: '13:45', yt: 'c-Q77KCTNQU', verified: true , blurb: 'St. Mary\'s Academy Gospel Choir brings the spirited soul of New Orleans\' rich educational legacy to the Gospel Tent with soaring harmonies, infectious energy, and that signature joy that turns a performance into a communal celebration. Their powerful blend of traditional gospel, contemporary spirituals, and uplifting arrangements captures everything Jazz Fest devotees crave—authentic New Orleans roots delivered with unshakeable conviction and pure heart.'},
  { id: 'b126', name: "LB Landry Gospel Choir"                                    , day: 'd2', stage: 'gospel',     start: '13:55', end: '14:40', yt: 'Du98kT8_-vI', verified: true , blurb: 'The LB Landry Gospel Choir channels the spiritual power and joyful exuberance that defines New Orleans gospel tradition, blending soaring harmonies with infectious rhythms that\'ll have the whole Gospel Tent on their feet. Their sound is pure soul—rooted in faith, electrified by the city\'s incomparable musical energy, and delivered with the kind of authenticity that makes Jazz Fest pilgrims return year after year.'},
  { id: 'b127', name: "Terrell Griffin & Free"                                    , day: 'd2', stage: 'gospel',     start: '14:50', end: '15:40', yt: 'f-jqtMZE3S4', verified: true , blurb: 'Terrell Griffin & Free brings transcendent spiritual energy and contemporary gospel soul to the Jazz Fest stage, blending traditional hymnal roots with modern R&B sensibilities for a set that moves both body and spirit. Their infectious grooves and heartfelt vocals create an irresistible celebration of faith and community that defines the Gospel Tent experience.'},
  { id: 'b128', name: "Arri Kee"                                                  , day: 'd2', stage: 'gospel',     start: '15:50', end: '16:40', yt: 't4yfCcjLu7w', verified: true , blurb: 'Arri Kee brings transcendent soul and spiritual fire to the Gospel Tent with a sound that blends traditional New Orleans gospel roots with contemporary R&B warmth, creating an uplifting experience that celebrates faith, family, and the city\'s unshakeable musical heritage.'},
  { id: 'b129', name: "Big Freedia"                                               , day: 'd2', stage: 'gospel',     start: '17:00', end: '17:40', yt: 'bHNiNP3hDkU', verified: true , blurb: 'Known as the Queen of Bounce music, Big Freedia is New Orleans-based hip-hop artist and worldwide ambassador of bounce music. After a series of cult hit singles during the mid 2000’s, she was tapped for a reality show, Big Freedia Bounces Back on Fuse TV. The docuseries followed the life of a choirboy turned bounce rapper and remains the highest rated original series on the network. It was only a matter of time until Big Freedia caught the attention of iconic artists including Beyoncé and Drake. She was featured on both Beyoncé’s Grammy-winning single, “Formation” and Drake’s “Nice For What.” Big Freedia released the critically acclaimed album, ‘3rd Ward Bounce’ (which featured Lizzo among others) on Asylum Records in 2018. In the summer of 2019, the Queen of Bounce debuted her limited run ice cream flavor ‘Big Freedia’s Bouncin’ Beignets’ with the ice cream giant Ben & Jerry’s. She graced the cover of Billboard Magazine, and was invited by Vogue Magazine to be the official host of the Iive Instagram stream for the Met Gala. In October 2019, Big Freedia and multi-platinum pop artist Kesha released their new pop single “Raising Hell.” The song remains on the pop radio charts and the two performed the hit song on Jimmy Kimmel LIVE! Big Freedia’s latest single “Louder” from her forthcoming project dropped in November. She is also the author of the critically acclaimed memoir, Big Freedia: God Save the Queen Diva! on Gallery Books/Simon & Schuster.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41368/festivalartist-12027-artist_image-aae4c416-bb9b-43d6-a973-a318a82cb402.jpg'},
  { id: 'b130', name: "Jeffery Pelrean and Created to Worship"                    , day: 'd2', stage: 'gospel',     start: '17:55', end: '18:40', yt: 'WrSTtkNe8M0', verified: true , blurb: 'Jeffery Pelrean and Created to Worship bring transcendent spirit and modern praise to the Gospel Tent, blending soulful vocals with infectious grooves that celebrate faith and uplift the soul. Their dynamic energy and heartfelt message create an irresistible invitation to move, sing, and connect—essential Gospel Tent medicine for Jazz Fest seekers hungry for joy and spiritual resonance.'},
  { id: 'b131', name: "The Asylum Chorus"                                         , day: 'd2', stage: 'lagniappe',  start: '11:30', end: '12:25', yt: 'zf8qj4M6c50', verified: true , blurb: 'The Asylum Chorus channels the raw, unfiltered spirit of New Orleans R&B and funk with vocal harmonies that feel like a joyful uprising—think streetside revival meets modern soul, all delivered with the kind of infectious energy that transforms casual listeners into true believers. Jazz Fest devotees will gravitate to their boundary-pushing sound that honors tradition while refusing to be confined by it, making the Lagniappe Stage their perfect home for discovery.'},
  { id: 'b132', name: "Patrice Fisher and Arpa with special guests from Honduras" , day: 'd2', stage: 'lagniappe',  start: '12:50', end: '13:45', yt: '086pHev6xs8', verified: true , blurb: 'Patrice Fisher and Arpa bring a luminous blend of Latin percussion and otherworldly string textures to the Lagniappe Stage, fusing Honduran rhythmic traditions with contemporary world music grooves that\'ll have you moving and mesmerized. This is the kind of ensemble that transforms a festival afternoon into a transcendent cultural exchange—infectious, inventive, and impossible to resist.'},
  { id: 'b133', name: "Billy Iuso"                                                , day: 'd2', stage: 'lagniappe',  start: '14:10', end: '15:15', yt: 'X-Qpfu90_Tc', verified: true , blurb: 'Billy Iuso brings authentic New Orleans R&B and funk to the Lagniappe Stage, channeling the city\'s rich tradition of soulful grooves and street-level swagger with a modern edge that\'ll have you moving from the first note. His infectious blend of classic soul, brass-powered funk, and genuine New Orleans character is exactly what Jazz Fest lovers crave—real, rootsy, and unapologetically local.'},
  { id: 'b134', name: "Joy Clark"                                                 , day: 'd2', stage: 'lagniappe',  start: '15:35', end: '16:40', yt: 'PtzHKB_yaCA', verified: true , blurb: 'Joy Clark’s musical artistry feels like a warm, fresh twist on the fervently familiar. Her tranquil yet ardent original creations are a heady mix of her major influences. Think Tracy Chapman, Lizz Wright, Maxwell, Anita Baker, Stevie Nicks and Chris Eaton. Now add a bluesy bayou vibe with a splash of folk sensibility and a dash of alternative appeal and you’ll understand why this homegrown New Orleans singer/ songwriter/guitarist transcends both age and the ordinary. Having studied her self-taught craft since the age of 12, Joy truly embodies the bliss that comes with creating melodies and rhythms to celebrate peace and the undeniable power of love. Her music is often described as the essence of ease, upliftment, self-affirmation and sensitivity. It’s no wonder that she quickly rose to critical acclaim as a founding member of the disbanded Soulkestra. Joy has also performed with Water Seed, and living-legend Cyril Neville, and continues to enchant audiences throughout the United States and around the world.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41582/festivalartist-12546-artist_image-92945c31-fbc9-472d-ac19-ba531c094e63.jpg'},
  { id: 'b135', name: "The Bottoms"                                               , day: 'd2', stage: 'lagniappe',  start: '17:00', end: '18:00', yt: 'xb7v8ZXPkSM', verified: true , blurb: 'The Bottoms bring New Orleans funk and soul straight from the heart of the city, blending deep grooves with authentic brass arrangements that hit like a second line parade meeting a smoky nightclub. Their high-energy, community-rooted sound captures everything Jazz Fest celebrates—raw talent, infectious rhythm, and the kind of neighborhood spirit that makes you move whether you planned to or not.'},
  { id: 'b136', name: "Papa Mali's Shantytown Underground"                        , day: 'd2', stage: 'jamaica',    start: '11:30', end: '12:30', yt: '_40p-O3UHn8', verified: true , blurb: 'Papa Mali\'s Shantytown Underground channels the raw, roots-deep sound of Haitian and Caribbean tradition through a New Orleans lens, blending folk storytelling with hypnotic rhythms that feel both ancient and urgently alive. Jazz Fest devotees seeking authentic, unfiltered cultural expression will find their spiritual home in this ensemble\'s gritty, soulful groove.'},
  { id: 'b137', name: "Silver Birds Steel Orchestra"                              , day: 'd2', stage: 'jamaica',    start: '12:55', end: '13:45', yt: 'mdMc7-T4RkU', verified: true , blurb: 'Silver Birds Steel Orchestra brings the hypnotic, shimmering percussion magic of Caribbean steelband tradition to Jazz Fest, transforming Sandals Jamaica Cultural Pavilion into a vibrant island celebration where intricate melodic layers and infectious rhythms create pure sonic joy that\'ll have you moving from first note to last.'},
  { id: 'b138', name: "ShowJam Mento Band"                                        , day: 'd2', stage: 'jamaica',    start: '14:10', end: '15:10', yt: 'v6y5Q14l7mU', verified: true , blurb: 'ShowJam Mento Band brings the infectious rhythms and playful spirit of traditional Jamaican mento to Jazz Fest, blending Caribbean storytelling with infectious grooves that\'ll have you moving from the first note. Their warm, vintage-flavored sound is pure joy—perfect for fans seeking that soulful, cross-cultural magic that makes the Fest unforgettable.'},
  { id: 'b139', name: "Sevana"                                                    , day: 'd2', stage: 'jamaica',    start: '15:35', end: '16:35', yt: 'GAd3JQ1V-10', verified: true , blurb: 'Anna-Sharé Blake, professionally known as Sevana, is a Jamaican R & B, soul and reggae singer. She describes her music as "every genre with a Jamaican filter on it.'},
  { id: 'b140', name: "Los Skarnales"                                             , day: 'd2', stage: 'jamaica',    start: '17:00', end: '18:00', yt: 'XdOEUGvx4qc', verified: true , blurb: 'Sounds Like	A good fusion of danzon, cumbia, reggae, ska and cantina music with a punk rock attitude! (Una buena fusion de danzon, cumbia, reggae, ska y musica de cantina con actitud punk!)'},
  { id: 'b141', name: "A.J. Haynes of Seratones"                                  , day: 'd2', stage: 'rhythm',     start: '12:00', end: '12:45', yt: 'FIABJRuUXWs', verified: true , blurb: 'A.J. Haynes of Seratones brings electrifying soul-funk energy to the Rhythmpourium Tent, blending New Orleans groove with contemporary R&B swagger and raw vocal power that\'ll have you moving from the first note. This is the sound of the modern Crescent City—rhythmic, soulful, and impossible to resist.'},
  { id: 'b142', name: "Dayna Kurtz and Robert Maché"                              , day: 'd2', stage: 'rhythm',     start: '13:10', end: '13:55', yt: 'UO3XP9oQ8P4', verified: true , blurb: 'Dayna Kurtz and Robert Maché blend intimate folk storytelling with adventurous instrumental textures, creating a soulful, genre-bending sound that feels both timeless and urgent—the kind of set that reminds you why the Rhythmpourium Tent is where discovery happens at Jazz Fest.'},
  { id: 'b143', name: "Louis Michot & Swamp Magic"                                , day: 'd2', stage: 'rhythm',     start: '14:20', end: '15:05', yt: 'QHRlmLi0bfI', verified: true , blurb: 'Louis Michot & Swamp Magic conjures the raw, hypnotic pulse of Louisiana bayou music—a intoxicating blend of zydeco, folk, and swamp blues that gets deep in your bones and won\'t let go. This is the sound that built New Orleans, and Rhythmpourium is the perfect tent to experience their earthy, dance-floor magic.'},
  { id: 'b144', name: "Sean Schulich"                                             , day: 'd2', stage: 'rhythm',     start: '15:30', end: '16:15', yt: 'EIHtcTOuI2Q', verified: true , blurb: 'Sean Schulich channels the soulful, improvisational spirit of New Orleans traditional jazz with a modern sensibility that keeps one foot in the classics and one on the dance floor. His WWOZ set delivers the kind of authentic, groove-heavy jazz that reminds you why this festival exists—intimate, conversational, and absolutely alive.'},
  { id: 'b145', name: "ShowJam Mento Band"                                        , day: 'd2', stage: 'rhythm',     start: '16:40', end: '17:30', yt: 'v6y5Q14l7mU', verified: true , blurb: 'ShowJam Mento Band brings the infectious rhythms and playful spirit of traditional Jamaican mento to Jazz Fest, blending Caribbean storytelling with infectious grooves that\'ll have you moving from the first note. Their warm, vintage-flavored sound is pure joy—perfect for fans seeking that soulful, cross-cultural magic that makes the Fest unforgettable.'},
  { id: 'b146', name: "Young Audiences Performing Arts Showcase"                  , day: 'd2', stage: 'children',   start: '11:30', end: '12:15', yt: 'I6AoeDJ652Q', verified: true , blurb: 'Young Audiences Performing Arts Showcase brings high-energy, family-friendly entertainment that blends New Orleans\' rich musical traditions with dynamic theatrical flair, making it the perfect introduction to live performance for the younger Jazz Fest crowd. Their infectious blend of jazz, funk, and playful storytelling creates an irresistible groove that gets kids and parents dancing together under the tent.'},
  { id: 'b147', name: "Black Magic Drumline"                                      , day: 'd2', stage: 'children',   start: '12:30', end: '13:00', yt: 'x8fu4iJo5qo', verified: true , blurb: 'Black Magic Drumline brings pure New Orleans percussion fire to the children\'s stage—thundering snares, hypnotic rhythms, and infectious energy that\'ll have kids and families moving instantly. These drumline wizards blend the city\'s sacred street-beating tradition with modern groove, creating that perfect blend of educational joy and absolute funk that makes Jazz Fest magic happen.'},
  { id: 'b148', name: "Lady Chops"                                                , day: 'd2', stage: 'children',   start: '13:25', end: '14:10', yt: 'EVKRpdIDp9I', verified: true , blurb: 'Lady Chops brings playful, high-energy funk and hip-hop to the kids\' stage with infectious grooves that get families moving and grooving together—their New Orleans roots shine through every beat, making them the perfect introduction to the city\'s irreplaceable musical spirit for the next generation.'},
  { id: 'b149', name: "Black Magic Drumline"                                      , day: 'd2', stage: 'children',   start: '14:25', end: '14:55', yt: 'x8fu4iJo5qo', verified: true , blurb: 'Black Magic Drumline brings pure New Orleans percussion fire to the children\'s stage—thundering snares, hypnotic rhythms, and infectious energy that\'ll have kids and families moving instantly. These drumline wizards blend the city\'s sacred street-beating tradition with modern groove, creating that perfect blend of educational joy and absolute funk that makes Jazz Fest magic happen.'},
  { id: 'b150', name: "Silver Birds Steel Orchestra"                              , day: 'd2', stage: 'children',   start: '15:15', end: '15:55', yt: 'mdMc7-T4RkU', verified: true , blurb: 'Silver Birds Steel Orchestra brings the hypnotic, shimmering percussion magic of Caribbean steelband tradition to Jazz Fest, transforming Sandals Jamaica Cultural Pavilion into a vibrant island celebration where intricate melodic layers and infectious rhythms create pure sonic joy that\'ll have you moving from first note to last.'},
  { id: 'b151', name: "Beverly Hills Polo Club"                                   , day: 'd2', stage: 'children',   start: '16:15', end: '17:00', yt: '2PH0hiLs-yQ', verified: true , blurb: 'Beverly Hills Polo Club brings elegantly playful, feel-good vibes that blend New Orleans funk grooves with sophisticated pop sensibilities—a sound that\'s pure joy for both kids discovering live music and parents rediscovering why they fell in love with the Festival. Their infectious energy and accessible style make them the perfect introduction to the Jazz Fest experience, proving that great musicianship and pure fun aren\'t mutually exclusive.'},
  { id: 'b152', name: "Ragtime Piano Terry Waldo Interviewer: Bruce Raeburn"      , day: 'd2', stage: 'miner',      start: '12:15', end: '13:00', yt: 'zK0zorASaKM', verified: true , blurb: 'Terry Waldo brings the syncopated swagger and infectious energy of classic ragtime piano to Jazz Fest, transporting audiences straight into the rolling rhythms that laid the foundation for New Orleans jazz itself. His virtuosic touch and deep reverence for this American art form make him an essential stop for anyone seeking the roots of the festival\'s musical soul.'},
  { id: 'b153', name: "Protoje Interviewer: Shelah Moody"                         , day: 'd2', stage: 'miner',      start: '13:15', end: '14:00', yt: 'Ehs_GYivwDg', verified: true , blurb: 'Protoje brings conscious reggae fire and lyrical depth to the Allison Miner stage, blending roots storytelling with modern production for a set that hits both the mind and the body. His introspective, socially aware sound paired with Shelah Moody\'s interview expertise creates an unmissable moment of Caribbean culture and authentic dialogue.'},
  { id: 'b154', name: "Donna’s B&G Jazz James Andrews, with Donna Sims & Treme Brass’ Benny Jones Interviewer: Sally Young", day: 'd2', stage: 'miner',      start: '14:15', end: '15:00' , blurb: 'Experience the soulful intersection of tradition and community as Donna\'s B&G brings together the raw, conversational energy of New Orleans jazz with the triumphant brass heritage that defines the Crescent City sound. This intimate gathering celebrates the city\'s living musical lineage, where Donna Sims and the Treme Brass create moments of pure, unfiltered joy that remind you why Jazz Fest exists.'},
  { id: 'b155', name: "Hiromi Interviewer: Jason Berry"                           , day: 'd2', stage: 'miner',      start: '15:15', end: '16:00', yt: 'pnISpahN2dM', verified: true , blurb: 'Hiromi Ueda\'s virtuosic piano ignites the stage with a fearless blend of jazz fusion, classical precision, and raw improvisational energy—a transcendent experience that proves why she\'s become a global force in contemporary jazz. At the Allison Miner Music Heritage Stage, her electrifying artistry and deep harmonic explorations will captivate audiences seeking the cutting edge of jazz innovation.'},
  { id: 'b156', name: "Tif Lamson & Taylor Guarisco of GIVERS Interviewer: Clint Maedgen", day: 'd2', stage: 'miner',      start: '16:15', end: '17:00', yt: 'ERAj2D6J47s', verified: true , blurb: 'GIVERS brings forward-thinking electronic production and soulful vocals that bridge experimental pop with New Orleans\' rich musical heritage, creating hypnotic soundscapes that feel both contemporary and deeply rooted in the city\'s innovative spirit. This is the sound of a new generation honoring tradition while pushing boldly into uncharted sonic territory.', members: 'Tif Lamson, Taylor Guarisco'},

  // ───────── Sat Apr 25 (d3) ─────────
  { id: 'b157', name: "Stooges Brass Band"                                        , day: 'd3', stage: 'festival',   start: '11:15', end: '12:10', yt: 'F2sMENVzghY', verified: true , blurb: 'After years of "second lining" through the streets of New Orleans and tearing the roof off its many neighborhood bars, the Stooges Brass Band is bringing its music to the world.'},
  { id: 'b158', name: "Jelly Joseph"                                              , day: 'd3', stage: 'festival',   start: '12:30', end: '13:30', yt: 'r_m_kam2wLY', verified: true , blurb: 'Jelly Joseph channels the raw, infectious energy of New Orleans funk and soul, layering sticky grooves with modern production and undeniable swagger that gets the Festival Stage moving. A hometown artist steeped in the city\'s tradition yet pushing boldly forward, Joseph delivers the kind of set that makes Jazz Fest crowds forget everything except the moment.'},
  { id: 'b159', name: "Samantha Fish"                                             , day: 'd3', stage: 'festival',   start: '13:55', end: '15:05', yt: 'yHGKgKChPqA', verified: true , blurb: '"You should always get outside of the box," Samantha Fish says while discussing her boundary-breaking new album Belle of the West. "Challenging yourself is how you grow." After launching her recording career in 2009, Samantha Fish quickly established herself as a rising star in the contemporary blues world. Since then, the charismatic young singer-guitarist-songwriter has earned a reputation as a rising guitar hero and powerful live performer, while releasing a series of acclaimed albums that have shown her restless creative spirit consistently taking her in new and exciting musical directions. The New York Times called Fish "an impressive blues guitarist who sings with sweet power" and "one of the genre\'s most promising young talents." Her hometown paper The Kansas City Star noted, "Samantha Fish has kicked down the door of the patriarchal blues club" and observed that the young artist "displays more imagination and creativity than some blues veterans exhibit over the course of their careers."'},
  { id: 'b160', name: "The Revivalists"                                           , day: 'd3', stage: 'festival',   start: '15:35', end: '16:50', yt: 'o0Pt7M0weUI', verified: true , blurb: 'Some people say luck is the intersection of hard work and opportunity. The Revivalists have been on an unbelievable ride where ten years of tireless hard work was unexpectedly revved up by the wrongly dubbed “overnight success” of the gold-selling #1 single “Wish I Knew You.” Like any enduring band worth its salt, they set their sights on what’s next, buckling down and turning up with an album full of tunes marked by moments of sonic complexity, celebration, and catharsis, taking their songcraft to a whole new level. “All My Friends,” co-written by front man David Shaw and GRAMMY-nominated producer/songwriter Dave Bassett [Elle King, Vance Joy], signals this newfound depth and ambition.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41399/festivalartist-12107-artist_image-0cc2a44d-8ce8-4553-bbfa-1ddc98c8feb5.jpg'},
  { id: 'b161', name: "Stevie Nicks"                                              , day: 'd3', stage: 'festival',   start: '17:30', end: '19:00', yt: 'mwgg1Pu6cNg', verified: true , blurb: 'It’s hard to imagine but Stevie Nicks is poised to reach greater career heights in 2020 as one of rock’s most beloved and successful artists. But first, let’s go back a moment. Stevie Nicks made history in 2019. It was the year she became the first woman inducted into The Rock & Roll Hall of Fame for the second time! This time Nicks’ extraordinary career as a solo artist was officially honored. It followed her previous 1998 induction as a member of the legendary Fleetwood Mac. The year also included the completion of the phenomenally successful 2018/2019 Fleetwood Mac Tour which sold out a record breaking 89 shows and played to over 1.5 million fans around the globe. Nicks also performed as a guest artist on new albums by Lana Del Rey and Sheryl Crow in 2019. In 2018, Stevie returned to Ryan Murphy\'s American Horror Story series to reprise her role and bring her closer to a whole new generation of Stevie Nicks fans. The same year, she also released Stevie Nicks - The Ultimate Collaboration on Rhino Records - a career spanning collection outlining Nicks\' entire solo catalog - which includes various versions of her many hits including "Stand Back", "Dreams", "Gold Dust Woman", "Landslide", “Edge of Seventeen,” “Gypsy,” "Sara", "The Wild Heart", "Silver Springs" and scores more. Nicks, a multi-platinum Grammy Award winning singer-songwriter, has sold over 140 million albums including her solo work and as the heart and soul of Fleetwood Mac. She has ‘enchanted‘ audiences for decades with her thrilling mystical performances on stage, her unique songwriting skills, and her ongoing fashion influence. She continues to be an inspiration to many other female performers and has sustained the highest levels of love and respect from an ever-growing devoted fan base that spans generations. "It\'s not acting...It\'s never acting...The reason I go onstage and sing Edge of Seventeen every night since \'81 or Gold Dust Woman is to take myself back to that time when it was written…Sometimes I can\'t remember what happened yesterday but I remember so well what happened through the whole period of time that I wrote all these songs. That\'s what I bring to the audience whenever I step on the stage," commented Nicks in Rolling Stone Magazine. As for the future, 2020 is shaping up to be another banner year for Nicks with several special festival appearances and participation in other soon to be announced projects including new music and a feature film she has been writing and researching for many years. In 1981, six years after joining Fleetwood Mac, Nicks went solo for the first time with her debut album Bella Donna. A massive success, it sold more than five million copies in the US, topped the album charts, and produced four hit singles including her signature anthem, "Edge of Seventeen." More platinum albums followed - The Wild Heart (1983), Rock A Little (1985) and The Other Side of the Mirror (1989). Nicks received seven Grammy nominations for her solo work and six Grammy nominations as a member of Fleetwood Mac. She won a Grammy with Fleetwood Mac for Album of the Year (Rumours) which is one of the biggest selling albums of all time. Over the years, Stevie has also had many memorable collaborations with artists including "Stop Draggin\' My Heart Around" with Tom Petty & The Heartbreakers and "Leather and Lace" with Don Henley. Her most recent solo albums "In Your Dreams" and "24 Karat Gold: Songs From the Vault" both debuted in the Top Ten and received wide critical acclaim. Rolling Stone Magazine named Nicks "The Reigning Queen of Rock and Roll" and one of the "100 Greatest Singers of All Time". Along with Stevie\'s solo albums and tours, her four decade run with Fleetwood Mac remains a cornerstone of her unprecedented career. "I wouldn\'t have it any other way…When I joined the band decades ago, my life changed completely for the better. It\'s been an experience of a lifetime to record and perform with them - especially this last tour. I\'ve written so many songs and there are other great songwriters in the band so I only had the chance to put a few of them on each Fleetwood Mac album and perform them with the band. So early on, I realized that I would always have a dual career. My solo career is much more girlie-girl…It\'s still a rock band but the chance to perform more of my songs continues to inspire me to also have a big solo career…Every time a Fleetwood Mac tour ends, I hit the ground running. I\'d take a week off and then I\'d be in the studio. "At the ripe young age of 70, my voice hasn\'t changed…As long as I take care of myself, I am still going to be doing this when I\'m 80. There are so many things I want to do…I want to record another record…I want to make a movie. If the coven reforms, I want to go back to American Horror Story. I can still dance on stage and wear a short skirt and prance around in six-inch heels. As soon as I slip my toes into those boots, I become an African Queen." Rock on Gold Dust Woman!', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41560/festivalartist-12506-artist_image-d8c1a296-e233-49cd-9bb4-cebf14c2823f.jpg'},
  { id: 'b162', name: "The Deslondes"                                             , day: 'd3', stage: 'shell',      start: '11:15', end: '12:15', yt: '23wpsuEyL6o', verified: true , blurb: 'The Deslondes (formerly Sam Doores + Riley Downing & The Tumbleweeds) are a New Orleans-based country-soul, swamp-boogie band.'},
  { id: 'b163', name: "Dwayne Dopsie & the Zydeco Hellraisers"                    , day: 'd3', stage: 'shell',      start: '12:35', end: '13:35', yt: 'KIIxzR0LhJM', verified: true , blurb: 'Dwayne Dopsie & the Zydeco Hellraisers bring pure bayou fire to the Shell Gentilly Stage, delivering lightning-fast accordion grooves and infectious, sweat-soaked energy that gets the whole crowd moving. If you live for New Orleans\' unfiltered roots sound—where tradition meets raw, undeniable groove—these zydeco rebels are a must-see.'},
  { id: 'b164', name: "Crowe Boys"                                                , day: 'd3', stage: 'shell',      start: '14:00', end: '15:00', yt: '4FIcVEt99j4', verified: true , blurb: 'Crowe Boys bring infectious brass-fueled energy and swaggering New Orleans funk to the Shell Gentilly Stage, blending traditional second line grooves with modern bounce rhythms that\'ll have you moving before the first verse hits—pure NOLA soul that captures why this city\'s music DNA runs deep.'},
  { id: 'b165', name: "Jason Isbell and the 400 Unit"                             , day: 'd3', stage: 'shell',      start: '15:30', end: '16:50', yt: 'ivYkyC8J29M', verified: true , blurb: 'Jason Isbell and the 400 Unit is an Americana / Southern rock band originating largely from the Muscle Shoals area of Alabama, and led by former Drive-by Truckers singer / guitarist Jason Isbell.'},
  { id: 'b166', name: "Tyler Childers"                                            , day: 'd3', stage: 'shell',      start: '17:20', end: '19:00', yt: 'j-lwWgYLb68', verified: true , blurb: 'Tyler Childers (born June 21, 1991) is an American singer and songwriter. His music is a mix of country, bluegrass and folk. He released his breakthrough album Purgatory in August 2017.'},
  { id: 'b167', name: "HaSizzle"                                                  , day: 'd3', stage: 'congo',      start: '11:20', end: '12:20', yt: 'VLZvhR42EeA', verified: true , blurb: 'HaSizzle is the pulsating thump and the vivaciousness known as Bounce music. Never heard of him? Then you\'ve probably never been to New Orleans. To save you the trip, I suggest turning on Drake\'s "Child\'s Play" to hear his voice being sampled.  "She rode that **** like a soulja.'},
  { id: 'b168', name: "Rumba Buena"                                               , day: 'd3', stage: 'congo',      start: '12:45', end: '13:45', yt: 'FD6FUjN_iS4', verified: true , blurb: 'Rumba Buena brings infectious Latin percussion and swaggering groove to Congo Square, blending classic Cuban rumba rhythms with New Orleans soul for a performance that\'ll have the whole festival moving as one. This is dance music with serious roots—the kind of authentic, community-driven sound that makes Jazz Fest\'s most storied stage come alive.'},
  { id: 'b169', name: "Kermit Ruffins & the BBQ Swingers"                         , day: 'd3', stage: 'congo',      start: '14:10', end: '15:25', yt: 'E1gVOmRW4Bk', verified: true , blurb: 'Kermit Ruffins & the BBQ Swingers bring the smoke and soul of New Orleans brass tradition to Congo Square, blending fiery trumpet lines with gutsy funk grooves and that unmistakable Second Line swagger that keeps the crowd moving and the spirit alive. It\'s the sound of the city itself—part street parade, part backyard celebration, all authentic New Orleans jazz and soul.'},
  { id: 'b170', name: "DJ Raj Smoove"                                             , day: 'd3', stage: 'congo',      start: '15:25', end: '16:00', yt: '697zOhf8iwQ', verified: true , blurb: 'DJ Raj Smoove brings heat to Congo Square with a seamless blend of funk, soul, and New Orleans bounce that keeps the crowd moving from first drop to last—a master of the turntables who transforms classic grooves and contemporary rhythm into pure dancefloor magic.'},
  { id: 'b171', name: "Burning Spear"                                             , day: 'd3', stage: 'congo',      start: '16:00', end: '17:20', yt: 't7Ealg2s1jI', verified: true , blurb: 'Winston Rodney (born March 1, 1945), also known as Burning Spear, is a Jamaican roots reggae singer and musician. Like many famous Jamaican reggae artists, Burning Spear is known for his Rastafari movement messages. Rodney was born in Saint Ann\'s Bay, St.'},
  { id: 'b172', name: "DJ Raj Smoove"                                             , day: 'd3', stage: 'congo',      start: '17:20', end: '17:55', yt: '697zOhf8iwQ', verified: true , blurb: 'DJ Raj Smoove brings heat to Congo Square with a seamless blend of funk, soul, and New Orleans bounce that keeps the crowd moving from first drop to last—a master of the turntables who transforms classic grooves and contemporary rhythm into pure dancefloor magic.'},
  { id: 'b173', name: "Nas"                                                       , day: 'd3', stage: 'congo',      start: '17:55', end: '19:00', yt: 'VC4ORS5n9Hg', verified: true , blurb: 'Nasir bin Olu Dara Jones (/nɑːˈsɪər/ nah-SEER; born September 14, 1973), known professionally as Nas (/nɑːz/ NAHZ), is an American rapper, entrepreneur, and record producer.'},
  { id: 'b174', name: "Weatherford College Jazz Orchestra"                        , day: 'd3', stage: 'jazz',       start: '11:25', end: '12:20', yt: 'u8Lmyne3X2Y', verified: true , blurb: 'Weatherford College Jazz Orchestra brings the disciplined swing and bright ensemble energy of classic big band tradition to the WWOZ Jazz Tent, delivering exactly the kind of polished, joyful hard-swinging sound that keeps Jazz Fest audiences dancing through the afternoon.'},
  { id: 'b175', name: "David Bode Big Band"                                       , day: 'd3', stage: 'jazz',       start: '12:45', end: '13:45', yt: 'eAago5nzBqo', verified: true , blurb: 'David Bode Big Band swings with the full-throttle energy of classic New Orleans jazz, their horns blazing through arrangements that honor tradition while keeping the dance floor alive and electric. Catch them at the WWOZ Jazz Tent for that big-band sound that made this city legendary—pure joy, undeniable groove, and the kind of musicianship that reminds you exactly why Jazz Fest exists.'},
  { id: 'b176', name: "James Rivers Movement"                                     , day: 'd3', stage: 'jazz',       start: '14:10', end: '15:10', yt: 'vYlVNb54bUc', verified: true , blurb: 'James Rivers Movement brings virtuosic, boundary-pushing jazz to the WWOZ Jazz Tent with a sound rooted in New Orleans tradition but propelled toward tomorrow—expect fierce improvisation, deep grooves, and the kind of musical conversation that reminds you why this city invented jazz in the first place. Their fresh take on modern jazz will have you moving, thinking, and believing that the best is yet to come from New Orleans\' next generation.'},
  { id: 'b177', name: "John Boutté"                                               , day: 'd3', stage: 'jazz',       start: '15:35', end: '16:45', yt: 'FCNFmYoenmQ', verified: true , blurb: 'John Boutté is an American jazz singer based in New Orleans, Louisiana who has been active since the mid 1990s. He is known for diverse music style that goes beyond jazz to R&B, gospel, Latin, and blues. He is the younger brother to renown jazz and gospel singer Lillian Boutté.'},
  { id: 'b178', name: "Dave Koz & Friends Summer Horns"                           , day: 'd3', stage: 'jazz',       start: '17:20', end: '18:50', yt: '1aL3pLlq5pc', verified: true , blurb: 'Dave Koz & Friends Summer Horns brings smooth contemporary jazz sophistication and high-energy horn arrangements to the WWOZ Jazz Tent, delivering the kind of polished, feel-good grooves that get audiences moving and smiling. This all-star ensemble perfectly captures the spirit of New Orleans\' brass traditions while keeping things modern and accessible—exactly what Jazz Fest devotees crave.'},
  { id: 'b179', name: "Tin Men"                                                   , day: 'd3', stage: 'blues',      start: '11:20', end: '12:20', yt: 'U3cquFS6_wU', verified: true , blurb: 'This eclectic New Orleans trio features Alex McMurray on guitar and vocals, Washboard Chaz Leary on customized washboard,  percusion and vocals, and Matt Perrine on Sousaphone.'},
  { id: 'b180', name: "Little Freddie King Blues Band"                            , day: 'd3', stage: 'blues',      start: '12:45', end: '13:35', yt: 'CejcqPpk5iI', verified: true , blurb: 'If you want the real blues – and I’m not talkin’ about some long-haired hippy beatin’ on a National Resonator guitar or a mustachioed, Italian-suited slickster blowin’ on a chromatic harmonica – baby, you’d better call Little Freddie King. Normally only seen once a month at B.J.’s, a lounge located in the lowest bowels of the Ninth Ward where he shares floor space with a pool table and various carpet remnants, don’t think for a second that his band won’t be able to create the proper mood without their usual scrappy surroundings. The minute Freddie straps on his guitar and strikes up his gnarled chord and drummer “Wacko” Wade makes his presence known with a definitive cymbal crash, this lean, mean, swampy aggregation of gut-bucket wild men transforms the poshest of venues into a back-o-town beer joint. Born in McComb, Mississippi in 1940, Fread Martin grew up playing alongside his blues guitar-picking father, then rode the rails to New Orleans during the early fifties where he crossed paths with itinerant South Louisiana blues man such as Polka Dot Slim and Boogie Bill Webb whose unique country-cum-urban styles would influence his own. Honing his guitar chops at notorious joints like the Bucket of Blood (which he later immortalized in song), he jammed and gigged with Bo Diddley and John Lee Hooker, and played bass with Big Freddy King during one of the guitarist’s stints in New Orleans. People began comparing the two musicians’ styles, hence Martin’s nome-de-plume. While well-versed in a variety of styles, nowadays Little Freddie sounds a lot more like his cousin Lightin’ Hopkins – albeit after a three-day corn liquor bender! Nevertheless, the King sobriquet is fitting, as Freddie is undeniably the monarch of the Crescent City blues scene.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41408/festivalartist-12122-artist_image-3c2ffca6-7af8-4845-b701-125347d14863.jpg'},
  { id: 'b181', name: "Davell Crawford \"The Prince of New Orleans\""             , day: 'd3', stage: 'blues',      start: '14:00', end: '15:10', yt: 'gXMCyCi4fao', verified: true , blurb: 'Davell Crawford channels the raw soul and keyboard mastery of New Orleans funk and blues, delivering electrifying performances that blend classic soul grooves with contemporary swagger. The Prince brings arena-ready energy to the Blues Tent, proving why he\'s a hometown hero who keeps Jazz Fest fans coming back for more.'},
  { id: 'b182', name: "Sonny Landreth"                                            , day: 'd3', stage: 'blues',      start: '15:35', end: '16:55', yt: 'MENVyieB8rY', verified: true , blurb: 'The Louisiana slide guitar icon Sonny Landreth will be releasing his new studio album ‘Blacktop Run’ on 21st February via Provogue/Mascot Label Group. ‘Blacktop Run’ follows his previous Grammy-nominated album ‘Recorded Live In Lafayette’ (2017) and his back-to-back Blues Music Awards for Best Guitarist and Best Blues Album for ‘Bound by the Blues’ (2015). His groundbreaking work has long mixed familiarity with experimentation, his latest ten-song collection stretches from hard-edged electric instrumentals to wistful acoustic ballads. The project’s range is the fruit of a renewed collaboration. Producer RS Field – who helmed Landreth’s trio of breakout albums – joined the six-stringer and co-producer Tony Daigle to finish the album. “His brilliance and creative energy recharged us,” Landreth said of reuniting with Field. Most of the tracks were recorded live at famed Dockside Studios on the Vermilion River south of Lafayette, LA. “We came up with new and better ideas, and that’s what you want,” he added. “It couldn’t have gone better.” After two Grammy nominations, multiple appearances at Clapton’s Crossroads Festival and wide-ranging acclaim from fellow players and fans worldwide, Landreth is looking forward to playing the new material live. “It’s all about telling the story,” Landreth says, “as long as I can find my way up that path, I’m all in.” As the songwriter’s narrator sings in the title number of Blacktop Run, “A new day is dawning and I have never felt so alive.”'},
  { id: 'b183', name: "Rhiannon Giddens"                                          , day: 'd3', stage: 'blues',      start: '17:25', end: '18:55', yt: 'b1Z4PAZX9Bs', verified: true , blurb: 'Rhiannon Giddens (born February 21, 1977) is an American musician. She is known as the lead singer, violinist, banjo player and a founding member of the Grammy-winning country, blues and old-time music band Carolina Chocolate Drops .'},
  { id: 'b184', name: "The Garden of Joy"                                         , day: 'd3', stage: 'economy',    start: '11:15', end: '12:10', yt: 'tefPNUL_Yio', verified: true , blurb: 'The Garden of Joy blooms with the deep roots of New Orleans tradition, their horns and rhythms channeling the spiritual joy and second line swagger that makes this city\'s music sacred. Expect infectious funk grooves wrapped in classic brass arrangements—the kind of sound that fills Economy Hall with dancing ancestors and pure, unfiltered celebration.'},
  { id: 'b185', name: "Louis Ford & his New Orleans Flairs"                       , day: 'd3', stage: 'economy',    start: '12:30', end: '13:25', yt: 'vIQFsN2RPh8', verified: true , blurb: 'Louis Ford & his New Orleans Flairs bring the deep, soulful pocket of traditional New Orleans funk and R&B to the Economy Hall Tent, where their tight grooves and infectious horn charts capture the spirit of the city\'s golden era of soul and second-line swagger. This is the sound that built New Orleans\' reputation—raw, rhythmic, and real—perfect for fans seeking authenticity and dance-floor energy at their finest.'},
  { id: 'b186', name: "Preservation Brass"                                        , day: 'd3', stage: 'economy',    start: '13:45', end: '14:40', yt: '01w71-DqTD8', verified: true , blurb: 'Preservation Brass brings the deep funk and second-line soul of New Orleans brass tradition to the Economy Hall Tent, blending classic parade swagger with modern groove that\'ll have you moving before the first chorus ends. Their horns cut through with the raw energy of the city\'s street bands, delivering that authentic New Orleans sound that makes Jazz Fest feel like home.'},
  { id: 'b187', name: "Craig Klein presents A Tribute to Frog Joseph featuring Charles Joseph, Haruka Kikuchi, and Miles Lyons", day: 'd3', stage: 'economy',    start: '15:05', end: '16:05', yt: 'TGT_fqf_NNg', verified: true , blurb: 'Experience a masterclass in New Orleans brass tradition as Craig Klein honors the legacy of Frog Joseph with a powerful ensemble that seamlessly blends classic second line grooves, contemporary jazz sophistication, and the soulful swagger that makes the Economy Hall Tent the heartbeat of Jazz Fest. Charles Joseph\'s commanding horn presence, Haruka Kikuchi\'s innovative musicianship, and Miles Lyons\' rhythmic foundation create an irresistible celebration of the city\'s deepest musical roots.'},
  { id: 'b188', name: "Don Vappie's Creole Jazz Serenaders"                       , day: 'd3', stage: 'economy',    start: '16:30', end: '17:30', yt: 'rIVPdyUmomg', verified: true , blurb: 'Don Vappie\'s Creole Jazz Serenaders deliver authentic early jazz and traditional New Orleans sound with the sophistication and warmth that made Economy Hall legendary—expect elegant brass, conversational rhythms, and the kind of intimate groove that reminds you why this music was born right here. If you\'re chasing the soul of New Orleans jazz, this is where the lineage lives.'},
  { id: 'b189', name: "Eight Dice Cloth"                                          , day: 'd3', stage: 'economy',    start: '17:50', end: '18:45', yt: 'Hh-S0brBfEE', verified: true , blurb: 'Eight Dice Cloth brings the raw, unfiltered soul of New Orleans brass tradition to Economy Hall with a sound that blends second-line swagger and modern funk into something gloriously unpredictable—the kind of set that has the whole tent moving as one rhythm. Their music pulses with the DNA of the city\'s neighborhoods, full of wit, grit, and that infectious New Orleans joy that makes Jazz Fest the greatest party on Earth.'},
  { id: 'b190', name: "Amis du Teche"                                             , day: 'd3', stage: 'fais',       start: '11:20', end: '12:25', yt: 'NN3cdGb-sPY', verified: true , blurb: 'Amis du Teche brings the swampy, soulful heart of Cajun tradition to life with accordion-driven melodies and infectious two-step grooves that\'ll have you dancing before you know it. These keepers of South Louisiana\'s bayou heritage deliver the authentic fais do-do experience that makes Jazz Fest the ultimate cultural celebration.'},
  { id: 'b191', name: "Doctor Nativo"                                             , day: 'd3', stage: 'fais',       start: '12:50', end: '13:50', yt: 'JTIt6ZW2qVc', verified: true , blurb: 'Doctor Nativo blends traditional New Orleans rhythms with contemporary Latin and Caribbean influences, delivering high-energy performances that get the whole crowd moving at the Fais Do-Do Stage. Their infectious grooves and bilingual swagger capture the spirit of the city\'s most vibrant cultural crossroads, making them an essential stop for anyone seeking authentic New Orleans soul with a global heartbeat.'},
  { id: 'b192', name: "Curley Taylor and Zydeco Trouble"                          , day: 'd3', stage: 'fais',       start: '14:15', end: '15:20', yt: 'bNJ9bAnavvo', verified: true , blurb: 'Curley Taylor and Zydeco Trouble bring the swamp-fueled energy and accordion-driven grooves that define Louisiana\'s zydeco tradition, delivering infectious rhythms and raw, soulful performances that get the whole crowd moving. Catch them at the Sheraton Fais Do-Do Stage for an authentic taste of the Bayou\'s most danceable, feel-good sound.'},
  { id: 'b193', name: "Pine Leaf Boys"                                            , day: 'd3', stage: 'fais',       start: '15:45', end: '16:55', yt: '1F6jfSsqaX4', verified: true , blurb: 'The Pine Leaf Boys are a two-time Grammy Award-nominated Cajun and Creole band from South Louisiana. Members include Wilson Savoy (accordion, fiddle, vocals), Courtney Granger (fiddle, accordion, vocals), Drew Simon (drums and vocals), Jon Bertrand (guitars), and Thomas David (bass).'},
  { id: 'b194', name: "Bruce Hornsby & the Noisemakers"                           , day: 'd3', stage: 'fais',       start: '17:25', end: '18:55', yt: 'Nl3DFOGw_pk', verified: true , blurb: 'Bruce Hornsby & The Noisemakers are an American band led by Bruce Hornsby (piano/ accordion/ lead vocals) and featuring John"JT" Thomas (organ/keyboards vocals), John Mailander (mandolin/ fiddle/ vocals), J.V. Collier (bass), Gibb Droll (guitar/ vocals), and Chad Wright (drums).'},
  { id: 'b195', name: "La Tran-K Band"                                            , day: 'd3', stage: 'heritage',   start: '11:15', end: '12:05', yt: 'B08ZbYZ6PGw', verified: true , blurb: 'La Tran-K Band brings the resilient spirit of New Orleans brass tradition into bold new territory, fusing traditional jazz heritage with contemporary funk and world rhythms that\'ll have you moving from the moment they hit the stage. Their infectious energy, tight arrangements, and infectious grooves make them an essential Jazz Fest experience for anyone who loves music that honors the past while pushing straight into the future.'},
  { id: 'b196', name: "Creole Wild West Mardi Gras Indians"                       , day: 'd3', stage: 'heritage',   start: '12:25', end: '13:05', yt: 'P3PEAXQg-ug', verified: true , blurb: 'Creole Wild West Mardi Gras Indians blend the raw percussive energy of second line brass with the ancestral chants and rhythms rooted deep in New Orleans Black culture, creating a hypnotic sound that\'s equal parts street festival and spiritual ceremony. Jazz Fest devotees crave exactly this—authentic, unfiltered New Orleans tradition where music and cultural pride move as one.'},
  { id: 'b197', name: "Black Magic Drumline"                                      , day: 'd3', stage: 'heritage',   start: '13:20', end: '13:50', yt: 'x8fu4iJo5qo', verified: true , blurb: 'Black Magic Drumline brings pure New Orleans percussion fire to the children\'s stage—thundering snares, hypnotic rhythms, and infectious energy that\'ll have kids and families moving instantly. These drumline wizards blend the city\'s sacred street-beating tradition with modern groove, creating that perfect blend of educational joy and absolute funk that makes Jazz Fest magic happen.'},
  { id: 'b198', name: "Big 6 Brass Band"                                          , day: 'd3', stage: 'heritage',   start: '14:05', end: '15:05', yt: 'UbsfTpX03Ys', verified: true , blurb: 'On the streets of New Orleans, where brass bands play every Sunday for weekly second line parades, it’s not unusual for one brass band to catch the ear of the streets and dominate the second line season. Not long after their founding in 2017, the Big 6 Brass Band had the streets on lock. Their mixtape, which has made the rounds in the second line community, features covers of songs by Michael Jackson, Fantasia, and SZA, among others. Unsatisfied with playing only “radio tunes,” their song catalog runs deep into brass band history as they breathe new life into time-honored traditional tunes like “Red Dress” and “Lilly of the Valley.” Their debut album, Big Six, was released on June 24, 2019 on all streaming platforms. A thirteen-song tour through their original music, it’s an instant classic including hits like “Go Down,” and “On the Run.” The band’s all-star lineup is comprised of some of the most talented young brass band musicians in the city. Though the band is relatively young, their pedigree reveals a wealth of experience as their roster includes current and former members of the Rebirth, Stooges, Hot 8, TBC, and Da Truth brass bands. Though their music maintains ties to the tradition from which they come, they are very much the vanguard of the brass band scene. Their sound, which combines smooth R&B with the rough and ready sound of the streets, is, more than any other band, representative of the sound of contemporary New Orleans brass band music.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41450/festivalartist-12241-artist_image-49678104-ed7e-4fcc-95d9-d40b313bd368.jpg'},
  { id: 'b199', name: "Silver Birds Steel Orchestra"                              , day: 'd3', stage: 'heritage',   start: '15:30', end: '16:20', yt: 'mdMc7-T4RkU', verified: true , blurb: 'Silver Birds Steel Orchestra brings the hypnotic, shimmering percussion magic of Caribbean steelband tradition to Jazz Fest, transforming Sandals Jamaica Cultural Pavilion into a vibrant island celebration where intricate melodic layers and infectious rhythms create pure sonic joy that\'ll have you moving from first note to last.'},
  { id: 'b200', name: "Lutan Fyah"                                                , day: 'd3', stage: 'heritage',   start: '16:45', end: '17:30', yt: 'i9SdGSC8jQQ', verified: true , blurb: '" ... Rastafari livity means to tolerate and to live side by side with those of other faiths no matter which race, no matter which class. The purpose of Haile Selassie is to see that we become one in unity and love ... and that is my purpose.'},
  { id: 'b201', name: "Big Chief Hollywood & Dat Mighty 9"                        , day: 'd3', stage: 'heritage',   start: '17:50', end: '18:40', yt: '2npZwzmT02Q', verified: true , blurb: 'Big Chief Hollywood & Dat Mighty 9 bring the raw, undeniable pulse of New Orleans Indian culture and second line traditions to the Jazz Heritage Stage, blending Mardi Gras Indian chants, funk grooves, and brass-band energy into a celebration that\'s equal parts spiritual and irresistible. Their high-octane performance is pure New Orleans soul—the kind of authentic, community-rooted sound that defines what Jazz Fest is all about, guaranteed to get you moving and connected to the city\'s deepest musical roots.'},
  { id: 'b202', name: "Voices of Peter Claver celebrating the life of Veronica Downs-Dorsey", day: 'd3', stage: 'gospel',     start: '11:50', end: '12:35', yt: 'qaNiDMsWzwg', verified: true , blurb: 'Voices of Peter Claver channels deep spiritual tradition and contemporary soul through rich harmonies that honor the legacy of Veronica Downs-Dorsey, delivering the kind of transcendent Gospel Tent moment that reminds you why New Orleans remains the beating heart of American sacred music.'},
  { id: 'b203', name: "Pastor Jai Reed"                                           , day: 'd3', stage: 'gospel',     start: '12:45', end: '13:35', yt: 'aI6RWEpllnM', verified: true , blurb: 'Pastor Jai Reed brings contemporary gospel fire to the Jazz Fest Gospel Tent with a powerful blend of spiritual conviction and modern soul, delivering messages of hope through soaring vocals and infectious grooves that\'ll have the whole tent moving in unified celebration.'},
  { id: 'b204', name: "Cory Stewart and Authentically Anointed"                   , day: 'd3', stage: 'gospel',     start: '13:45', end: '14:30', yt: 'enYO0EHLerw', verified: true , blurb: 'Cory Stewart and Authentically Anointed bring transcendent soul power to the Gospel Tent with spiritually-grounded vocals and tight, joyful harmonies that blend traditional gospel roots with contemporary R&B sensibility—pure redemptive energy that\'ll have you on your feet and moving with the spirit.'},
  { id: 'b205', name: "Evangelist Jackie Tolbert"                                 , day: 'd3', stage: 'gospel',     start: '14:40', end: '15:25', yt: 'MujIugekXfc', verified: true , blurb: 'Evangelist Jackie Tolbert brings electrifying spiritual power to the Gospel Tent with a voice that cuts through the soul—blending traditional New Orleans gospel fervor with contemporary conviction that\'ll have the whole tent moving in unified praise.'},
  { id: 'b206', name: "Bishop Paul S. Morton and The Greater Sound Choir of Greater St. Stephen FGBC", day: 'd3', stage: 'gospel',     start: '15:45', end: '16:50', yt: '-Zsb2n8JPN4', verified: true , blurb: 'Bishop Paul S. Morton brings transcendent vocal power and deep-rooted New Orleans spirituality to the Gospel Tent, leading The Greater Sound Choir through soaring harmonies and soul-stirring arrangements that blend traditional gospel with contemporary uplift. His commanding presence and the choir\'s lush, dynamic sound create an unforgettable celebration of faith and community that captures the very heart of what makes Jazz Fest sacred ground.'},
  { id: 'b207', name: "Val & Love Alive Choir"                                    , day: 'd3', stage: 'gospel',     start: '17:05', end: '17:50', yt: 'h-aGZrX39OM', verified: true , blurb: 'Val & Love Alive Choir brings pure, transcendent spirit to the Gospel Tent with soaring harmonies and deep-rooted New Orleans soul that\'ll lift your whole being skyward. Their joyful, contemporary take on sacred music reminds you why gospel is the heartbeat of the festival—infectious, life-affirming, and absolutely undeniable.'},
  { id: 'b208', name: "Dr. Hezekiah Brinson & The Nineveh Baptist Church Mass Choir", day: 'd3', stage: 'gospel',     start: '18:00', end: '18:40', yt: 'Mw6nul8OzcQ', verified: true , blurb: 'Dr. Hezekiah Brinson & The Nineveh Baptist Church Mass Choir deliver soul-stirring traditional gospel with the kind of deep, rooted spirituality that defines New Orleans\' sacred musical legacy. Their powerful harmonies and infectious energy transform the Gospel Tent into a place of pure joy and transcendence—exactly what Jazz Fest is built for.'},
  { id: 'b209', name: "Freddie Blue & the Friendship Circle Band"                 , day: 'd3', stage: 'lagniappe',  start: '11:30', end: '12:20', yt: 'ssIDcLE4-Rg', verified: true , blurb: 'Freddie Blue & the Friendship Circle Band bring soulful, second-line energy to the Lagniappe Stage with their blend of New Orleans funk, blues, and community spirit that celebrates the city\'s deepest musical traditions. Their infectious grooves and feel-good vibes make them an essential discovery for festivalgoers seeking authentic local flavor and pure joy.'},
  { id: 'b210', name: "Riverbenders"                                              , day: 'd3', stage: 'lagniappe',  start: '12:40', end: '13:40', yt: 'w79YW8IKRrs', verified: true , blurb: 'Riverbenders brings the flexible, soulful sound of New Orleans R&B and funk to the Lagniappe Stage, bending genres as fluidly as the Mississippi itself with grooves that get under your skin and won\'t let go. These cats deliver the kind of infectious, community-driven energy that makes Jazz Fest legendary—expect horn-driven arrangements, deep pocket rhythms, and that distinctly New Orleans magic that transforms a performance into a celebration.'},
  { id: 'b211', name: "Mahmoud Chouki"                                            , day: 'd3', stage: 'lagniappe',  start: '14:00', end: '15:05', yt: 'kpdrBrJLfac', verified: true , blurb: 'Mahmoud Chouki brings hypnotic North African grooves and soulful oud-driven melodies to the Lagniappe Stage, blending traditional Maghrebi music with contemporary world rhythms that\'ll transport you straight to the medinas of Marrakech. Jazz Fest devotees who crave the intersection of ancient traditions and modern sonic adventurism won\'t want to miss this mesmerizing set.'},
  { id: 'b212', name: "Cristina Kaminis"                                          , day: 'd3', stage: 'lagniappe',  start: '15:30', end: '16:30', yt: 'pOWMwST0J0U', verified: true , blurb: 'Cristina Kaminis brings sultry, genre-bending sophistication to the Lagniappe Stage with her hypnotic blend of jazz, soul, and Mediterranean-inflected grooves that feel both intimate and expansive. Her crystalline vocals and modern sensibility make her a standout discovery for Jazz Fest explorers seeking sophisticated artistry beyond the main stages.'},
  { id: 'b213', name: "Ever More Nest"                                            , day: 'd3', stage: 'lagniappe',  start: '16:55', end: '18:00', yt: 'wkje9PYO62E', verified: true , blurb: 'Ever More Nest brings layered, sophisticated soundscapes that blend jazz with contemporary experimental textures—a perfect fit for seekers of tomorrow\'s sonic frontier who still dig deep roots. Their intimate yet expansive aesthetic captures the Lagniappe Stage\'s spirit: where New Orleans tradition meets avant-garde vision, and every set feels like discovering something precious you didn\'t know you needed.'},
  { id: 'b214', name: "Silver Birds Steel Orchestra"                              , day: 'd3', stage: 'jamaica',    start: '11:30', end: '12:20', yt: 'mdMc7-T4RkU', verified: true , blurb: 'Silver Birds Steel Orchestra brings the hypnotic, shimmering percussion magic of Caribbean steelband tradition to Jazz Fest, transforming Sandals Jamaica Cultural Pavilion into a vibrant island celebration where intricate melodic layers and infectious rhythms create pure sonic joy that\'ll have you moving from first note to last.'},
  { id: 'b215', name: "ShowJam Mento Band"                                        , day: 'd3', stage: 'jamaica',    start: '12:45', end: '13:45', yt: 'v6y5Q14l7mU', verified: true , blurb: 'ShowJam Mento Band brings the infectious rhythms and playful spirit of traditional Jamaican mento to Jazz Fest, blending Caribbean storytelling with infectious grooves that\'ll have you moving from the first note. Their warm, vintage-flavored sound is pure joy—perfect for fans seeking that soulful, cross-cultural magic that makes the Fest unforgettable.'},
  { id: 'b216', name: "Lutan Fyah"                                                , day: 'd3', stage: 'jamaica',    start: '14:10', end: '15:10', yt: 'i9SdGSC8jQQ', verified: true , blurb: '" ... Rastafari livity means to tolerate and to live side by side with those of other faiths no matter which race, no matter which class. The purpose of Haile Selassie is to see that we become one in unity and love ... and that is my purpose.'},
  { id: 'b217', name: "BrukOut Sound System ft. Seani B, NESTA, Laa Lee & Izzy Bossy", day: 'd3', stage: 'jamaica',    start: '15:35', end: '16:35', yt: 'Xp-p8FtMILU', verified: true , blurb: 'BrukOut Sound System brings the infectious energy of Jamaica\'s dance-hall and reggae underground to Jazz Fest, with Seani B, NESTA, Laa Lee, and Izzy Bossy delivering bass-heavy riddims and lyrical fire that\'ll have you moving from the first drop. This is Caribbean club culture at its rawest—expect hypnotic grooves, rapid-fire flows, and the kind of communal heat that makes the Sandals Jamaica Cultural Pavilion feel like Kingston after dark.'},
  { id: 'b218', name: "Doctor Nativo of Guatemala"                                , day: 'd3', stage: 'jamaica',    start: '17:00', end: '18:00', yt: '_xNO8CguTz4', verified: true , blurb: 'Doctor Nativo of Guatemala brings rootsy Caribbean and Central American rhythms to the Sandals Jamaica Cultural Pavilion, blending traditional Garifuna percussion with contemporary grooves that\'ll have you moving from the first beat. Their infectious energy and deep cultural roots make them essential listening for Jazz Fest fans seeking authentic, world-music vibes beyond the main stages.'},
  { id: 'b219', name: "Gizinti"                                                   , day: 'd3', stage: 'rhythm',     start: '12:00', end: '12:45', yt: 'fuW-BjJV9ok', verified: true , blurb: 'Gizinti brings infectious rhythmic energy and cross-cultural grooves to the Rhythmpourium Tent, blending New Orleans funk traditions with global percussion and modern production for a dance-floor experience that feels both ancestral and urgently contemporary. Jazz Fest devotees hungry for something that moves the body as much as the spirit will find their groove here.'},
  { id: 'b220', name: "Cristina Kaminis"                                          , day: 'd3', stage: 'rhythm',     start: '13:10', end: '13:55', yt: 'pOWMwST0J0U', verified: true , blurb: 'Cristina Kaminis brings sultry, genre-bending sophistication to the Lagniappe Stage with her hypnotic blend of jazz, soul, and Mediterranean-inflected grooves that feel both intimate and expansive. Her crystalline vocals and modern sensibility make her a standout discovery for Jazz Fest explorers seeking sophisticated artistry beyond the main stages.'},
  { id: 'b221', name: "Dirk & Amelia Powell"                                      , day: 'd3', stage: 'rhythm',     start: '14:20', end: '15:05', yt: 'uGifFGDVIno', verified: true , blurb: 'Dirk & Amelia Powell bring infectious, groove-heavy funk and soul to the Rhythmpourium Tent, blending New Orleans tradition with contemporary edge and undeniable chemistry that\'ll have you moving from the first note. Their tight interplay and feel-good energy capture everything Jazz Fest fans crave—authenticity, soul, and pure danceable joy.'},
  { id: 'b222', name: "The Desert Nudes"                                          , day: 'd3', stage: 'rhythm',     start: '15:30', end: '16:20', yt: 'qpGmIbcAGgo', verified: true , blurb: 'The Desert Nudes bring a sun-baked, hypnotic groove to the Rhythmpourium Tent—blending psych-funk rhythms with raw, unfiltered energy that transforms the festival grounds into a shimmering mirage of sound. These sonic outlaws strip rock and soul down to their essence, delivering the kind of transcendent, late-night set that makes Jazz Fest the ultimate pilgrimage for adventurous music lovers.'},
  { id: 'b223', name: "Kr3wcial"                                                  , day: 'd3', stage: 'rhythm',     start: '16:45', end: '17:30', yt: 'bCzv2Rz4s34', verified: true , blurb: 'Kr3wcul brings high-octane electronic energy and boundary-pushing beats to the Rhythmpourium Tent, fusing New Orleans\' krewes culture with cutting-edge production and bass-heavy grooves that hit different. Their infectious, dance-floor-ready sound blends local flavor with global club sensibility—exactly what Jazz Fest fans crave when they want to move.'},
  { id: 'b224', name: "The Reckless Band from Breakfast Land"                     , day: 'd3', stage: 'children',   start: '11:30', end: '12:10', yt: 'pOWaiiJLt40', verified: true , blurb: 'The Reckless Band from Breakfast Land serves up playful, high-energy funk and brass-fueled grooves that\'ll have kids and families dancing in the aisles—a New Orleans institution that turns the Ochsner Children\'s Tent into an instant party where joy and musicianship collide.'},
  { id: 'b225', name: "Johnette Downing and Scott Billington"                     , day: 'd3', stage: 'children',   start: '12:35', end: '13:20', yt: 'beheB2hTQKk', verified: true , blurb: 'It’s time to romp in the swamp and boogie on the bayou when multi-award winning singer and children’s book author Johnette Downing, and three-time Grammy® winner Scott Billington share their joyful musical and cultural celebration of Louisiana roots music for families. Children sing along with Jazz, Cajun, Creole, Isleño, Blues and Zydeco tunes in an interactive toe-tapping, two-stepping good time.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41588/festivalartist-12564-artist_image-d501924d-6369-41a1-8e2d-d166e724cc8e.jpg'},
  { id: 'b226', name: "All For One Brass Band & Social Aid & Pleasure Clubs"      , day: 'd3', stage: 'children',   start: '13:20', end: '13:55', yt: 'E3pYZvIRbSQ', verified: true , blurb: 'Experience the infectious energy of New Orleans brass tradition at its most joyful—All For One Brass Band & Social Aid & Pleasure Clubs deliver second line swagger, strutting rhythms, and pure celebratory soul that\'ll have families dancing in the aisles and kids discovering why this city\'s brass legacy is unstoppable. Their high-octane horns, thundering percussion, and community-rooted spirit capture everything Jazz Fest is about: music that moves bodies and brings people together.'},
  { id: 'b227', name: "The Hoot-n-Holler Inn"                                     , day: 'd3', stage: 'children',   start: '13:55', end: '14:40', yt: 'LF7vSonOI9E', verified: true , blurb: 'The Hoot-n-Holler Inn brings playful, high-energy folk and roots music to the children\'s stage, spinning infectious singalongs and toe-tapping rhythms that blend Americana storytelling with pure New Orleans joy. Jazz Fest families will love their infectious, interactive sets that turn the Ochsner Children\'s Tent into a hootenanny of laughter, learning, and unbridled fun.'},
  { id: 'b228', name: "ShowJam Mento Band"                                        , day: 'd3', stage: 'children',   start: '15:05', end: '15:50', yt: 'v6y5Q14l7mU', verified: true , blurb: 'ShowJam Mento Band brings the infectious rhythms and playful spirit of traditional Jamaican mento to Jazz Fest, blending Caribbean storytelling with infectious grooves that\'ll have you moving from the first note. Their warm, vintage-flavored sound is pure joy—perfect for fans seeking that soulful, cross-cultural magic that makes the Fest unforgettable.'},
  { id: 'b229', name: "Mestre Curtis Pierre \"The Samba Man\""                    , day: 'd3', stage: 'children',   start: '16:15', end: '17:00', yt: 'f_Sk2H0MHQw', verified: true , blurb: 'Mestre Curtis Pierre brings infectious Brazilian samba rhythms and joyful percussion magic to the Ochsner Children\'s Tent, turning the festival grounds into a dance floor where families move together in pure celebration. His high-energy grooves and masterful drumming create the perfect soundtrack for young ears discovering the vibrant pulse of New Orleans\' deep connection to world music.'},
  { id: 'b230', name: "Crowe Boys Interviewer: Alex Kennon Shahin"                , day: 'd3', stage: 'miner',      start: '12:15', end: '13:00', yt: 'oJ7ckvbVef0', verified: true , blurb: 'The Crowe Boys deliver raw, soulful roots music steeped in New Orleans tradition—dusty blues, gospel grit, and intergenerational storytelling that hits like a late-night sermon. If you\'re seeking authentic heritage sounds that honor the city\'s musical DNA, they\'re essential listening.'},
  { id: 'b231', name: "Bishop Paul S. Morton Interviewer: Joyce Jackson"          , day: 'd3', stage: 'miner',      start: '13:15', end: '14:00', yt: 'ZX--1zzFWmw', verified: true , blurb: 'Bishop Paul S. Morton brings transcendent gospel power and spiritual depth to the Allison Miner stage, channeling the rich tradition of New Orleans sacred music with a voice and presence that moves souls—perfect for Jazz Fest devotees seeking the festival\'s most uplifting, authentically rooted performances.'},
  { id: 'b232', name: "HaSizzle Interviewer: Slangston Hughes"                    , day: 'd3', stage: 'miner',      start: '14:15', end: '15:00', yt: 'fpFMTbpkv6s', verified: true , blurb: 'HaSizzle Interviewer: Slangston Hughes brings lyrical fire and deep-rooted New Orleans soul to the Heritage Stage, blending spoken word intensity with jazz-inflected beats that honor the city\'s rich tradition of poetic storytelling. This is must-see artistry for anyone seeking authentic cultural voice and the kind of raw, unfiltered performance that makes Jazz Fest legendary.'},
  { id: 'b233', name: "Jelly Joseph Interviewer: Bryan Wagner"                    , day: 'd3', stage: 'miner',      start: '15:15', end: '16:00', yt: 'Fm9N-lyNQms', verified: true , blurb: 'Jelly Joseph channels the deep, soulful traditions of New Orleans R&B and funk with a voice that cuts straight to the heart, delivering the kind of authentic Heritage Stage performance that reminds you why this music matters. Bryan Wagner\'s interviewer presence amplifies the intimate storytelling that defines Jelly Joseph\'s sound—raw, rooted, and real.'},
  { id: 'b234', name: "Ivan Neville Interviewer: Kate Pieroudis"                  , day: 'd3', stage: 'miner',      start: '16:15', end: '17:00', yt: 'xV0I-_DHwFg', verified: true , blurb: 'Ivan Neville channels the soulful legacy of New Orleans R&B and funk with a groove-soaked authenticity that runs deep—expect rhythmic storytelling, blazing keyboards, and the kind of musical conversation that only happens when generations of tradition meet raw talent. This is the sound that built the city, delivered with the swagger and precision that keeps Jazz Fest\'s heart beating.'},

  // ───────── Sun Apr 26 (d4) ─────────
  { id: 'b235', name: "Ronnie Lamarque"                                           , day: 'd4', stage: 'festival',   start: '11:20', end: '12:15', yt: 'sPjQkyChoB4', verified: true , blurb: 'Ronnie Lamarque brings that deep, soulful New Orleans groove to the Festival Stage—a masterclass in traditional jazz piano and vocals that channels the city\'s classic spirit with modern sensibility. This is the sound that reminds you why Jazz Fest exists: authentic, swinging, and impossibly cool.'},
  { id: 'b236', name: "New Orleans Nightcrawlers"                                 , day: 'd4', stage: 'festival',   start: '12:40', end: '13:40', yt: 'EQf3jaBZDYg', verified: true , blurb: 'by far one of the best of the newer offerings coming out of the crescent city... an essential piece of the sound trying to re-emerge since Katrina'},
  { id: 'b237', name: "Rockin' Dopsie, Jr. & the Zydeco Twisters"                 , day: 'd4', stage: 'festival',   start: '14:05', end: '15:05', yt: 'RJw2Cp_wnkk', verified: true , blurb: 'Rockin\' Dopsie, Jr. & the Zydeco Twisters bring the swamp-fire energy of Louisiana zydeco to the Festival Stage, spinning accordion-driven grooves and call-and-response vocals that get crowds moving from the opening note. If you crave that irresistible blend of Creole soul, washboard percussion, and pure danceable joy, this is the New Orleans sound you came for.'},
  { id: 'b238', name: "Irma Thomas"                                               , day: 'd4', stage: 'festival',   start: '15:35', end: '16:45', yt: 'G_K9xsSdgMs', verified: true , blurb: 'Irma Thomas (b. February 18, 1941, Ponchatoula, Louisiana) whose only national chart hit in a 50 year career is 1963\'s "Wish Someone Would Care", is an enduring, Grammy winning, soul, gospel, rhythm and blues singer from New Orleans.'},
  { id: 'b239', name: "Rod Stewart"                                               , day: 'd4', stage: 'festival',   start: '17:25', end: '18:55', yt: 'w46bWxS9IjY', verified: true , blurb: 'Sir Roderick David Stewart (born 10 January 1945) is a British singer and songwriter. Known for his distinctive raspy singing voice, Stewart has sold more than 120 million records worldwide. His music career began in 1962 when he started busking with a harmonica.'},
  { id: 'b240', name: "Kinfolk Brass Band"                                        , day: 'd4', stage: 'shell',      start: '11:20', end: '12:20', yt: 'z60fHAfOeB8', verified: true , blurb: 'Kinfolk Brass Band started in October of 2006, a year after Katrina. What started with a few players here and there quickly morphed into a six-man lineup, which solidified quickly into a single voice.'},
  { id: 'b241', name: "People Museum"                                             , day: 'd4', stage: 'shell',      start: '12:40', end: '13:40', yt: '25ev5QbjDtk', verified: true , blurb: 'People Museum is a four-piece New Orleans band that has found inspiration in the lush musical and cultural roots of their Louisiana birthplace.'},
  { id: 'b242', name: "Boyfriend"                                                 , day: 'd4', stage: 'shell',      start: '14:10', end: '15:10', yt: 'j8dq763_sMw', verified: true , blurb: 'Boyfriend is a writer, singer, producer, choreographer, and performance artist. Best known for her live show, which is "as much cone-bra arena-sized Madonna as it is an intimate hilariously profane psychosexual drama" (Gambit), Boyfriend has taken her special brand of "campy rap antagonism" (LA Times), "high-concept booty bass" (Rolling Stone), and "candy-coated cultural criticism" (Nasty Gal) to stages across the globe.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41529/festivalartist-12435-artist_image-c1403440-b307-416a-b272-9ee93e08a40b.jpg'},
  { id: 'b243', name: "St. Vincent"                                               , day: 'd4', stage: 'shell',      start: '15:40', end: '16:55', yt: 'mVAxUMuhz98', verified: true , blurb: 'A pseudonym of Annie Clark (b. 28 Sept 1982), a USA multi-instrumentalist singer-songwriter. She was a member of The Polyphonic Spree and Sufjan Stevens\' touring band.'},
  { id: 'b244', name: "David Byrne"                                               , day: 'd4', stage: 'shell',      start: '17:30', end: '19:00', yt: 'JAqB0-OKyBQ', verified: true , blurb: 'David Byrne (Dumbarton, Scotland, May 14, 1952) is a founding member and principal songwriter of the American New Wave band Talking Heads, which was active between 1975 and 1991.'},
  { id: 'b245', name: "New Birth Brass Band"                                      , day: 'd4', stage: 'congo',      start: '11:20', end: '12:20', yt: 'U-TlL32lvEw', verified: true , blurb: 'The New Birth Brass Band are part of a long line in the New Orleans brass band tradition, but their relative youth means their music yields an eclectic set of musical genres.'},
  { id: 'b246', name: "Nomfusi of South Africa"                                   , day: 'd4', stage: 'congo',      start: '12:45', end: '13:45', yt: 'MCvbOcdgpzY', verified: true , blurb: 'Nomfusi brings the spiritual soul of South African jazz and roots music to Congo Square, blending traditional rhythms with contemporary grooves that\'ll have you moving from the first note. This is the kind of authentic, genre-defying performance that reminds you why Jazz Fest exists—to celebrate the global language of improvisation, community, and pure musical joy.'},
  { id: 'b247', name: "Erica Falls"                                               , day: 'd4', stage: 'congo',      start: '14:15', end: '15:15', yt: 'e0vmC4mRb9Y', verified: true , blurb: 'Erica Falls brings soulful, genre-blending artistry to the Congo Square Stage with a sound rooted in contemporary R&B, neo-soul, and New Orleans funk—her rich vocals and rhythmic sensibility creating an irresistible groove that honors tradition while pushing boldly forward. Jazz Fest audiences will find in her performance the perfect blend of intimate storytelling and infectious energy that defines the festival\'s spirit.'},
  { id: 'b248', name: "Carlos Vives"                                              , day: 'd4', stage: 'congo',      start: '15:50', end: '17:00', yt: 'Mtau4v6foHA', verified: true , blurb: 'Before he graduated from Jorge Tadeo Lozano\'s University with a publicist degree, singer Carlos Vives joined different bands and participated in several plays.'},
  { id: 'b249', name: "The Isley Brothers"                                        , day: 'd4', stage: 'congo',      start: '17:40', end: '18:55', yt: '-qnSz6Lh5pY', verified: true , blurb: 'The Isley Brothers are an American soul group originating from Cincinnati, Ohio. The group began in 1954 as a vocal trio consisting of brothers O\'Kelly Isley Jr., Rudolph Isley, and Ronald Isley. Together with another brother, Vernon Isley, the group initially performed gospel music.'},
  { id: 'b250', name: "NOCCA Jazz Ensemble"                                       , day: 'd4', stage: 'jazz',       start: '11:15', end: '12:00', yt: 'iaSHv4_eXIM', verified: true , blurb: 'NOCCA Jazz Ensemble brings the sophisticated sound of New Orleans\' most promising young players—blending straight-ahead bebop with modern sensibilities and the unmistakable pocket groove that only comes from the city\'s legendary music education pipeline. Their tight arrangements and telepathic interplay prove why NOCCA alumni are shaping jazz\'s future, delivering the kind of fresh-yet-rooted performance that makes Jazz Fest devotees return to the WWOZ tent year after year.'},
  { id: 'b251', name: "Roger Lewis' Baritone Bliss"                               , day: 'd4', stage: 'jazz',       start: '12:20', end: '13:10', yt: 'JW0i3oE3yP0', verified: true , blurb: 'Experience the warm, soulful depths of baritone saxophone mastery as Roger Lewis brings his signature blend of traditional New Orleans jazz and contemporary soul to the WWOZ Jazz Tent—a must-catch set for anyone seeking that perfect intersection of brass-driven groove and intimate, bluesy sophistication.'},
  { id: 'b252', name: "The Great Duets: Jolynda \"Kiki\" Chapman and Roderick Harper", day: 'd4', stage: 'jazz',       start: '13:30', end: '14:30' , blurb: 'Jolynda "Kiki" Chapman and Roderick Harper bring together voices steeped in New Orleans soul and jazz tradition, crafting intimate duets that feel like conversations between old friends—expect lush harmonies, vintage swing grooves, and the kind of authentic chemistry that makes the WWOZ Jazz Tent the heart of the Fest.'},
  { id: 'b253', name: "Love Is Supreme: A Tribute to John Coltrane featuring Derek Douget, Trevarri Huff-Boone, Ricardo Pascal", day: 'd4', stage: 'jazz',       start: '14:50', end: '15:50', yt: 'Y9GXxie_iV4', verified: true , blurb: 'Experience a spiritually transcendent journey through Coltrane\'s timeless legacy as Derek Douget, Trevarri Huff-Boone, and Ricardo Pascal channel the harmonic depths and soulful intensity of jazz\'s greatest innovator. This reverent yet electrifying tribute captures the modal sophistication and devotional power that made Coltrane sacred ground for New Orleans musicians and jazz pilgrims alike.'},
  { id: 'b254', name: "The Headhunters"                                           , day: 'd4', stage: 'jazz',       start: '16:15', end: '17:15', yt: 'reCo-EfiuD8', verified: true , blurb: 'There is more than one band that goes by the name \'The Headhunters\', three are  mentioned below: 1.) A USA jazz funk fusion band,  2.) A side project of Swedish rock group Ultima Thule   3.'},
  { id: 'b255', name: "The Ron Carter Foursight Quartet"                          , day: 'd4', stage: 'jazz',       start: '17:45', end: '19:00', yt: '4H5xwWj_usY', verified: true , blurb: 'Ron Carter\'s legendary bass anchors this intimate quartet in elegant, straight-ahead jazz that swings with understated sophistication—the kind of timeless groove that reminds you why the WWOZ tent is hallowed ground. Foursight delivers conversation over combustion, where every note counts and the interplay between voices creates that rare magic that defines New Orleans jazz at its most refined.', members: 'Ron Carter, James Spaulding, Mulgrew Miller, Loren Schoenberg'},
  { id: 'b256', name: "River Eckert"                                              , day: 'd4', stage: 'blues',      start: '11:15', end: '12:15', yt: 'm0AIt4BaE04', verified: true , blurb: 'River Eckert brings raw, soulful blues to the Blues Tent with a gritty authenticity that channels New Orleans\' deepest roots—expect weathered vocals, slide guitar licks, and grooves that\'ll have you moving before you know it. This is the real deal: no frills, no polish, just pure blues emotion that speaks directly to the heart.'},
  { id: 'b257', name: "Chris Thomas King"                                         , day: 'd4', stage: 'blues',      start: '12:40', end: '13:40', yt: 'laWj4OOGo7c', verified: true , blurb: 'Born in 1962, guitarist Chris Thomas King became the last major folk blues discovery of the 20th Century when he was discovered in Louisiana in 1979 by a folklorist from the Smithsonian Institute in Washington D. C. He was introduced to the world the following year by venerable folk label Arhoolie Records as an authentic folk blues successor to Huddie Ledbetter, Muddy Waters, Mississippi John Hurt and Manse Lipscomb. As the darling of blues purists and aficionados, and the last great hope of the waning folk blues revival, which began during the 1960s folk movement, Chris Thomas King shocked the music world in the early ‘90s when he abandoned all pretenses of primitivism and embraced hip hop modernity and digital aesthetics, turning the blues world upside down. The Blues Mafia — a consortium of folklorists, record collectors, and researchers; white self-appointed arbiters of black musical authenticity who ironically had a cartel on the lucrative new market of white rock fans interested in its musical roots — felt betrayed by King. They denounced him in the music press as a heretic, banning the young rebel from festivals and theaters across the United States. Unbowed, King moved to Europe in 1993 and went on to write and produced a series of ground breaking recordings including “21st Century Blues” and “My Pain Your Pleasure,” which boldly challenged the ostensible primitivism ideology of “authenticity” as either naive romanticism or an outright bigoted appropriation of his culture. The French, having a penchant for recognizing gifted unsung black American artists, were enthralled by King’s subversive bohemian stance. He was lauded a genius for his transcendent folk art, which he coined twenty-first-century blues. Celebrated as an expatriate artist, yet alienated from his culture back home, and seemingly destined for obscurity in his own country, King decided to return to New Orleans in 1996 to contend for the soul of the blues. But he found it difficult to re-enter the traditional American market, from which he had been exiled. Nevertheless, as fate would have it, King was chosen by the Coen brothers to play the role of itinerant bluesman Tommy Johnson along side George Clooney in the movie “O Brother, Where Art Thou? (2000).” Larger than life on the silver screen, Chris Thomas King, acoustic guitar in hand, captivated audiences the world over, silencing his critics. His authenticity as a folk blues artist, by any measure, proved to be undeniable. A star of stage and screen was born. New fans the world over packed sold out theaters and art centers to immerse themselves in his illuminating melodious glow. King sold millions of records and won numerous awards, superseding the success of his folk blues predecessors. King’s major contributions to the “O Brother, Where Art Thou” phenomenon, along with its follow up album and tour, “Down From The Mountain,” has inspired a new generation of musicians such as, Hozier, Mumford & Sons, and the Lumineers. His songs “Hard Time Killing Floor Blues” and “John Law Burned Down the Liqour Sto,’” to name a few, have been covered by numerous artists including legend Buddy Guy. Thirty years after becoming the last major folk blues discovery of the 20th Century, Chris Thomas King, whose career is a coda for the folk blues revival of the ‘60s, is today, one of the most important artists in the world for having changed the way we think of blues. In a newly written song King sings a remarkable refrain that goes, “The blues was born in, Louisiana, not Mississippi, or Texarkana,” about the ostensible fallacy that it orginated in the Delta. He then goes on to state unequivocally in the following verse, “Down in New Orleans” is “where the blues was born. You can still hear the sound of, Buddy Bolden’s horn.” Thankfully, also in New Orleans, we can still hear the enlightened art of Chris Thomas King.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41537/festivalartist-12447-artist_image-ae96b954-09bc-4e77-8677-ba7559028b53.jpg'},
  { id: 'b258', name: "Glen David Andrews"                                        , day: 'd4', stage: 'blues',      start: '14:05', end: '15:10', yt: 'fH7CTetZVCg', verified: true , blurb: 'Glen David Andrews is Trombone Shorty\'s big brother. Just as skilled on the trombone as Shorty, he tends to play in a more conventional New Orleans/R&B/jazz mode. If you love Second Line variations, then this is it.'},
  { id: 'b259', name: "The Music of Marcia Ball with the Marcia Ball Band and special guests*", day: 'd4', stage: 'blues',      start: '15:40', end: '16:50', yt: 'HhpWSjodNCY', verified: true , blurb: 'Marcia Ball brings her signature boogie-woogie piano and raspy, soulful vocals to the Blues Tent, blending Louisiana blues, funk, and R&B into a irresistible groove that\'ll have you dancing from the first note. This New Orleans institution and her band deliver authentic, high-energy performances that capture the raw spirit and infectious joy that make Jazz Fest legendary.'},
  { id: 'b260', name: "Jon Batiste presents Swamp"                                , day: 'd4', stage: 'blues',      start: '17:30', end: '19:00', yt: '3YHVC1DcHmo', verified: true , blurb: 'Jon Batiste presents Swamp brings the raw, funky soul of Louisiana bayou blues to the Blues Tent, blending virtuosic piano with earthy grooves that feel like they were born from the wetlands themselves. This is blues that moves—rooted in tradition but bursting with the creative energy that makes Batiste a vital force in New Orleans music.'},
  { id: 'b261', name: "Jenavieve and the Winding Boys"                            , day: 'd4', stage: 'economy',    start: '11:15', end: '12:05', yt: '3F0qmxShz0s', verified: true , blurb: 'Jenavieve and the Winding Boys bring second-line swagger and deep-rooted New Orleans soul to Economy Hall, where their gritty brass-fueled grooves and vintage R&B sensibility cut straight to the heart of what makes this city\'s music sacred and irresistible. Expect infectious rhythms, raw horn arrangements, and the kind of joyful authenticity that reminds you why Jazz Fest exists.'},
  { id: 'b262', name: "Lars Edegran's New Orleans Ragtime Orchestra"              , day: 'd4', stage: 'economy',    start: '12:25', end: '13:20', yt: 'MZxTBT4WiHs', verified: true , blurb: 'Lars Edegran\'s New Orleans Ragtime Orchestra brings the syncopated swagger and hot clarinet lines of early jazz straight from the Crescent City\'s golden age, transforming Economy Hall into a time machine where ragtime rhythms and New Orleans tradition collide with infectious joy. Their tight ensemble and meticulous arrangements celebrate the ragtime pioneers who built this city\'s musical foundation, making them essential for anyone craving authentic New Orleans jazz in its purest, most exuberant form.'},
  { id: 'b263', name: "Dr. Michael White's Original Liberty Jazz Band featuring Thais Clark", day: 'd4', stage: 'economy',    start: '13:40', end: '14:40', yt: 'IB2TgtyOIAA', verified: true , blurb: 'Dr. Michael White\'s Original Liberty Jazz Band featuring Thais Clark delivers the deep, grooving New Orleans jazz tradition with soul-stirring clarinet and a rhythm section locked into the city\'s heartbeat—exactly the kind of authentic, multigenerational sound that makes Economy Hall the festival\'s spiritual center. Thais Clark\'s vocals bring a sultry, conversational warmth to standards and originals alike, making this a must-catch set for anyone seeking genuine New Orleans jazz, not the tourist version.'},
  { id: 'b264', name: "Catherine Russell"                                         , day: 'd4', stage: 'economy',    start: '15:05', end: '16:10', yt: 'Y4bK5_48a5U', verified: true , blurb: 'Catherine Russell (*1956) is a native New Yorker, born with an enviable musical pedigree. Her father, the late Luis Russell, was born in Panama and moved to New Orleans and then New York City, becoming a pioneering pianist/bandleader, and Louis Armstrong’s long-time musical director.'},
  { id: 'b265', name: "Tuba Skinny"                                               , day: 'd4', stage: 'economy',    start: '16:35', end: '17:35', yt: 'bBINhDYXoEg', verified: true , blurb: 'Formed in in 2009, Tuba Skinny has steadily evolved from a loose collection of street musicians into a solid ensemble dedicated to bringing the traditional New Orleans sound to audiences around the world. Drawing on a wide range of musical influences—from spirituals to Depression-era blues, from ragtime to traditional jazz—their sound evokes the rich musical heritage of their New Orleans home. The band has gained a loyal following through their distinctive sound, their commitment to reviving long-lost songs, and their barnstorming live performances.'},
  { id: 'b266', name: "Kevin Louis & The Friday Night Jazz Band feat. Yolanda Robinson", day: 'd4', stage: 'economy',    start: '17:55', end: '18:45', yt: 'X6PeAks-YA4', verified: true , blurb: 'Kevin Louis & The Friday Night Jazz Band feat. Yolanda Robinson brings the deep, soulful tradition of New Orleans jazz to the Economy Hall Tent—a masterclass in classic swing and blues-rooted grooves where Yolanda Robinson\'s commanding vocals float over propulsive brass and rhythm that\'ll have you moving from the first note.'},
  { id: 'b267', name: "Horace Trahan & the Ossun Express"                         , day: 'd4', stage: 'fais',       start: '11:20', end: '12:20', yt: 'mWpVmlqJ-nw', verified: true , blurb: 'Horace Trahan & the Ossun Express bring traditional Louisiana swamp pop and zydeco grooves with a modern twist, delivering the kind of infectious, dance-floor energy that reminds you why the Fais Do-Do stage is a Jazz Fest institution. Their accordion-driven sound celebrates the bayou\'s rich cultural heritage while keeping the spirit of New Orleans alive and swinging.'},
  { id: 'b268', name: "Jambalaya Cajun Band"                                      , day: 'd4', stage: 'fais',       start: '12:45', end: '13:45', yt: 'SzCMV_zpez0', verified: true , blurb: 'The Jambalaya Cajun Band, which has been playing Cajun music on stage for over 44 years, still has the same members it had in 1986 - Terry Huval on Fiddle, his brother, Tony Huval on Drums, Accordionist Reggie Matte, Bobby Dumatrait on Guitar and Ken David on Bass. Beginning with its first Jazz Fest performance in 1991, this year will mark Jambalaya’s 26th year on the Jazz Fest stage. The band\'s "weekend warrior" approach has allowed them to continue their chosen work careers, while still having an opportunity to play the French Cajun they nurture and love. Jambalaya\'s recordings have provided some opportunities to travel abroad to Canada and Europe. The band has garnered a number of Cajun French Music Association awards for its self-produced recordings. Through the years, the band has made a point inviting honored legendary greats from previous generations - such as DL Menard, Merlin Fontenot, Johnnie Allen and Hank Williams’ steel guitarist, Don Helms. Members of the group have also assisted the Hackberry Ramblers at Jazz Fest. Some members of the band have even nurtured their own children into the culture - like Terry\'s sons, Luke and Phillip Huval, and Ken\'s son, Thomas David - with the Pine Leaf Boys. With all the band members conversant in French, the audience gets the feel of the “Real Deal” of guys who are really steeped in the culture. But, you better listen closely… Laissez Les Bon Temps Rouler (Let the Good Times Roll) with Jambalaya 2020!', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41446/festivalartist-12233-artist_image-ed95d267-28a6-4ac4-ac70-eb9b0bd07688.jpg'},
  { id: 'b269', name: "Zachary Richard"                                           , day: 'd4', stage: 'fais',       start: '14:10', end: '15:20', yt: 'IP5RpXtd1uo', verified: true , blurb: 'Born and raised in southwest Louisiana Zachary Richard is a singer-songwriter and poet with 21 albums to his credit in an international career spanning four decades. Founding member of Action Cadienne, he has devoted himself to the promotion of Louisiana’s French language and Acadian culture and is Louisiana’s first French language Poet Laureat.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41436/festivalartist-12202-artist_image-0b3934ce-1f8d-4c69-8ef9-7328826aaa63.jpg'},
  { id: 'b270', name: "Sunpie and The Louisiana Sunspots"                         , day: 'd4', stage: 'fais',       start: '15:45', end: '16:50', yt: 'qkX9lY6Xb7I', verified: true , blurb: 'Sunpie and The Louisiana Sunspots bring swamp-tested funk and soul to the Sheraton Fais Do-Do Stage, where their infectious grooves and raw, feel-good energy capture everything that makes New Orleans music irresistible—expect dancing, sweating, and pure joy from start to finish.'},
  { id: 'b271', name: "Leftover Salmon"                                           , day: 'd4', stage: 'fais',       start: '17:20', end: '18:50', yt: 'OBGegHr8e4o', verified: true , blurb: 'Leftover Salmon is a genre-bending band from Boulder, Colorado. Their unique blend of bluegrass, rock, country, and Cajun/Zydeco, which the band calls "Polyethnic Cajun Slamgrass", has found favor with the jam band scene.'},
  { id: 'b272', name: "Fi Yi Yi & the Mandingo Warriors Mardi Gras Indians"       , day: 'd4', stage: 'heritage',   start: '11:20', end: '12:00', yt: 'K32hFhc8Hhg', verified: true , blurb: 'Experience the raw spiritual power and polyrhythmic swagger of Fi Yi Yi & the Mandingo Warriors, where Mardi Gras Indian tradition collides with West African percussion and modern New Orleans soul—a hypnotic, body-moving force that channels decades of street culture, ancestral memory, and unfiltered joy that only this city can produce.'},
  { id: 'b273', name: "Young Pinstripe Brass Band"                                , day: 'd4', stage: 'heritage',   start: '12:20', end: '13:20', yt: 'oqhulBg6RZ0', verified: true , blurb: 'Young Pinstripe Brass Band brings razor-sharp precision and infectious swagger to the Jazz & Heritage Stage, blending traditional New Orleans brass band traditions with modern funk and hip-hop grooves that\'ll have the whole festival moving. These rising stars deliver the polished sound of a new generation of NOLA brass musicians—snappy horns, thundering rhythm, and pure joy in every note.'},
  { id: 'b274', name: "Javier Olondo and AsheSon"                                 , day: 'd4', stage: 'heritage',   start: '13:45', end: '14:45', yt: 'vodYoqTqZWI', verified: true , blurb: 'Javier Olondo and AsheSon blend Afro-Caribbean rhythms with contemporary jazz sensibilities, crafting a hypnotic sound that honors New Orleans\' deep roots in African diaspora music and spiritual tradition. This is music for moving bodies and open hearts—a transcendent experience that reminds you why the city remains the beating heart of American jazz.'},
  { id: 'b275', name: "ShowJam Mento Band"                                        , day: 'd4', stage: 'heritage',   start: '15:05', end: '16:00', yt: 'v6y5Q14l7mU', verified: true , blurb: 'ShowJam Mento Band brings the infectious rhythms and playful spirit of traditional Jamaican mento to Jazz Fest, blending Caribbean storytelling with infectious grooves that\'ll have you moving from the first note. Their warm, vintage-flavored sound is pure joy—perfect for fans seeking that soulful, cross-cultural magic that makes the Fest unforgettable.'},
  { id: 'b276', name: "Big Chief Monk Boudreaux & The Golden Eagles"              , day: 'd4', stage: 'heritage',   start: '16:25', end: '17:20', yt: 'P00axcsvmds', verified: true , blurb: 'Big Chief Monk Boudreaux & The Golden Eagles bring the raw spiritual power of New Orleans Indian culture to life, blending second-line grooves with hypnotic chants and traditional percussion into a transcendent celebration that only the Crescent City can claim. This is Jazz Fest authenticity at its core—a living connection to the neighborhoods and traditions that make New Orleans music sacred.'},
  { id: 'b277', name: "Dr. Brice Miller & Mahogany Brass Band"                    , day: 'd4', stage: 'heritage',   start: '17:40', end: '18:40', yt: 'ENujSz6vD-4', verified: true , blurb: 'Dr. Brice Miller & Mahogany Brass Band delivers the authentic, swaggering soul of New Orleans brass tradition—blending second-line grooves, funk, and hymnal depth into a sound that moves bodies and spirits alike. Jazz Fest devotees will find themselves swept into the jubilant heart of the city\'s street culture, where every note hits like a celebration.'},
  { id: 'b278', name: "E'Dana"                                                    , day: 'd4', stage: 'gospel',     start: '11:15', end: '12:00', yt: 'du33ChTTaLM', verified: true , blurb: 'E\'Dana brings transcendent soul power to the Gospel Tent with a voice that cuts through decades of tradition while honoring New Orleans\' sacred musical roots—expect uplifting harmonies, deep spiritual conviction, and the kind of authentic joy that fills every corner of the festival grounds.'},
  { id: 'b279', name: "Zack Landry & PhaZe"                                       , day: 'd4', stage: 'gospel',     start: '12:10', end: '12:50', yt: 'fC7y_MeF8PE', verified: true , blurb: 'Zack Landry & PhaZe bring transcendent soul and contemporary groove to the Gospel Tent, blending New Orleans\' deep spiritual traditions with modern R&B sensibilities for a performance that uplifts and moves. Their infectious energy and heartfelt vocals create an irresistible celebration of faith, community, and the timeless power of gospel music that defines the Jazz Fest experience.'},
  { id: 'b280', name: "Jada Tanner"                                               , day: 'd4', stage: 'gospel',     start: '13:00', end: '13:45', yt: 'F8Ll2mbxllQ', verified: true , blurb: 'Jada Tanner brings transcendent soul and contemporary gospel fire to the Gospel Tent, blending traditional spiritual depth with modern vocal sophistication that\'ll have you on your feet and reaching skyward. This is the kind of performance that reminds you why New Orleans remains the beating heart of American sacred music.'},
  { id: 'b281', name: "Tyronne Foster & the Arc Singers"                          , day: 'd4', stage: 'gospel',     start: '13:55', end: '14:40', yt: '_QwvqZjkDRo', verified: true , blurb: 'Tyronne Foster & the Arc Singers deliver pure, soul-stirring gospel that bridges traditional spirituals with contemporary praise, their voices rising in perfect harmony to lift the entire tent skyward. This is the sound of New Orleans faith made manifest—rooted, joyful, and absolutely transcendent.'},
  { id: 'b282', name: "The Zion Harmonizers"                                      , day: 'd4', stage: 'gospel',     start: '14:50', end: '15:35', yt: 'pBBwgqQS7ic', verified: true , blurb: 'It is hard to separate the words New Orleans Gospel and The Zion Harmonizers. The Zion Harmonizers are living legends, as one would expect from a group that has sung together for more than 70 years and who have repeatedly won every award there is to win for traditional gospel in their city. They have also performed all over the world to receptive audiences. Organized in 1939 by Benjamin Maxon, The Zion Harmonizers formed out of an old neighborhood in New Orleans known as "New Zion." Maxon\'s aunt was Alberta French Johnson, leader of the all women\'s gospel group The Southern Harps. She taught her nephew and his friends, Sherman and Nolan Washington, the ways of traditional gospel quartets, a style that they still practice to this day. Sherman Washington joined the Harmonizers as a teenager in 1941 and became their leader a few years later. For nearly 70 years, he led them in their glorious four-part harmonies. Nolan sang with the group until his passing in 1997. Throughout the years, the members have changed a little and the Harmonizers have added some instruments. The group is also known for their brightly-colored matching suits as well as their harmonies, but they still rely heavily on the old-time a cappella style, using it to get the message through. The Harmonizers first appeared at the very first New Orleans Jazz and Heritage Festival, held in the old Congo Square in 1969. Festival organizer Quint Davis then asked Sherman if he would put together a gospel tent. He agreed, and although it meant that church folk had to mingle with party-goers, it became a great opportunity to sing about the good news. The gospel tent is a big success story of Jazz Fest. For years, Washington, who ran the tent and chose the gospel acts, has been able to spread the Good News to appreciative festival goers. There is good music all over the fairgrounds at Jazz Fest, but everybody knows the spirit is higher in the gospel tent. The Zion Harmonizers are yearly performers at the tent. The 2011 performance included a special tribute to Sherman Washington, who passed away in March of that year. In addition, they often sing at many Churches for special events, Easter Sunrise Performances, the Abita Springs Opry and numerous overseas performances. The Zion Harmonizers are also one of the monthly featured groups at the New Orleans House of Blues Gospel Brunch. Brazella Briscoe used to listen to them on the radio with his brother William when they were little boys. Briscoe is now the leader of The Zion Harmonizers, (he joined the group 24 years ago), and his brother is also a member. Other current members are singers Franklin D. R. Smith, Marion H. Chambers, Jr., and Benjamin Francois III, Lead Guitarist Willie Williams, Keyboardist/Organist Joseph B. Warrick Jr., and Drummer Marvin Smith. The Zion Harmonizers\' exciting and powerful sets are filled with many tunes off of their recordings. Their CD releases include “Never Alone”, “Thank You Lord“, and “Gospel Glory” which was recorded with special guest “The Blues Queen of New Orleans”, Marva Wright. Yet, despite their many achievements, the Zion Harmonizers remain humble, approachable men whose purpose in performing is to entertain, enlighten and enjoy reaching out to their audience for a very memorable time.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41548/festivalartist-12464-artist_image-279cb467-0ba6-46a6-8534-a1eff18075bf.jpg'},
  { id: 'b283', name: "Shirley Caesar and The Caesar Singers"                     , day: 'd4', stage: 'gospel',     start: '15:55', end: '16:55', yt: 'Djw8HqJiRSE', verified: true , blurb: 'Shirley Caesar and The Caesar Singers bring transcendent, soul-shaking gospel power to the Gospel Tent with their signature blend of traditional hymns and contemporary praise—a masterclass in vocal precision and spiritual depth that channels decades of churchhouse tradition into performances that lift audiences straight into grace.'},
  { id: 'b284', name: "The Coolie Family Gospel Singers"                          , day: 'd4', stage: 'gospel',     start: '17:10', end: '17:55', yt: 'Dub6H2KVK5k', verified: true , blurb: 'The Coolie Family Gospel Singers bring generations of New Orleans soul and spiritual depth to the Gospel Tent with their rich harmonies and authentic devotional power—a rousing, joyful celebration of faith that embodies the heart and heritage Jazz Fest audiences cherish. Their blend of traditional gospel with the warmth of family vocals creates an uplifting experience that connects you directly to the spiritual roots running through New Orleans music.'},
  { id: 'b285', name: "Craig Adams & Higher Dimensions of Praise"                 , day: 'd4', stage: 'gospel',     start: '18:05', end: '18:50', yt: 'HpS7fb6-Ous', verified: true , blurb: 'Craig Adams & Higher Dimensions of Praise brings transcendent spiritual energy and contemporary gospel soul to the Gospel Tent, blending powerful vocals with dynamic instrumentation that elevates the traditional New Orleans sacred sound into something that lifts both body and spirit. Jazz Fest devotees return year after year for these authentic moments of joy and communal grace—this is the real deal, where faith meets funkified grooves and the music becomes pure celebration.'},
  { id: 'b286', name: "Kelly Love Jones"                                          , day: 'd4', stage: 'lagniappe',  start: '11:30', end: '12:25', yt: '4ZvKbUA5m1Q', verified: true , blurb: 'Kelly Love Jones brings soulful, groove-laden sounds to the Lagniappe Stage, blending New Orleans funk and R&B with modern swagger and infectious energy that\'ll have you moving through the festival grounds. This is the kind of authentic, feel-good performance that captures what Jazz Fest is all about—raw talent, undeniable charm, and pure good times.'},
  { id: 'b287', name: "Kristin Diable & The City"                                 , day: 'd4', stage: 'lagniappe',  start: '12:45', end: '13:45', yt: 'h2BEaTVSpqU', verified: true , blurb: 'Kristin Diable & The City brings authentic New Orleans soul to the Lagniappe Stage with a sultry blend of R&B, funk, and traditional jazz that celebrates the city\'s rich musical DNA—this is the sound of the streets, the neighborhoods, and the unfiltered heart of NOLA.'},
  { id: 'b288', name: "Paul Sanchez"                                              , day: 'd4', stage: 'lagniappe',  start: '14:05', end: '15:15', yt: 'PG6nKOMn3XQ', verified: true , blurb: 'Paul Sanchez is a New Orleans-born and based American guitarist and a singer-songwriter. Sanchez was a founding member of the New Orleans band Cowboy Mouth. Sanchez was a guitarist and one of the primary singers and songwriters for the band from 1990 to 2006.'},
  { id: 'b289', name: "The New Orleans Klezmer Allstars"                          , day: 'd4', stage: 'lagniappe',  start: '15:40', end: '16:40', yt: 'AMTX4K5ptgM', verified: true , blurb: 'The New Orleans Klezmer All-Stars are entering their 29th year as an active performing ensemble. In these times when folk music has meant rigidly sticking to a cliched format or collecting hackneyed stylistic features, the klezmer all stars have attempted to challenge and stretch boundaries...but without sacrificing the most exciting features of social music; driving rhythms, passion, and clear melodies that are sublime but remain memorable. Using the inspiration of the city where they began, the band has formed a unique approach to traditional melodies and, even more unusual, a way of writing in the style that leads to a sort of Yiddish Impressionism– keeping audiences dancing but cutting to the depths of their cultural imaginations, even where they didn\'t realize they had one. The Klezmer Allstars have grown into their name and are frequently seen with many of New Orleans\' greatest musicians, including: Mean Willie Green, Stanton Moore, Benjamin Ellman, Jonathan Freilich, Joe Cabral, Glenn Hartman, Doug Garrison, Dan Oestreicher, and Aurora Nealand.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41443/festivalartist-12219-artist_image-ca313009-5ca1-49f2-a0a2-5ac055031b53.jpg'},
  { id: 'b290', name: "Leroy Thomas & the Zydeco Roadrunners"                     , day: 'd4', stage: 'lagniappe',  start: '17:00', end: '18:00', yt: 'PkkzreuK6WQ', verified: true , blurb: 'Leroy Thomas & the Zydeco Roadrunners bring incendiary accordion-driven zydeco to the Lagniappe Stage, blending bayou soul with infectious two-step rhythms that\'ll have you dancing through the festival grounds. This is essential New Orleans groove—raw, joyful, and uncompromisingly authentic.'},
  { id: 'b291', name: "Claude Bryant and The Allstars"                            , day: 'd4', stage: 'jamaica',    start: '11:30', end: '12:20', yt: '6pHArPnrBNM', verified: true , blurb: 'Claude Bryant and The Allstars bring Caribbean warmth and New Orleans swagger to the Sandals Jamaica Cultural Pavilion, blending reggae rhythms with soul-deep grooves that\'ll have you moving from first note to last. These cats know how to make a festival crowd feel the island vibes while keeping that authentic NOLA spirit alive.'},
  { id: 'b292', name: "ShowJam Mento Band"                                        , day: 'd4', stage: 'jamaica',    start: '12:45', end: '13:45', yt: 'v6y5Q14l7mU', verified: true , blurb: 'ShowJam Mento Band brings the infectious rhythms and playful spirit of traditional Jamaican mento to Jazz Fest, blending Caribbean storytelling with infectious grooves that\'ll have you moving from the first note. Their warm, vintage-flavored sound is pure joy—perfect for fans seeking that soulful, cross-cultural magic that makes the Fest unforgettable.'},
  { id: 'b293', name: "Topp Brass plays Ska"                                      , day: 'd4', stage: 'jamaica',    start: '14:10', end: '15:10', yt: 'CVyJkKKfRFs', verified: true , blurb: 'Topp Brass brings the infectious energy of Caribbean ska to Jazz Fest with brass-driven rhythms that get bodies moving and spirits soaring—this is dance music with serious musicianship, perfect for anyone seeking joyful, high-octane grooves that blend New Orleans brass tradition with island swagger.'},
  { id: 'b294', name: "BrukOut Sound System ft. Seani B, NESTA, Laa Lee & Izzy Bossy", day: 'd4', stage: 'jamaica',    start: '15:35', end: '16:35', yt: 'Xp-p8FtMILU', verified: true , blurb: 'BrukOut Sound System brings the infectious energy of Jamaica\'s dance-hall and reggae underground to Jazz Fest, with Seani B, NESTA, Laa Lee, and Izzy Bossy delivering bass-heavy riddims and lyrical fire that\'ll have you moving from the first drop. This is Caribbean club culture at its rawest—expect hypnotic grooves, rapid-fire flows, and the kind of communal heat that makes the Sandals Jamaica Cultural Pavilion feel like Kingston after dark.'},
  { id: 'b295', name: "Nomfusi of South Africa"                                   , day: 'd4', stage: 'jamaica',    start: '17:00', end: '18:00', yt: 'MCvbOcdgpzY', verified: true , blurb: 'Nomfusi brings the spiritual soul of South African jazz and roots music to Congo Square, blending traditional rhythms with contemporary grooves that\'ll have you moving from the first note. This is the kind of authentic, genre-defying performance that reminds you why Jazz Fest exists—to celebrate the global language of improvisation, community, and pure musical joy.'},
  { id: 'b296', name: "Renée Gros + Tiago Guy"                                    , day: 'd4', stage: 'rhythm',     start: '12:00', end: '12:50', yt: '7pcKco7oAXA', verified: true , blurb: 'Renée Gros and Tiago Guy blend New Orleans\' deep funk roots with contemporary rhythm experimentation, creating a hypnotic groove that pulls you straight onto the dance floor. Their Rhythmpourium set is pure sonic alchemy—where traditional percussion meets modern production in a sound that feels both ancestral and urgently present.'},
  { id: 'b297', name: "BrukOut Dancehall Experience"                              , day: 'd4', stage: 'rhythm',     start: '13:15', end: '14:00', yt: 'ZGi53afgCf8', verified: true , blurb: 'BrukOut Dancehall Experience brings high-octane Caribbean heat and infectious riddim to the Rhythmpourium Tent, fusing Jamaica\'s most electrifying dancehall culture with New Orleans\' own bounce and brass traditions. This is pure movement, pure energy—the kind of performance that turns festival grounds into a spontaneous street party, where every beat demands your body respond.'},
  { id: 'b298', name: "Gitkin"                                                    , day: 'd4', stage: 'rhythm',     start: '14:25', end: '15:10', yt: 'nt9Ny1IR1zA', verified: true , blurb: 'Gitkin’s music exists somewhere between primal, rootsy memory and distant exotic yearning — A dusty bordertown where the familiar blends imperceptibly into the enchantingly foreign.'},
  { id: 'b299', name: "Kristy Lee"                                                , day: 'd4', stage: 'rhythm',     start: '15:35', end: '16:25', yt: 'LtYmLa5diZA', verified: true , blurb: 'No relation to kristy lee cook! A singer from Alabama, by the time she reached 18, she landed her first album nationwide, to be sold exclusively with "Target Stores" across the states. Kristy Lee\'s first album gave her an early jump on, what is now, a career.'},
  { id: 'b300', name: "Jamaica Vibes: DJ T-Roy"                                   , day: 'd4', stage: 'rhythm',     start: '16:50', end: '17:30', yt: 'qunEBJNUWcY', verified: true , blurb: 'DJ T-Roy brings pure Caribbean heat to the Rhythmpourium Tent, blending reggae, dancehall, and island funk into a infectious groove that transforms every set into a spontaneous celebration. His sound is the sonic embodiment of Jamaica\'s rhythm DNA filtered through New Orleans\' party spirit—expect heavy bass, riddim mastery, and the kind of infectious energy that has the whole tent moving as one.'},
  { id: 'b301', name: "Glenn Hartman and the Earthtones"                          , day: 'd4', stage: 'children',   start: '11:30', end: '12:15', yt: 'KBcYympmVlk', verified: true , blurb: 'Glenn Hartman and The Earthtones are a family friendly, crazy fun band that takes the audience on a musical world tour. With the help of professional dancers, this eclectic band will have everyone in the audience participating in the show, and learning about world culture and human expression. The Earthtones have been performing at schools, festivals and libraries for more than 25 years. With Glenn Hartman - accordion, Washboard Chaz – Washboard, Jimbo Walsh – bass and Riley Hartman – percussion.'},
  { id: 'b302', name: "New Orleans Dance Collective"                              , day: 'd4', stage: 'children',   start: '12:40', end: '13:25', yt: 'c5m0C2FJ0NE', verified: true , blurb: 'New Orleans Dance Collective actively links dance and social work and seeks to address the overwhelming need for positive, esteem-building dance activities for inner-city at-risk youth and is a registered a registered non-profit corporation with the Louisiana Secretary of State and has a 501(c)(3) tax exempt status with the IRS. NODC\'s mission is to celebrate community and diversity by providing dance program for inner-city at-risk youth utilizing group therapy techniques as a means of intervention and to positively affect behavior through dance within a group setting.'},
  { id: 'b303', name: "The Roots of Music Marching Crusaders 2:10 - 2:25 pm The Woodlawn Lion Dance Team", day: 'd4', stage: 'children',   start: '13:25', end: '14:40' , blurb: 'Watch the Roots of Music Marching Crusaders 2 bring high-energy brass and percussion mastery to the Ochsner Children\'s Tent, where young dancers from the Woodlawn Lion Dance Team add vibrant movement to this New Orleans tradition. It\'s the perfect blend of second line swagger and community joy that makes Jazz Fest magic for families and festival fans of all ages.'},
  { id: 'b304', name: "New Voices New Orleans (NVNO)"                             , day: 'd4', stage: 'children',   start: '14:40', end: '15:25', yt: 't1v6ET57tsk', verified: true , blurb: 'New Voices New Orleans brings infectious, family-friendly energy to the Ochsner Children\'s Tent with vibrant New Orleans rhythms that blend traditional jazz, funk, and contemporary sounds—perfect for introducing the next generation to the city\'s rich musical heritage while keeping adults grooving too.'},
  { id: 'b305', name: "The Woodlawn Lion Dance Team"                              , day: 'd4', stage: 'children',   start: '15:25', end: '16:00', yt: 'PSJmNCtj_FE', verified: true , blurb: 'The Woodlawn Lion Dance Team brings infectious, high-energy percussion and movement that celebrates New Orleans\' rich Black cultural traditions, turning the Ochsner Children\'s Tent into a celebration of community pride and rhythmic joy. Their dynamic blend of drums, chants, and choreography creates pure festival magic that gets kids and families moving while honoring the second line spirit that runs through the city\'s veins.'},
  { id: 'b306', name: "Trombone Shorty Academy featuring Primera Linea of Cuba"   , day: 'd4', stage: 'children',   start: '16:00', end: '17:00', yt: '1K0QN8xy1kM', verified: true , blurb: 'Trombone Shorty Academy brings the infectious, joy-filled energy of New Orleans brass tradition colliding with the vibrant son and rumba rhythms of Cuba\'s Primera Linea, creating a multigenerational celebration of Caribbean and American musical kinship that\'ll have kids and families moving from the first note.'},
  { id: 'b307', name: "Rockin’ Dopsie, Jr. Interviewer: Herman Fuselier"          , day: 'd4', stage: 'miner',      start: '12:00', end: '12:45', yt: 'n-05XilCVbw', verified: true , blurb: 'Rockin\' Dopsie Jr. carries forward a Louisiana legacy of swamp pop and zydeco fire, bringing that irresistible accordion-driven groove and dancehall energy that gets the whole crowd moving—this is the sound that built New Orleans\' backyard parties and honky-tonks, pure joy in musical form.'},
  { id: 'b308', name: "Catherine Russell Interviewer: Nick Spitzer"               , day: 'd4', stage: 'miner',      start: '13:00', end: '13:45', yt: 'ceJCGboivPk', verified: true , blurb: 'Catherine Russell brings a masterful command of American vocal tradition—from jazz standards to blues and folk—with the kind of authentic storytelling that makes the Allison Miner stage a gathering place for purists and seekers alike. Her collaboration with musicologist and radio legend Nick Spitzer creates an intimate, conversational experience that celebrates the deep roots and living legacy of New Orleans music culture.'},
  { id: 'b309', name: "Glenn Hartman, Jonathan Freilich & Ben Ellman of New Orleans Klezmer Allstars Interviewer: Peggy Scott Laborde", day: 'd4', stage: 'miner',      start: '14:00', end: '14:45', yt: 'zLjGBw6JkuM', verified: true , blurb: 'Klezmer Allstars bring the joyous, soulful traditions of Jewish instrumental music to life with virtuosic energy and deep New Orleans roots, blending clarinet-led melodies with infectious rhythms that celebrate cultural heritage and communal spirit. This is music that moves bodies and souls alike—perfect for Jazz Fest explorers seeking the festival\'s most eclectic, life-affirming sounds.', members: 'Glenn Hartman, Jonathan Freilich, Ben Ellman'},
  { id: 'b310', name: "River Eckert & Jake Eckert Interviewer: Tim Miller"        , day: 'd4', stage: 'miner',      start: '15:00', end: '15:45', yt: '0o8e3iMmooY', verified: true , blurb: 'River Eckert & Jake Eckert bring soulful, roots-deep Americana and folk traditions to life with the kind of intimate authenticity that defines the Jazz Fest spirit—expect fingerpicked guitars, weathered harmonies, and the timeless storytelling that keeps New Orleans\' musical heritage alive and breathing.'},
  { id: 'b311', name: "Roger Lewis Interviewer: David Kunian"                     , day: 'd4', stage: 'miner',      start: '16:00', end: '16:45', yt: 'Ftz-SLQl7r8', verified: true , blurb: 'Roger Lewis brings the soul and storytelling tradition of New Orleans brass culture to the Allison Miner stage, with David Kunian conducting intimate conversations that reveal the heart behind the city\'s most iconic sounds. This is heritage music at its finest—where legends share their craft and Jazz Fest fans get to witness the living history that built American jazz.'},

  // ───────── Thu Apr 30 (d5) ─────────
  { id: 'b312', name: "Sons of Jazz Brass Band"                                   , day: 'd5', stage: 'festival',   start: '11:15', end: '11:45', yt: 'Qa_TBzqQDYE', verified: true , blurb: 'Sons of Jazz Brass Band brings the Second Line spirit straight from the streets of New Orleans, blending traditional parade brass with contemporary funk and soul grooves that\'ll have the Festival Stage crowd moving. Their high-energy horns and infectious rhythms capture everything Jazz Fest celebrates—the living, breathing heartbeat of New Orleans music culture.'},
  { id: 'b313', name: "The Iceman Special"                                        , day: 'd5', stage: 'festival',   start: '12:05', end: '13:00', yt: 'SuwWralya2I', verified: true , blurb: 'The Iceman Special brings smooth, cool-running R&B and funk that cuts through the New Orleans heat with precision and soul—a groove-heavy experience that proves the city\'s tradition of funky sophistication is alive and thriving on the Festival Stage.'},
  { id: 'b314', name: "Zigaboo Modeliste Funk Revue"                              , day: 'd5', stage: 'festival',   start: '13:20', end: '14:20', yt: 'aQ3LRg9JOGE', verified: true , blurb: 'Zigaboo Modeliste Funk Revue brings the deep, percussive groove that only New Orleans can produce—a masterclass in second-line swagger and funky precision that\'ll have you moving before the first beat drops. This is essential local flavor served straight from the birthplace of funk, where every rhythm section lock-in feels like a conversation between the ancestors and the dance floor.'},
  { id: 'b315', name: "Lettuce"                                                   , day: 'd5', stage: 'festival',   start: '14:45', end: '16:00', yt: 'dw5FnUWRMLc', verified: true , blurb: 'Lettuce is an American funk band formed in 1992. Adam “Shmeeans” Smirnoff: guitar Erick “Jesus” Coomes: bass Ryan Zoidis: alto, baritone and tenor sax, Korg X-911 Eric “Benny” Bloom: trumpet, horns Nigel Hall: vocals, Hammond B-3, Rhodes, clavinet, keyboards Adam Deitch: drums, percussion'},
  { id: 'b316', name: "Widespread Panic"                                          , day: 'd5', stage: 'festival',   start: '16:30', end: '19:00', yt: 'f57QlAlMtyw', verified: true , blurb: 'Widespread Panic is a rock band from Athens, Georgia, United States in 1986, originally formed by John Bell and the late Michael Houser.'},
  { id: 'b317', name: "SOUL Brass Band"                                           , day: 'd5', stage: 'shell',      start: '11:20', end: '12:20', yt: 'XStD4rudYWQ', verified: true , blurb: 'Soul Brass Band is exactly what it needs to be: a great New Orleans Brass Band steeped in tradition that also plays the perfect party. Day after day in New Orleans, this all-star lineup is called upon for its top-flight traditional Brass Band repertoire and Second line Parades; and then night after night, they’re called upon again for frontman Derrick Freeman’s signature brass band infusion of classic Soul.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41469/festivalartist-12292-artist_image-009ff465-4489-4f30-ad4f-8964fcb7ec1b.jpg'},
  { id: 'b318', name: "Hans Williams"                                             , day: 'd5', stage: 'shell',      start: '12:45', end: '13:50', yt: '-OycwpEkf7w', verified: true , blurb: 'Hans Williams is a 21-year-old independent singer-songwriter from Norwich, Vermont. First releasing music in third grade when he would hand out CDs after school, Hans fell in love with songwriting as a means of expression.'},
  { id: 'b319', name: "Terrance Simien and the Zydeco Experience"                 , day: 'd5', stage: 'shell',      start: '14:15', end: '15:20', yt: 'GwAcmxAMbEI', verified: true , blurb: 'As a zydeco master, Terrance Simien is one of Louisiana\'s most respected Creole cultural ambassadors and his musical journey continues on its own unique course with his eclectic fusion of first class originals and diverse covers, all the while making them seem refreshingly new with his unlikely arra…'},
  { id: 'b320', name: "Sweet Crude"                                               , day: 'd5', stage: 'shell',      start: '15:45', end: '17:00', yt: 'BYFmM6aSVT0', verified: true , blurb: 'There are six musicians in the raucous pop ensemble Sweet Crude, but their ultimate goal is duality. The lyrics are bilingual, with French and English lyrics sometimes sharing space in one song. As a gang of bodies in motion onstage, their clamor of percussion and shouts whips up the dance floor in contagious physical joy – but the tunes lend themselves as well to deep listening, revealing complex layers of both craft and content. Of course, there’s the band name itself: a reference to the petroleum export of Sweet Crude’s home state of Louisiana, an unintentionally poetic linking of two concepts operating in seeming opposition. And like the title of Sweet Crude’s latest album – Officiel//Artificiel - when everything comes together, the product is more than the sum of the parts. The choice to write and sing in two languages came as members were still learning French - specifically, Louisiana French, the regional vernacular that was once commonly spoken in the Southern part of the state by descendants of antebellum immigrants. A push to “Americanize” the area’s diverse culture after World War One had led to strict Englishonly rules in public schools. Louisianians of a certain age recall facing ridicule and even physical punishment for being caught speaking French at school. Thus, natural usage declined. Louisiana natives like multi-instrumentalist brothers Sam and Jack Craft or singer-songwriter Alexis Marceaux, who recall older relatives speaking French at home might have grown up naturally bilingual but for that. In making music together, they reimagine – and then make real – a world in which those ways of speaking survived and naturally evolved. What if there had been no prohibition, and young musicians who listened to Radiohead, Talking Heads and Arcade Fire were also fluent in Louisiana French? This opens up a world of possibilities. There’s room for Afrobeat-inflected drums, marching-band parade honk and rumble, a flirtation with Cajun tradition (via the Balfa Brothers’ classic drinking tune “Parlez-Nous à Boire,” recorded on their 2013 debut EP Super Vilaine and featured in FX’s American Horror Story) but funneled through New Orleans bounce. To the band, the sound of language itself is an instrument in its own right, one more tool in the creative arsenal. Hard consonants and smooth sibilances, as the band chooses which language best expresses a thought, work in a team alongside kick drums and violins. Sweet Crude’s first LP, 2017’s Créatures, which Consequence of Sound called “glorious” and “stunning,” continued down that road of freewheeling experimentation - a buoyant, liberated sense of why not. Officiel//Artificiel is the work of a band that’s been at work together for seven years, with some shifting membership and a lot of evolving skill, feelings and ideas. Trust and comfort born of such a long, dynamic relationship emanates off the stage during Sweet Crude’s explosive live shows, and more subtly on wax: it’s an assurance that this team can captain you letting feelings take over bodily on the dance floor through an infectious beat, or down the subtler journey of losing yourself emotionally in a record. “It’s never one sound, and there’s always all of us in every song,” Jack Craft said. “And every song feels like it’s been some collaborative splatter painting.” Officiel//Artificiel was produced in New Orleans by Sonny DiPerri, a veteran of projects by Animal Collective, Portugal. The Man, Trent Reznor, My Bloody Valentine and DIIV, among others. In the studio, he fueled Sweet Crude’s push to innovate, weaving rougher and rawer found sounds and quirky experiments into their signature sweeping synths and pop ecstasies. These new frontiers are interior, as well, making for both lushly cinematic songs like “Skin,” a dreamy but intense self-investigation showcasing the emotional range of Marceaux’s vocals, or “The Purge,” a taut, snappy meditation on what gets let go – objects and ideas alike - as we grow. “Rougarou,” named for the mythical Louisiana werewolf-like cryptid, is a glossy, simmering slice of electro-pop that considers the monstrous nature of other people. “The whole record is about trying to find your authentic self,” said Alexis Marceaux. “Stripping yourself down, and realizing what other people and society tell you to be, and what you actually are. And each song tells that story in its own little way.” “I always come back to vulnerability being the key emotion in all of this,” said keyboardist Skyler Stroup. “Going through any kind of transformation, you have to be vulnerable. That’s the most powerful to me. Being that naked to the world is terrifying, and you either run away from it or you persist through it.”', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41492/festivalartist-12356-artist_image-06e6eaf1-c381-4af8-a455-8b3af6540ea0.jpg'},
  { id: 'b321', name: "Lake Street Dive"                                          , day: 'd5', stage: 'shell',      start: '17:30', end: '19:00', yt: '6EPwRdVg5Ug', verified: true , blurb: 'Lake Street Dive are an American band founded in 2004 in Boston, Massachusetts. The band\'s original members are Rachael Price (lead vocals), Mike "McDuck" Olson (trumpet, guitar), Bridget Kearney (upright bass), and Mike Calabrese (drums).'},
  { id: 'b322', name: "Higher Heights Reggae"                                     , day: 'd5', stage: 'congo',      start: '11:20', end: '12:20', yt: 'IPb6f60Kk14', verified: true , blurb: 'Higher Heights Reggae brings rootsy, spiritually grounded reggae vibes to Congo Square, where their conscious lyrics and hypnotic rhythms echo the stage\'s legacy of cultural resistance and unity. With infectious grooves that blend traditional roots reggae with contemporary Caribbean consciousness, they\'re the perfect soundtrack for Jazz Fest explorers seeking positive vibrations and communal good feeling.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41361/festivalartist-12009-artist_image-08c5e345-209a-49e8-a75a-2c6b77ab8e46.jpg'},
  { id: 'b323', name: "Tonya Boyd-Cannon"                                         , day: 'd5', stage: 'congo',      start: '12:45', end: '13:50', yt: 'A1Yz5qGKRJ8', verified: true , blurb: 'Mississippi born; Louisiana raised, Tonya Boyd-Cannon is a "witty and dope soul artist." Tonya’s fairly-rare contralto voice, almost identical to that of a countertenor, pushes the envelope on every song she sings! Boyd-Cannon’s delivery is sharp yet soulful, contemporary and authentic. Boyd-Cannon’s combination of creative vocals and instrumentation creates a fused-melodic kaleidoscope. Boyd-Cannon got her professional start as a background vocalist for Jean Knight, best known for her 1970’s hit single, “Mr. Big Stuff". Boyd-Cannon took her career to the next level by competing in talent competitions. Her hard work paid off; making her a "Top 20" finalist on NBC’s Emmy-Award winning show, “The Voice; where she was on Adam Levine’s team. Tonya\'s passion for her music has allowed her to tour the US, Europe and South America. Boyd-Cannon incessantly states, “I love performing and connecting with people! I hope my fans enjoy my music and the journey we are embarking on together.” Boyd-Cannon is currently working on her third album, scheduled to release summer 2020.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41381/festivalartist-12061-artist_image-bdbfc69b-93ca-4eda-bccf-e122ee2c9d03.jpg'},
  { id: 'b324', name: "Batiste Brothers Band"                                     , day: 'd5', stage: 'congo',      start: '14:20', end: '15:30', yt: 'BRk5afjxXuI', verified: true , blurb: 'The Batiste Brothers Band brings the deep, ancestral groove of New Orleans funk and soul to Congo Square, where their family legacy of musicianship channels generations of the city\'s spiritual and rhythmic traditions into electrifying, dance-floor energy that honors both the ancestors and the present moment.'},
  { id: 'b325', name: "New Breed Brass Band"                                      , day: 'd5', stage: 'congo',      start: '15:55', end: '17:05', yt: 'Y2RJoRKYWdc', verified: true , blurb: 'New Breed Brass Band lives and breathes the culture of New Orleans, infusing funk, rock, jazz, and hip-hop into a custom-made enhancement of second-line brass band tradition. “That’s what we came up under,” says snare-drummer Jenard Andrews of second line bands like the ReBirth, Dirty Dozen and Lil’ Rascals Brass Bands. “Now we’re trying to take that sound and bring in some new stuff and expand it. We bring outside influences like Earth Wind & Fire and Brass Construction, trying to interpret a different song for every genre, and make it all our own sound.” With a founding core of five New Orleans natives, New Breed Brass Band made its street debut as a nine-man unit in November 2013 at the Nine Times Second Line. Since then, they have showcased their originality opening for such diverse bands as The Fray, Red Baraat, Dr. John, The Waterboys, and Trombone Shorty & Orleans Avenue, as well as competing in the Red Bull Street Kings brass band competition in 2013. Most of the members have been playing music since they were toddlers and count such New Orleans legends as James “12” Andrews, Troy “Trombone Shorty” Andrews, Topsy Chapman, Karl Leblanc, and Bruce “Sun-pie” Barnes as family members. Honing their childhood experiences playing music with their families, and on through high school marching bands and concert ensembles, the nine members of New Breed are united to one cause: rocking each show and entertaining audiences to the maximum degree possible. The band’s strong desire is to be the next heavyweight contender among internationally-known New Orleans brass bands. Whether performing in their hometown or on the road, New Breed will forever bring the vibe of the New Orleans second-line with them. “We can’t wait,” Andrews says of bringing the New Breed sound to stages and festivals around the world. “It’s a new breed of music that we’ll be bringing to our culture, and we hope to create a new sound for our city in the process.”'},
  { id: 'b326', name: "Leela James"                                               , day: 'd5', stage: 'congo',      start: '17:35', end: '18:55', yt: 'CjOIQnCbDU0', verified: true , blurb: 'Leela James is a Los Angeles native and soul singer who cites James Brown, Roberta Flack, and Gladys Knight, among others, as influences. Her deep, rich and gritty vocals easily draw comparisons to Aretha Franklin and Gladys Knight.'},
  { id: 'b327', name: "Delgado Community College Jazz Band"                       , day: 'd5', stage: 'jazz',       start: '11:15', end: '12:00', yt: '3Z5gTMOwHIs', verified: true , blurb: 'Delgado Community College Jazz Band brings the authentic swing and precision of New Orleans\' finest educational program, delivering straight-ahead jazz standards with the energy and tight musicianship that keeps the WWOZ tent packed with serious listeners and newcomers alike. Their blend of classic bebop vocabulary and traditional New Orleans grooves proves why this band remains a festival favorite—pure, unadorned jazz played by musicians who live it.'},
  { id: 'b328', name: "Pat Casey and the New Sound"                               , day: 'd5', stage: 'jazz',       start: '12:20', end: '13:15', yt: 'V8sNbJ-bRq4', verified: true , blurb: 'Pat Casey and the New Sound bring a contemporary twist to New Orleans\' deep jazz traditions, blending modern sophistication with the raw, improvisational spirit that makes the Jazz Tent the festival\'s creative heart. Their fresh arrangements and fearless interplay will resonate with anyone seeking the next evolution of the city\'s sound.'},
  { id: 'b329', name: "Steve Masakowski Family & Friends"                         , day: 'd5', stage: 'jazz',       start: '13:35', end: '14:35', yt: 'LUc6mBfzz-c', verified: true , blurb: 'Steve Masakowski and his circle deliver sophisticated, groove-rooted modern jazz that bends between straight-ahead bebop and contemporary fusion, anchored by Masakowski\'s fluid guitar work and the warm interplay of longtime New Orleans collaborators. If you crave inventive soloing, tight ensemble work, and the kind of musical conversation that only happens when friends who\'ve played together for decades hit the stage, this is essential WWOZ Tent listening.'},
  { id: 'b330', name: "Ricky Sebastian"                                           , day: 'd5', stage: 'jazz',       start: '14:55', end: '15:55', yt: 'EbL4byFx7uw', verified: true , blurb: 'Ricky Sebastian brings that deep, soulful New Orleans tradition to the WWOZ Jazz Tent with a sound rooted in classic jazz sophistication and contemporary groove—expect intimate vocals, rich instrumentation, and the kind of authenticity that reminds you why this music was born right here.'},
  { id: 'b331', name: "Isaiah Collier “The World Is On Fire”!"                    , day: 'd5', stage: 'jazz',       start: '16:20', end: '17:20', yt: 'QKzMLp3NxzM', verified: true , blurb: 'Isaiah Collier & The World Is On Fire brings spiritual urgency and modern soul to the Jazz Tent, blending New Orleans tradition with contemporary groove that hits like a sermon and swings like a prophecy. This is jazz that moves bodies and opens hearts—exactly what Jazz Fest was built for.'},
  { id: 'b332', name: "Fred Wesley and his New JBs"                               , day: 'd5', stage: 'jazz',       start: '17:45', end: '19:00', yt: 'gs6SB6ccoNc', verified: true , blurb: 'Fred Wesley and his New JBs bring the deep funk-jazz fusion that defines New Orleans\' most adventurous spirit—slick, soulful, and endlessly groovy, with Wesley\'s legendary trombone leading a tight ensemble through the kind of sophisticated dance-floor energy that makes Jazz Fest devotees keep coming back.'},
  { id: 'b333', name: "Charmaine Neville Band"                                    , day: 'd5', stage: 'blues',      start: '11:20', end: '12:20', yt: 'K1kc1OUBu70', verified: true , blurb: 'Charmaine Neville Band brings soulful, gutsy New Orleans blues with a family legacy of musical excellence, delivering the kind of authentic, foot-stomping grooves that make the Blues Tent the heart of Jazz Fest. Their tight interplay and Neville\'s commanding presence cut straight to the emotional core of blues tradition while keeping the energy electric and irresistible.'},
  { id: 'b334', name: "John \"Papa\" Gros"                                        , day: 'd5', stage: 'blues',      start: '12:45', end: '13:50', yt: 'pgbj18RusHs', verified: true , blurb: 'Papa Gros brings authentic New Orleans soul to the Blues Tent with his gritty harmonica work and weathered vocals, delivering the kind of deep, soulful blues that connects directly to the city\'s roots and keeps crowds swaying late into the evening.'},
  { id: 'b335', name: "Johnny Sansone"                                            , day: 'd5', stage: 'blues',      start: '14:15', end: '15:15', yt: 'AUD_BX8BiWs', verified: true , blurb: 'Johnny Sansone was born in Orange, New Jersey. His father was a schoolteacher, and played saxophone. "I was about eight years old when I started taking saxophone lessons and understanding music," he says.'},
  { id: 'b336', name: "Grace Bowers"                                              , day: 'd5', stage: 'blues',      start: '15:45', end: '17:00', yt: 'qnuSUfI-g3I', verified: true , blurb: 'Grace Bowers brings raw, gritty soul to the Blues Tent with a voice that cuts through the noise like a knife through silk—modern blues with deep roots, perfect for anyone seeking authenticity and edge at Jazz Fest.'},
  { id: 'b337', name: "Mike Zito"                                                 , day: 'd5', stage: 'blues',      start: '17:30', end: '19:00', yt: 'e6kzMKZo9sM', verified: true , blurb: 'Growing up in St. Louis, Missouri, Zito was immersed in the gritty sounds of the south side that would unknowingly become the groundwork of his future in music. Like the legends before him, music has coursed through his veins from the early age of five, when he began singing and performing.'},
  { id: 'b338', name: "The New Orleans Rug Cutters"                               , day: 'd5', stage: 'economy',    start: '11:20', end: '12:15', yt: 'prO8rCk-zfo', verified: true , blurb: 'The New Orleans Rug Cutters bring hard-swinging traditional jazz and blues to Economy Hall with the infectious energy of a second-line parade—their tight ensemble work and rollicking rhythms will have you dancing in the grass and ready to cut a rug yourself.'},
  { id: 'b339', name: "Clive Wilson's New Orleans Serenaders"                     , day: 'd5', stage: 'economy',    start: '12:35', end: '13:30', yt: 'w73YIh42kTM', verified: true , blurb: 'The New Orleans Serenaders performs for Jazz Festivals and concerts. They revisit the repertoire associated with famous jazz pioneers Kid Ory, Louis Armstrong and others, bringing to life musical selections from all phases of their careers such as Ory\'s Creole Trombone, Cornet Chop Suey, Potato Head Blues, West End Blues, Maple Leaf Rag, Gatemouth, Down Home Rag, Shim-Me-Sha-Wabble, Black Snake Blues, and many more. Gathered together by Clive Wilson, the members of the Serenaders have a long history of musical friendships and associations going back nearly four decades. Playing with one another many times over the years in jam sessions, concerts, recording sessions, parades and even New Orleans funerals, they have a profound sense of a shared experience and a common love of the New Orleans style music. Most of them spent considerable time during the 1960s and 1970s, their musically formative years, listening to, studying with, and playing with, the living legends of New Orleans jazz. The Serenaders have played in concerts and jazz festivals on both sides of the Atlantic in recent years, and have been received with critical acclaim.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41354/festivalartist-11995-artist_image-2a0c7537-4026-48cd-a518-c6fb8ebfd1b1.jpg'},
  { id: 'b340', name: "Hot Club of New Orleans"                                   , day: 'd5', stage: 'economy',    start: '13:50', end: '14:45', yt: '8PwLgMG-QC4', verified: true , blurb: 'The Hot Club of New Orleans swings hard with that timeless Dixieland spirit and gypsy jazz flair that makes Economy Hall the beating heart of the fest—these virtuosos channel New Orleans\' golden age through modern ears, delivering infectious grooves that\'ll have you dancing in the brass-soaked afternoon heat.'},
  { id: 'b341', name: "Judith Owen & The Callers"                                 , day: 'd5', stage: 'economy',    start: '15:10', end: '16:10', yt: '4U-8AR66K8M', verified: true , blurb: 'Judith Owen & The Callers deliver swaggering, soulful Americana with jazz-inflected grooves and narrative-driven songwriting that channels the spirit of New Orleans\' storied songwriting tradition. Their intimate, conversational style and infectious rhythm section make them a perfect fit for Economy Hall\'s legendary venue—where authenticity and artistry converge.'},
  { id: 'b342', name: "The Palmetto Bug Stompers"                                 , day: 'd5', stage: 'economy',    start: '16:30', end: '17:25', yt: '_UFwSlNSZ4s', verified: true , blurb: 'The Palmetto Bug Stompers are one of New Orleans finest purveyors of traditional and New Orleans Jazz. With a wide and varied background of musical influences, they get the crowd dancing all night at such venues as dba, where they have a weekly gig. Band members include Washboard Chaz on washboard and vocals, Robert Snow on acoustic bass, John Rodli on guitar and vocals, Charlie Halloran on trombone, Kevin Louis on trumpet and vocals and Bruce Brackman on clarinet. The band has performed at New Orleans Jazz and Heritage Festival, French Quarter Festival and Lincoln Center Summer Swing as well as at various functions for the Ultimate Lindy Hoppers organization. They have four recordings, 2004\'s Palmetto Bug Stompers, 2006\'s Ol’ New Orleans Home, 2009\'s Live at dba and 2013\'s Sugar Blues. Each member has performed with some of New Orleans finest jazz bands, both in the U.S. and around the world. The Bugs have a weekly show at dba on Sundays since 2004. Put on your dancing shoes and come on down!', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41506/festivalartist-12384-artist_image-e01070b7-36bc-4059-8969-ab1c8795033b.jpg'},
  { id: 'b343', name: "Ingrid Lucia"                                              , day: 'd5', stage: 'economy',    start: '17:45', end: '18:40', yt: 'XdRx-q_3ctM', verified: true , blurb: 'Born into a family of street musicians, Ingrid Lucia sang in her family band, the Flying Neutrinos, from the age of eight, so she has music coursing deep in her soul. This sassy New Orleans native has a voice that\'s prompted thousands of comparisons to Billie Holiday.'},
  { id: 'b344', name: "Ryan Brunet and the Malfecteurs"                           , day: 'd5', stage: 'fais',       start: '11:15', end: '12:05', yt: 'aORTEelmwHA', verified: true , blurb: 'Ryan Brunet and the Malfecteurs bring swamp-fired energy and gritty authenticity to the Fais Do-Do stage, blending traditional New Orleans R&B, funk, and zydeco into a sound that\'s equal parts dance floor and soul. With Brunet\'s commanding presence and his band\'s razor-sharp groove, they\'re the kind of act that makes Jazz Fest feel like a late-night juke joint—raw, infectious, and impossible to stand still through.'},
  { id: 'b345', name: "Cedric Watson et Bijou Créole"                             , day: 'd5', stage: 'fais',       start: '12:25', end: '13:20', yt: 'JygS9kX-kak', verified: true , blurb: 'Cedric Watson et Bijou Créole bring the authentic fire of Creole Louisiana to the Fais Do-Do Stage, blending traditional accordion-driven zydeco with soulful vocals and infectious rhythms that get the whole crowd moving. This is the real deal—the sound of South Louisiana\'s cultural heartbeat, raw and joyful, perfect for anyone seeking genuine roots music and unbreakable grooves.'},
  { id: 'b346', name: "The Iguanas"                                               , day: 'd5', stage: 'fais',       start: '13:40', end: '14:40', yt: 'P-J53zNsBGM', verified: true , blurb: 'What if Americana actually encompassed ALL of North America? You\'d have the Franco-Acadian inflections of Canada, as best exemplified by le accordion, blues and jazz, the only truly indigenous music the US has ever produced, and the lilting grace and fiery passion of the music of Mexico. You\'d also have New Orleans\' premiere distillers of this continental musical mélange, The Iguanas. The members of the Iguanas have (collectively or individually) played or recorded with everyone from Charlie Rich, Alex Chilton, and Willie DeVille to Emmylou Harris, Allen Toussaint, and Pretty Lights. Their two-decade ride has taken them all over the map musically and geographically, yet the inescapable patina of their hometown infuses every note they play. Through eight studio albums, countless tours and Jazz Fest appearances, and a flood that did its best to take their adopted city with it, it\'s a testament to the band\'s endurance that the same four guys that started playing in the early 1990s are still together. Joe Cabral is philosophical about the bands persistence in the face of challenges that would have felled — indeed have felled — lesser bands. “First of all, this is all we know how to do; we’re musicians. But more than that,” he continues, “we respect the power of the band as an entity, and each individual in the band steps up to play his part. When it’s good, that’s really what it’s all about.” Rod Hodges agrees. “I don’t want to get all heady and mystical about this, but it’s not really an outward reward we’re looking for. We all enjoy playing music, we all get along, and finding a group of people who can say that after all this time is a rare thing.'},
  { id: 'b347', name: "Jourdan Thibodeaux et Les Rôdailleurs"                     , day: 'd5', stage: 'fais',       start: '15:00', end: '16:00', yt: 'G4iUvkZgDwk', verified: true , blurb: 'After taking the Louisiana music scene by storm in 2018, Jourdan Thibodeaux et Les Rôdailleurs have developed a reputation for pairing ancient traditions with incomparable energy.'},
  { id: 'b348', name: "Buckwheat Zydeco Jr. and The Legendary Ils Sont Partis Band", day: 'd5', stage: 'fais',       start: '16:20', end: '17:20', yt: 'fjcJxPPwB14', verified: true , blurb: 'Buckwheat Zydeco Jr. brings the swamp-fire energy of authentic Louisiana zydeco to the Fais Do-Do stage, with accordion-driven grooves and infectious rhythms that get the whole crowd moving. This is the sound of New Orleans tradition at its most vital—raw, joyful, and impossibly danceable.'},
  { id: 'b349', name: "Alejandro Escovedo"                                        , day: 'd5', stage: 'fais',       start: '17:50', end: '19:00', yt: 'YxUaLKJ_978', verified: true , blurb: 'Alejandro Escovedo (born January 10, 1951, in San Antonio, Texas) is a Mexican-American singer-songwriter. Escovedo\'s family tree includes former Santana percussionist Pete Escovedo and Pete\'s daughter, Sheila E (also Prince\'s former drummer and later a pop star).'},
  { id: 'b350', name: "Comanche Hunters Mardi Gras Indians"                       , day: 'd5', stage: 'heritage',   start: '11:25', end: '12:05', yt: 'mWC2sNwvSU8', verified: true , blurb: 'The Comanche Hunters bring the electric soul of New Orleans street traditions to the stage—a fierce blend of funk, brass, and cultural pride that transforms Mardi Gras Indian culture into a high-octane celebration of rhythm and resilience. Jazz Fest devotees will feel the raw energy, intricate percussion work, and that unmistakable New Orleans sound that makes this city\'s musical heritage impossible to resist.'},
  { id: 'b351', name: "Forgotten Souls"                                           , day: 'd5', stage: 'heritage',   start: '12:25', end: '13:25', yt: '1hMF8c9bfgI', verified: true , blurb: 'Country of origin: Poland Location: Cracow Status: Active Formed in: 1998 Genre: Gothic/Doom/Death Metal Current label: Nija Art Years active: 1998-present Members:  Mateusz Zachorowski	 Bass See also: Dementia Piotr Wójcik: Drums See also: ex-Delight Krzysztof Wójcik: Guitars Paweł Grobler: Keyboar…'},
  { id: 'b352', name: "Jesse Royal"                                               , day: 'd5', stage: 'heritage',   start: '13:50', end: '14:50', yt: 'FET__7Z89qY', verified: true , blurb: 'Jesse Royal (Jesse David Leroi Grey, born April 29, 1989) enjoyed his early years in the hills of Maroon Town and the District of Orange in St. James before moving in the late 90’s with his mother and brother to join his father in Kingston, Jamaica.'},
  { id: 'b353', name: "Sons of Jazz Brass Band"                                   , day: 'd5', stage: 'heritage',   start: '15:10', end: '16:10', yt: 'Qa_TBzqQDYE', verified: true , blurb: 'Sons of Jazz Brass Band brings the Second Line spirit straight from the streets of New Orleans, blending traditional parade brass with contemporary funk and soul grooves that\'ll have the Festival Stage crowd moving. Their high-energy horns and infectious rhythms capture everything Jazz Fest celebrates—the living, breathing heartbeat of New Orleans music culture.'},
  { id: 'b354', name: "Frank Waln"                                                , day: 'd5', stage: 'heritage',   start: '16:30', end: '17:30', yt: 'vhDj-n3kSg4', verified: true , blurb: 'Frank Waln is a Sicangu Lakota hip hop artist originally from The Rosebud Indian Reservation, South Dakota. Currently he resides in Chicago, Illinois.'},
  { id: 'b355', name: "Flagboy Giz"                                               , day: 'd5', stage: 'heritage',   start: '17:50', end: '18:35', yt: '7u9vWG7IL0Q', verified: true , blurb: 'Flagboy Giz brings second-line swagger and deep funk grooves to the Jazz & Heritage Stage, blending New Orleans brass traditions with modern hip-hop energy and infectious rhythms that\'ll have you moving through the festival grounds. This is the sound of the city\'s streets transformed into pure celebration—raw, joyful, and unmistakably NOLA.'},
  { id: 'b356', name: "Academy of Our Lady School Choir"                          , day: 'd5', stage: 'gospel',     start: '11:20', end: '12:05', yt: 'OmxZiaBU-lU', verified: true , blurb: 'Rooted in New Orleans\' rich sacred music tradition, the Academy of Our Lady School Choir brings transcendent harmonies and spirited devotion to the Gospel Tent, their voices soaring with the joyful conviction that makes this city\'s gospel legacy legendary.'},
  { id: 'b357', name: "McDonogh #35 High School Gospel Choir"                     , day: 'd5', stage: 'gospel',     start: '12:20', end: '13:05', yt: 'C4irOaM5I7Q', verified: true , blurb: 'McDonogh #35 High School Gospel Choir brings pure, soaring voices and deep spiritual energy to the Gospel Tent, delivering the kind of transcendent harmonies that make Jazz Fest audiences rise to their feet. These young New Orleans vocalists channel generations of tradition through powerful arrangements that blend classic gospel with contemporary soul, creating an unforgettable celebration of faith and community.'},
  { id: 'b358', name: "Knights of Praise from St. Augustine Campus Ministry"      , day: 'd5', stage: 'gospel',     start: '13:20', end: '14:05', yt: 'RbCVPkzE-WE', verified: true , blurb: 'Knights of Praise from St. Augustine Campus Ministry bring jubilant, spirited vocals and tight harmonies that celebrate faith through infectious New Orleans gospel traditions—their powerful blend of contemporary and classic spiritual sounds will have the entire Gospel Tent moving in unified joy.'},
  { id: 'b359', name: "The Showers"                                               , day: 'd5', stage: 'gospel',     start: '14:20', end: '15:10', yt: '6Z2-y4gEcyo', verified: true , blurb: 'The Showers bring a radiant, contemporary gospel sound to the Gospel Tent, blending soulful vocals with modern production that feels both deeply rooted and refreshingly alive. Their uplifting harmonies and infectious energy capture the spiritual heart of New Orleans while connecting with the next generation of festival-goers seeking authentic joy and communion.'},
  { id: 'b360', name: "Paul Porter and The Christianaires"                        , day: 'd5', stage: 'gospel',     start: '15:30', end: '16:35', yt: 'voLQ1-s5b30', verified: true , blurb: 'Paul Porter and The Christianaires deliver soul-stirring gospel with the warmth and rhythmic vitality that defines New Orleans\' spiritual music tradition, blending timeless hymns with infectious contemporary grooves that\'ll have the whole tent on their feet. Jazz Fest devotees flock to the Gospel Tent for exactly this kind of authentic, joyful witness—raw vocals, tight harmonies, and that undeniable connection between faith and funk that only happens in the Crescent City.'},
  { id: 'b361', name: "Nu Nation Choir"                                           , day: 'd5', stage: 'gospel',     start: '16:50', end: '17:40', yt: 'SW9BZYjQOq0', verified: true , blurb: 'Nu Nation Choir brings contemporary spiritual fire to the Gospel Tent with soaring harmonies and modern production that honors tradition while pushing it forward—a joyful, high-energy celebration of faith that\'ll have you on your feet. Their infectious blend of modern gospel, soul, and New Orleans soul-deep grooves proves that sacred music can be both deeply rooted and boldly innovative.'},
  { id: 'b362', name: "Donnell Russell"                                           , day: 'd5', stage: 'gospel',     start: '17:55', end: '18:40', yt: 'i9CrGVcsr5o', verified: true , blurb: 'Donnell Russell brings soul-deep vocal power and spiritual authenticity to the Gospel Tent, delivering the kind of transcendent performances that remind you why New Orleans remains the heartbeat of American sacred music. His commanding presence and rich, emotionally textured voice connect generations of Jazz Fest pilgrims through timeless gospel traditions infused with contemporary heart.'},
  { id: 'b363', name: "OperaCréole"                                               , day: 'd5', stage: 'lagniappe',  start: '11:30', end: '12:25', yt: 'DNhtF_MrYnw', verified: true , blurb: 'OperaCréole brings operatic grandeur colliding with New Orleans soul, blending classical vocals and French Creole traditions into something that feels both timeless and startlingly alive—a sound that transforms the intimate Lagniappe Stage into a European garden party hijacked by the bayou. Jazz Fest devotees hungry for sophisticated vocal storytelling and cross-cultural fusion will find their spirit soaring here.'},
  { id: 'b364', name: "Helen Gillet"                                              , day: 'd5', stage: 'lagniappe',  start: '12:45', end: '13:45', yt: 'TZNOrZIdct8', verified: true , blurb: 'Helen is a singer/cellist/improviser based in New Orleans, Louisiana.  Her band is Wazozo. More here: http://helengillet.com'},
  { id: 'b365', name: "Anna Moss"                                                 , day: 'd5', stage: 'lagniappe',  start: '14:05', end: '15:15', yt: 'v2173grW8Bw', verified: true , blurb: 'Anna Moss brings soulful, intimate storytelling to the Lagniappe Stage with her blend of folk-influenced R&B and classic New Orleans sensibilities—a refreshing sound that captures both vulnerability and groove. Her warm, expressive vocals paired with live instrumentation create the kind of authentic, late-night magic that defines the festival\'s most treasured discoveries.'},
  { id: 'b366', name: "The Rising Suns"                                           , day: 'd5', stage: 'lagniappe',  start: '15:40', end: '16:40', yt: 'N4bFqW_eu2I', verified: true , blurb: 'The Rising Suns bring that deep New Orleans soul to the Lagniappe Stage with a sound steeped in funk, blues, and second-line swagger—raw, infectious grooves that\'ll have you moving before the first chorus hits. These cats capture the spirit of the city\'s musical backbone, blending traditional New Orleans traditions with modern energy in a way that proves why this town remains the heartbeat of American music.'},
  { id: 'b367', name: "Gregg \"MacDaddy\" Martinez"                               , day: 'd5', stage: 'lagniappe',  start: '17:00', end: '18:00', yt: 'DSOZ4CavVe0', verified: true , blurb: 'Gregg "MacDaddy" Martinez brings swaggering funk and soul to the Lagniappe Stage with a signature New Orleans groove that\'s equal parts street-corner charisma and late-night club heat. His infectious blend of R&B, funk, and New Orleans bounce will have you moving from your first encounter—this is the sound that keeps the city\'s spirit alive after dark.'},
  { id: 'b368', name: "Ambush Reggae Band"                                        , day: 'd5', stage: 'jamaica',    start: '11:30', end: '12:20', yt: 'IYpsC9U_5xg', verified: true , blurb: 'Ambush Reggae Band brings the infectious rhythms and conscious vibes of Jamaica\'s reggae tradition to Jazz Fest, delivering rootsy grooves and island heat that transport you straight to the Caribbean with every sun-soaked set. Their blend of classic reggae sounds and contemporary energy makes them an essential stop for anyone seeking good vibrations and feel-good music at the Festival.'},
  { id: 'b369', name: "The Rising Suns"                                           , day: 'd5', stage: 'jamaica',    start: '12:40', end: '13:50', yt: 'N4bFqW_eu2I', verified: true , blurb: 'The Rising Suns bring that deep New Orleans soul to the Lagniappe Stage with a sound steeped in funk, blues, and second-line swagger—raw, infectious grooves that\'ll have you moving before the first chorus hits. These cats capture the spirit of the city\'s musical backbone, blending traditional New Orleans traditions with modern energy in a way that proves why this town remains the heartbeat of American music.'},
  { id: 'b370', name: "Charlie & the Tropicales"                                  , day: 'd5', stage: 'jamaica',    start: '14:15', end: '15:15', yt: 'aHYXhgCpD8E', verified: true , blurb: 'Charlie & the Tropicales bring island warmth and infectious groove to Jazz Fest with their irresistible blend of reggae, ska, and Caribbean funk—a sonic vacation that\'ll have you moving from the moment they hit the Sandals Jamaica Cultural Pavilion stage. Their high-energy, feel-good sound is pure joy, the kind of authentic tropical vibes that remind you exactly why New Orleans and the Caribbean are kindred spirits in the music world.'},
  { id: 'b371', name: "Kaya Jonkunnu Band & Walking Tall Jamaica"                 , day: 'd5', stage: 'jamaica',    start: '15:15', end: '15:50', yt: 'tldLqfvH-jc', verified: true , blurb: 'Kaya Jonkunnu Band & Walking Tall Jamaica brings the infectious rhythms of Jamaica straight to the heart of Jazz Fest, blending traditional jonkunnu percussion with modern reggae and roots energy that\'ll have you moving from the first beat. Their celebration of Caribbean culture and vibrant island grooves makes them an essential stop for anyone seeking the festival\'s most irresistible cross-cultural vibes.'},
  { id: 'b372', name: "Jesse Royal"                                               , day: 'd5', stage: 'jamaica',    start: '15:50', end: '17:00', yt: 'FET__7Z89qY', verified: true , blurb: 'Jesse Royal (Jesse David Leroi Grey, born April 29, 1989) enjoyed his early years in the hills of Maroon Town and the District of Orange in St. James before moving in the late 90’s with his mother and brother to join his father in Kingston, Jamaica.'},
  { id: 'b373', name: "Higher Heights Reggae"                                     , day: 'd5', stage: 'jamaica',    start: '17:20', end: '18:00', yt: 'IPb6f60Kk14', verified: true , blurb: 'Higher Heights Reggae brings rootsy, spiritually grounded reggae vibes to Congo Square, where their conscious lyrics and hypnotic rhythms echo the stage\'s legacy of cultural resistance and unity. With infectious grooves that blend traditional roots reggae with contemporary Caribbean consciousness, they\'re the perfect soundtrack for Jazz Fest explorers seeking positive vibrations and communal good feeling.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41361/festivalartist-12009-artist_image-08c5e345-209a-49e8-a75a-2c6b77ab8e46.jpg'},
  { id: 'b374', name: "Los Baches Flamenco Project"                               , day: 'd5', stage: 'rhythm',     start: '12:00', end: '12:45', yt: 'kL_QZ3DP3GM', verified: true , blurb: 'Los Baches Flamenco Project ignites the Rhythmpourium Tent with electrifying flamenco passion—tight percussion, searing guitar, and raw vocal intensity that channels centuries of Spanish tradition through a modern, danceable lens. Jazz Fest devotees craving rhythm-driven virtuosity and cross-cultural fire will find themselves transported by this ensemble\'s hypnotic grooves and undeniable chemistry.'},
  { id: 'b375', name: "James Linden Hogg"                                         , day: 'd5', stage: 'rhythm',     start: '13:10', end: '13:55', yt: 'AtpmdK6X1Fg', verified: true , blurb: 'James Linden Hogg brings a soulful blend of contemporary funk and New Orleans groove to the Rhythmpourium Tent, combining infectious rhythms with introspective lyricism that celebrates the city\'s rich cultural legacy. His dynamic stage presence and genre-bending sound—rooted in traditional jazz harmonies but propelled by modern production—makes him an essential discovery for fans seeking the next evolution of New Orleans music.'},
  { id: 'b376', name: "Grayson Capps"                                             , day: 'd5', stage: 'rhythm',     start: '14:20', end: '15:10', yt: 'zmRrfhsQ-3o', verified: true , blurb: 'Grayson Capps (born April 17, 1967 in Opelika, Alabama) is an American singer-songwriter. The title Rott \'N\' Roll originated with Capps’ fans in New Orleans as an explanation of his music.'},
  { id: 'b377', name: "Micah McKee"                                               , day: 'd5', stage: 'rhythm',     start: '15:35', end: '16:20', yt: 'TSEiycldy7k', verified: true , blurb: 'Micah McKee brings contemporary soul and neo-funk grooves to the Rhythmpourium Tent, blending New Orleans rhythmic DNA with modern production sensibilities for a set that moves both body and spirit. Jazz Fest devotees will find an artist who honors the city\'s improvisational legacy while pushing boldly into tomorrow\'s sound.'},
  { id: 'b378', name: "Sasha Masakowski as Tra$h Magnolia"                        , day: 'd5', stage: 'rhythm',     start: '16:45', end: '17:30', yt: 'HNH3Qo_DmNo', verified: true , blurb: 'Sasha Masakowski as Tra$h Magnolia brings experimental hip-hop swagger and New Orleans bounce to the Rhythmpourium Tent, blending trap beats with local flavor and irreverent energy that feels like the city\'s underground rap scene distilled into pure, unfiltered performance art. Expect provocative production, clever wordplay, and the kind of genre-bending vibes that make Jazz Fest\'s forward-thinking crowds lose their minds.'},
  { id: 'b379', name: "Mardi de Musique"                                          , day: 'd5', stage: 'children',   start: '11:30', end: '12:15', yt: '8pdvelpHnUU', verified: true , blurb: 'Mardi de Musique brings infectious French-influenced pop and world music rhythms to the Ochsner Children\'s Tent, creating an irresistible dance party that celebrates New Orleans\' multicultural spirit with playful energy and multigenerational appeal. Their joyful blend of accordion, brass, and handclaps transforms the tent into a celebration of festive tradition and musical discovery that families will replay all year long.'},
  { id: 'b380', name: "Kaya Jonkunnu Band & Walking Tall Jamaica"                 , day: 'd5', stage: 'children',   start: '12:15', end: '13:05', yt: 'tldLqfvH-jc', verified: true , blurb: 'Kaya Jonkunnu Band & Walking Tall Jamaica brings the infectious rhythms of Jamaica straight to the heart of Jazz Fest, blending traditional jonkunnu percussion with modern reggae and roots energy that\'ll have you moving from the first beat. Their celebration of Caribbean culture and vibrant island grooves makes them an essential stop for anyone seeking the festival\'s most irresistible cross-cultural vibes.'},
  { id: 'b381', name: "Sheepy & the Hen"                                          , day: 'd5', stage: 'children',   start: '13:05', end: '13:50', yt: 'mcXf9UrMvXw', verified: true , blurb: 'Sheepy & the Hen brings barnyard charm and infectious joy to Jazz Fest with playful, percussion-driven folk-pop that gets kids moving and parents smiling—think whimsical storytelling meets New Orleans funk grooves, perfect for families looking to kick back in the Ochsner Children\'s Tent.'},
  { id: 'b382', name: "NOLA Capoeira"                                             , day: 'd5', stage: 'children',   start: '14:15', end: '14:45', yt: 'sGGPnSrGWHU', verified: true , blurb: 'NOLA Capoeira brings the infectious rhythms and martial grace of Brazilian capoeira tradition to the heart of Jazz Fest, blending explosive percussion, call-and-response vocals, and acrobatic energy into a performance that celebrates movement as music. This dynamic ensemble captures the spirit of New Orleans\' own multicultural dance legacy, delivering a joyful, high-octane experience that\'ll have kids and families jumping to their feet.'},
  { id: 'b383', name: "Kaya Jonkunnu Band & Walking Tall Jamaica"                 , day: 'd5', stage: 'children',   start: '14:45', end: '15:20', yt: 'tldLqfvH-jc', verified: true , blurb: 'Kaya Jonkunnu Band & Walking Tall Jamaica brings the infectious rhythms of Jamaica straight to the heart of Jazz Fest, blending traditional jonkunnu percussion with modern reggae and roots energy that\'ll have you moving from the first beat. Their celebration of Caribbean culture and vibrant island grooves makes them an essential stop for anyone seeking the festival\'s most irresistible cross-cultural vibes.'},
  { id: 'b384', name: "Gray Hawk presents Native American Folklore"               , day: 'd5', stage: 'children',   start: '15:20', end: '16:00', yt: 'knvFD1vJz6s', verified: true , blurb: 'Gray Hawk weaves enchanting Native American stories and traditional folklore into a mesmerizing musical journey that captivates curious minds of all ages, blending rhythmic percussion, natural instrumentation, and ancestral wisdom into an unforgettable cultural celebration perfect for families seeking authentic connection and wonder at Jazz Fest.'},
  { id: 'b385', name: "Majekfingers Drumming Ensemble"                            , day: 'd5', stage: 'children',   start: '16:15', end: '17:00', yt: 'eOqTQOwdZm4', verified: true , blurb: 'Majekfingers Drumming Ensemble brings infectious polyrhythmic grooves and hand-percussion mastery to the Ochsner Children\'s Tent, blending West African, Caribbean, and New Orleans traditions into a joyful, participatory celebration that gets kids and families moving together. Their high-energy, accessible sound—rooted in call-and-response and irresistible rhythms—captures the spirit of cultural exchange that makes Jazz Fest a multigenerational treasure.'},
  { id: 'b386', name: "Isaiah Collier Interviewer: Charles Burchell"              , day: 'd5', stage: 'miner',      start: '12:45', end: '13:30', yt: '6zMHAODi2Ko', verified: true , blurb: 'Isaiah Collier brings soulful, modern jazz storytelling to the Heritage Stage, with Charles Burchell\'s interviewer presence creating an intimate dialogue between tradition and innovation that captures the essence of New Orleans\' living musical legacy.'},
  { id: 'b387', name: "Troy “Trombone Shorty” Andrews & Jenard Andrews Interviewer: Keith Spera", day: 'd5', stage: 'miner',      start: '13:45', end: '14:30', yt: '1jD_U_Ilg6I', verified: true , blurb: 'Troy "Trombone Shorty" Andrews channels the unfiltered soul of New Orleans brass tradition, blending second-line swagger with contemporary funk and soul that feels both timeless and alive. Expect a masterclass in trombone virtuosity paired with infectious grooves that\'ll have the whole stage moving in perfect New Orleans harmony.', members: 'Troy Andrews, Jenard Andrews'},
  { id: 'b388', name: "Tonya Boyd-Cannon Interviewer: Karen Celestan"             , day: 'd5', stage: 'miner',      start: '14:45', end: '15:30', yt: 'A1Yz5qGKRJ8', verified: true , blurb: 'Tonya Boyd-Cannon brings masterful vocal storytelling and deep roots musicianship to the Heritage Stage, blending soul, blues, and New Orleans tradition with intimate, conversation-like authenticity that feels like sitting on a front porch with someone who knows exactly what jazz means.'},
  { id: 'b389', name: "Fred Wesley Interviewer: Melissa “Soul Sister” Weber"      , day: 'd5', stage: 'miner',      start: '15:45', end: '16:30', yt: 'Bzgini_vhTs', verified: true , blurb: 'Fred Wesley and Melissa "Soul Sister" Weber bring the deep funk and soulful storytelling that defines New Orleans\' musical legacy, blending trombone virtuosity with powerhouse vocals that\'ll have you moving from the first note. This is heritage music alive and thriving—the sound of the city itself.'},

  // ───────── Fri May 1 (d6) ─────────
  { id: 'b390', name: "Amanda Shaw and The Cute Guys"                             , day: 'd6', stage: 'festival',   start: '11:20', end: '12:20', yt: 'cFoA0n9yjas', verified: true , blurb: 'Amanda Shaw and the Cute Guys deliver high-octane Cajun swing that fuses accordion-fired energy with infectious grooves, proving that Louisiana\'s traditional sounds are anything but dusty. Their playful spirit and genre-bending musicianship make them a Festival Stage essential for anyone craving that irresistible New Orleans blend of roots authenticity and pure, unfiltered fun.'},
  { id: 'b391', name: "Rickie Lee Jones"                                          , day: 'd6', stage: 'festival',   start: '12:45', end: '13:40', yt: 'UjeEV9L9SJM', verified: true , blurb: 'RICKIE LEE JONES has spent a life time dancing with her muse. She is the most iconic American female singer-songwriter of her time, a woman who outlasted all her adversaries--including youth and self-destruction. A seasoned humility brings her performances an authenticity that only long-enduring musicians achieve. Her artistry is brilliantly underlined with her 2019 forthcoming album KICKS. The album spans two decades (50s-70s) of pop, rock and jazz, presenting her unique and sophisticated interpretations of songs that were pivotal to her musical journey. By the time she was 19, JONES was living in Los Angeles, waiting tables and occasionally playing music in out of the way coffee houses and bars. All the while, she was developing her unique aesthetic: music that was sometimes spoken, often beautifully sung, and while emotionally accessible, she was writing lyrics as taut and complex as any by the great American poet, Elizabeth Bishop. In JONES’ voice and songs, we saw smoky stocking seams, love being everything but requited. And it was during these years that RICKIE LEE’s song, "Easy Money," caught the attention of one musician and then the music industry. The song was recorded by Lowell George, the founder of the band, Little Feat. He used it on his solo album, Thanks, I’ll Eat It Here. Shortly thereafter, Warner Brothers auditioned JONES and quickly signed her to the label. Her 1979 debut RICKIE LEE JONES (Warner Bros) won the Grammy for “Best New Artist.” She was hailed by one critic as a "highly touted new pop-jazz-singer-songwriter" and another critic as "one of the best--if not the best--artist of her generation." In addition to the album’s brilliant songs--including the exceptional "On Saturday Afternoons in 1963," the haunting "Last Chance Texaco," and the popular "Chuck E’s in Love"--JONES was becoming a figure whose life was bearing a great deal of emulation by young women and men who found, in her deep and personal and idiosyncratic life and work, a model for the new generation of hipster. The American culture was instantly intrigued. RICKIE LEE seemed as much of a hit as her song. She was the alternative to punk/new wave, representing the revitalization of the dying art of the pop song. She liked pop and said so. JONES’ work was the amalgamation of jazz and rock and pop, a percolating zygote that made itself into a brave new world called RICKIE LEE JONES. American culture was changed.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41403/festivalartist-12115-artist_image-3a6234c3-47f8-4450-9a32-b225cddf902d.jpg'},
  { id: 'b392', name: "John Foster"                                               , day: 'd6', stage: 'festival',   start: '14:05', end: '15:05', yt: 'yHek4xBeaYw', verified: true , blurb: 'John Foster is a 19 year old country singer who rose to fame as a runner-up on American Idol.'},
  { id: 'b393', name: "Marc Broussard"                                            , day: 'd6', stage: 'festival',   start: '15:30', end: '16:45', yt: 'hoJQQuseZ7g', verified: true , blurb: 'Marc Broussard (born January 14, 1982) is an American singer and songwriter. The Louisiana native released his first major album (with Island Def Jam Records) on August 3, 2004. The album\'s title Carencro pays tribute to the musician\'s hometown of Carencro, Louisiana.'},
  { id: 'b394', name: "Lainey Wilson"                                             , day: 'd6', stage: 'festival',   start: '17:20', end: '19:00', yt: 'm1zFk58Dohw', verified: true , blurb: 'Singer and songwriter Lainey Wilson blends tough-as-nails grit and tenderhearted sentiment in contemporary country tunes with more than a touch of traditionalism.'},
  { id: 'b395', name: "Pocket Chocolate"                                          , day: 'd6', stage: 'shell',      start: '11:20', end: '12:10', yt: 'iWOMS0sIh7E', verified: true , blurb: 'Pocket Chocolate brings swaggering funk grooves and soulful horn arrangements to the Shell Gentilly Stage, blending New Orleans tradition with modern swagger—this is the sound that makes you move before you even realize you\'re dancing. Jazz Fest devotees crave this exact energy: local flavor, undeniable pocket, and that perfect balance of sophistication and street-level joy that keeps the Gentilly Stage packed all weekend.'},
  { id: 'b396', name: "Bonerama"                                                  , day: 'd6', stage: 'shell',      start: '12:35', end: '13:35', yt: 'vZwYoMBMyMs', verified: true , blurb: 'Bonerama has always been hailed as "unlike anything you\'ve ever heard before”. It’s the best way to describe this 20-year-old powerhouse touring band from New Orleans, LA. In addition to changing the way people think about the trombone, the sound of Bonerama has become an influence and contribution to the sound of New Orleans music today. With newer acts such as Trombone Shorty and Big Sam’s Funky Nation on the national music scene, it’s New Orleans that has benefited with a newfound reputation as being a bonafide "Trombone Town". These bands all carry the trombone like the trophy it truly is in New Orleans. Bonerama helped cement this in present day New Orleans music culture. The band has performed and recorded with countless national artists such as R.E.M., OK Go, Tom Morello, Wayne Kramer (MC5), Jill Sobule and so many more, all while bringing their distinctive sounds from New Orleans to a national spotlight. Festivals and events such as Monterey Jazz Fest to High Sierra Music Festival, Jam Cruise, Bear Creek Festival and of course the New Orleans Jazz & Heritage Festival outline some of the extensive festival work this band is involved with. National television appearances on CBS (Late Show with David Letterman), HBO (Comic Relief, Treme) and CNN has further exposed Bonerama to a wide range of unsuspecting new viewers. “I never knew the trombone could do that.” -Audience members everywhere. While enduring lineup changes, member displacement, tragedy and loss over the years, the song for Bonerama has remained the same; being centered around their beloved trombone, city, and culture while striving for greatness with a fun spirit. Whether it’s their inventive covers or funky, rocking originals, rest assured, Bonerama will take you on your most memorable RIDE ON THE SLIDE! The new studio album “Bonerama Plays Zeppelin” in 2019 on Basin Street Records and was a top seller at the New Orleans Jazz and Heritage Festival and Louisiana Music Factory during the festival. This is Bonerama’s seventh major release after Live at the Old Point (2001), LIVE From New York (2004), Bringing It Home (2007), You Are Not Alone (2008, OKGo and Bonerama), Hard Times (2009), Shake It Baby (2013), Hot Like Fire (2017). In addition to being their debut release on Basin Street Records, the album features some fantastic robust and colorful packaging created by New Orleans artist and beloved musician Molly Reeves. Bonerama -- now in their 20th year of changing the way you think about the trombone and New Orleans Music.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41493/festivalartist-12357-artist_image-4d08ea25-3493-48be-a7df-8dfec4723923.jpg'},
  { id: 'b397', name: "The Skatalites"                                            , day: 'd6', stage: 'shell',      start: '14:00', end: '15:10', yt: 'xeJHGlCaFwQ', verified: true , blurb: 'The Skatalites are a Jamaican music group that played a major role in popularising ska, the first truly Jamaican music created by fusing boogie-woogie blues, rhythm and blues, jazz, mento, calypso, and African rhythms.'},
  { id: 'b398', name: "Dragon Smoke"                                              , day: 'd6', stage: 'shell',      start: '15:40', end: '16:55', yt: '4PA2YChF5Zk', verified: true , blurb: 'Dragon Smoke ignites the Shell Gentilly Stage with a fiery blend of contemporary funk, soul, and New Orleans R&B that moves from sultry grooves to explosive crescendos, delivering the kind of infectious energy that gets the whole crowd moving as one. These local innovators channel the spirit of the city\'s deep musical roots while pushing boldly into modern sounds—exactly what Jazz Fest devotees crave.'},
  { id: 'b399', name: "The Black Keys"                                            , day: 'd6', stage: 'shell',      start: '17:30', end: '19:00', yt: 'a_426RiwST8', verified: true , blurb: 'The Black Keys are an alternative rock  group from Akron, Ohio, United States which formed in 2001, consisting of singer and guitarist Dan Auerbach and drummer Patrick Carney.'},
  { id: 'b400', name: "Tony Hall & The New Orleans Soul Stars’ Tribute to James Brown", day: 'd6', stage: 'congo',      start: '11:20', end: '12:20', yt: '8PSOgmmqqvo', verified: true , blurb: 'Watch Tony Hall & The New Orleans Soul Stars ignite Congo Square with a fiery celebration of the Godfather of Soul—hard-hitting horns, unrelenting funk grooves, and that raw, electrifying energy that made James Brown a legend. If you\'re craving authentic New Orleans soul power delivered with total command and infectious joy, this is the set that\'ll have you dancing before the first chorus hits.'},
  { id: 'b401', name: "Cha Wa"                                                    , day: 'd6', stage: 'congo',      start: '12:45', end: '13:45', yt: 'nMlnt85iysY', verified: true , blurb: 'From the funk-laced beats and bass-heavy sousaphone blasts that kick off their Grammy-nominated album “Spyboy” to the gritty warmth of singer J’Wan Boudreaux’s voice, New Orleans brass band-meets-Mardi Gras Indian outfit Cha Wa radiates the fiery energy of the best features of the city’s street culture. “Spyboy” was produced by Galactic’s Ben Ellman and features special guests Big Chief Monk Boudreaux (The Wild Magnolias, HBO’s Treme), Nigel Hall (Lettuce, Nth Power), and Danica Hart. Cha Wa’s debut, “Funk N Feathers,” explored contemporary riffs on the traditional music Boudreaux grew up singing alongside his grandfather, Big Chief Monk Boudreaux, in the Golden Eagles Mardi Gras Indian tribe. Now “Spyboy” ups the ante by digging deeper into the sound of New Orleans culture and giving it a modern twist. The disc’s largely original material takes advantage of the band’s new horn section to highlight the musicians’ personal ties to the street music of their hometown. “We wanted to take the roots of what we love about New Orleans brass band music and Mardi Gras Indian music and then voice it in our own way,” says the group’s drummer and founder, Joe Gelini. Dating back to the late 1800s, the Mardi Gras Indian tradition began when African-American men first marched in Native American dress through the streets of New Orleans on Mardi Gras day. The tradition, which includes a host of songs shared among the various tribes, has been kept alive for over a century and today is as vital as ever. Mardi Gras Indians have influenced the biggest names in New Orleans music: The Meters, Dr. John, the Marsalis family, the Neville Brothers, Trombone Shorty and others. The most prominent Mardi Gras Indian today is Monk Boudreaux, the Big Chief of the Golden Eagles tribe, and his grandson J’Wan Boudreaux (who holds the position of Spyboy in the tribe) is stepping up with Cha Wa to propel their culture forward. J’Wan joined the group when he was still in high school. At the time, Gelini, then a recent Berklee School of Music grad, had been playing drums for Boudreaux’s grandfather, having learned the traditional Mardi Gras Indian beats from original Wild Magnolias bass drummer Norwood “Geechie” Johnson at Sunday night Indian practices in Uptown New Orleans. As the band evolved, J’Wan emerged as the front man. On “Spyboy,” Boudreaux’s vocals (with support from Thaddeus “Peanut” Ramsey’s smooth-voiced Indian style), the booming, funked-up sound of the band’s new four-part horn section, and Gelini’s mix of second line grooves and soulful Indian rhythms have all combined to kindle a new fire in Cha Wa’s ever-developing sound. Although “cha wa” means “we’re comin’ for ya” in Indian vernacular, Boudreaux says the album “Spyboy” is “Cha Wa all around” for a different reason. With songwriting contributions to “Spyboy” from band members Joe Maize, Thaddeus ‘Peanut’ Ramsey, Ari Teitel and Clifton ‘Spug’ Smith, along with J’Wan and Gelini, Cha Wa ignites an entire new generation with contemporary anthems set ablaze by its high-flying ensemble. Says Boudreaux, “Everyone put their minds together to make this music. Everyone had input on at least one song. And the whole band has a different type of connection these days. Everybody’s bonded now. Everybody’s just having fun”. The track “Get On Out the Way” -- with its loose, ‘70s funk rhythm, tight horn parts and deep, bouncing sousaphone -- brings that celebratory vibe to life by spiking a traditional Indian phrase with a fast-moving brass band twist. There’s also a more serious, social message at work in Cha Wa’s music. Gelini and Monk wrote “Visible Means Of Support” about Monk’s experience with the ‘50s-era Jim Crow vagrancy law used primarily to arrest African-American men. On the J’Wan-penned, big beat-centric “Chapters,” the singer tackles more contemporary issues, in this case, the internal struggles he faced while being raised by a single mom. The mellow, piano and vocals-only “J’Wan’s story” sees him taking a different approach to bridging the gap between beauty and harsh reality in New Orleans when he explains, spoken word-style, the basics about how and why Mardi Gras Indian culture developed. “We dress up in the Indian suits to pay homage to the Native American Indians, because around the time of slavery, they were the first ones to take us in,” he says, elaborating on the song. “Everything on our suits is handmade -- the beads, the patterns, we sew together pieces of fabric and make the panels, we make the boots -- everything.” Not that you need a firm understanding of Indian or brass band culture to feel the dance-ready vibrations of Cha Wa’s new music. “It’s dance music so I think people are attracted to it. Even if people have no idea what the history is, it’s automatically infectious,” Gelini explains. “J’wan’s the next generation,” the drummer adds. “He’s keeping this flame lit.”', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41444/festivalartist-12223-artist_image-c4493091-93b5-456b-8548-f74869377112.jpg'},
  { id: 'b402', name: "Hot 8 Brass Band"                                          , day: 'd6', stage: 'congo',      start: '14:10', end: '15:20', yt: 'ZsDUXo5TcZY', verified: true , blurb: 'The Hot 8 Brass Band is a New Orleans based brass band that blends hip-hop, jazz and funk styles with a traditional New Orleans brass sounds. It was formed in 1995 by tubist Bennie "Big Peter" Pete, merging two earlier bands, the Looney Tunes Brass Band and the High Steppers Brass Band.'},
  { id: 'b403', name: "Original Koffee"                                           , day: 'd6', stage: 'congo',      start: '15:55', end: '16:55', yt: 'p8HoEvDh70Y', verified: true , blurb: 'Mikayla Victoria Simpson (born February 16, 2000), who performs under the stage name Original Koffee and formerly as Koffee, is a Jamaican singer, songwriter, rapper, and guitarist from Spanish Town.'},
  { id: 'b404', name: "Ziggy Marley"                                              , day: 'd6', stage: 'congo',      start: '17:30', end: '19:00', yt: 'p4jZKM5Y6-0', verified: true , blurb: 'David Nesta "Ziggy" Marley (born October 17, 1968 in Saint Ann Parish, ghetto of Trenchtown, Jamaica), composer, singer and guitarist, is a multiple Grammy-winning (reggae) Jamaican musician.'},
  { id: 'b405', name: "Southern University Baton Rouge Jazz Ensemble"             , day: 'd6', stage: 'jazz',       start: '11:20', end: '12:10', yt: 'Yc_PS5dExP4', verified: true , blurb: 'Southern University Baton Rouge Jazz Ensemble brings the academic rigor and soul-deep tradition of Louisiana\'s premier HBCU to the Jazz Tent, delivering straight-ahead jazz with the polished sophistication and generational passion that defines the River City sound. These young lions honor the classic New Orleans jazz lineage while carving their own path—expect tight ensemble work, smoking solos, and the kind of infectious energy that reminds you why this music never gets old.'},
  { id: 'b406', name: "Stephen Walker"                                            , day: 'd6', stage: 'jazz',       start: '12:35', end: '13:35', yt: 'hm-C49RpvfM', verified: true , blurb: 'Stephen Walker brings a luminous, contemporary jazz sensibility to the WWOZ stage, blending lyrical sophistication with the soulful traditions that make New Orleans the heartbeat of American jazz. His intelligent compositions and commanding presence create an intimate yet expansive sound that resonates with both seasoned jazz heads and curious explorers alike.'},
  { id: 'b407', name: "Victor Campbell"                                           , day: 'd6', stage: 'jazz',       start: '14:00', end: '15:10', yt: 'jOMz9Dx6MNk', verified: true , blurb: 'Victor Campbell brings soulful, tradition-steeped jazz that honors New Orleans\' deep roots while pushing the music forward with contemporary energy and impeccable musicianship. Jazz Fest devotees will find themselves transported by his warm, expressive playing and the kind of authentic New Orleans sound that reminds you exactly why this music was born in this city.'},
  { id: 'b408', name: "Lawrence Sieberth presents da Groove featuring David Fiuczynski & Daniel Sadownick", day: 'd6', stage: 'jazz',       start: '15:40', end: '16:55', yt: 'jrlqaJCh6VQ', verified: true , blurb: 'Lawrence Sieberth presents da Groove featuring David Fiuczynski & Daniel Sadownick brings the deep funk and polyrhythmic heat that defines modern New Orleans jazz, blending virtuosic guitar wizardry with precision drums to create a sound that\'s both rooted in tradition and impossibly fresh. This is the kind of groove-forward, high-energy set that reminds you why the WWOZ Jazz Tent is where innovation meets soul.'},
  { id: 'b409', name: "Terence Blanchard + Ravi Coltrane: Miles Davis & John Coltrane Centennial", day: 'd6', stage: 'jazz',       start: '17:30', end: '19:00', yt: '8VE_dP90V84', verified: true , blurb: 'Terence Blanchard and Ravi Coltrane pay towering tribute to two jazz immortals with a program that honors Miles Davis and John Coltrane\'s revolutionary legacies through modern ears, blending post-bop sophistication with deep spiritual searching that only artists of their caliber can channel.', members: 'Terence Blanchard, Ravi Coltrane'},
  { id: 'b410', name: "D.K. Harrell Band"                                         , day: 'd6', stage: 'blues',      start: '11:20', end: '12:20', yt: 'sKpTBhKYJgc', verified: true , blurb: 'D.K. Harrell Band brings deep, soulful blues with that authentic New Orleans grit—a masterclass in traditional blues storytelling backed by tight instrumentation and genuine feel. Their set at the Blues Tent is essential listening for anyone who wants to hear blues played with the kind of conviction and regional flavor that only the Crescent City can deliver.'},
  { id: 'b411', name: "Meschiya Lake and the Little Big Horns"                    , day: 'd6', stage: 'blues',      start: '12:45', end: '13:50', yt: 'm_SMk42zcfI', verified: true , blurb: 'Meschiya Lake and the Little Big Horns is a New Orleans, Louisiana based Dixie influenced Jazz band, formed in 2009. They have released two albums \'Lucky Devil \' (2010) and \' Fooler\'s Gold \' (2013).'},
  { id: 'b412', name: "Kevin \"Sonny\" Gullage & Blues Groovers"                  , day: 'd6', stage: 'blues',      start: '14:15', end: '15:20', yt: '6tNI8rGZt80', verified: true , blurb: 'Kevin "Sonny" Gullage & Blues Groovers bring deep, soulful New Orleans blues to the Blues Tent with the kind of gritty authenticity and groove-heavy swagger that defines the Crescent City sound—raw vocals, tight rhythm, and that unmistakable low-down feel that keeps Jazz Fest audiences coming back for more.'},
  { id: 'b413', name: "Sue Foley"                                                 , day: 'd6', stage: 'blues',      start: '15:50', end: '17:05', yt: 'uqhSQUxSoZw', verified: true , blurb: 'Sue Foley (born March 29, 1968, Ottawa, Ontario, Canada) is a Canadian blues singer and guitarist. She has also recorded as Peter Karp & Sue Foley.  Since her first album in 1992  Foley has recorded a string of albums, for both Antone\'s Records and Shanachie Records.'},
  { id: 'b414', name: "Tab Benoit"                                                , day: 'd6', stage: 'blues',      start: '17:35', end: '18:55', yt: 'odYwplZSU9U', verified: true , blurb: 'Tab Benoit is a Grammy nominated singer, songwriter and guitarist who has built a remarkable 30+ year career on the foundation of his gritty and soulful Delta swamp blues and acquiring a devoted legion of fans along the way, as well as 5 Blues Music Awards, including BB King Entertainer of the Year (twice) and an induction into The Louisiana Music Hall of Fame. He has recorded and/or performed with Junior Wells, George Porter Jr, Dr. John, Willie Nelson, Big Chief Monk Boudreaux, Billy Joe Shaver, Maria Muldaur, James Cotton, Cyril Neville, Kenny Aronoff, Allen Toussaint, Kim Wilson, Jimmy Thackery, Charlie Musslewhite, Kenny Neal, Chris Layton, Ivan Neville, Jimmy Hall, Jim Lauderdale, Anders Osborne, and Alvin Youngblood Hart to name a few. Tab\'s accomplishments as a musician are matched only by his devotion to the environmental health of his native Louisiana wetlands. Benoit is the founder and driving force behind Voice of the Wetlands, an organization working to preserve the coastal waters of his home state. In 2010, he received the Governor\'s Award for Conservationist of the Year from the Louisiana Wildlife Federation. Benoit also starred in the iMax motion picture Hurricane on the Bayou, a documentary of Hurricane Katrina\'s effects and a call to protect and restore the wetlands.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41432/festivalartist-12197-artist_image-b452e890-dd71-4bac-a1d8-1c4c32685bfa.jpg'},
  { id: 'b415', name: "The Slick Skillet Serenaders"                              , day: 'd6', stage: 'economy',    start: '11:20', end: '12:15', yt: 'j8hP-w73eDk', verified: true , blurb: 'The Slick Skillet Serenaders bring traditional New Orleans brass band heat with a smooth, intimate touch—expect gleaming horns, propulsive rhythms, and that perfect balance of rollicking parade energy and late-night groove that keeps Jazz Fest devotees coming back to Economy Hall. Their cooking sound captures the soul of the Crescent City\'s golden era while staying fresh enough to make you move all night long.'},
  { id: 'b416', name: "Louisiana Repertory Jazz Ensemble"                         , day: 'd6', stage: 'economy',    start: '12:40', end: '13:35', yt: 'bE9oo9Ds-ps', verified: true , blurb: 'The Louisiana Repertory Jazz Ensemble channels the deep traditions of New Orleans jazz with scholarly precision and soulful authenticity, breathing new life into the classic standards and obscure gems that built this city\'s musical legacy. Their Economy Hall performances are a masterclass in ensemble interplay—expect tight harmonies, conversational horn sections, and the kind of swinging rhythm that reminds you why this music will never die.'},
  { id: 'b417', name: "Charlie Gabriel and Friends"                               , day: 'd6', stage: 'economy',    start: '13:55', end: '14:45', yt: '3NVj9OZlXzg', verified: true , blurb: 'Charlie Gabriel is New Orleans born and traditionally trained musician who also is fluent in be-bop, R&B and other genres of music. He will be accompanied by Shannon Powell on percussion, wonderful pianist Meghan Schwartz, Mark Brooks, one of NO\'s finest bassist, and exciting trumpeter, Branden Lewis.'},
  { id: 'b418', name: "Tribute to New Orleans Early Blues Singers featuring Jolynda \"Kiki\" Chapman and Thais Clark with the Lars Edegran Band", day: 'd6', stage: 'economy',    start: '15:10', end: '16:10', yt: 'RnGJ3KJri1g', verified: true , blurb: 'Experience the raw soul and timeless elegance of New Orleans\' blues roots as Jolynda "Kiki" Chapman and Thais Clark channel the spirit of early blues legends, backed by Lars Edegran\'s masterful band in a performance that captures the gritty intimacy and emotional depth that built this city\'s musical foundation. This is authentic New Orleans heritage at its most compelling—where classic blues tradition meets the warm, conversational storytelling that only true keepers of the culture can deliver.'},
  { id: 'b419', name: "Gerald French & The Original Tuxedo Jazz Band"             , day: 'd6', stage: 'economy',    start: '16:30', end: '17:25', yt: 'zCdMVYoNfpc', verified: true , blurb: 'Gerald French & The Original Tuxedo Jazz Band bring authentic New Orleans brass tradition to life with their sharp, swinging sound that honors the city\'s golden age of jazz while keeping the spirit dancing in the present. Catch them at Economy Hall Tent for a masterclass in traditional jazz that\'ll have you understanding exactly why this music invented the party.'},
  { id: 'b420', name: "The Pfister Sisters"                                       , day: 'd6', stage: 'economy',    start: '17:45', end: '18:40', yt: 'BZji8fur8As', verified: true , blurb: 'Like most good New Orleans bands, their songlist spans 3 centuries and much of the American Songbook.   What is different about The Pfister Sisters is that they do it in rhythm and harmony.'},
  { id: 'b421', name: "Corey Ledet Zydeco & Black Magic"                          , day: 'd6', stage: 'fais',       start: '11:15', end: '12:05', yt: 'kry0sxTJdtI', verified: true , blurb: 'Corey Ledet Zydeco & Black Magic bring the irresistible accordion-driven energy of authentic Louisiana zydeco to the Sheraton Fais Do-Do Stage, fusing traditional Creole rhythms with modern groove that\'ll have you dancing before the first song ends. This is the sound of swamp soul and bayou celebration—raw, infectious, and unmistakably New Orleans.'},
  { id: 'b422', name: "Travis Matte & the Kingpins featuring Johnnie Allan"       , day: 'd6', stage: 'fais',       start: '12:25', end: '13:20', yt: 'KsdbL-2qQ1k', verified: true , blurb: 'Travis Matte & the Kingpins featuring Johnnie Allan bring authentic Louisiana swamp pop and zydeco fire to the Fais Do-Do stage, blending accordion-driven grooves with gritty guitar and that unmistakable down-bayou swagger that makes you move whether you\'re ready or not. These keepers of the regional sound tradition deliver the kind of danceable, soulful R&B-inflected roots music that reminds you why this festival exists.'},
  { id: 'b423', name: "Bruce Daigrepont Cajun Band"                               , day: 'd6', stage: 'fais',       start: '13:40', end: '14:40', yt: 'MnkFLAkJW5Q', verified: true , blurb: 'The Bruce Daigrepont Cajun Band plays Cajun and Zydeco music sung in Louisiana Cajun French. The band is made up of seasoned, experienced musicians. The group has toured throughout North America, Europe, and South America. Perhaps the band’s most impressive accomplishment is it has maintained a loyal local fan base since 1980. They have performed at weekly “Fais Do Do” dance for over thirty years. Since 1986 the dance has been held monthly on Sunday’s at the legendary Tipitina’s in New Orleans. The band uses the most basic instrumentation of hand-made Cajun accordion, fiddle, bass, and drums. The band has a vast repertoire of over three hundred songs, many written by Bruce Daigrepont himself. All of Bruce’s original compositions are written in traditional Cajun French language and many have been covered by recording artists in the U.S., Canada, France, and several other European countries. He is steeped in the knowledge of the history of the Cajun people and fluent in the Cajun French language. He has conducted Cajun music presentations at both elementary and high schools, universities, and libraries. In North America they have performed at such prestigious venues as New York\'s Lincoln Center, Wolf Trap Center for the Performing Arts, the Winnipeg Folk Festival, the National Folk Festival, and, of course, the New Orleans Jazz and Heritage festival (repeatedly). The band has also taken their music to France, Belgium, Holland, Switzerland, Germany, Denmark, Norway, and Sweden. At the request of the American Embassies, they have performed even in the third-world countries of EI Salvador and Venezuela. Bruce and his band have released four albums on Rounder Records "Stir Up the Roux," "Coeur des Cajuns," "Petit Cadeau," and, "Paradis." In 2013 Bruce himself released a self-produced recording: “Jamais de la Vie”, a unique foray employing only his voice and his accordion. Look for his newest release “Bienvenue dans le sud de la Louisiane” – “Welcome to South Louisiana” and find him at his monthly Fais Do Do at Tipitina’s in New Orleans.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41379/festivalartist-12057-artist_image-500e7979-8ce5-427e-9788-3caebffb280f.jpg'},
  { id: 'b424', name: "Geno Delafose & French Rockin' Boogie"                     , day: 'd6', stage: 'fais',       start: '15:00', end: '16:00', yt: 'nQwCXVRmiJ4', verified: true , blurb: 'Son of zydeco musician John Delafose, Geno\'s a creole cowboy accordion player and with his band French Rockin\' Boogie he has established a worldwide reputation as one of the better known zydeco groups playing today.'},
  { id: 'b425', name: "BeauSoleil avec Michael Doucet"                            , day: 'd6', stage: 'fais',       start: '16:25', end: '17:25', yt: 'KBwRddleQJ8', verified: true , blurb: 'BeauSoleil or Beausoleil avec Michael Doucet is a group specializing in Cajun music, founded in 1975. It\'s based in Lafayette, Louisiana, USA.'},
  { id: 'b426', name: "The California Honeydrops"                                 , day: 'd6', stage: 'fais',       start: '17:50', end: '19:00', yt: '-xEOfdqGCmY', verified: true , blurb: 'The California Honeydrops is an American blues and R&B band, formed in November 2007 playing in the subway stations of Oakland, CA. Digging deep into the roots of American music, the band members embrace the traditions of Blues, Gospel, Second Line New Orleans Jazz, and early R&B.'},
  { id: 'b427', name: "Muévelo"                                                   , day: 'd6', stage: 'heritage',   start: '11:20', end: '12:10', yt: 'LbTqvLzz3Qs', verified: true , blurb: 'New Orleans’ Latin music scene is flourishing and its latest sensation is Muévelo. That means "Move It" in Spanish, and that\'s just what you\'ll be doing with your feet, your hips and all the rest! Singer Margie Perez and Saxophonist Brent Rose and their talented ensemble take you on a Caribbean musical journey that won\'t let you leave the dance floor. They\'ve played The New Orleans Jazz Festival, The French Quarter Fest, The Congo Square Rhythms Festival, and Gretna Fest. Catch their monthly residency at Three Keys Ace Hotel for "La Noche Caliente" a hot night of music and dance.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41554/festivalartist-12481-artist_image-a325ef97-a86a-4452-aafc-4172edee1a12.jpg'},
  { id: 'b428', name: "Big Chief Kevin Goodman & the Flaming Arrows Mardi Gras Indians", day: 'd6', stage: 'heritage',   start: '12:30', end: '13:20', yt: 'GLqjcmcvu0A', verified: true , blurb: 'Experience the raw spiritual fire and second-line swagger of New Orleans\' most legendary Mardi Gras Indian tradition as Big Chief Kevin Goodman & the Flaming Arrows deliver hypnotic percussion, call-and-response vocals, and the unshakeable groove that defines the city\'s deepest cultural DNA. This is the sound that moves through the streets on Mardi Gras morning—ancestral, defiant, and absolutely unmissable for anyone seeking the soul of Jazz Fest.'},
  { id: 'b429', name: "Los Guiros"                                                , day: 'd6', stage: 'heritage',   start: '13:45', end: '14:45', yt: 'kWzK3MZlSIc', verified: true , blurb: 'Los Guiros brings infectious Latin-Caribbean rhythms and percussion-driven grooves to the Jazz & Heritage Stage, blending traditional guiro sounds with contemporary improvisation for a high-energy celebration that gets everyone moving. Their vibrant, dance-ready energy and masterful interplay of layered percussion makes them a festival favorite for anyone seeking the joyful intersection of roots music and modern groove.'},
  { id: 'b430', name: "Baby Boyz Brass Band"                                      , day: 'd6', stage: 'heritage',   start: '15:05', end: '16:00', yt: 'GhZA3yPYUwc', verified: true , blurb: 'Baby Boyz Brass Band brings the rollicking, second-line swagger of New Orleans tradition with a youthful energy that transforms classic brass into pure celebration—their horns cut through the festival air like pure joy, making them essential listening for anyone who came to Jazz Fest to move their feet and feel their soul.'},
  { id: 'b431', name: "Runkus & Royal Blu with Dub Squad"                         , day: 'd6', stage: 'heritage',   start: '16:25', end: '17:25', yt: 'oSkrsTpag6Q', verified: true , blurb: 'Runkus & Royal Blu with Dub Squad bring a hypnotic blend of reggae roots, New Orleans funk, and electronic dub vibes that transform the Jazz Heritage Stage into a sonic celebration—where island rhythms meet Crescent City soul and the bass drops hit like a second line parade. This is the sound of New Orleans colliding with Caribbean consciousness: irresistible, forward-thinking, and made for moving bodies and open minds.'},
  { id: 'b432', name: "Big Chief Juan & Jockimo's Groove"                         , day: 'd6', stage: 'heritage',   start: '17:50', end: '18:40', yt: '2lU_kLI46HY', verified: true , blurb: 'Big Chief Juan & Jockimo\'s Groove delivers the raw, second-line soul of New Orleans—a fierce blend of traditional jazz, funk, and Mardi Gras Indian swagger that gets the whole crowd moving as one. This is the sound that built the city, and Jazz Fest fans who live for authentic New Orleans groove won\'t want to miss it.'},
  { id: 'b433', name: "Zulu Male Ensemble"                                        , day: 'd6', stage: 'gospel',     start: '11:20', end: '12:05', yt: 'gbljPQbxtTQ', verified: true , blurb: 'The Zulu Male Ensemble brings transcendent vocal harmonies and deep spiritual resonance to the Gospel Tent, their rich, layered voices steeped in New Orleans\' sacred traditions and the soulful power of the city\'s legendary choirs. This is pure, unfiltered gospel that moves both body and spirit—a must-see for anyone seeking the authentic heart of the festival.'},
  { id: 'b434', name: "Shades of Praise Interracial Gospel Choir"                 , day: 'd6', stage: 'gospel',     start: '12:20', end: '13:05', yt: 'Fkk9aqVOUzg', verified: true , blurb: 'Shades of Praise Interracial Gospel Choir brings transcendent harmonies and radiant joy to the Gospel Tent, their unified voices soaring through spirituals and contemporary gospel with the inclusive spirit that makes New Orleans music sacred. Jazz Fest devotees will be moved by their powerful blend of traditional depth and modern energy—a celebration of faith, community, and the healing power of collective praise.'},
  { id: 'b435', name: "Arthur & Friends Community Choir"                          , day: 'd6', stage: 'gospel',     start: '13:20', end: '14:05', yt: 'iQF7vCDiFs4', verified: true , blurb: 'Arthur & Friends Community Choir brings the pure, unfiltered joy of New Orleans gospel to the Festival with voices that blend traditional hymnal power and contemporary soul—expect hand-claps, call-and-response, and the kind of spiritual electricity that turns the Gospel Tent into a revival meeting you won\'t want to leave.'},
  { id: 'b436', name: "Morning Star Missionary Mass Choir"                        , day: 'd6', stage: 'gospel',     start: '14:20', end: '15:10', yt: 'eVGG7Yn8u5M', verified: true , blurb: 'The Morning Star Missionary Mass Choir brings the spirited soul of New Orleans gospel tradition to the Gospel Tent with their powerful, jubilant harmonies and deep roots in the city\'s church community—a transcendent experience that captures the spiritual heart beating beneath Jazz Fest\'s celebration of American music.'},
  { id: 'b437', name: "Jekalyn Carr"                                              , day: 'd6', stage: 'gospel',     start: '15:30', end: '16:35', yt: 'Yjey4J2b5Rs', verified: true , blurb: 'At the age of sixteen, Jekalyn is an entrepreneur, national recording artist and profound preacher. Her passion for ministry began at the early age of five. During this time, her parents recognized that had an extreme anointing and gift.'},
  { id: 'b438', name: "The Johnson Extension"                                     , day: 'd6', stage: 'gospel',     start: '16:50', end: '17:40', yt: 'qerhfRYxgQQ', verified: true , blurb: 'The Johnson Extension brings transcendent soul power to the Gospel Tent with their signature blend of traditional New Orleans gospel roots and contemporary spiritual energy, delivering the kind of uplifting, call-and-response driven performances that remind you why this festival started in a church in the first place.'},
  { id: 'b439', name: "Watson Memorial Teaching Ministries Mass Choir"            , day: 'd6', stage: 'gospel',     start: '17:55', end: '18:40', yt: 'jrK6TZF7Pz0', verified: true , blurb: 'Watson Memorial Teaching Ministries Mass Choir brings the soul-stirring power of traditional gospel to the Gospel Tent with voices that soar in rich, layered harmonies—a joyful, spirit-filled celebration that connects New Orleans\' deep church roots to Jazz Fest\'s heart. Their dynamic blend of classic hymns and contemporary gospel grooves will have you on your feet, moved by the kind of authentic, community-rooted music that makes the festival feel like a spiritual homecoming.'},
  { id: 'b440', name: "Sarah Quintana"                                            , day: 'd6', stage: 'lagniappe',  start: '11:30', end: '12:35', yt: 'rSPYo3mlpWY', verified: true , blurb: 'Sarah Quintana is an American singer-songwriter from New Orleans, Louisiana.'},
  { id: 'b441', name: "Gal Holiday & The Honky Tonk Revue"                        , day: 'd6', stage: 'lagniappe',  start: '13:00', end: '14:00', yt: '1KhhnWnU7-8', verified: true , blurb: 'The Honky Tonk Revue was founded in the summer of 2004 as Gal Holiday set out to create a band that harkened back to her rural roots in the mountains of Western Maryland.'},
  { id: 'b442', name: "The New Orleans Guitar Masters: John Rankin, Jimmy Robinson, and Cranston Clements", day: 'd6', stage: 'lagniappe',  start: '14:20', end: '15:20', yt: 'pqKIK_5afx4', verified: true , blurb: 'Three generations of New Orleans guitar wizardry converge on the Lagniappe Stage as Rankin, Robinson, and Clements weave traditional blues, funk, and second-line grooves into an intimate masterclass that proves why this city remains the soul of American guitar. Jazz Fest devotees seeking authentic, unplugged musicianship and deep New Orleans roots will find their spiritual home in this trio\'s finger-picked anthems and soulful licks.'},
  { id: 'b443', name: "Tyron Benoit Band"                                         , day: 'd6', stage: 'lagniappe',  start: '15:40', end: '16:40', yt: '8LGwsM2CaDM', verified: true , blurb: 'The Tyron Benoit Band brings the deep, soulful pocket of contemporary New Orleans funk and R&B to the Lagniappe Stage, where their tight grooves and infectious energy remind you why this city remains the heartbeat of American music. Jazz Fest devotees will feel right at home in their blend of traditional soul sensibility with modern swagger—it\'s the sound of New Orleans looking forward while honoring its roots.'},
  { id: 'b444', name: "Panorama Jazz Band"                                        , day: 'd6', stage: 'lagniappe',  start: '17:00', end: '18:00', yt: '7grZRNXl9W4', verified: true , blurb: 'These guys play the goodtime music that gets people dancing: a New Orleans "second-line" AND a Jewish hora; a biguine, a polka, and a habañera. The instrumentation (clarinet, trombone, accordion, banjo, tuba and drums) lends itself to traditional styles of music from all over the world.'},
  { id: 'b445', name: "The Maroons Band"                                          , day: 'd6', stage: 'jamaica',    start: '11:30', end: '12:00', yt: 'mBL7VYC9WbQ', verified: true , blurb: 'The Maroons Band brings the rhythmic soul of Caribbean resistance and celebration to Jazz Fest, blending reggae, roots, and traditional Jamaican sounds into a groove that moves both body and spirit. Their infectious energy and rich cultural storytelling make them essential listening for anyone seeking authentic island vibes and the deeper grooves that define New Orleans\' global musical spirit.'},
  { id: 'b446', name: "Kaya Jonkunnu Band & Walking Tall Jamaica"                 , day: 'd6', stage: 'jamaica',    start: '12:00', end: '12:50', yt: 'tldLqfvH-jc', verified: true , blurb: 'Kaya Jonkunnu Band & Walking Tall Jamaica brings the infectious rhythms of Jamaica straight to the heart of Jazz Fest, blending traditional jonkunnu percussion with modern reggae and roots energy that\'ll have you moving from the first beat. Their celebration of Caribbean culture and vibrant island grooves makes them an essential stop for anyone seeking the festival\'s most irresistible cross-cultural vibes.'},
  { id: 'b447', name: "Sunpie ak Vodou Blues Ayiti"                               , day: 'd6', stage: 'jamaica',    start: '12:50', end: '13:45' , blurb: 'Sunpie ak Vodou Blues Ayiti brings the raw spiritual power of Haitian vodou tradition fused with deep blues grooves, creating an electrifying sound that honors ancestral roots while hitting you with modern soul and grit. This is transcendent, uncompromising music that transforms the stage into a sacred space—exactly what Jazz Fest devotees crave when they\'re ready to go beyond the mainstream.'},
  { id: 'b448', name: "Runkus & Royal Blu with Dub Squad"                         , day: 'd6', stage: 'jamaica',    start: '14:10', end: '15:10', yt: 'oSkrsTpag6Q', verified: true , blurb: 'Runkus & Royal Blu with Dub Squad bring a hypnotic blend of reggae roots, New Orleans funk, and electronic dub vibes that transform the Jazz Heritage Stage into a sonic celebration—where island rhythms meet Crescent City soul and the bass drops hit like a second line parade. This is the sound of New Orleans colliding with Caribbean consciousness: irresistible, forward-thinking, and made for moving bodies and open minds.'},
  { id: 'b449', name: "The Rising Suns"                                           , day: 'd6', stage: 'jamaica',    start: '15:30', end: '16:30', yt: 'N4bFqW_eu2I', verified: true , blurb: 'The Rising Suns bring that deep New Orleans soul to the Lagniappe Stage with a sound steeped in funk, blues, and second-line swagger—raw, infectious grooves that\'ll have you moving before the first chorus hits. These cats capture the spirit of the city\'s musical backbone, blending traditional New Orleans traditions with modern energy in a way that proves why this town remains the heartbeat of American music.'},
  { id: 'b450', name: "Kaya Jonkunnu Band & Walking Tall Jamaica"                 , day: 'd6', stage: 'jamaica',    start: '16:30', end: '17:00', yt: 'tldLqfvH-jc', verified: true , blurb: 'Kaya Jonkunnu Band & Walking Tall Jamaica brings the infectious rhythms of Jamaica straight to the heart of Jazz Fest, blending traditional jonkunnu percussion with modern reggae and roots energy that\'ll have you moving from the first beat. Their celebration of Caribbean culture and vibrant island grooves makes them an essential stop for anyone seeking the festival\'s most irresistible cross-cultural vibes.'},
  { id: 'b451', name: "The Skatalites"                                            , day: 'd6', stage: 'jamaica',    start: '17:00', end: '18:00', yt: 'xeJHGlCaFwQ', verified: true , blurb: 'The Skatalites are a Jamaican music group that played a major role in popularising ska, the first truly Jamaican music created by fusing boogie-woogie blues, rhythm and blues, jazz, mento, calypso, and African rhythms.'},
  { id: 'b452', name: "Victor Campbell Cuban Quartet"                             , day: 'd6', stage: 'rhythm',     start: '12:00', end: '12:45', yt: 'fkQq-mPusYI', verified: true , blurb: 'Victor Campbell Cuban Quartet brings the heat of Havana to the Rhythmpourium with infectious son cubano rhythms, blazing brass, and that perfect blend of tradition and contemporary groove that gets the whole tent moving. These cats know how to make you feel the island pulse while keeping things fresh and modern—exactly what Jazz Fest is all about.'},
  { id: 'b453', name: "The Rising Suns"                                           , day: 'd6', stage: 'rhythm',     start: '13:10', end: '14:00', yt: 'N4bFqW_eu2I', verified: true , blurb: 'The Rising Suns bring that deep New Orleans soul to the Lagniappe Stage with a sound steeped in funk, blues, and second-line swagger—raw, infectious grooves that\'ll have you moving before the first chorus hits. These cats capture the spirit of the city\'s musical backbone, blending traditional New Orleans traditions with modern energy in a way that proves why this town remains the heartbeat of American music.'},
  { id: 'b454', name: "David Doucet"                                              , day: 'd6', stage: 'rhythm',     start: '14:25', end: '15:10', yt: '1VdpAIYH_Wo', verified: true , blurb: 'David Doucet was born on July 6, 1957, in Lafayette, LA. The acoustic guitar has been transformed into an important voice of southwest Louisiana\'s Cajun music by David Doucet.'},
  { id: 'b455', name: "Andrew Jobin and the Thick Smoke"                          , day: 'd6', stage: 'rhythm',     start: '15:35', end: '16:20', yt: 'TEVX964anXw', verified: true , blurb: 'Andrew Jobin and the Thick Smoke brew a sultry blend of New Orleans funk, soul, and second-line grooves that hits like humid midnight air—hypnotic, unstoppable, and deeply rooted in the city\'s street music tradition. Rhythmpourium regulars know this is where the festival\'s beating heart lives, and Jobin\'s crew delivers the kind of transcendent, sweat-soaked performance that reminds you why you came to Jazz Fest in the first place.'},
  { id: 'b456', name: "Debbie Davis and Friends"                                  , day: 'd6', stage: 'rhythm',     start: '16:45', end: '17:30', yt: 'JLLmOiqj-o0', verified: true , blurb: 'Debbie Davis and Friends bring infectious, feel-good soul and funk grooves that celebrate New Orleans\' rich tradition of celebration and community — expect horn-driven arrangements, tight rhythms, and the kind of joyful energy that gets the whole tent moving together.'},
  { id: 'b457', name: "KIPP New Orleans Regional High School Choir"               , day: 'd6', stage: 'children',   start: '11:30', end: '12:15', yt: '9xt9iCxkw-4', verified: true , blurb: 'KIPP New Orleans Regional High School Choir brings soaring harmonies and infectious joy to the Ochsner Children\'s Tent, blending gospel roots with contemporary arrangements that celebrate the region\'s rich vocal tradition. Their youthful energy and pristine ensemble work create the perfect introduction to New Orleans\' most soulful musical heritage for young listeners and families.'},
  { id: 'b458', name: "Jumping for Joy Double Dutch Club"                         , day: 'd6', stage: 'children',   start: '12:15', end: '13:15', yt: 'b3R8AkAYM-Y', verified: true , blurb: 'Jumping for Joy Double Dutch Club brings high-energy percussive magic and infectious rhythm to the Ochsner Children\'s Tent, blending traditional New Orleans bounce culture with acrobatic artistry that\'ll have kids and families moving in unison. This is pure joy in motion—a celebration of community, coordination, and the kind of infectious fun that makes Jazz Fest memories last forever.'},
  { id: 'b459', name: "Electric Yat Quartet featuring Andrè Bohren & Anne Chabreck “Peter present & the Wolf”", day: 'd6', stage: 'children',   start: '13:15', end: '14:05', yt: 'RcQ-ZpUYP4U', verified: true , blurb: 'Experience a playful collision of New Orleans tradition and modern imagination as Electric Yat Quartet transforms Prokofiev\'s beloved classic into a swinging, family-friendly adventure that proves jazz is the universal language of joy. André Bohren and Anne Chabreck lead this dynamic ensemble through a groovy reimagining that\'ll have kids and grown-ups alike moving to the irresistible blend of brass, rhythm, and pure New Orleans soul.'},
  { id: 'b460', name: "Jumping for Joy Double Dutch Club"                         , day: 'd6', stage: 'children',   start: '14:05', end: '15:05', yt: 'b3R8AkAYM-Y', verified: true , blurb: 'Jumping for Joy Double Dutch Club brings high-energy percussive magic and infectious rhythm to the Ochsner Children\'s Tent, blending traditional New Orleans bounce culture with acrobatic artistry that\'ll have kids and families moving in unison. This is pure joy in motion—a celebration of community, coordination, and the kind of infectious fun that makes Jazz Fest memories last forever.'},
  { id: 'b461', name: "Champagniacs!"                                             , day: 'd6', stage: 'children',   start: '15:05', end: '15:55', yt: 'o9wzdZvsK-s', verified: true , blurb: 'Champagniacs! brings bubbly brass-fueled funk and second-line swagger to the kids\' stage, turning the Ochsner Children\'s Tent into a celebration of New Orleans\' most infectious street parade energy. Jazz Fest families will groove on their infectious horn arrangements and playful spirit that proves the Crescent City\'s musical joy belongs to all ages.'},
  { id: 'b462', name: "Ellis Marsalis Center for Music Jazz Ensemble"             , day: 'd6', stage: 'children',   start: '16:20', end: '17:00', yt: 'p9uaae279Lg', verified: true , blurb: 'The Ellis Marsalis Center for Music Jazz Ensemble brings the Next Generation sound to the Fest with vibrant, education-focused jazz that honors New Orleans tradition while inviting young ears into the genre\'s infectious groove—perfect for families seeking authentic, joyful music that swings hard and welcomes everyone to dance.'},
  { id: 'b463', name: "Kevin “Sonny” Gullage Interviewer: John Wirt"              , day: 'd6', stage: 'miner',      start: '12:15', end: '13:00', yt: 'DjfrlPSlL8o', verified: true , blurb: 'Kevin "Sonny" Gullage brings authentic New Orleans soul to the Allison Miner stage, channeling the city\'s deep traditions of blues, R&B, and gospel with a voice that cuts straight to the heart—a must-see for anyone seeking the real roots of the New Orleans sound.'},
  { id: 'b464', name: "Original Koffee Interviewer: Joel Hitchcock"               , day: 'd6', stage: 'miner',      start: '13:15', end: '14:00', yt: 'F2-2RBi1qzY', verified: true , blurb: 'Original Koffee Interviewer Joel Hitchcock brings intimate acoustic storytelling and roots-forward authenticity to the Heritage Stage, blending New Orleans tradition with modern folk sensibility—a must-see for anyone seeking the real soul of the festival.'},
  { id: 'b465', name: "Ziggy Marley Interviewer: Jonathan McHugh"                 , day: 'd6', stage: 'miner',      start: '14:15', end: '15:00', yt: 'ikzQmC3S-mE', verified: true , blurb: 'Ziggy Marley carries the spiritual essence of reggae\'s greatest legacy into a living, breathing dialogue—backed by Jonathan McHugh\'s expert musicianship, this is roots music that talks back, blending island rhythms with soulful storytelling that only resonates deeper in New Orleans\' sacred ground.'},
  { id: 'b466', name: "Terence Blanchard + Ravi Coltrane Interviewer: Ashley Kahn", day: 'd6', stage: 'miner',      start: '15:15', end: '16:00', yt: 'UGIbpvKN3X4', verified: true , blurb: 'Witness a transcendent dialogue between two of jazz\'s most visionary saxophonists as Terence Blanchard and Ravi Coltrane explore the spiritual depths and harmonic frontiers that connect their legacies, guided by the legendary interviewer Ashley Kahn in an intimate musical conversation that bridges tradition and innovation. This rare meeting of minds at the Allison Miner Music Heritage Stage promises the kind of improvisational brilliance and ancestral wisdom that defines what Jazz Fest is really about.', members: 'Terence Blanchard, Ravi Coltrane, Ashley Kahn'},
  { id: 'b467', name: "Los Guiros Interviewer: Dan Sharp"                         , day: 'd6', stage: 'miner',      start: '16:15', end: '17:00', yt: '5M-_2opDzH0', verified: true , blurb: 'Los Guiros deliver authentic son jarocha rhythms and traditional Veracruz sensibilities with a modern pulse that honors New Orleans\' deep roots in Caribbean and Latin music traditions. Their infectious guitar interplay, layered percussion, and danceable grooves make them an unmissable set for anyone seeking the festival\'s true spirit of cultural exchange and cross-border musical kinship.'},

  // ───────── Sat May 2 (d7) ─────────
  { id: 'b468', name: "Honey Island Swamp Band"                                   , day: 'd7', stage: 'festival',   start: '11:15', end: '12:05', yt: 'i2nFpJhwt9M', verified: true , blurb: 'New Orleans, LA or San Francisco, CA– From the pristine waters of the Honey Island Swamp, to the vibrant streets of New Orleans, to the hazy corner of Haight-Asbury in San Francisco, this band has endured devastation, relocation, and revitalization. A group whose sound has been tagged “Bayou Americana,” the Honey Island Swamp Band takes the hammer to the nail with the help of producer Luther Dickinson, and presents Demolition Day to the world April 29 on Ruf Records. This album marks the 10-year anniversary of the Honey Island Swamp Band, which formed in San Francisco, CA via New Orleans after Hurricane Katrina displaced the founding members. With little hope of returning to their beloved city, the band channeled the blues and emotions of their circumstances to develop a soulful style and sound that critics have compared to legendary Blues-Roots-Rock Artists such as The Allman Brothers, Little Feat and The Band. Recording at the Parlor Studio in New Orleans, Honey Island Swamp Band teams up with producer/musician Luther Dickinson of the North Mississippi Allstars to capture a rhythm and a feel born straight from the heart of Americana. The album features a host of New Orleans finest musicians, including guest appearances by keyboardist Ivan Neville and Tab Benoit on pedal steel. “Their all encompassing sound of blues, roots, country, and soul has been described as “Bayou Americana.” – No Depression “We’ve always wanted to record to two-inch tape, to get that old analog sound,” says bandleader Aaron Wilkinson, “and this was our first opportunity to make it happen. Luther was the perfect producer to help us nail that old-school, authentic sound. He was great at keeping us focused on the spirit of each performance, not getting bogged down in details and perfectionism. That’s what we were looking for and what we needed.” After all, polish isn’t necessary when you’re working with songs this strong. Across its eleven cuts, Demolition Day tips a hat to most of the great American genres, while adding the Honey Island Swamp Band’s inimitable thumbprint. There’s the spring-heeled slide-blues of “Ain’t No Fun”, the upbeat funk of “Head High Water Blues”, the cat-house piano and country-fried guitars of “How Do You Feel”. But then, on the emotional flipside, there’s also the reflective wah-guitar lilt of “Say It Isn’t True”, the mournful funeral-jazz slow-burn of “No Easy Way” and the heart-in-mouth acoustic confessional of “Katie”. “We’re diverse and complex people,” explains Chris Mule, the band’s guitarist, “and our audiences are as well. So we try to let our music reflect that.” Drawing from their diverse backgrounds, the band’s lyrical content is quite colorful. “They really are all over the map,” Aaron explains of the topics explored on Demolition Day. “Some are rooted in reality and personal experience. “Head High Water Blues” is a look back at the Hurricane Katrina experience now that ten years has passed. Much has been rebuilt, but much has not and never will be – and the song is more about the emotional scars that can never be fully erased. Others are just fiction and storytelling. We had the music for “Through Another Day”, and it sounded sort of old and epic and Southern, and that inspired this Civil War-era storyline that became the lyrics. Others are just sort of playful nonsense about life and relationships, like “Watch And Chain.” Demolition Day is about rebuilding more than tearing down. It’s about a renewal of purpose, reflected through powerful lyrics and stories, great slide guitar on top of deep bass and rhythms that continue to move the foundation that the band was built upon. New Orleans has a deep well of music, and that well has no rules – the only boundaries are the ones that we place on ourselves. On Demolition Day, the Honey Island Swamp Band breaks these boundaries to deliver a sound so relevant and honest that even in the darkest of days – like the violent storm that brought this group of musicians together – Demolition Day still shines brightly.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41342/festivalartist-11953-artist_image-60f68bd4-47e0-4c2e-88c5-312c25a05451.jpg'},
  { id: 'b469', name: "J & The Causeways"                                         , day: 'd7', stage: 'festival',   start: '12:25', end: '13:20', yt: 'WgWSmnWlXGg', verified: true , blurb: 'New-Aged Original Soul band “J & The Causeways” were founded on a hot summer’s night in New Orleans at the Maple Leaf Bar by Lead Singer/Songwriter Jordan Anderson. He envisioned a group so infectiously authentic and soulful that the audience could practically feel it’s warm embrace at any given show. With stunning lead vocals, refined songwriting, a powerhouse rhythm section, and wonderfully intricate horn and guitar melodies, the group began sculpting a robust festival-style sound, winning over crowds at every step of the way. J & The Causeways have shared the stage with notable acts such as: The Revivalists, George Porter Jr., Better Than Ezra, Marc Broussard, Bonerama, Flow Tribe, Cowboy Mouth, Ivan Neville’s Dumpstaphunk, Tab Benoit, and others. J & The Causeways regularly perform at Maple Leaf Bar, Howlin Wolf, and the legendary Tipitina’s in their hometown of New Orleans. The goal of this band is to spread the value of love, connection, and positivity with new aged music tailored for the old soul!', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41574/festivalartist-12534-artist_image-bc2c0988-0540-425d-b54f-5df57900ec51.jpg'},
  { id: 'b470', name: "Wayne Toups"                                               , day: 'd7', stage: 'festival',   start: '13:40', end: '14:35', yt: 'RYRGoVpB-HI', verified: true , blurb: 'High-energy showman Wayne Toups has long been dubbed “The Cajun Springsteen,” and now holds the title of “Grammy Award Winner.” The Grammy Award caps a wave of recent career highs for Wayne Toups. In 2009, he earned an Album-of-the-Year award from Offbeat magazine. In 2010, he was inducted into the Louisiana Music Hall of Fame. In 2011, he entered both the Gulf Coast Hall of Fame and the Cajun French Music Hall of Fame. He is also a member of the Louisiana Blues Hall of Fame. This year will also mark his continued activism in the Coastal Vision Foundation, the organization dedicated to restoring America’s eroding ocean coastlines. “We are losing 2,400 acres a year in Louisiana, alone,” says Toups. Wayne Toups picked up the accordion at age 13 and hasn’t put it down since. He mixes Cajun sounds with the rhythms of zydeco, adding elements of soul music and Southern rock. He calls the revved-up result “ZyDecajun,” and his electrifying group, “a Cajun fusion band with a rock ‘n’ roll attitude.” He has recorded more than a dozen albums and toured to more than 20 countries. His songs have been heard on such film soundtracks as Steel Magnolias and Dirty Rice. Always in demand for session work in his native Louisiana, Wayne Toups has also been hired to back the British pop artist Thomas Dolby as well as many of the stars of Nashville, including Alan Jackson (“Little Bitty”), Clay Walker (“Live, Laugh, Love”), Mark Chesnutt (“It Sure Is Monday” and “Gonna Get a Life”), Sammy Kershaw, George Jones, Garth Brooks, Ty England and Mark Wills, to name a few. Toups says “We’ll be doing more than 100 shows this year. I’ve surrounded myself with some really good players, the band is better than ever.”', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41463/festivalartist-12278-artist_image-a5ee9f1f-4e5b-4a19-8363-492ce53a5d17.jpg'},
  { id: 'b471', name: "Anders Osborne"                                            , day: 'd7', stage: 'festival',   start: '15:00', end: '16:00', yt: 'LgqRp3v00xY', verified: true , blurb: 'At one point on his 2019 album, Buddha and The Blues, Anders Osborne sings, “Oh, it’s a miracle we still care. Oh, it’s so wonderful we’re still here. We’re still here!” He’s not going anywhere either… Osborne’s six-string virtuosity, inventive musicality, and poetic songcraft underpin an ever-expanding three-decade catalog celebrated by fans and critics alike. As a sought-after studio talent, his writing resounds through Keb Mo’s GRAMMY® Award-winning Slow Down, Tim McGraw’s number one “Watch The Wind Blow By,” and covers by Brad Paisley, Jonny Lang, Edwin McCain, Aaron Neville, and more. His output live and in the studio spans working with everyone from Eric Church, Toots and the Maytals, and John Scofield to The Meters, North Mississippi Allstars, and Galactic. His extensive touring history encompasses gigs, collaborations, and performances alongside everyone from Derek Trucks, Warren Haynes, and Stanton Moore to The Grateful Dead’s Phil Lesh and Jackie Greene. Not to mention, he lights up the screen on an episode of the HBO hit Treme. Plus, he has garnered acclaim from USA Today, Guitar Player, Relix, Offbeat, and more.'},
  { id: 'b472', name: "Eagles"                                                    , day: 'd7', stage: 'festival',   start: '16:45', end: '19:00', yt: 'sTuiAM2DM_E', verified: true , blurb: 'The Eagles are an American rock band formed in Los Angeles in 1971. They have sold more than 200 million records worldwide, including 100 million in the United States.'},
  { id: 'b473', name: "Mia Borders"                                               , day: 'd7', stage: 'shell',      start: '11:20', end: '12:20', yt: 'r-Nw7HbaeWY', verified: true , blurb: 'Born and raised in New Orleans, Mia Borders’ powerhouse vocals and charismatic songwriting have made her a perennial figure in the regional music scene. Heralded locally and nationally as one of the city’s best talents, Borders has been featured on AXS.tv’s coverage of The New Orleans Jazz & Heritage Festival, and has performed at such renowned venues as Essence Festival, Brazil’s Bourbon Street Music Festival, House of Blues New Orleans, Tipitina’s, Santa Cruz Blues Fest, Chattanooga’s Night Fall, Voice of the Wetlands, Memphis’ Levitt Shell, Wakarusa, Long’s Park Amphitheater, 2012 Food & Wine Classic, and The Kennedy Center for Performing Arts. She has shared bills with B.B. King, Corinne Bailey Rae, Lee Fields, and Marc Broussard, among others. Her live shows are regularly praised as “deeply funky” (USA Today) and “confident and cool” (The Times-Picayune). Borders herself is “a chanteuse of the highest order” with “miles of style and charisma” (AXS.com). Her expansive catalogue includes three EPs, various live albums, three singles, and six LPs – including 2016’s “completely authoritative” Fever Dreams (Offbeat Magazine). 2019 brings Borders’ latest self-produced EP, “Good Side of Bad,” released under Borders’ own label, Blaxican Records.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41536/festivalartist-12446-artist_image-61fad195-ef57-46f1-ac3e-86fe16b51e07.jpg'},
  { id: 'b474', name: "Corey Henry & The Treme Funktet"                           , day: 'd7', stage: 'shell',      start: '12:45', end: '13:45', yt: 'fhr5tevIO9s', verified: true , blurb: 'Corey Henry & The Treme Funktet bring the deep, soulful pocket of New Orleans funk and brass tradition to life, channeling generations of second line swagger and organ-driven grooves that\'ll have you moving before the first note ends. This is authentic Crescent City funk born from the streets—raw, joyful, and absolutely irresistible.'},
  { id: 'b475', name: "Leo Nocentelli of The Meters"                              , day: 'd7', stage: 'shell',      start: '14:10', end: '15:10', yt: 'BsE8uoXHayU', verified: true , blurb: 'Leo Nocentelli brings the deep funk grooves and precision guitar work that made The Meters legendary, delivering hypnotic New Orleans rhythms that\'ll have the whole stage moving as one. This is essential funk royalty—the sound that built the city\'s musical foundation and still makes every body on the floor lock into the same irresistible pocket.'},
  { id: 'b476', name: "Dumpstaphunk"                                              , day: 'd7', stage: 'shell',      start: '15:35', end: '16:50', yt: 'Nh1m3g_tFek', verified: true , blurb: 'Dumpstaphunk is a New Orleans funk band formed in 2002 and fronted by Ivan Neville.  Neville, a multi-instrumentalist, singer and songwriter, is the son of Aaron Neville and nephew to members of the Neville Brothers.'},
  { id: 'b477', name: "Alabama Shakes"                                            , day: 'd7', stage: 'shell',      start: '17:20', end: '19:00', yt: 'Le-3MIBxQTw', verified: true , blurb: 'Alabama Shakes is an American rock band formed in Athens, Alabama, United States in 2009. The group consists of lead singer Brittany Howard, guitarist Heath Fogg, bassist Zac Cockrell, and drummer Steve Johnson.'},
  { id: 'b478', name: "Dee-1"                                                     , day: 'd7', stage: 'congo',      start: '11:20', end: '12:25', yt: 'UJU35ayvFsQ', verified: true , blurb: 'Often described as “a mix between Lupe Fiasco and T.I.”, Dee-1 is one of the few Hip-Hop artists who specialize in making music that appeals to the masses without sacrificing an ounce of lyrical integrity.'},
  { id: 'b479', name: "Runkus & Royal Blu with Dub Squad"                         , day: 'd7', stage: 'congo',      start: '12:50', end: '13:50', yt: 'oSkrsTpag6Q', verified: true , blurb: 'Runkus & Royal Blu with Dub Squad bring a hypnotic blend of reggae roots, New Orleans funk, and electronic dub vibes that transform the Jazz Heritage Stage into a sonic celebration—where island rhythms meet Crescent City soul and the bass drops hit like a second line parade. This is the sound of New Orleans colliding with Caribbean consciousness: irresistible, forward-thinking, and made for moving bodies and open minds.'},
  { id: 'b480', name: "The Soul Rebels"                                           , day: 'd7', stage: 'congo',      start: '14:15', end: '15:30', yt: 'KcfAqKogSKk', verified: true , blurb: 'Brass sensation The Soul Rebels are riding high in 2019 after receiving national attention following the release of their new album, Poetry In Motion. In 2019, the eight-member collective appeared on Def Jam artist Dave East and Nas’ Godfather 4 single and reached sports fans with their song “Greatness”, featured as ESPN\'s official College Hoops season\'s theme anthem. The Soul Rebels have impressed late night viewers with an appearance on The Late Show with Stephen Colbert, featured on NPR\'s Tiny Desk series with Wu Tang Clan frontman GZA, headlined the global TED Conference, and appeared in and were featured on the official soundtrack for Universal Pictures\' hit comedy Girls Trip. On the heels of supporting The Wu Tang Clan and The Rolling Stones, The Soul Rebels continue to expand their international reach touring four continents including Europe, Australia, China, South Korea and Japan. Their explosive stage presence has led to live collaborations with the likes of Katy Perry, Nas, G-Eazy, DMX, Robin Thicke, Macy Gray, Portugal. The Man, Robert Glasper, Pretty Lights, Curren$y, Joey Bada$$, Talib Kweli, GZA, Macklemore & Ryan Lewis, Raekwon, Metallica, and Marilyn Manson among many others, and opening for Lauryn Hill and Nile Rodgers. The Soul Rebels started with an idea - to expand upon the pop music they loved on the radio and the New Orleans brass tradition they grew up on. They took that tradition and blended funk and soul with elements of hip hop, jazz and rock all within a brass band context. The band has built a career around an eclectic live show that harnesses the power of horns and drums in a deep pocket funk party-like atmosphere. The Soul Rebels continue to chart new territory as they feature in major films, tour globally, and combine topnotch musicianship with songs that celebrate dancing, life, funk and soul.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41401/festivalartist-12113-artist_image-8c6128f2-16b7-4b62-818d-d320ce1d4f19.jpg'},
  { id: 'b481', name: "DJ Jess"                                                   , day: 'd7', stage: 'congo',      start: '15:30', end: '16:10', yt: 'mYtkV3EV8u0', verified: true , blurb: 'DJ Jess spins a hypnotic blend of contemporary electronic production and deep house grooves rooted in New Orleans\' underground dance culture, bringing forward-thinking beats that honor the city\'s legacy of sonic innovation. Her sets at Congo Square Stage are a celebration of Black joy and experimental sound design—expect infectious rhythms, ethereal synths, and the kind of transcendent energy that keeps the crowd moving from sunrise to sunset.'},
  { id: 'b482', name: "Big Freedia"                                               , day: 'd7', stage: 'congo',      start: '16:10', end: '17:15', yt: 'bHNiNP3hDkU', verified: true , blurb: 'Known as the Queen of Bounce music, Big Freedia is New Orleans-based hip-hop artist and worldwide ambassador of bounce music. After a series of cult hit singles during the mid 2000’s, she was tapped for a reality show, Big Freedia Bounces Back on Fuse TV. The docuseries followed the life of a choirboy turned bounce rapper and remains the highest rated original series on the network. It was only a matter of time until Big Freedia caught the attention of iconic artists including Beyoncé and Drake. She was featured on both Beyoncé’s Grammy-winning single, “Formation” and Drake’s “Nice For What.” Big Freedia released the critically acclaimed album, ‘3rd Ward Bounce’ (which featured Lizzo among others) on Asylum Records in 2018. In the summer of 2019, the Queen of Bounce debuted her limited run ice cream flavor ‘Big Freedia’s Bouncin’ Beignets’ with the ice cream giant Ben & Jerry’s. She graced the cover of Billboard Magazine, and was invited by Vogue Magazine to be the official host of the Iive Instagram stream for the Met Gala. In October 2019, Big Freedia and multi-platinum pop artist Kesha released their new pop single “Raising Hell.” The song remains on the pop radio charts and the two performed the hit song on Jimmy Kimmel LIVE! Big Freedia’s latest single “Louder” from her forthcoming project dropped in November. She is also the author of the critically acclaimed memoir, Big Freedia: God Save the Queen Diva! on Gallery Books/Simon & Schuster.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41368/festivalartist-12027-artist_image-aae4c416-bb9b-43d6-a973-a318a82cb402.jpg'},
  { id: 'b483', name: "DJ Jess"                                                   , day: 'd7', stage: 'congo',      start: '17:15', end: '17:55', yt: 'mYtkV3EV8u0', verified: true , blurb: 'DJ Jess spins a hypnotic blend of contemporary electronic production and deep house grooves rooted in New Orleans\' underground dance culture, bringing forward-thinking beats that honor the city\'s legacy of sonic innovation. Her sets at Congo Square Stage are a celebration of Black joy and experimental sound design—expect infectious rhythms, ethereal synths, and the kind of transcendent energy that keeps the crowd moving from sunrise to sunset.'},
  { id: 'b484', name: "T-Pain"                                                    , day: 'd7', stage: 'congo',      start: '17:55', end: '18:55', yt: 'Lt2wjJlP2N4', verified: true , blurb: 'Faheem Rasheed Najm (born September 30, 1985 in Tallahassee, Florida), better known by his stage name T-Pain, is a prolific American singer, producer, and writer.'},
  { id: 'b485', name: "UNO Jazz All-Stars"                                        , day: 'd7', stage: 'jazz',       start: '11:15', end: '12:00', yt: 'wFVHcIha4Tc', verified: true , blurb: 'UNO Jazz All-Stars delivers the authentic voice of New Orleans\' next generation, blending bebop sophistication with deep funk grooves that honor the city\'s lineage while pushing boldly forward. Jazz Fest devotees crave exactly this—the sound of tradition alive in young hands, where technical mastery meets the soulful swagger that only this city breeds.'},
  { id: 'b486', name: "James Jordan and The Situation"                            , day: 'd7', stage: 'jazz',       start: '12:20', end: '13:10', yt: 'o4UcZvlGAFo', verified: true , blurb: 'James Jordan and The Situation bring a sharp, contemporary take on New Orleans jazz tradition, blending sophisticated harmonies with infectious grooves that honor the city\'s legacy while pushing boldly forward. This is the sound that keeps jazz vital and unpredictable—exactly what Jazz Fest devotees crave.'},
  { id: 'b487', name: "Jeremy Davenport"                                          , day: 'd7', stage: 'jazz',       start: '13:30', end: '14:25', yt: 'MdOeM-97n0M', verified: true , blurb: 'Trumpeter/vocalist Jeremy Davenport was born May 4, 1970 in St. Louis, Missouri. Raised in a musical family by a music educator mother, and trombonist father who’s been a member of the St. Louis Symphony for forty five years, Jeremy seemed pre-destined to challenge the bounds of his musical heritage. While in high school, Jeremy studied with members of the St. Louis Symphony, including trumpeter, Susan Slaughter. In the eight grade his father would arrange an auspicious introduction to trumpet idol Wynton Marsalis that would change his life forever. A merit scholar at the prestigious Manhattan School of music, Davenport began private study with Raymond Mase and Wynton Marsalis. He went on to study at the University of New Orleans with the patriarch of the Marsalis family, music educator and jazz pianist Ellis Marsalis. His talents flourished swiftly under such renowned tutelage. His craftsmanship and tireless work ethic became indisputable and he was honored to become the youngest performer on four world tours with Harry Connick Jr.’s Big Band. Currently he can be found performing multiple international Jazz festivals and special events with his own band. Jeremy specializes in a unique genre of jazz that captures the improvisational and spontaneous facets of this truly American art form. A devout fan of storytelling standards of past ages, Mr. Davenport pushes the boundaries of modern jazz stereotypes while celebrating the song-and-dance element that inspires romantics worldwide. Jeremy’s most recent recording, “We’ll Dance ‘Til Dawn” is available on the Basin Street Records label. You can catch Jeremy Davenport at The Davenport Lounge in the Ritz-Carlton New Orleans on Wednesday, Thursday, Friday & Saturday evenings.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41373/festivalartist-12038-artist_image-a35e6f03-0a4d-4edc-815b-73b0fde5f2e8.jpg'},
  { id: 'b488', name: "Alexey Marti & Sugarflow"                                  , day: 'd7', stage: 'jazz',       start: '14:50', end: '15:50', yt: 'otnfWe1syJg', verified: true , blurb: 'Alexey Marti & Sugarflow blend sophisticated jazz harmonies with infectious New Orleans groove, delivering the kind of fluid, soulful sound that makes you move without thinking. This is modern jazz with deep roots—where technical mastery meets the unbridled joy that defines the Jazz Fest experience.'},
  { id: 'b489', name: "Dianne Reeves"                                             , day: 'd7', stage: 'jazz',       start: '16:15', end: '17:30', yt: '7M4kX6LWmX4', verified: true , blurb: 'Dianne Reeves, born 23 October 1956 in Detroit, Michigan, is an American jazz singer, known more for her live performances than her albums. Alongside her peers Dee Dee Bridgewater, Diana Krall and Cassandra Wilson she is considered one of the most important female jazz singers of our time.'},
  { id: 'b490', name: "Delfeayo Marsalis & The Uptown Jazz Orchestra"             , day: 'd7', stage: 'jazz',       start: '18:00', end: '19:00', yt: 'RH9GC9fcyiw', verified: true , blurb: 'Delfeayo Marsalis & The Uptown Jazz Orchestra deliver deep, soulful New Orleans jazz rooted in tradition yet alive with contemporary energy—a masterclass in ensemble interplay where horn sections soar and rhythm sections lock in tight. This is jazz that honors the city\'s legacy while pushing forward, exactly what Jazz Fest devotees come to hear.'},
  { id: 'b491', name: "John Mooney & Bluesiana"                                   , day: 'd7', stage: 'blues',      start: '11:20', end: '12:15', yt: 'brcZ6CDpR5Q', verified: true , blurb: 'Throughout the years John Mooney has developed one of the most distinctive and easily identifiable guitar and vocal signatures of anyone alive today. Part of the original impetus for his interest in music may have filtered down from his grandfather, a musician himself. “He used to play the mandolin and banjo back in the 20’s” says Mooney. “He even cut a couple of 78’s for the Peerless label that I’ve heard. It was really hot stuff, a kind of raggy jazz.“ John left home at 15 and began playing with Joe Beard at about that same time. Joe introduced him to the first and most enduring influence on the development of Mooney’s music, the legendary Delta blues singer, Ed “Son” House. Impressed by the 16 year old musician’s talent, Son and John soon became friends. “I wasn’t aware of what the opportunity meant, but I knew there was nobody better in Delta blues.“ Mooney cites Son’s heavily rhythmic style having a strong influence on him. In fact, the way Mooney adapts acoustic playing to a modern electric format is one of his most distinctive trademarks. In 1976 John moved to New Orleans and immersed himself in that city’s vibrant music scene. John regularly played with the likes of Earl King, The Meters, Snooks Eaglin, and the man who was to influence his music greatly, the father of New Orleans piano, Professor Longhair. He was playing regularly in front of New Orleans drummers like Zigaboo Modeliste, John Vidacovich, and Herman Ernest. At this place in time John successfully combined the sounds of the delta with the syncopated rhythms of the Crescent City to create the style that has become uniquely his own. Since 1981 he has been touring with his group, the Bluesiana Band, performing throughout the U.S., Canada, Panama, Europe, Australia, and Japan. After the loss of long time friend and band member Jeff Sarli, Mooney has called upon Rene Coman of the Iguanas for Bluesiana Bass rhythms and renowned New Orleans drummer Kevin O’Day to keep the beat. Over the years John and his band have earned a musical reputation that have gained them invitations to play at numerous folk, jazz, and blues festivals across the globe, including the Montreaux Jazz Festival, the Newport Folk Festival, the Chicago Blues Festival, and a yearly appearance at New Orleans’ world renowned Jazz & Heritage Festival. In 2000 Mooney released “Gone to Hell,” with special guest Dr. John adding some extra spice. The critics welcomed this comeback with open arms and high praise. Blues Access called the album “a seductive musical cocktail that leaves you deliriously drunk with pleasure every time.“ Blues Revue wrote, ”‘Gone to Hell’ bumps, grinds, and simmers with the emotional intensity of a musician who plays directly from his soul to yours.” His newest disc, “Big Ol’ Fiya” with special guest Jon Cleary has been a long time coming but Mooney has brought some profound musical styles and songwriting to his signature syncopated delta blues sound. If there was ever a Mooney CD to own, this one is truly it. By far his most heartfelt, intimate, soulful and incredibly intricate vocals, this is a John Mooney album that is simply like none other.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41374/festivalartist-12040-artist_image-36f4d4e6-7442-4472-a7f9-21e8551299e6.jpg'},
  { id: 'b492', name: "C.J. Chenier & the Red Hot Louisiana Band"                 , day: 'd7', stage: 'blues',      start: '12:40', end: '13:40', yt: 'wNSuw186Bpo', verified: true , blurb: 'C. J. Chenier (born Clayton Joseph Thompson, September 28, 1957, Port Arthur, Texas, is the Creole son of the Grammy Award winning "King of Zydeco", Louisiana musician, Clifton Chenier.'},
  { id: 'b493', name: "Eric Lindell"                                              , day: 'd7', stage: 'blues',      start: '14:05', end: '15:15', yt: '8jyt4tpYL3U', verified: true , blurb: 'Eric Lindell is an American singer-songwriter, born in San Mateo, California in 1969. He is best-known for his 2008 album Low on Cash, Rich In Love and the single from it, "Lay Back Down.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/42357/festivalartist-12367-artist_image-b98913bd-8ffb-4efe-86bb-53b2f4e29a37.jpg'},
  { id: 'b494', name: "Larry McCray"                                              , day: 'd7', stage: 'blues',      start: '15:45', end: '17:00', yt: '2mVzXsEJgjA', verified: true , blurb: 'If contemporary blues has a longterm future as we boldly venture into the 21st century, it\'s very likely that guitarist Larry McCray will play a recurring role in its ongoing development.'},
  { id: 'b495', name: "Little Feat"                                               , day: 'd7', stage: 'blues',      start: '17:30', end: '19:00', yt: '3z-GwdaKrn8', verified: true , blurb: 'Little Feat is an American band who have mixed blues, R&B, country, and rock and roll styles together since they formed in 1969 in Los Angeles, and are known for their eclectic blend of many forms of music.'},
  { id: 'b496', name: "Jacky Blaire & The Hot Biscuits"                           , day: 'd7', stage: 'economy',    start: '11:15', end: '12:05', yt: '9Ajx42qK25o', verified: true , blurb: 'Jacky Blaire & The Hot Biscuits bring the swaggering, horn-driven sound of New Orleans R&B and funk straight to Economy Hall, where gritty grooves and infectious brass arrangements get the whole tent moving. These cats deliver the kind of down-home soul and second-line spirit that reminds you exactly why Jazz Fest exists—to celebrate the real New Orleans sound that makes you dance whether you planned to or not.'},
  { id: 'b497', name: "The Paulin Brothers Brass Band"                            , day: 'd7', stage: 'economy',    start: '12:25', end: '13:25', yt: 'Nv_jCaViGzQ', verified: true , blurb: 'The Paulin Brothers Brass Band brings the raw, unfiltered soul of New Orleans brass tradition to the Economy Hall Tent with their blazing horns and infectious second-line swagger—this is the sound that built the city\'s streets, delivered with infectious energy that\'ll have you moving whether you planned to or not.'},
  { id: 'b498', name: "Mark Braud's New Orleans Jazz Giants"                      , day: 'd7', stage: 'economy',    start: '13:45', end: '14:45', yt: 'RjhmbqreVqA', verified: true , blurb: 'Mark Braud\'s New Orleans Jazz Giants deliver the unvarnished, swinging soul of traditional New Orleans jazz—the kind that echoes through the Marigny streets and Economy Hall\'s storied walls. Their sound is pure ensemble interplay, where horns lock and unlock with hypnotic groove, drawing you back to the golden age while keeping you absolutely present.'},
  { id: 'b499', name: "Tribute to Jelly Roll Morton's Red Hot Peppers featuring Dr. Michael White and Shaye Cohn", day: 'd7', stage: 'economy',    start: '15:05', end: '16:05', yt: 'VkQyXmAJeFU', verified: true , blurb: 'Experience the scorching New Orleans jazz lineage as Dr. Michael White and Shaye Cohn resurrect the compositional genius of Jelly Roll Morton\'s Red Hot Peppers, delivering clarion-bright ensemble playing and rollicking rhythms that capture early jazz\'s raw innovation and street-level swagger. This is foundational New Orleans jazz at its most authentic and thrilling—the sound that built the city\'s musical soul.'},
  { id: 'b500', name: "Leroy Jones & New Orleans' Finest"                         , day: 'd7', stage: 'economy',    start: '16:30', end: '17:20', yt: 'Aq0Mt-jro18', verified: true , blurb: 'The legendary jazz trumpeter Leroy Jones is known to music lovers as the "keeper of the flame" for traditional New Orleans jazz and to critics as one of the top musicians ever produced by the Crescent City. "The mission of the Leroy Jones Quintet is to expose audiences everywhere to the authentic music of New Orleans, the music of Louis Armstrong, Buddy Bolden, Danny Barker and all the other greats who have helped create the rich gumbo that is the sound of New Orleans," he says, "while putting our own more modern stamp on it." Jones himself, a native of New Orleans, whose playing has been described as a blend of Louis Armstrong and bebop virtuoso Clifford Brown, has been a critical figure in the history of New Orleans music. A member of the New Orleans Jazz Hall of Fame, he was leader at the tender age of 12, of the seminal Fairview Band, a brass band whose alumni have included some of the best known musicians in New Orleans. It was the Fairview Brass Band which is widely credited with restoring interest in the brass band tradition of New Orleans. Today, in fact, New Orleans has more brass bands performing than at any time in the city\'s history – an achievement that can be traced back directly to the Fairview Band and its successor the Leroy Jones Hurricane Brass Brand. A regular at Preservation Hall in New Orleans and a featured performer in the Harry Connick Orchestra, where his playing and singing have made him a crowd favorite, Leroy has performed on every continent and in every major U.S. city at prestigious theaters, festivals and jazz clubs like the Village Vanguard in New York City. His television appearances include The Tonight Show, Good Morning America, Late Night with David Letterman, The Today Show, Arsenio Hall, Conan O\'Brien and Oprah Winfrey. He is also a regular at the world famous New Orleans Jazz and Heritage Festival, as well as French Quarter Fest and the Satchmo Summerfest. He has also appeared on the soundtrack of the smash hit movie "Sleepless in Seattle" starring actor Tom Hanks. Leroy has released a series of highly regarded CDs including "Props for Pops" his tribute to Louis Armstrong, "Back to My Roots," "Mo\' Cream from the Crop", "Soft Shoe" and "Sweeter Than A Summer Breeze". He has appeared on numerous recordings with other artists such as Dr. John, the Preservation Hall Jazz Band, Anders Osborne, Chuck Carbo, Spirit of New Orleans, John Boutté, Lillian Boutté, Paul Sanchez, Danish Radio Big Band, Guillaume Nouaux and many, more others. "The Leroy Jones Quintet sound sums up all those great experiences and influences," says Leroy, "and gives me a chance each night to make sure that the great music of New Orleans is performed authentically and with great respect for the artists who came before me. Not in an old-fashioned way, but with a modern swing that comes from my love of bebop and other forms of modern jazz." A typical set list for the Leroy Jones Quintet includes traditional numbers like "Bourbon Street Parade," "Sleepy Time Down South," "Basin Street Blues," "Do You Know What it Means (to Miss New Orleans)," "Dinah" and "When My Dreamboat Comes Home" along with his own compositions like "Soft Shoe" that are played and sung impeccably by Jones with the kind of swing that only a musician with his pedigree can deliver consistently night after night.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41550/festivalartist-12466-artist_image-b5f92c08-fab9-48db-8a79-455543f03062.jpg'},
  { id: 'b501', name: "Twisty River Band"                                         , day: 'd7', stage: 'economy',    start: '17:40', end: '18:35', yt: '8VpOEsExI4k', verified: true , blurb: 'Twisty River Band brings a fluid, shape-shifting blend of traditional New Orleans jazz, funk, and soul that keeps audiences moving and grooving through every set at Economy Hall. Their intuitive interplay and deep roots in the city\'s musical traditions make them essential viewing for anyone seeking the authentic, anything-can-happen spirit that defines Jazz Fest.'},
  { id: 'b502', name: "Yvette Landry & the Jukes"                                 , day: 'd7', stage: 'fais',       start: '11:15', end: '12:05', yt: 'K3rW9ZLqKMw', verified: true , blurb: 'Yvette Landry & the Jukes bring authentic Louisiana swamp pop and zydeco heat to the Fais Do-Do stage, where their accordion-driven grooves and infectious energy get the whole crowd moving in that irresistible New Orleans way. If you\'re craving real bayou soul with dancing in mind, this is the sound that makes Jazz Fest legendary.'},
  { id: 'b503', name: "Savoy Family Cajun Band"                                   , day: 'd7', stage: 'fais',       start: '12:25', end: '13:20', yt: 'ncOQACVViyk', verified: true , blurb: 'The Savoy Family Cajun Band brings the spirited, accordion-driven sound of deep Cajun country to the Fais Do-Do Stage, blending traditional bayou rhythms with infectious energy that gets the whole crowd dancing. Rooted in authentic Louisiana heritage and multigenerational musicianship, they\'re the perfect reason to kick off your boots and embrace the dancing, sweating, joyful soul of Jazz Fest.'},
  { id: 'b504', name: "Leyla McCalla"                                             , day: 'd7', stage: 'fais',       start: '13:40', end: '14:35', yt: 'czmaR4wVqoQ', verified: true , blurb: 'Leyla McCalla finds inspiration from her past and present, whether it is her Haitian heritage or her adopted home of New Orleans, she — a bilingual multi-instrumentalist, and alumna of Grammy award-winning African-American string band, the Carolina Chocolate Drops — has risen to produce a distinctive sound that reflects the union of her roots and experience. Deeply influenced by Creole music, as well as by American jazz and folk, McCalla’s music is at once earthy, elegant, soulful and witty — it vibrates with three centuries of history, yet also feels strikingly fresh, distinctive and contemporary. In her most recent release and third solo album, The Capitalist Blues (2019), McCalla processed the current political environment in her own way, by sonically blending New Orleans music and Haitian jazz, with lyrics sung in English, French and Haitian Creole. The album “imaginatively maps her vision of the Afro-Caribbean diaspora while gently taking Anglocentricism (and capitalism) down a notch,” said NPR. “She\'s partly in the moment and partly looking beyond it, and seeing truths that we\'ve missed.” McCalla’s widely-acclaimed collaborative project, Songs of Our Native Daughters (Rhiannon Giddens, Amythyst Kiah, Leyla McCalla, and Allison Russell), released via Smithsonian Folkways in 2019. The album pulled influence from past sources to create a reinvented slave narrative, confronting sanitized views about America’s history of slavery, racism, and misogyny from a powerful, modern black female perspective. She is currently working on her newest project, Breaking the Thermometer to Hide the Fever, a multidisciplinary performance commissioned by Duke Performances that delves into the legacy of Radio Haiti, Haiti’s first privately owned Creole-speaking radio station, through its archive housed at the Rubenstein Library at Duke University. Leyla’s music reflects her eclectic and diverse life experiences, projecting a respect for eloquent simplicity that is rarely achieved.'},
  { id: 'b505', name: "The Revelers"                                              , day: 'd7', stage: 'fais',       start: '14:55', end: '15:50', yt: 'QzSbql15FMs', verified: true , blurb: 'The Ultimate Louisiana supergroup - The Revelers have been bringing their party around the world for nearly 10 years. With their long-awaited follow up to 2016\'s Grammy nominated record out Fall 2019 - the band has taken their place firmly at the top of a game where they make the rules.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41411/festivalartist-12141-artist_image-ef2cfaf8-5dd1-45e0-b63b-ba295cbbfa7e.jpg'},
  { id: 'b506', name: "Sierra Hull"                                               , day: 'd7', stage: 'fais',       start: '16:20', end: '17:35', yt: 'sFIQgPAms88', verified: true , blurb: 'Sierra Dawn Hull is an American bluegrass singer, mandolinist, and guitarist. Hull was signed to Rounder Records at the age of 13 and released her debut vocal album, Secrets, in 2008 at the age of 16.'},
  { id: 'b507', name: "Nathan & The Zydeco Cha Chas"                              , day: 'd7', stage: 'fais',       start: '18:00', end: '19:00', yt: 'nlm1Y68fFkw', verified: true , blurb: 'Nathan Williams is the leader of the Zydeco Cha Chas. His stylings on the piano accordion have made him one of the most-admired players in the zydeco scene, following in Clifton Chenier\'s and Buckwheat Zydeco\'s huge footsteps. Nathan Williams was the youngest of seven children and grew up in St. Martinville, LA. Times were hard for the Williams family and Nathan Williams lost his father when he was only seven years old. Williams grew up admiring his uncle, Harry Hypolite, who is best-known for his guitar work with Clifton Chenier. Later in life, Williams moved to Lafayette to live with his older brother, Sid Williams, and his wife. He worked in Sid\'s grocery store and began practicing on the accordion and practiced in the bathroom because he didn\'t want anyone to hear him play. With the aid of one of his friends, Buckwheat Zydeco, and steady hard work, it was not long before he was playing for people. Just five years after graduating from high school, he was recording 45s on his brother\'s El Sid indie record label. He got his lucky break when Buckwheat Zydeco left Rounder Records for Island Records, leaving Rounder in need of an accordion player to fill a slot on a project they had lined up. Buckwheat Zydeco suggested Nathan Williams for the spot and he auditioned and got the job. In the year 2000, Williams released his seventh album for Rounder Records, Let\'s Go! The Zydeco Cha Chas members include Dennis Paul Williams as guitarist, Allen "Cat Roy" Broussard on alto and tenor saxophones, Wayne Burns on bass, Mark Anthony Williams on rubboard, and Gerard St. Julien, Jr. on drums. Special guest artist on the 2000 release was tenor saxophonist Derek Huston and Scott Billington played harmonica and produced the album. With Nathan & the Zydeco Cha Chas, fame and fortune take a back seat to the music they play. They want to bring zydeco and traditional Louisiana Cajun music to the attention of mainstream music listeners. They believe that the energy and up-tempo Louisiana music has been regionalized for far too long and is due for international and worldwide acclaim. As one listens to their music, it is easy to agree that the time has come for the world to be introduced to the best-kept secret in the music world.'},
  { id: 'b508', name: "Big Chief Bird & the Young Hunters Black Masking Indians"  , day: 'd7', stage: 'heritage',   start: '11:20', end: '12:00', yt: 'a1RiLC0MwV0', verified: true , blurb: 'Big Chief Bird & the Young Hunters Black Masking Indians bring the raw spiritual power of New Orleans Mardi Gras Indian tradition to the Jazz & Heritage Stage, blending deep-pocket funk grooves, call-and-response vocals, and layers of percussion that pulse with the soul of the city\'s most sacred street culture. Their sound is a living bridge between second-line revelry and contemporary funk—hypnotic, ceremonial, and irresistibly danceable.'},
  { id: 'b509', name: "Storyville Stompers Brass Band"                            , day: 'd7', stage: 'heritage',   start: '12:20', end: '13:20', yt: 'Juoae0lHVUE', verified: true , blurb: 'Started as a group of friends who had a love of traditional, New Orleans music, the Storyville Stompers have grown to become one of the preeminent brass bands in the nation, having played throughout the US, Europe, South America and Asia. The band continues to play New Orleans-music in the traditional style, a music considered the foundation for traditional Jazz and Dixieland. It was once written that, "The Storyville Stompers are an integral part of the brass band scene with a big fat sound and plenty of spirit ... the group is one of a handful of ensembles carrying on the tradition with a repertoire of classic jazz tunes too rarely heard these days." The band plays regularly at weddings, second lines and parades, conventions, festivals, concerts, airport greetings, receptions, parties, and any other function that warrants celebration. With numerous nominations, the Storyville Stompers were awarded "Best Traditional Brass Band" in 2010 & 2011 by Big Easy Music Awards. The band is acoustic and able to play in almost any setting. From the stages of major festivals to the grand ballrooms of the finest hotels; from paddle wheel riverboats to the streets of the city, the Storyville Stompers have been heard, enjoyed, and danced to by thousands. Whether you desire a large stage band, a parade band, or a smaller intimate band, the Storyville Stompers can provide quality New Orleans entertainment to fit the occasion. In its 30 years, one New Orleans tradition that the Storyville Stompers helped to perpetuate is the colorful second-line parade when audiences dance behind the strolling brass band waiving handkerchiefs or twirling decorated umbrellas, becoming part of a festive entourage. The grand marshal, clad in crisp tuxedo, sash and matching umbrella, leads the band and everybody dances. In addition, the traditional New Orleans Jazz Funeral is a part of the fabric and rich cultural traditions of New Orleans and the Storyville Stompers have continued this tradition as a means of celebrating the life of loved ones with a class and dignity. Some of the band\'s performances over the past thirty years have included: New Orleans Jazz and Heritage Festival; the French Quarter Festival; the Macau International Jazz Festival in Macau, China; Kobe Urban Resort Jazz Festival in Kobe Japan; Carnival Ambrosiana in Milan, Italy; Guayaquil Jazz Festival in Guayaquil, Ecuador; First Lady Hillary Clinton\'s Congressional Luncheon in Washington, D.C.; the Sugar Bowl; the King\'s Float in world famous Bacchus and Orpheus Mardi Gras Parades; Louisiana Mardi Gras Ball in Washington D.C.; Satchmo Summer Fest in New Orleans, Louisiana; as a house band on "Live with Regis and Kelly"; hundreds of national conventions; and numerous other events worldwide.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41499/festivalartist-12370-artist_image-52ad6c41-b6b3-47e5-9812-f24fd5c1976f.jpg'},
  { id: 'b510', name: "Jemere Morgan"                                             , day: 'd7', stage: 'heritage',   start: '13:45', end: '14:45', yt: 'tWe3AaV4tTg', verified: true , blurb: 'Jemere, son of Gramps Morgan has now branched out into the music business like many of his relatives before him. According to Jemere, it was his father who discovered his talent.'},
  { id: 'b511', name: "Bill Summers & Jazalsa"                                    , day: 'd7', stage: 'heritage',   start: '15:10', end: '16:05', yt: 'e3btpGZLRiU', verified: true , blurb: 'Bill Summers & Jazalsa bring the irresistible groove of Afro-Cuban jazz and Latin percussion to the Jazz & Heritage Stage, blending tumbao rhythms with soulful horn arrangements that get the whole grounds moving. This is the sound that makes Jazz Fest what it is—infectious, worldly, and built for dancing.'},
  { id: 'b512', name: "Midnite Disturbers"                                        , day: 'd7', stage: 'heritage',   start: '16:25', end: '17:15', yt: '5SuZUYdBz-c', verified: true , blurb: 'Midnite Disturbers bring the raw, syncopated backbone of New Orleans R&B and funk to the Jazz & Heritage Stage—a high-octane blend of greasy grooves, tight horn arrangements, and that unmistakable late-night swagger that defines the city\'s underground soul. Their infectious energy and deep roots in New Orleans\' traditions make them a must-catch for anyone seeking the real, unvarnished heartbeat of the festival.'},
  { id: 'b513', name: "Hardhead Hunters Mardi Gras Indians"                       , day: 'd7', stage: 'heritage',   start: '17:40', end: '18:35', yt: '-s8EC1Xh3I4', verified: true , blurb: 'The Hardhead Hunters bring the raw, percussive swagger of Mardi Gras Indian tradition to the Jazz & Heritage Stage, layering hypnotic chants, thunderous drums, and brass flourishes into a sound that\'s pure New Orleans soul—this is the living heartbeat of the city\'s most iconic cultural legacy, and Jazz Fest devotees won\'t want to miss it.'},
  { id: 'b514', name: "Archdiocese of New Orleans Choir"                          , day: 'd7', stage: 'gospel',     start: '11:10', end: '11:50', yt: 'gD1fNoCcaxk', verified: true , blurb: 'The Archdiocese of New Orleans Choir brings transcendent spiritual power to the Gospel Tent with soaring harmonies rooted in the city\'s deep Catholic and African American musical traditions, blending classical hymnal grandeur with soul-stirring contemporary gospel that\'ll lift your spirit skyward.'},
  { id: 'b515', name: "Akia Nevills & Grace Unlimited"                            , day: 'd7', stage: 'gospel',     start: '12:00', end: '12:45', yt: 'UxRexhPPyQU', verified: true , blurb: 'Akia Nevills & Grace Unlimited bring authentic, soul-stirring gospel to the Jazz Fest stage with a contemporary sound rooted in New Orleans\' rich spiritual tradition. Their powerful vocals and dynamic arrangements blend traditional hymns with modern energy, creating an uplifting experience that celebrates faith, community, and the transformative power of music.'},
  { id: 'b516', name: "Pastor Mitchell Stevens"                                   , day: 'd7', stage: 'gospel',     start: '12:55', end: '13:35', yt: 'qq6sClgSpQs', verified: true , blurb: 'Pastor Mitchell Stevens brings soul-stirring traditional and contemporary gospel to the Gospel Tent with a voice that channels decades of New Orleans spiritual tradition, backed by infectious organ and horn arrangements that\'ll have you on your feet. His infectious energy and deep connection to the faith community make him an essential Jazz Fest experience for anyone seeking authentic, heart-filled music.'},
  { id: 'b517', name: "Felicia E. Travis"                                         , day: 'd7', stage: 'gospel',     start: '13:45', end: '14:30', yt: 'wK_4-mb8wVQ', verified: true , blurb: 'Felicia E. Travis brings soulful, spirit-filled vocals to the Gospel Tent with a powerful blend of traditional gospel and contemporary soul that celebrates faith, resilience, and joy—a must-see for anyone seeking authentic New Orleans spirituality and unshakeable vocal prowess.'},
  { id: 'b518', name: "The City of Love Worship"                                  , day: 'd7', stage: 'gospel',     start: '14:40', end: '15:25', yt: 'oCAY_qeDo-w', verified: true , blurb: 'The City of Love Worship brings transcendent joy and soul-deep grooves to the Gospel Tent, blending traditional New Orleans spiritual fervor with contemporary praise that\'ll have you on your feet and moved to tears. Their infectious energy and devotional authenticity capture everything Jazz Fest celebrates—the sacred heart of this city\'s music and faith.'},
  { id: 'b519', name: "The Gospel Soul of Irma Thomas"                            , day: 'd7', stage: 'gospel',     start: '15:50', end: '16:50', yt: 'K_0eBu9r6KQ', verified: true , blurb: 'Irma Thomas commands the Gospel Tent with her legendary soul voice and deep roots in New Orleans R&B and spiritual tradition, delivering transcendent performances that bridge sacred and secular with raw emotional power. Her timeless contralto and unshakeable conviction make her a festival favorite for anyone seeking authentic soul music rooted in the city\'s most cherished musical heritage.'},
  { id: 'b520', name: "Jermaine Landrum & The Abundant Praise Revival Choir"      , day: 'd7', stage: 'gospel',     start: '17:05', end: '17:50', yt: '51R5laxQWSo', verified: true , blurb: 'Jermaine Landrum & The Abundant Praise Revival Choir bring electrifying spiritual energy and deep-rooted New Orleans gospel tradition to the Gospel Tent, blending contemporary praise with classic soul power that\'ll lift your spirit and move your feet. Their joyful, choir-driven sound celebrates faith with infectious grooves and unshakeable conviction—the kind of transcendent moment that makes Jazz Fest sacred ground.'},
  { id: 'b521', name: "Franklin Avenue Baptist Church Mass Choir"                 , day: 'd7', stage: 'gospel',     start: '18:00', end: '18:45', yt: '8fATFoxTPEc', verified: true , blurb: 'The Franklin Avenue Baptist Church Mass Choir brings the soul-shaking power of traditional New Orleans gospel, with rich harmonies and jubilant energy that\'ll have you on your feet celebrating faith, community, and the unshakeable spirit that built this city. Their deeply rooted devotional sound—anchored in hand-clapping rhythms and call-and-response intensity—captures the raw spiritual heart that flows through Jazz Fest\'s Gospel Tent.'},
  { id: 'b522', name: "Johanna Rose"                                              , day: 'd7', stage: 'lagniappe',  start: '11:30', end: '12:30', yt: 'cVjHu56CjoI', verified: true , blurb: 'There are at least two artists with the name Johanna Rose. 1)Johanna Rose is a New Orleans-based singer, songwriter, upright bassist, and street performer making music that lives somewhere between jazz and the gutter. Her sound—smoky, sultry, sometimes chaotic—walks the line between beauty and grit.'},
  { id: 'b523', name: "Dustin Dale Gaspard & the Rockin Babines"                  , day: 'd7', stage: 'lagniappe',  start: '12:50', end: '13:50', yt: 'EUPWXkBUfRg', verified: true , blurb: 'Dustin Dale Gaspard & the Rockin Babines deliver high-energy, foot-stomping Cajun and zydeco that gets the whole crowd moving—this is authentic South Louisiana soul with accordion-driven grooves and infectious brass that\'ll have you dancing whether you planned to or not. Their blend of traditional bayou culture and modern rock energy makes them a Lagniappe Stage essential for anyone seeking the real New Orleans spirit.'},
  { id: 'b524', name: "Susan Cowsill"                                             , day: 'd7', stage: 'lagniappe',  start: '14:10', end: '15:15', yt: 'BsMTqyiGl88', verified: true , blurb: 'Though she\'s been singing for most of her life, Susan Cowsill has never gone solo before - unless you count a couple of early \'70s singles that you\'d have to hire a detective to find.'},
  { id: 'b525', name: "Creole String Beans"                                       , day: 'd7', stage: 'lagniappe',  start: '15:35', end: '16:35', yt: 'dfRGB0spQcQ', verified: true , blurb: 'Creole String Beans is a band that does its own archival digging, bringing back hits from the glory days of New Orleans R&B and Swamp Pop, that polyglot, only-in-Louisiana blend of Cajun, country, R&B and rock-and-roll that cropped up in the late 1950s. Like a form of found-object art, the band mixes these salvaged, from-the-crypt covers with their own originals composed in the same spirit. The band was formed back in 2003 by bassist/singer Rob Savoy, a veteran of the Bluerunners and Cowboy Mouth, and guitarist/singer Rick Olivier, an accomplished photographer and a musician rumored to have hundreds upon hundreds of songs at instant, uncanny recall. They’re joined by Brian Rini on organ and piano, Mike "Melvis Yatly" Sipos on drums and then Derek Huston on baritone sax and Travis Blotsky on tenor sax, a brass duo known as “the Terrytown Horns.” The Creole String Beans are big on the local party circuit, especially neighborhood festivals and weddings where the New Orleans nostalgia in their sets finds a reliably susceptible audience. They nail the revived Allen Toussaint/Ernie K-Doe number “Here Come the Girls,” for instance. Their original material is a lot of fun too, especially with the way it mines Louisiana’s peculiar anthropology. There’s "Funky Spillway," honoring the Bonnet Carre Spillway, the engineering wonder of last resort to save New Orleans from a runaway river, and "St. Gabriel," going out to the women’s prison of the same name up in Iberville Parish, the old stomping grounds of Rick Olivier himself. Perhaps the deepest dive, though, is a tribute song to local horror show host Morgus the Magnificent and his obscure, campy New Orleans-shot 1962 movie “The Wacky World of Dr. Morgus,” the plot of which the Creole String Beans reprise in their song “Instant People.” When you\'re plumbing this far into New Orleans lore, no spoiler alert is necessary.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41412/festivalartist-12143-artist_image-f121405a-3c23-466f-8058-4bf0a68136ae.jpg'},
  { id: 'b526', name: "Lilli Lewis"                                               , day: 'd7', stage: 'lagniappe',  start: '17:00', end: '18:00', yt: 'pHnXvzgMv24', verified: true , blurb: 'Lilli Lewis brings soulful, genre-bending energy to the Lagniappe Stage with a voice that cuts through tradition and reimagines it—think neo-soul meets modern R&B with deep New Orleans roots that\'ll have you moving before you even know what hit you. Jazz Fest devotees will connect with her fearless approach to rhythm and lyrical depth, where every performance feels like a intimate conversation with someone who understands the city\'s musical DNA.'},
  { id: 'b527', name: "Chula featuring Vivi del Rio"                              , day: 'd7', stage: 'jamaica',    start: '11:30', end: '12:15', yt: 'ebXEaHEYYng', verified: true , blurb: 'Chula featuring Vivi del Rio brings the infectious rhythms and soulful swagger of Caribbean and Latin jazz to the Jamaica pavilion, blending island grooves with New Orleans\' improvisational spirit for a set that\'ll have you moving from the first note. This is where tropical heat meets jazz cool—the perfect soundtrack for wandering the festival grounds with a drink in hand.'},
  { id: 'b528', name: "Yaadcore"                                                  , day: 'd7', stage: 'jamaica',    start: '12:40', end: '13:40', yt: '_9CgoyLvp_Y', verified: true , blurb: 'Yaadcore brings the vibrant, rootsy energy of Caribbean reggae and dancehall to the Sandals Jamaica Cultural Pavilion, delivering infectious rhythms and conscious lyrics that celebrate island culture and community—a must-see for Jazz Fest fans hungry for global grooves and positive vibes.'},
  { id: 'b529', name: "The Skatalites"                                            , day: 'd7', stage: 'jamaica',    start: '14:05', end: '15:05', yt: 'xeJHGlCaFwQ', verified: true , blurb: 'The Skatalites are a Jamaican music group that played a major role in popularising ska, the first truly Jamaican music created by fusing boogie-woogie blues, rhythm and blues, jazz, mento, calypso, and African rhythms.'},
  { id: 'b530', name: "Kaya Jonkunnu Band & Walking Tall Jamaica"                 , day: 'd7', stage: 'jamaica',    start: '15:05', end: '15:35', yt: 'tldLqfvH-jc', verified: true , blurb: 'Kaya Jonkunnu Band & Walking Tall Jamaica brings the infectious rhythms of Jamaica straight to the heart of Jazz Fest, blending traditional jonkunnu percussion with modern reggae and roots energy that\'ll have you moving from the first beat. Their celebration of Caribbean culture and vibrant island grooves makes them an essential stop for anyone seeking the festival\'s most irresistible cross-cultural vibes.'},
  { id: 'b531', name: "Runkus & Royal Blu with Dub Squad"                         , day: 'd7', stage: 'jamaica',    start: '15:35', end: '16:35', yt: 'oSkrsTpag6Q', verified: true , blurb: 'Runkus & Royal Blu with Dub Squad bring a hypnotic blend of reggae roots, New Orleans funk, and electronic dub vibes that transform the Jazz Heritage Stage into a sonic celebration—where island rhythms meet Crescent City soul and the bass drops hit like a second line parade. This is the sound of New Orleans colliding with Caribbean consciousness: irresistible, forward-thinking, and made for moving bodies and open minds.'},
  { id: 'b532', name: "Jemere Morgan"                                             , day: 'd7', stage: 'jamaica',    start: '17:00', end: '18:00', yt: 'tWe3AaV4tTg', verified: true , blurb: 'Jemere, son of Gramps Morgan has now branched out into the music business like many of his relatives before him. According to Jemere, it was his father who discovered his talent.'},
  { id: 'b533', name: "The Russell Welch Hot Quartet"                             , day: 'd7', stage: 'rhythm',     start: '12:00', end: '12:50', yt: '5syC3w_WCoM', verified: true , blurb: 'The Russell Welch Hot Quartet ignites the Rhythmpourium Tent with blazing New Orleans jazz traditionalism, where hot swing rhythms collide with soulful brass and piano-driven grooves that\'ll have you moving before the first chorus ends. This is the sound that built the city—straight-ahead, fiery, and impossibly infectious.'},
  { id: 'b534', name: "Eric Adcock plays Louisiana Piano featuring Derek Huston"  , day: 'd7', stage: 'rhythm',     start: '13:15', end: '14:00', yt: 'puwLnJ7bb9o', verified: true , blurb: 'Eric Adcock\'s Louisiana Piano is a masterclass in deep-rooted regional soul, blending the swaggering stride and blues-soaked sophistication of New Orleans keyboard tradition with modern groove sensibility—Derek Huston\'s collaborations amplify that rich, improvisational energy into a set that feels both timeless and alive. If you\'re hunting for the kind of music that makes you understand why this city invented jazz, the Rhythmpourium Tent is your destination.'},
  { id: 'b535', name: "Mia Borders Acoustic Trio"                                 , day: 'd7', stage: 'rhythm',     start: '14:25', end: '15:10', yt: '-7FKFkgFgHA', verified: true , blurb: 'Mia Borders Acoustic Trio brings intimate, intricate melodies to the Rhythmpourium Tent, blending jazz sophistication with folk sensibility for a late-night listening experience that rewards close attention. Their unplugged approach cuts through the festival noise with warmth and precision, perfect for Jazz Fest devotees seeking connection over spectacle.'},
  { id: 'b536', name: "Dustin Dale Gaspard"                                       , day: 'd7', stage: 'rhythm',     start: '15:35', end: '16:20', yt: '_6SMeYNM8gM', verified: true , blurb: 'Dustin Dale Gaspard channels the soulful, syncopated energy of modern New Orleans funk and soul, blending traditional rhythmic grooves with contemporary production that keeps the Rhythmpourium tent moving all night long. His infectious, dancefloor-ready sound is pure New Orleans spirit—funky, feel-good, and impossible to stand still for.'},
  { id: 'b537', name: "Ghalia Volt"                                               , day: 'd7', stage: 'rhythm',     start: '16:45', end: '17:30', yt: 'OMUc8kozIgs', verified: true , blurb: 'You can’t miss Ghalia Volt. She’s the natural-born rock star with the leather jacket and wicked grin, leaning from her album sleeve to offer you a hit on her hip flask. But the real Southern blend ain’t in the bottle, it’s on the songs.'},
  { id: 'b538', name: "Guardians of Culture with Queen Reesie & Chief Jeremy"     , day: 'd7', stage: 'children',   start: '11:30', end: '12:15' , blurb: 'Queen Reesie & Chief Jeremy bring pure joy and cultural storytelling to the Ochsner Children\'s Tent, blending New Orleans second line traditions with playful rhythms that get kids dancing and families moving together. Their infectious, feel-good performance celebrates the city\'s rich heritage through music that\'s rooted in soul but light enough to keep the littlest Jazz Fest fans grinning from start to finish.'},
  { id: 'b539', name: "Kaya Jonkunnu Band & Walking Tall Jamaica"                 , day: 'd7', stage: 'children',   start: '12:15', end: '13:05', yt: 'tldLqfvH-jc', verified: true , blurb: 'Kaya Jonkunnu Band & Walking Tall Jamaica brings the infectious rhythms of Jamaica straight to the heart of Jazz Fest, blending traditional jonkunnu percussion with modern reggae and roots energy that\'ll have you moving from the first beat. Their celebration of Caribbean culture and vibrant island grooves makes them an essential stop for anyone seeking the festival\'s most irresistible cross-cultural vibes.'},
  { id: 'b540', name: "The RRAAMS"                                                , day: 'd7', stage: 'children',   start: '13:05', end: '13:50', yt: 'Dn-B-rrAams', verified: true , blurb: 'The RRAAMS bring infectious second-line energy and playful funk grooves that transform the Ochsner Children\'s Tent into a dance floor, mixing New Orleans traditions with modern swagger that keeps kids and families moving all day long. Their high-spirited horn arrangements and irresistible rhythm section prove that the best Jazz Fest moments happen when everyone—young and old—is laughing, dancing, and fully alive.'},
  { id: 'b541', name: "Junior Baby Doll Ladies"                                   , day: 'd7', stage: 'children',   start: '13:50', end: '14:45', yt: 'oNgxZpeKXt0', verified: true , blurb: 'The Junior Baby Doll Ladies bring New Orleans\' most playful tradition to life with infectious brass-fueled rhythms, call-and-response vocals, and the kind of joyful second-line energy that gets kids and families moving together—it\'s the spirit of Mardi Gras distilled into pure, accessible fun that reminds you why this festival belongs to everyone.'},
  { id: 'b542', name: "Bruce Daigrepont's Family Fais Do Do and Cajun Dance Workshop", day: 'd7', stage: 'children',   start: '14:45', end: '15:30', yt: 'MnkFLAkJW5Q', verified: true , blurb: 'Bring the whole family to stomp, clap, and spin at Bruce Daigrepont\'s Family Fais Do Do, where authentic Cajun accordion, fiddle, and infectious dance rhythms transform the Children\'s Tent into Louisiana\'s living room—pure joy, zero pretension, the real heartbeat of South Louisiana culture that kids and grandkids will remember forever.'},
  { id: 'b543', name: "Junior Baby Doll Ladies"                                   , day: 'd7', stage: 'children',   start: '15:30', end: '16:20', yt: 'oNgxZpeKXt0', verified: true , blurb: 'The Junior Baby Doll Ladies bring New Orleans\' most playful tradition to life with infectious brass-fueled rhythms, call-and-response vocals, and the kind of joyful second-line energy that gets kids and families moving together—it\'s the spirit of Mardi Gras distilled into pure, accessible fun that reminds you why this festival belongs to everyone.'},
  { id: 'b544', name: "Kai Knight's Silhouette Dance Ensemble"                    , day: 'd7', stage: 'children',   start: '16:20', end: '17:00', yt: 'OYKSObPLl7I', verified: true , blurb: 'Kai Knight\'s Silhouette Dance Ensemble brings infectious, family-friendly rhythms and visual storytelling to the Ochsner Children\'s Tent, blending contemporary movement with New Orleans\' soulful musical traditions into an unforgettable performance that gets kids and parents dancing together. This ensemble\'s dynamic energy and accessible grooves make them the perfect gateway into Jazz Fest magic for the youngest festival lovers.'},
  { id: 'b545', name: "Lisa Knowles-Smith & Roland Jack Interviewer: Mona Lisa Saloy", day: 'd7', stage: 'miner',      start: '12:30', end: '13:15', yt: 'n6JjQKBOvTo', verified: true , blurb: 'Lisa Knowles-Smith and Roland Jack bring deep New Orleans roots and intimate storytelling to the Allison Miner stage, blending traditional jazz vocals with the rich cultural heritage that defines the city\'s soul—a must-see for fans seeking authentic, generational wisdom delivered through music.'},
  { id: 'b546', name: "Sierra Hull Interviewer: Mollie Farr"                      , day: 'd7', stage: 'miner',      start: '13:30', end: '14:15', yt: 'bGUy6cwbhyw', verified: true , blurb: 'Sierra Hull brings mandolin mastery and bluegrass innovation to the Allison Miner stage, blending traditional roots music with modern sensibility in a performance that feels both timeless and urgent. Fans of acoustic virtuosity and genre-defying storytelling will find themselves drawn into her intricate fingerpicking and soulful vocal delivery.'},
  { id: 'b547', name: "Lilli Lewis Interviewer: Alison Fensterstock"              , day: 'd7', stage: 'miner',      start: '14:30', end: '15:15', yt: 'hQLsMYJU1lE', verified: true , blurb: 'Lilli Lewis channels the soulful depth of New Orleans tradition with a voice that cuts through like aged whiskey—intimate, complex, and utterly mesmerizing. Whether you\'re a heritage purist or discovering the city\'s living musical legacy, this is essential Jazz Fest listening that reminds you why this festival exists.'},
  { id: 'b548', name: "Wayne Toups Interviewer: Pat Mould"                        , day: 'd7', stage: 'miner',      start: '15:30', end: '16:15', yt: 'q1PVr6AeUT0', verified: true , blurb: 'Wayne Toups brings that swamp-pop soul and Cajun groove that runs through Louisiana\'s musical backbone—a master of accordion and vocals who channels the bayou\'s raw energy with infectious joy and undeniable authenticity that\'ll have you moving whether you know the words or not.'},
  { id: 'b549', name: "Members of The Skatalites Interviewer: Alex Rawls"         , day: 'd7', stage: 'miner',      start: '16:30', end: '17:15', yt: 'bIHh32YKHxY', verified: true , blurb: 'The Skatalites bring the infectious, syncopated pulse of Jamaica\'s ska and rocksteady pioneers to the Heritage Stage, with Alex Rawls illuminating the stories behind every ska-inflected groove and vintage melody that shaped Caribbean and American music. Their tight horn arrangements and propulsive rhythms are pure joy—the sound of musical history made tangible and undeniably danceable.'},

  // ───────── Sun May 3 (d8) ─────────
  { id: 'b550', name: "Jemere Morgan"                                             , day: 'd8', stage: 'festival',   start: '11:20', end: '12:15', yt: 'tWe3AaV4tTg', verified: true , blurb: 'Jemere, son of Gramps Morgan has now branched out into the music business like many of his relatives before him. According to Jemere, it was his father who discovered his talent.'},
  { id: 'b551', name: "Big Sam's Funky Nation"                                    , day: 'd8', stage: 'festival',   start: '12:40', end: '13:45', yt: 'qKuj6WXaJyg', verified: true , blurb: 'BIG SAM\'S FUNKY NATION: Presiding over his Funky Nation is Big Sam, formerly the trombonist for the Dirty Dozen Brass Band, who blows the funk out of his trombone and refuses to let the audience sit still.'},
  { id: 'b552', name: "Galactic featuring Jelly Joseph"                           , day: 'd8', stage: 'festival',   start: '14:10', end: '15:25', yt: 'KlMdWEBnKgs', verified: true , blurb: 'Galactic featuring Jelly Joseph brings infectious funk and soul grooves that blur the lines between New Orleans tradition and contemporary hip-hop, with Joseph\'s commanding vocals leading the charge through an irresistible blend of bass-heavy rhythms and live instrumentation that gets the whole crowd moving as one.', members: 'Stanton Moore, Ben Ellman, Robert Mercurio, Jeff Raines, Jelly Joseph'},
  { id: 'b553', name: "Teddy Swims"                                               , day: 'd8', stage: 'festival',   start: '16:05', end: '17:20', yt: '9gWIIIr2Asw', verified: true , blurb: 'Jaten Dimsdale, known by his moniker, Teddy Swims, is an American Singer-songwriter from Atlanta, GA. Teddy grew up navigating different worlds: he was a football player, a musical theater student and the grandson of a Pentecostal pastor.'},
  { id: 'b554', name: "Trombone Shorty & Orleans Avenue"                          , day: 'd8', stage: 'festival',   start: '17:45', end: '19:00', yt: 'CisPSigqfls', verified: true , blurb: 'Trombone Shorty\'s new album opens with a dirge, but if you think the beloved bandleader, singer, songwriter and horn-blower born Troy Andrews came here to mourn, you got it all wrong. That bit of beautiful New Orleans soul—"Laveau Dirge No. 1," named after one of the city\'s most famous voodoo queens—shows off our host\'s roots before Parking Lot Symphony branches out wildly, wonderfully, funkily across 12 diverse cuts. True to its title, this album contains multitudes of sound—from brass band blare and deep-groove funk, to bluesy beauty and hip-hop/pop swagger— and plenty of emotion all anchored, of course, by stellar playing and the idea that, even in the toughest of times, as Andrews says, "Music brings unity." As for why it\'s taken Andrews so long to follow 2013\'s Raphael Saadiq-produced Say That to Say This, the man simply says, "I didn\'t realize so much time passed. Some artists don\'t work until they put a record out but I never stopped going." Truly. In the last four years, Andrews banked his fifth White House gig; backed Macklemore and Madonna at the Grammys; played on albums by She & Him, Zac Brown, Dierks Bentley, and Mark Ronson; opened tours for Daryl Hall & John Oates and Red Hot Chili Peppers; appeared in Foo Fighters\' Sonic Highways documentary series; voiced the iconic sound of the adult characters in The Peanuts Movie; inherited the esteemed annual festclosing set at the New Orleans Jazz & Heritage Festival in the tradition of Crescent City greats like the Neville Brothers and Professor Longhair; and released Trombone Shorty, a children\'s book about his life that was named a Caldecott Honor Book in 2016. Adding to that legacy, his Blue Note Records debut Parking Lot Symphony finds Andrews teamed with Grammy-nominated producer Chris Seefried (Andra Day, Fitz and the Tantrums) and an unexpected array of cowriters and players including members of Edward Sharpe & The Magnetic Zeros, The Meters, Better Than Ezra, and Dumpstaphunk. Considering Andrews\' relentless schedule, it\'s all the more surprising that this LP began with him in a room, all alone, back in New Orleans. "I had two weeks at home so I went to the studio and set up the \'playground,\'" he recalls. "I had everything in a circle: tuba, trombone, trumpet, keyboard, Fender Rhodes, Wurly, B3 organ, guitar, bass, drums—and me buried in the middle." He recorded an album\'s worth of ideas and then, well, walked away for a year. Not because he was too busy, but because he wanted to hit the road and see how the music changed on him. When Andrews came back with a full band, the songs came to life. Take the album\'s two covers, a pair of NOLA deep cuts: there\'s "Here Comes the Girls," a 1970 Allen Toussaint song originally recorded by Ernie K-Doe that here (with Ivan Neville on piano) sounds bawdy and regal, like something from a current Bruno Mars album; and The Meters\' lovesick "It Ain\'t No Use," which swirls a vintage R&B vibe with resonant choir vocals and upbeat guitar from The Meters\' Leo Nocentelli himself to transport the listener to the center of the jumpingest jazz-soul concert hall that never was. The story there is almost too good. The session band—guitarist Pete Murano, sax men Dan Oestreicher and BK Jackson, and drummer Joey Peebles with Dumpstaphunk\'s Tony Hall in for Orleans Avenue bassist Mike Bass-Bailey—were in the studio to lay down "It Ain\'t No Use." Hall even had the vintage acoustic he bought from Nocentelli years ago, which was used on the original Meters session. On the way to the bathroom, Andrews saw Nocentelli coming out of a different tracking room: it was meant to be. But that\'s not unusual for a man raised in one of the Tremé\'s most musical families. Andrews got his name when he picked up his instrument at four ("My parents pushed me toward trombone because they didn\'t need another trumpet player," he laughs). By eight, he led his own band in parades, halls and even bars: "They\'d have to lock the door so the police couldn\'t come in." Promoters would try to hand money to his older cousins, but they\'d kindly redirect them to the boy. In histeens, Andrews played shows abroad with the Neville Brothers. Fresh out of high school (New Orleans Center for Creative Arts) he joined Lenny Kravitz\' band. Across that time, three Trombone Shorty albums and many collaborations since, Andrews nurtured a voracious appetite for all types of music—a phenomenon on fluid display with Parking Lot Symphony. On "Familiar," co-written by Aloe Blacc, they practically mint a new genre (trap-funk?) while Andrews channels his inner R. Kelly to spit game at an old flame. Meanwhile, the instrumental "Tripped Out Slim" (the nickname of a family friend who recently passed) bends echoes of the Pink Panther theme into something fit for James Brown to strut to. And if you listen closely to "Where It At?," written with Better Than Ezra\'s Kevin Griffin, you may even hear a little Y2K pop. "I know it wasn\'t cool to listen to *NSYNC or Britney Spears in high school," says Andrews, "but those bass lines and melodies are funky." They pair astonishingly well with all the Earth, Wind & Fire that bubbles beneath these songs. It\'s worth noting that Andrews\' vocals sound better than ever (he credits Seefried for that), because Parking Lot Symphony might be the man\'s most heartfelt offering yet. The breezy title track, which Andrews wrote with Alex Ebert (Edward Sharpe & The Magnetic Zeros), is as much about walking the Tremé, being uplifted by the music that seems to seep from every surface, as it is about moving on from a broken heart. And the shuffling, bluesy "No Good Time" reminds us, with a world-weary smile, that "nobody never learned nothin\' from no good time." But Andrews is clear that this isn\'t some kind of breakup record. "It\'s a life record," he says, "about prevailing no matter what type of roadblock is in front of you." That message is clearest on "Dirty Water," where over an easy groove, Andrews adopts a soft falsetto to address just about anyone going through it—personal, political, whatever. "There\'s a lot of hope turning to doubt," he coos. "I\'ve got something to say to them / You don\'t know what you\'re talking about / When you believe in love, it all works out." Amen. Now let the horns play us out.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41562/festivalartist-12508-artist_image-506d21c2-795b-4d74-9cf6-9c6e8e5ef82d.jpg'},
  { id: 'b555', name: "Original Pinettes Brass Band"                              , day: 'd8', stage: 'shell',      start: '11:15', end: '12:15', yt: 'C1WTfalidcw', verified: true , blurb: 'The Original Pinettes Brass Band delivers raw, unfiltered New Orleans brass tradition with infectious energy that\'ll have you second-lining before the first note hits—their jubilant horns and thundering rhythms are pure Crescent City soul, the sound that built this festival\'s foundation.'},
  { id: 'b556', name: "George Porter Jr & Runnin' Pardners"                       , day: 'd8', stage: 'shell',      start: '12:40', end: '13:40', yt: 'xv5FWh4fs3g', verified: true , blurb: 'George Porter Jr & Runnin\' Pardners bring the deep funk and soul that built New Orleans, delivering groove-heavy grooves and infectious energy that\'ll have the Shell stage dancing from first note to last. This is the sound of the city\'s bass-driven backbone—seasoned, soulful, and impossibly tight.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41406/festivalartist-12119-artist_image-0380c1d5-bb55-42cf-8d13-0fd203d781a6.jpg'},
  { id: 'b557', name: "Jon Cleary & the Absolute Monster Gentlemen"               , day: 'd8', stage: 'shell',      start: '14:00', end: '15:10', yt: 'lSDyh36miqY', verified: true , blurb: 'Jon Cleary is Originally from Great Britain but he has moved to the US. He is currently living near New Orleans, and he has for quite a while been carrying the traditions of New Orleans Funk into the new millenium. Cleary builds on the traditions of such people as Dr. John and Professor Longhair.'},
  { id: 'b558', name: "The Radiators"                                             , day: 'd8', stage: 'shell',      start: '15:35', end: '16:45', yt: '5Al49APO62I', verified: true , blurb: 'There are three bands known as The Radiators. 1) A swamp rock band from the United States 2) A pub rock band from Australia 3) A punk rock/power pop band from Ireland that also released music as The Radiators from Space.'},
  { id: 'b559', name: "Tedeschi Trucks Band"                                      , day: 'd8', stage: 'shell',      start: '17:20', end: '19:00', yt: '6GkdCiqsFUI', verified: true , blurb: 'Tedeschi Trucks Band (formerly known as the Derek Trucks & Susan Tedeschi Band) is an American blues rock group based in Jacksonville, Florida. Formed in 2010, the band is led by husband-and-wife musicians Derek Trucks and Susan Tedeschi, and primarily features members from their solo groups.'},
  { id: 'b560', name: "BRW"                                                       , day: 'd8', stage: 'congo',      start: '11:25', end: '12:15', yt: 'zacv142_6QQ', verified: true , blurb: 'BRW brings ancestral rhythms and contemporary soul to the Congo Square Stage, blending deep roots percussion with modern production for a transcendent sound that honors New Orleans\' spiritual legacy while pushing boldly forward. Their hypnotic grooves and layered instrumentation create an immersive experience that speaks directly to why Jazz Fest devotees return year after year—music that moves both body and spirit.'},
  { id: 'b561', name: "Shamarr Allen"                                             , day: 'd8', stage: 'congo',      start: '12:40', end: '13:40', yt: 'UMf-e8JHdMo', verified: true , blurb: 'Shamarr Allen is carrying on a New Orleans musical tradition. Unlike many of the young lions of Crescent City jazz and funk, he didn\'t have any scholastic-based musical training growing up, opting for an education in science and math over the performing arts.'},
  { id: 'b562', name: "Lila Iké"                                                  , day: 'd8', stage: 'congo',      start: '14:10', end: '15:20', yt: 'qWj6gGWm0og', verified: true , blurb: 'Lila Iké (neé Alecia Grey) is a singer and songwriter from Manchester, Jamaica.  She gained attention at home and abroad with her distinctive delivery, old-school sensibilities and modern-day swagger.'},
  { id: 'b563', name: "DJ Captain Charles"                                        , day: 'd8', stage: 'congo',      start: '15:20', end: '15:55', yt: 'vyWGhxoHGLg', verified: true , blurb: 'Born and raised in New Orleans, Louisiana, Charles Leach, a.k.a., “DJ Captain Charles”, has been a local favorite for over 35 years. His charismatic personality, talent, genuine love of people, diversity in music, and no nonsense work ethic, have escalated him to maximum popularity! DJ Captain Charles has shared his talents throughout the United States and has worked internationally as well. His solid reputation for creating fun, safe, sophisticate and electrifying entertainment environments, has made him the “go to” disc jockey for many in the sports, music and entertainment industries. He has entertained at official events for NFL and NBA sport teams and players, performed on the Tom Joyner’s “Fantastic Voyage”, Essence Music Festival, has earned a spot as the featured disc jockey for BET’s Comic View and The Apollo Kids Talent Search, and was the first disc jockey to receive an invitation to entertain on a primary stage at The New Orleans Jazz & Heritage Music Festival. Other events include Odyssey Media’s Annual Women’s Conferences and grand opening celebrations for Nordstrom stores in Louisiana. He has been featured on concerts with various artists and is a regular entertainment favorite for many popular local venues (House of Blues, Bally’s Casino New Orleans, Harrah’s Casino New Orleans, Boomtown Casino New Orleans, Hyatt, Marriott, and Hilton Hotel Brands). Because of his popularity with party goers from all economic and social backgrounds between the ages of 21 and 101, DJ Captain Charles has earned the respect and support of major corporations such as Budweiser, Entergy and local businesses alike. But most importantly, he has earned the respect and support of the people. Whenever and wherever DJ Captain Charles spins, people follow with the expectation of a great party experience.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41579/festivalartist-12541-artist_image-f415e18e-1c5c-4dfd-abdc-7adcc8dce633.jpg'},
  { id: 'b564', name: "Rebirth Brass Band"                                        , day: 'd8', stage: 'congo',      start: '15:55', end: '17:05', yt: 'GaKkoqDa8Ng', verified: true , blurb: 'Whether seen on HBO’s Treme or at their legendary Tuesday night gig at The Maple Leaf, Grammy-winning Rebirth Brass Band is a true New Orleans institution. Formed in 1983 by the Frazier brothers, the band has evolved from playing the streets of the French Quarter to playing festivals and stages all over the world. While committed to upholding the tradition of brass bands, they’ve also extended themselves into the realms of funk and hip-hop to create their signature sound. “Rebirth can be precise whenever it wants to,” says The New York Times, “but it’s more like a party than a machine. It’s a working model of the New Orleans musical ethos: as long as everybody knows what they’re doing, anyone can cut loose.” In the wake of the sometimes-stringent competition amongst New Orleans brass bands, Rebirth is the undisputed leader of the pack, and they show no signs of slowing down.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41434/festivalartist-12200-artist_image-a267e47c-6f97-4b24-8122-32e8c891b2d6.jpg'},
  { id: 'b565', name: "DJ Captain Charles"                                        , day: 'd8', stage: 'congo',      start: '17:05', end: '17:40', yt: 'vyWGhxoHGLg', verified: true , blurb: 'Born and raised in New Orleans, Louisiana, Charles Leach, a.k.a., “DJ Captain Charles”, has been a local favorite for over 35 years. His charismatic personality, talent, genuine love of people, diversity in music, and no nonsense work ethic, have escalated him to maximum popularity! DJ Captain Charles has shared his talents throughout the United States and has worked internationally as well. His solid reputation for creating fun, safe, sophisticate and electrifying entertainment environments, has made him the “go to” disc jockey for many in the sports, music and entertainment industries. He has entertained at official events for NFL and NBA sport teams and players, performed on the Tom Joyner’s “Fantastic Voyage”, Essence Music Festival, has earned a spot as the featured disc jockey for BET’s Comic View and The Apollo Kids Talent Search, and was the first disc jockey to receive an invitation to entertain on a primary stage at The New Orleans Jazz & Heritage Music Festival. Other events include Odyssey Media’s Annual Women’s Conferences and grand opening celebrations for Nordstrom stores in Louisiana. He has been featured on concerts with various artists and is a regular entertainment favorite for many popular local venues (House of Blues, Bally’s Casino New Orleans, Harrah’s Casino New Orleans, Boomtown Casino New Orleans, Hyatt, Marriott, and Hilton Hotel Brands). Because of his popularity with party goers from all economic and social backgrounds between the ages of 21 and 101, DJ Captain Charles has earned the respect and support of major corporations such as Budweiser, Entergy and local businesses alike. But most importantly, he has earned the respect and support of the people. Whenever and wherever DJ Captain Charles spins, people follow with the expectation of a great party experience.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41579/festivalartist-12541-artist_image-f415e18e-1c5c-4dfd-abdc-7adcc8dce633.jpg'},
  { id: 'b566', name: "Earth, Wind & Fire"                                        , day: 'd8', stage: 'congo',      start: '17:40', end: '19:00', yt: 'Gs069dndIYk', verified: true , blurb: 'Earth, Wind & Fire (abbreviated as EW&F or EWF) is an American band formed in Chicago, Illinois, in 1969. Their music encompasses a wide range of genres, including jazz, R&B, soul, funk, disco, pop, Latin, and Afro-pop.'},
  { id: 'b567', name: "John Mahoney Little Big Band"                              , day: 'd8', stage: 'jazz',       start: '11:30', end: '12:25', yt: '5D8KSZrUcvw', verified: true , blurb: 'John Mahoney Little Big Band swings with the sophisticated energy of classic New Orleans jazz, blending traditional ensemble warmth with modern improvisational fire that keeps dancers moving and listeners leaning in. This is the sound that built the city\'s reputation—crafted by musicians who understand that the best jazz speaks in conversation, not declarations.'},
  { id: 'b568', name: "Jason Marsalis"                                            , day: 'd8', stage: 'jazz',       start: '12:50', end: '13:50', yt: 'SwIdDHQShJI', verified: true , blurb: 'Jason Marsalis (March 4, 1977, New Orleans, Louisiana) is an American jazz drummer and member of the famous New Orleans Marsalis jazz musical family. He is the youngest son of Delores Ferdinand Marsalis and Ellis Marsalis, Jr. .'},
  { id: 'b569', name: "Trumpet Mafia's Tribute to Miles Davis featuring Keyon Harrold", day: 'd8', stage: 'jazz',       start: '14:15', end: '15:20', yt: 'ejrrbJ2OvaA', verified: true , blurb: 'Trumpet Mafia brings fiery reverence to Miles Davis\'s legacy at the WWOZ Jazz Tent, with virtuoso Keyon Harrold leading a collective of New Orleans cats through modal explorations and electric funk grooves that honor the past while pushing toward tomorrow. This is straight-ahead jazz with swagger—the kind of tribute that reminds you why Miles mattered and why he still does.'},
  { id: 'b570', name: "The Allen Toussaint Jazzity Project"                       , day: 'd8', stage: 'jazz',       start: '15:50', end: '17:05', yt: 'hJPkGC3bPbY', verified: true , blurb: 'The Allen Toussaint Jazzity Project channels the spirit of New Orleans\' greatest musical ambassador through sophisticated arrangements that blend traditional jazz with modern soul and funk—a celebration of legacy that honors the past while swinging boldly into the present. Deep grooves, elegant horn sections, and that unmistakable New Orleans pocket make this a must-see for anyone seeking the true heartbeat of Jazz Fest.'},
  { id: 'b571', name: "Herbie Hancock"                                            , day: 'd8', stage: 'jazz',       start: '17:40', end: '19:00', yt: 'GHhD4PD75zY', verified: true , blurb: 'Herbert Jeffrey Hancock (born April 12, 1940) is a jazz  pianist and composer from Chicago, Illinois, United States. Hancock is one of jazz music\'s most important and influential pianists and composers. He embraced elements of rock, funk, and soul while adopting freer stylistic elements from jazz.'},
  { id: 'b572', name: "Marc Stone"                                                , day: 'd8', stage: 'blues',      start: '11:20', end: '12:25', yt: 'yhUi_N_IpF0', verified: true , blurb: 'With a deeply rooted yet truly personal sound, Marc Stone holds a unique space in the New Orleans scene. He honors his place as a link to many of the departed and living masters while remaining steadfastly open in his writing and presentation. Wielding fiery slide guitar, earthy rhythms and incisive lyrics, Stone\'s originals eschew clichés and well-trodden forms in favor of music that always bears his own stamp. Whether playing solo on his National steel or leading genre-bending all-star ensembles, he is more invested in playing the moment than playing it safe. Stone has released 4 albums, touring extensively in the US and Europe as an artist/bandleader. He has also clocked a quarter century of experience making music with the masters of wide array of Roots music styles from New Orleans RnB and funk, Delta Blues, African music and Zydeco. He has collaborated with Walter "Wolfman" Washington, John Mooney, Leo Nocentelli, Alvin "Youngblood\' Hart, Marilyn Barbarin, Papa Mali, Benny Turner, Seguenon Kone, the Naughty Professor Horns, Jordan Anderson, Mikayla Braun, the Campbell Brothers and Betty Harris, and performed or recorded with Eddie Bo, Allen Toussaint, C.J. Chenier, Rockin\' Dopsie, Jr., Leftover Salmon with Col. Bruce Hampton, Marcia Ball, Carol Fran, Henry Gray, Dr. Lonnie Smith, Ernie K-Doe, Buckwheat Zydeco, Alana Davis, Cole Williams, Little Maker and many others.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41508/festivalartist-12392-artist_image-f56feaac-6e19-4fa5-8220-948384ca55d9.jpg'},
  { id: 'b573', name: "Deacon John"                                               , day: 'd8', stage: 'blues',      start: '12:50', end: '13:50', yt: 'x1UTC1tENnY', verified: true , blurb: 'Alternately known as Deacon John Moore, this longtime New Orleans R&B performer and session musician (also known early on as Johnny Moore ) earned his nickname  \'Deacon\' from an old bandmate for his well groomed, clean-cut, church ready look.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41341/festivalartist-11950-artist_image-0f5535dd-917f-4b19-b1e1-0e2a80439985.jpg'},
  { id: 'b574', name: "James Andrews & the Crescent City Allstars"                , day: 'd8', stage: 'blues',      start: '14:15', end: '15:30', yt: 'IaaukuA_7Kc', verified: true , blurb: 'James Andrews & the Crescent City Allstars bring deep, gutsy blues straight from the heart of New Orleans, blending classic Delta grit with the city\'s signature horn-driven soul for a set that\'ll have you moving and believing every note. This is the real deal—authentic, high-energy blues that proves why the Blues Tent is always packed at Jazz Fest.'},
  { id: 'b575', name: "Jackie Venson"                                             , day: 'd8', stage: 'blues',      start: '16:00', end: '17:15', yt: 'R1VztRpRf1A', verified: true , blurb: 'A native Texan, Jackie Venson intimately portrays her love for the Blues through thoughtful lyrics, screamin\' guitar solos and an unforgettable voice. Jackie Venson is a singer, songwriter, and musician from Austin, Texas.  Her unique voice is certain to appeal to music fans of all ages.'},
  { id: 'b576', name: "Mavis Staples"                                             , day: 'd8', stage: 'blues',      start: '17:50', end: '18:50', yt: 'ANw38xX_EuM', verified: true , blurb: 'Mavis Staples (born July 10, 1939 in Chicago, Illinois) is an American rhythm and blues singer. Most of her career has been as lead singer for The Staple Singers. She first recorded solo for the Stax subsidiary Volt in 1969.'},
  { id: 'b577', name: "The New Leviathan Oriental Fox-Trot Orchestra"             , day: 'd8', stage: 'economy',    start: '11:15', end: '12:05', yt: '1QVezDE1ffU', verified: true , blurb: 'The New Leviathan Oriental Fox-Trot Orchestra brings swagger and brass-fueled eccentricity to Economy Hall, blending New Orleans traditional jazz with vaudeville theatricality and off-kilter orchestral arrangements that feel simultaneously vintage and delightfully unhinged. Their high-energy, anything-goes approach to classic jazz standards and originals is pure Crescent City irreverence—the kind of joyful chaos that makes Jazz Fest unforgettable.'},
  { id: 'b578', name: "Tommy Sancton's New Orleans Legacy Band"                   , day: 'd8', stage: 'economy',    start: '12:25', end: '13:20', yt: 'V4DedNDiw08', verified: true , blurb: 'The NOLB is a New Orleans-based group specializing in traditional jazz. Led by clarinetist Tommy Sancton, who learned at the feet of the great George Lewis and other jazz pioneers active around Preservation Hall in the 1960s, the NOLB is a band with strong roots in the past and a reach towards the younger generation of New Orleans jazz musicians. The band has been featured at numerous festivals in Europe and the U.S. and has made numerous appearances at Jazzfest and other New Orleans jazz venues. Their album "City of a Million Dreams" is available from G.H.B. records.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41479/festivalartist-12322-artist_image-eb76a639-3c02-4707-99c0-73e434f182ba.jpg'},
  { id: 'b579', name: "Greg Stafford & His Young Tuxedo Brass Band"               , day: 'd8', stage: 'economy',    start: '13:40', end: '14:35', yt: 'vlcPYx-2rls', verified: true , blurb: 'Greg Stafford & His Young Tuxedo Brass Band bring the unbridled joy and street-smart swagger of traditional New Orleans brass tradition to Economy Hall, mixing classic second-line grooves with infectious energy that gets the whole tent moving. This is the sound that built the city—raw horns, deep pocket rhythms, and the kind of call-and-response spirit that reminds you why Jazz Fest exists in the first place.'},
  { id: 'b580', name: "Banu Gibson"                                               , day: 'd8', stage: 'economy',    start: '15:00', end: '16:00', yt: 'Vh7x3Zahb9w', verified: true , blurb: 'During an era when most female singers who interpret music from the 1920s come across as dated "red hot mamas," camp, or satirical, Banu Gibson practically stands alone.'},
  { id: 'b581', name: "Doreen's Jazz New Orleans"                                 , day: 'd8', stage: 'economy',    start: '16:20', end: '17:15', yt: 'OcP2sAX90jI', verified: true , blurb: 'Doreen\'s Jazz New Orleans channels the soulful, conversational spirit of traditional New Orleans jazz with modern sensibilities, delivering the kind of intimate, groove-centered performance that makes the Economy Hall Tent feel like a secret you\'ve been let in on. Their sound swings with the warmth of brass-led storytelling and second-line swagger—the perfect soundtrack for discovering why this city\'s jazz legacy remains endlessly alive.'},
  { id: 'b582', name: "Kermit Ruffins' Tribute to Louis Armstrong"                , day: 'd8', stage: 'economy',    start: '17:35', end: '18:45', yt: 'jpDBBVeai7Y', verified: true , blurb: 'Kermit Ruffins channels the golden age of New Orleans jazz with his luminous trumpet and infectious joy, delivering a reverent yet swinging tribute to Louis Armstrong\'s legacy that\'ll have you dancing in the sawdust and grinning ear-to-ear. This is the sound that built the city—warm, soulful, and absolutely unstoppable.'},
  { id: 'b583', name: "Chère Élise with special guest Kelli Jones"                , day: 'd8', stage: 'fais',       start: '11:15', end: '12:05', yt: 'LEbzVnBdEkU', verified: true , blurb: 'Chère Élise brings the soul-deep traditions of New Orleans R&B and funk to the Fais Do-Do Stage, where Kelli Jones\'s guest appearance amplifies their already electrifying blend of smooth vocals, tight grooves, and that irresistible je ne sais quoi that makes you move. This is authentic New Orleans sound—rooted, joyful, and impossible to sit still for.'},
  { id: 'b584', name: "Andrew Duhon"                                              , day: 'd8', stage: 'fais',       start: '12:25', end: '13:20', yt: '6fPHa8nhVIE', verified: true , blurb: 'Andrew Duhon is a songwriter from New Orleans whose ability to craft 4-minute novels has earned him comparisons to John Prine and Jim Croce, while the powerful soul of his voice evokes a youthful Van Morrison. He has released four recordings, including his 2014 release, “The Moorings,” which was nominated for a Grammy award for “Best Engineered Album.” His latest album, “False River” is described by American Songwriter as “fresh, innovative, and complicated in all the right ways.”', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41442/festivalartist-12218-artist_image-3037af07-a683-4b2c-b53d-88da33b6fb57.jpg'},
  { id: 'b585', name: "Steve Riley & the Mamou Playboys"                          , day: 'd8', stage: 'fais',       start: '13:40', end: '14:40', yt: '6PNFkWfZDR8', verified: true , blurb: 'Steve Riley and the Mamou Playboys began thirty years ago with a reputation for excellence. Their stunningly clean and cohesive performance of Cajun French music from the backwaters of Southwest Louisiana propelled them into the world music limelight early on, and by their third release, Trace of Time, had garnered them a Grammy nomination in the worldwide field of traditional folk music, another in 2004 for Bon Reve, in 2009 for Live at the New Orleans Jazz & Heritage Festival and again in 2011 for their release, Grand Isle. From the day they started, they have gone from strength to strength. Never before in Cajun music has a comparable wealth of skills been brought to the same table. When all that heart and all that skill focus on the revelry of a hot two-step, then turn on a dime and deliver an a cappella ballad, then play something that sounds like Howlin’ Wolf fell in lust with a Creole girl, you’ve found the most Cajun music you can find in any one spot. You’ve found Steve Riley and the Mamou Playboys.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41378/festivalartist-12055-artist_image-92c49780-bf3d-4751-868c-54d98f28a315.jpg'},
  { id: 'b586', name: "Lil' Nathan & the Zydeco Big Timers"                       , day: 'd8', stage: 'fais',       start: '15:00', end: '15:55', yt: 'DPr-PdzR_c8', verified: true , blurb: 'Lil\' Nathan & the Zydeco Big Timers bring swamp-fire energy and accordion-driven groove to the Fais Do-Do Stage, blending traditional Louisiana zydeco with infectious modern swagger that gets the whole crowd moving as one. These New Orleans natives are masters of the celebratory spirit that makes Jazz Fest unforgettable—expect rapid-fire rhythms, call-and-response joy, and the kind of dancing that spills way beyond the stage.'},
  { id: 'b587', name: "Roddie Romero & the Hub City All-Stars"                    , day: 'd8', stage: 'fais',       start: '16:15', end: '17:10', yt: '_E1_QKO-CQQ', verified: true , blurb: 'Roddie Romero & the Hub City All-Stars bring swamp-fired zydeco and Louisiana French soul to the Fais Do-Do stage, spinning accordion-driven grooves that get the whole crowd moving as one joyful mass. These are the sounds of South Louisiana\'s heartbeat—raw, danceable, and deeply rooted in the region\'s cultural legacy that makes Jazz Fest feel like coming home.'},
  { id: 'b588', name: "Steve Earle featuring Anders Osborne"                      , day: 'd8', stage: 'fais',       start: '17:40', end: '19:00', yt: '4CxPKa1kddo', verified: true , blurb: 'Steve Earle and Anders Osborne bring weathered storytelling and soulful Americana to the Fais Do-Do Stage, blending roots rock grit with New Orleans funk and slide guitar soul—a masterclass in how tradition and innovation collide. This is music for people who love their heroes real, their rhythms deep, and their narratives unflinching.'},
  { id: 'b589', name: "Fermín Ceballos Band"                                      , day: 'd8', stage: 'heritage',   start: '11:20', end: '12:20', yt: '18I7hE9UBZw', verified: true , blurb: 'Fermín Ceballos Band brings the infectious rhythms and soulful sophistication of Cuban jazz and son traditions to the Jazz & Heritage Stage, blending classic Caribbean grooves with modern improvisational fire that hits like a perfect mojito on a New Orleans afternoon. Their music pulses with the kind of irresistible energy that gets the whole crowd moving—a masterclass in how rhythm and melody become one.'},
  { id: 'b590', name: "Chiefs of the Indian Nation Mardi Gras Indians"            , day: 'd8', stage: 'heritage',   start: '12:40', end: '13:20', yt: 'RA9TyYIrcik', verified: true , blurb: 'Chiefs of the Indian Nation bring the raw spiritual power and infectious rhythms of New Orleans\' legendary Mardi Gras Indian tradition to the Jazz & Heritage Stage, blending deep-rooted secondline grooves with funkified percussion and call-and-response vocals that\'ll have you moving before you know what hit you. If you\'re here for authentic New Orleans culture, unapologetic funk energy, and the kind of neighborhood soul that makes this city undeniable, these chiefs are essential.'},
  { id: 'b591', name: "Pocket Aces Brass Band"                                    , day: 'd8', stage: 'heritage',   start: '13:40', end: '14:40', yt: 'glZBT916joY', verified: true , blurb: 'Pocket Aces Brass Band brings the swagger and soul of New Orleans brass tradition with a modern edge, layering punchy horns over infectious grooves that\'ll have you dancing before they hit the second verse. These guardians of the second line sound know exactly how to blend timeless New Orleans funk with contemporary flair—the kind of band that makes Jazz Fest the unmissable pilgrimage it\'s always been.'},
  { id: 'b592', name: "Mariachi Jalisco"                                          , day: 'd8', stage: 'heritage',   start: '15:00', end: '16:00', yt: '9J9YxWNXS4c', verified: true , blurb: 'Mariachi Jalisco brings the blazing brass brilliance and romantic swagger of Mexico\'s most storied musical tradition to Jazz Fest, blending centuries-old mariachi authenticity with the improvisational spirit that makes this festival legendary. Their lush violins, soaring trumpets, and percussive fire create an irresistible cross-cultural moment where New Orleans\' love of brass bands meets Jalisco\'s passion and precision.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41552/festivalartist-12476-artist_image-663a2431-d327-4678-8714-f9dbbf9d74a1.jpg'},
  { id: 'b593', name: "Big Chief Bo Dollis Jr. & The Wild Magnolias"              , day: 'd8', stage: 'heritage',   start: '16:25', end: '17:25', yt: 'FYn4H0AFE_A', verified: true , blurb: 'Experience the raw soul and thunderous percussion of Big Chief Bo Dollis Jr. & The Wild Magnolias, New Orleans\' most electrifying Mardi Gras Indian collective, where second-line swagger meets hypnotic chants and layered rhythms that\'ll have you moving before the first beat drops. Their unapologetic blend of traditional Indian culture, funk grooves, and call-and-response energy is pure New Orleans—a visceral celebration that proves why Jazz Fest fans can\'t resist the Magnolias\' unstoppable sound.'},
  { id: 'b594', name: "Herbert McCarver & Pin Stripe Brass Band"                  , day: 'd8', stage: 'heritage',   start: '17:45', end: '18:45', yt: 'IeoBUDoM15Q', verified: true , blurb: 'Herbert McCarver & Pin Stripe Brass Band brings the street-parade energy and soulful swagger of New Orleans brass tradition straight to the Jazz Heritage Stage, blending classic New Orleans funk grooves with contemporary horn arrangements that\'ll have you moving. Their crisp, sharp-dressed sound—anchored by punchy brass and deep pocket rhythms—captures the spirit of the city\'s most vibrant second lines and social aid club traditions.'},
  { id: 'b595', name: "Quint Adkins & Lighthouse Music"                           , day: 'd8', stage: 'gospel',     start: '11:10', end: '11:50', yt: 'fleTf5dp9Yg', verified: true , blurb: 'Quint Adkins & Lighthouse Music illuminate the Gospel Tent with soul-stirring vocals and uplifting spiritual harmonies that blend traditional New Orleans gospel with contemporary praise, creating an infectious, feel-good experience that\'ll have the whole crowd swaying. Their dynamic energy and heartfelt delivery make them a Jazz Fest essential for anyone seeking that transcendent moment of joy and connection.'},
  { id: 'b596', name: "Pastor Woodrow Hayden"                                     , day: 'd8', stage: 'gospel',     start: '12:00', end: '12:40', yt: 'CPNu8ohdMtE', verified: true , blurb: 'Pastor Woodrow Hayden brings soulful, spirit-filled vocals and deep-rooted New Orleans gospel tradition to the Gospel Tent, delivering the kind of authentic, heart-stirring performances that remind you why this music moves generations. His rich baritone and commanding stage presence create an irresistible call-and-response energy that\'ll have the whole tent on their feet—perfect for Jazz Fest pilgrims seeking genuine spiritual uplift and undeniable groove.'},
  { id: 'b597', name: "Jessica Harvey and The Difference"                         , day: 'd8', stage: 'gospel',     start: '12:50', end: '13:35', yt: '-XbCTpcsBLk', verified: true , blurb: 'Jessica Harvey and The Difference is a ministry that was birthed out of the dreams and prophecies given to Elder Jessica Harvey-Daranda. In May of 2015, Jessica asked some ladies if they would prayerfully take this journey with her, and with no hesitation, they all said yes. These ladies are on a mission to make “the difference” in this world and spread love and hope to everyone they encounter. It is our goal to lead everyone to a real place of worship, and to a deeper relationship with Jesus Christ. All of the ladies that are in “The Difference” are from New Orleans, LA and are members of different churches, but they all love to sing and worship the Lord. The Difference also embraces the old school gospel sound to their music. We plan on traveling the world and spreading the good news of Jesus Christ. In the almost 5 years that The Difference has been in existence, God has allowed us to travel across the country and share the stage with many gospel artists. We have been on WWLTV Channel 4 Morning Show and the local TV show, “The 504” with Sheba Turk. We were blessed to be featured at the Essence Music Festival in 2016 and 2019 for the Empowerment Series that has paid tribute to many gospel stars. We were also granted with the opportunity to open up for gospel star James Fortune and FIYA. The Difference has been nominated for and won several NOLA Gospel Awards. We are also nominated for the 2019 Rhythm of Gospel Awards. We were blessed to release singles in 2018 and 2019 entitled, “Simply” and “For He’s Been Good”, and we plan on recording and singing for many years to come.'},
  { id: 'b598', name: "The New Orleans Gospel Soul Children"                      , day: 'd8', stage: 'gospel',     start: '13:45', end: '14:25', yt: '6qkqAIvWzN8', verified: true , blurb: 'The New Orleans Gospel Soul Children bring transcendent harmonies and deep spiritual grooves that blend traditional New Orleans gospel with contemporary soul—their infectious energy and authentic joy make them an unmissable sanctuary moment in the Gospel Tent. These guardians of the city\'s sacred musical tradition deliver the kind of performance that lifts your spirit and keeps your feet moving all at once.'},
  { id: 'b599', name: "Jabez"                                                     , day: 'd8', stage: 'gospel',     start: '14:45', end: '15:45', yt: 'pjXpP9d4d44', verified: true , blurb: 'Jabez brings transcendent soul-stirring vocals and contemporary gospel grooves to the Jazz Fest stage, blending New Orleans\' rich spiritual traditions with modern R&B sensibilities that\'ll have you moving and swaying from the first note. This is pure, joyful celebration—the kind of authentic Gospel Tent experience that reminds you why this festival exists.'},
  { id: 'b600', name: "Davell Crawford presents Fabulous Friends Forever with special guests Cyril Neville, Charmaine Neville, Wanda Rouzan, The Davell Crawford Singers, and more", day: 'd8', stage: 'gospel',     start: '16:05', end: '17:05', yt: '6O57GVt2Sss', verified: true , blurb: 'Davell Crawford presents an all-star celebration of New Orleans soul and sacred music, bringing together generations of the city\'s most beloved voices for an uplifting, joyful experience that proves gospel is the beating heart of the Fest. With the Neville family legacy, powerhouse vocals, and the Crawford Singers bringing infectious energy and deep spiritual roots, this is pure New Orleans church music at its finest.'},
  { id: 'b601', name: "Jonté Mayon"                                               , day: 'd8', stage: 'gospel',     start: '17:15', end: '18:00', yt: 'FAkz2xoRRdo', verified: true , blurb: 'Jonté Mayon brings soulful, contemporary gospel fire to the Gospel Tent with a voice that channels deep spiritual conviction and modern R&B sensibility, delivering the kind of transcendent performances that remind you why New Orleans remains the beating heart of sacred American music.'},
  { id: 'b602', name: "New Orleans Metropolitan Choral Union"                     , day: 'd8', stage: 'gospel',     start: '18:10', end: '18:50', yt: 'Mq6hprGOxpY', verified: true , blurb: 'The New Orleans Metropolitan Choral Union brings transcendent vocal harmonies and soul-deep spirituality to the Gospel Tent, their voices layered with the rich tradition of Black sacred music that built this city\'s sound from the ground up. Jazz Fest devotees seeking authentic New Orleans gospel—the kind that moves your spirit and gets your feet moving—will find themselves transported by their powerful, community-rooted arrangements.'},
  { id: 'b603', name: "Don “Moose” Jamison Heritage School of Music"              , day: 'd8', stage: 'lagniappe',  start: '11:30', end: '12:25', yt: 'mdKR8Qk3y4M', verified: true , blurb: 'Don "Moose" Jamison Heritage School of Music brings the authentic soul of New Orleans brass tradition to life, blending classic second-line swagger with modern energy that honors the city\'s deepest musical roots. Their infectious, community-driven sound celebrates the mentorship and joy that defines the heritage school movement, making them an unmissable set for anyone seeking the real heartbeat of the festival.'},
  { id: 'b604', name: "James McClaskey & The Rhythm Band"                         , day: 'd8', stage: 'lagniappe',  start: '12:50', end: '13:50', yt: 'I-24Z1A6i5I', verified: true , blurb: 'James McClaskey & The Rhythm Band deliver infectious New Orleans funk and soul that gets deep into your bones, blending classic R&B grooves with contemporary edge and the kind of feel-good energy that makes the Lagniappe Stage the festival\'s beating heart. These are players who understand that rhythm is everything, serving up the kind of music that moves you whether you\'re dancing or standing still.'},
  { id: 'b605', name: "Vicki Peterson & John Cowsill"                             , day: 'd8', stage: 'lagniappe',  start: '14:10', end: '15:10', yt: 'KSpTYEhD0vE', verified: true , blurb: 'Vicki Peterson and John Cowsill bring the spirited backbone of American roots music to the Lagniappe Stage, blending folk sensibility with infectious melodies and the kind of storytelling that makes Jazz Fest audiences feel right at home in the New Orleans groove. These seasoned musicians deliver authenticity and warmth with every note, proving why legacy artists remain festival favorites year after year.'},
  { id: 'b606', name: "Carol C"                                                   , day: 'd8', stage: 'lagniappe',  start: '15:30', end: '16:30', yt: 'AjrbA5kkQps', verified: true , blurb: 'Carol C brings sultry, soulful vocals and classic New Orleans R&B to the Lagniappe Stage, delivering intimate performances that showcase the city\'s rich tradition of groove-centered storytelling and late-night sophistication that keeps Jazz Fest audiences coming back for more.'},
  { id: 'b607', name: "Robin Barnes & the FiyaBirds"                              , day: 'd8', stage: 'lagniappe',  start: '16:55', end: '18:00', yt: 'dtsm_4esbyk', verified: true , blurb: 'Robin Barnes & the FiyaBirds bring incendiary funk and soul to the Lagniappe Stage, blending New Orleans\' deep roots traditions with explosive contemporary grooves that\'ll get you moving from the opening note. This is the sound of the city\'s future—searing horns, locked-in rhythms, and pure unbridled energy that reminds you why Jazz Fest exists.'},
  { id: 'b608', name: "Dex Daley & Jam-X"                                         , day: 'd8', stage: 'jamaica',    start: '11:30', end: '12:15', yt: 'svoEAcHJ9bA', verified: true , blurb: 'Dex Daley & Jam-X bring infectious reggae and Caribbean rhythms to the Sandals Jamaica Cultural Pavilion, blending island vibes with New Orleans funk for a feel-good set that\'ll have you moving from first note to last. Their high-energy grooves and soulful horns celebrate the deep connection between Jamaica and the Crescent City, delivering the kind of transcendent, cross-cultural jam that makes Jazz Fest legendary.'},
  { id: 'b609', name: "Jabez"                                                     , day: 'd8', stage: 'jamaica',    start: '12:35', end: '13:35', yt: 'pjXpP9d4d44', verified: true , blurb: 'Jabez brings transcendent soul-stirring vocals and contemporary gospel grooves to the Jazz Fest stage, blending New Orleans\' rich spiritual traditions with modern R&B sensibilities that\'ll have you moving and swaying from the first note. This is pure, joyful celebration—the kind of authentic Gospel Tent experience that reminds you why this festival exists.'},
  { id: 'b610', name: "RAM from Haiti"                                            , day: 'd8', stage: 'jamaica',    start: '14:00', end: '15:00', yt: 'hvny_tmVzFc', verified: true , blurb: 'RAM from Haiti brings electrifying Caribbean rhythms and roots reggae fire to the Sandals Jamaica Cultural Pavilion, fusing island consciousness with infectious grooves that\'ll have the whole crowd moving as one. Their high-energy blend of dancehall, reggae, and traditional Haitian sounds captures the spirit of the islands—expect contagious positivity, powerful lyrics, and the kind of performance that reminds you why Jazz Fest celebrates the full spectrum of global music culture.'},
  { id: 'b611', name: "Jemere Morgan"                                             , day: 'd8', stage: 'jamaica',    start: '15:25', end: '16:25', yt: 'tWe3AaV4tTg', verified: true , blurb: 'Jemere, son of Gramps Morgan has now branched out into the music business like many of his relatives before him. According to Jemere, it was his father who discovered his talent.'},
  { id: 'b612', name: "Kaya Jonkunnu Band & Walking Tall Jamaica"                 , day: 'd8', stage: 'jamaica',    start: '16:25', end: '17:00', yt: 'tldLqfvH-jc', verified: true , blurb: 'Kaya Jonkunnu Band & Walking Tall Jamaica brings the infectious rhythms of Jamaica straight to the heart of Jazz Fest, blending traditional jonkunnu percussion with modern reggae and roots energy that\'ll have you moving from the first beat. Their celebration of Caribbean culture and vibrant island grooves makes them an essential stop for anyone seeking the festival\'s most irresistible cross-cultural vibes.'},
  { id: 'b613', name: "Lila Iké"                                                  , day: 'd8', stage: 'jamaica',    start: '17:00', end: '18:00', yt: 'qWj6gGWm0og', verified: true , blurb: 'Lila Iké (neé Alecia Grey) is a singer and songwriter from Manchester, Jamaica.  She gained attention at home and abroad with her distinctive delivery, old-school sensibilities and modern-day swagger.'},
  { id: 'b614', name: "Anders Parker"                                             , day: 'd8', stage: 'rhythm',     start: '12:00', end: '12:45', yt: 'H9AOG9NedD8', verified: true , blurb: 'Anders Parker is a modest man who lives in Burlington, Vermont and works as a musician. People who are into American songwriters know him as the frontman of Varnaline.'},
  { id: 'b615', name: "Raphael Bas and Harmonouche"                               , day: 'd8', stage: 'rhythm',     start: '13:10', end: '14:00', yt: 'j2gBQwuX-DY', verified: true , blurb: 'Raphael Bas and Harmonouche bring hypnotic, polyrhythmic grooves that blur the lines between Caribbean percussion, Afrobeat, and New Orleans funk—a transcendent dance-floor experience that transforms the Rhythmpourium Tent into a celebration of global rhythm and local soul. If you\'re seeking infectious energy, masterful instrumentation, and the kind of set that makes your body move before your mind catches up, this is your moment.'},
  { id: 'b616', name: "Songwriters Craig Wiseman, Lee Thomas Miller and Jim McCormick", day: 'd8', stage: 'rhythm',     start: '14:25', end: '15:10', yt: 'XlFSM70N0W8', verified: true , blurb: 'These three celebrated songwriters bring their craft and chemistry to the Rhythmpourium Tent, blending country soul, folk wisdom, and Nashville polish with a deep New Orleans groove that speaks to real life and real love. Expect intimate storytelling, infectious rhythms, and the kind of authentic songwriting that makes Jazz Fest audiences lean in and remember why the music matters.'},
  { id: 'b617', name: "Rich Collins"                                              , day: 'd8', stage: 'rhythm',     start: '15:35', end: '16:20', yt: 'ub7Di_1ohjU', verified: true , blurb: 'Rich Collins is an Emmy Award-winning songwriter, drummer, guitarist and singer who co-created the Disney television series “Imagination Movers.” He has released two solo albums: “That Escalated Quickly” (2013) and “Golden Pick” (2015). His third album, “Minivan Wilder,” will be available this spring. Rich has performed for millions of fans on stages worldwide as well as live on “Good Morning America,” “The View” and “LIVE with Regis and Kelly.” When he’s not on the road, he plays in various haunts around New Orleans. Rich is equally interested in writing songs, playing the drums (often while standing up) and playing finger-style acoustic guitar. As a result, his music is a blend of singer-songwriter melodies and dance-able New Orleans grooves. Rich grew up in the Washington, D.C. suburbs and relocated to New Orleans after college. He and his wife Becky have five children.', img: 'https://festuff-production.s3.amazonaws.com/uploads/image/attachment/41555/festivalartist-12487-artist_image-4b082b79-92db-4d57-aef7-f6075f509a25.jpg'},
  { id: 'b618', name: "Michael \"The Sheik\" O'Hara"                              , day: 'd8', stage: 'rhythm',     start: '16:45', end: '17:30', yt: '0XSD5yySrws', verified: true , blurb: 'Michael "The Sheik" O\'Hara brings swagger and soul to the Rhythmpourium Tent with a hypnotic blend of funk, New Orleans R&B, and contemporary hip-hop that gets the whole tent moving as one. His commanding presence and genre-bending grooves make him a festival favorite for anyone seeking that perfect intersection of tradition and modern edge.'},
  { id: 'b619', name: "Dancing Grounds Dance for Social Change"                   , day: 'd8', stage: 'children',   start: '11:30', end: '12:15', yt: 'DFOB06ipmnQ', verified: true , blurb: 'Dancing Grounds brings infectious, socially conscious choreography and live music that gets kids and families moving with purpose, blending contemporary dance, global rhythms, and the spirit of community activism that makes New Orleans culture unforgettable. Their high-energy performances turn the Children\'s Tent into a celebration of joy, movement, and positive change—exactly the kind of cross-generational magic that keeps Jazz Fest audiences coming back year after year.'},
  { id: 'b620', name: "Rising Dragon Lion Dance"                                  , day: 'd8', stage: 'children',   start: '12:15', end: '13:05', yt: 'xrZtB7Ur-OQ', verified: true , blurb: 'Rising Dragon Lion Dance brings explosive energy and vibrant cultural tradition to the children\'s stage, blending percussive dynamism with the mesmerizing visual spectacle of classical lion choreography—a must-see for families seeking the Festival\'s most joyful, interactive performances.'},
  { id: 'b621', name: "Amy Bruton Bluemel: Chickasaw Storyteller"                 , day: 'd8', stage: 'children',   start: '13:05', end: '13:55', yt: 'nYyvisy6Hes', verified: true , blurb: 'Amy Bruton Bluemel spins infectious folk-rooted storytelling and playful melodies that captivate young audiences while celebrating Chickasaw heritage and Southern tradition—a joyful, educational performance that reminds Jazz Fest families why live music matters.'},
  { id: 'b622', name: "Rising Dragon Lion Dance"                                  , day: 'd8', stage: 'children',   start: '13:55', end: '14:50', yt: 'xrZtB7Ur-OQ', verified: true , blurb: 'Rising Dragon Lion Dance brings explosive energy and vibrant cultural tradition to the children\'s stage, blending percussive dynamism with the mesmerizing visual spectacle of classical lion choreography—a must-see for families seeking the Festival\'s most joyful, interactive performances.'},
  { id: 'b623', name: "Square Dance NOLA"                                         , day: 'd8', stage: 'children',   start: '14:50', end: '15:40', yt: 'L3L0rZimyUE', verified: true , blurb: 'Square Dance NOLA brings infectious energy and playful swagger to the festival, blending New Orleans funk grooves with call-and-response fun that gets kids and families moving together in pure joy. Their high-octane, brass-fueled sound celebrates the city\'s dance-floor DNA while keeping the vibe family-friendly and undeniably fun.'},
  { id: 'b624', name: "Kaya Jonkunnu Band & Walking Tall Jamaica"                 , day: 'd8', stage: 'children',   start: '15:40', end: '16:20', yt: 'tldLqfvH-jc', verified: true , blurb: 'Kaya Jonkunnu Band & Walking Tall Jamaica brings the infectious rhythms of Jamaica straight to the heart of Jazz Fest, blending traditional jonkunnu percussion with modern reggae and roots energy that\'ll have you moving from the first beat. Their celebration of Caribbean culture and vibrant island grooves makes them an essential stop for anyone seeking the festival\'s most irresistible cross-cultural vibes.'},
  { id: 'b625', name: "Culu Children's Traditional African Dance Company"         , day: 'd8', stage: 'children',   start: '16:20', end: '17:00', yt: 'gMtPy0K0PUE', verified: true , blurb: 'Culu Children\'s Traditional African Dance Company brings the infectious rhythms and vibrant storytelling of West African tradition to life, with spirited percussion and movement that will have young audiences dancing in the aisles and discovering the roots of the rhythms that built New Orleans itself.'},
  { id: 'b626', name: "Kyle Roussel Interviewer: Jason Patterson"                 , day: 'd8', stage: 'miner',      start: '12:00', end: '12:45', yt: 'ZJt54YUi350', verified: true , blurb: 'Kyle Roussel brings authentic Louisiana storytelling to life through intimate, soulful performances that celebrate the region\'s rich musical traditions. With Jason Patterson as interviewer, this session captures the heart of Creole and Cajun culture that Jazz Fest fans crave—real voices, real stories, real New Orleans.'},
  { id: 'b627', name: "Kaya Jonkunnu of Jamaica: Rhythms, Masquerade, and Cultural Resistance Interviewer: Bruce “Sunpie” Barnes", day: 'd8', stage: 'miner',      start: '13:00', end: '13:45', yt: 'p7IXaBUrUjs', verified: true , blurb: 'Kaya Jonkunnu brings the spiritual fire of Jamaican masquerade traditions and resistance anthems to Jazz Fest, blending hypnotic rhythms with Bruce "Sunpie" Barnes\' deep roots expertise for a performance that honors Caribbean cultural memory and African diaspora resilience. This is music that moves both body and soul, celebrating the untamed spirit that defines New Orleans\' own heritage of cultural defiance.'},
  { id: 'b628', name: "Jackie Venson Interviewer: Scott Jordan"                   , day: 'd8', stage: 'miner',      start: '14:00', end: '14:45', yt: 'mDD8flMdwTg', verified: true , blurb: 'Jackie Venson brings intimate, soulful storytelling to the Heritage Stage, blending Americana roots with Louisiana soul and the kind of conversational ease that makes you feel like you\'re in her living room. Scott Jordan\'s interview format lets her authenticity shine through in a way that lets you discover why she\'s become an essential voice in folk and Americana circles.'},
  { id: 'b629', name: "Steve Earle Interviewer: Mark Guarino"                     , day: 'd8', stage: 'miner',      start: '15:00', end: '15:45', yt: 'xvaEJzoaYZk', verified: true , blurb: 'Steve Earle brings raw Americana storytelling and weathered authenticity to the Heritage Stage, with Mark Guarino\'s sharp interview framing the legacy of a Nashville icon who\'s never stopped pushing roots music forward—a must-see for anyone chasing real, unfiltered artistry.'},
  { id: 'b630', name: "Big Chiefs of the Indian Juan Pardo, Nation: Terrance Mitchell & Shaka Zulu Interviewer: Matt Sakakeeny", day: 'd8', stage: 'miner',      start: '16:00', end: '16:45', yt: 'HU9hGNmO5rw', verified: true , blurb: 'Experience the raw spiritual power of New Orleans Mardi Gras Indian culture as Big Chiefs Terrance Mitchell and Shaka Zulu bring the Indian Juan Pardo Nation\'s thunderous chants, hypnotic rhythms, and hand-sewn pageantry to life—a celebration of Black creativity, resistance, and joy that defines the soul of the city. Jazz Fest devotees know that the real heritage of New Orleans lives in moments like this, where music, tradition, and community become one unstoppable force.'},
];

const isFull = window.SCHEDULE_MODE === 'full';
